};

const HostTableColumnKind = enum(u8) {
    boolean,
    int,
    float,
    string,
    date,
    time,
    time_ns,
    time_tz,
    timestamp,
    timestamp_s,
    timestamp_ms,
    timestamp_ns,
    timestamp_tz,
