    }

    fn beginSamplingProfileScope(self: *Session, label: SamplingProfileLabel) SamplingProfileScope {
        if (comptime !enable_sampling_profile) {
            return .{};
        }
        if (self.profile_sampling_enabled.load(.unordered) == 0) return .{};
        const previous_label = self.profile_current_label.load(.unordered);
        self.profile_current_label.store(@intFromEnum(label), .unordered);
        return .{
            .session = self,
            .previous_label = previous_label,
        };
    }

    pub fn wasmAcceleratorArrayInfo(self: *Session, value: Value) KError!?WasmArrayInfo {
        return runtime_backend_wasm.wasmAcceleratorArrayInfo(.{
            .Session = Session,
            .Value = Value,
            .WasmArrayInfo = WasmArrayInfo,
            .KError = KError,
            .mlx = mlx,
            .wasmAcceleratorPayload = wasmAcceleratorPayload,
        }, self, value);
    }

    pub fn renderValue(self: *Session, value: Value) anyerror![]u8 {
        var profile_scope = self.beginSamplingProfileScope(.render);
        defer profile_scope.end();
        return switch (value.tag()) {
            .int => std.fmt.allocPrint(self.allocator, "{d}", .{value.asInt()}),
            .float => formatFloat(self.allocator, value.asFloat()),
            .bool => std.fmt.allocPrint(self.allocator, "{d}b", .{@intFromBool(value.asBool())}),
            .builtin => std.fmt.allocPrint(self.allocator, "{c}", .{builtinChar(value.asBuiltin())}),
            .closure => std.fmt.allocPrint(self.allocator, "{{...}}", .{}),
            .array => self.renderArray(value),
        };
    }

    fn renderArray(self: *Session, value: Value) anyerror![]u8 {
        if (valueNumericHandle(value)) |handle| return self.renderNumericArray(handle);
        const kind = value.arrayKind();
        return switch (kind) {
            .host_dense_array => self.renderHostArray(value.asHostDenseArray()),
            .host_boxed_array => self.renderHostBoxedArray(value.asHostBoxedArray()),
            .host_string => self.renderHostString(value.asHostString()),
            .host_symbol => self.renderHostSymbol(value.asHostSymbol()),
            .host_string_list => self.renderHostStringList(value.asHostStringList()),
            .host_string_view => self.renderHostStringView(value.asHostStringView()),
            .host_relation => self.renderHostRelation(value.asHostRelation()),
            .host_keyed_store => self.renderHostKeyedStore(value.asHostKeyedStore()),
            .host_table_scalar => self.renderHostTableScalar(valueAsHostTableScalar(value)),
            .backend_array => self.renderBackendArray(value.asBackendArray()),
            else => error.Internal,
        };
    }

    fn appendRenderedFloat(out: *std.ArrayList(u8), allocator: std.mem.Allocator, value: f64) !void {
        const part = try formatFloat(allocator, value);
        defer allocator.free(part);
        try out.appendSlice(allocator, part);
    }

    fn renderNumericArray(self: *Session, handle: *const NumericArray) anyerror![]u8 {
        return switch (handle.activeKind()) {
            .host_dense_array => self.renderHostNumericArray(handle, numericHostAttachment(handle) orelse return error.Internal),
            .backend_array => self.renderBackendArray(numericBackendAttachment(handle) orelse return error.Internal),
            .numeric_array => blk: {
                const value = Value.array(@constCast(handle));
                if (!numericHasHostAttachment(handle) and hasBackendRealization(value)) {
                    _ = try tryEnsureHostRealizationForHandle(self, @constCast(handle)) orelse return error.Type;
                    break :blk try self.renderNumericArray(handle);
                }
                const mode = valueNumericMode(Value.array(@constCast(handle))) orelse return error.Type;
                const len = numericFlatLen(value) orelse return error.Type;
                if (handle.rank <= 1) {
                    if (len == 0 and mode == .int) return try self.allocator.dupe(u8, "!0");
                    var out = std.ArrayList(u8).empty;
                    errdefer out.deinit(self.allocator);
                    for (0..len) |idx| {
                        if (idx != 0) try out.append(self.allocator, ' ');
                        switch (mode) {
                            .int => try out.writer(self.allocator).print("{d}", .{try numericIntAt(value, idx)}),
                            .float => try appendRenderedFloat(&out, self.allocator, try numericFloatAt(value, idx)),
                        }
                    }
                    break :blk out.toOwnedSlice(self.allocator);
                }
                if (handle.rank == 2) {
                    const rows: usize = @intCast(handle.shape[0]);
                    const cols: usize = @intCast(handle.shape[1]);
                    if (rows * cols != len) return error.Internal;
                    if (cols == 0 and mode == .int) {
                        var out = std.ArrayList(u8).empty;
                        errdefer out.deinit(self.allocator);
                        for (0..rows) |row| {
                            if (row != 0) try out.append(self.allocator, '\n');
                            try out.appendSlice(self.allocator, "!0");
                        }
                        break :blk out.toOwnedSlice(self.allocator);
                    }
                    var out = std.ArrayList(u8).empty;
                    errdefer out.deinit(self.allocator);
                    for (0..rows) |row| {
                        if (row != 0) try out.append(self.allocator, '\n');
                        const base = row * cols;
                        for (0..cols) |col| {
                            if (col != 0) try out.append(self.allocator, ' ');
                            switch (mode) {
                                .int => try out.writer(self.allocator).print("{d}", .{try numericIntAt(value, base + col)}),
                                .float => try appendRenderedFloat(&out, self.allocator, try numericFloatAt(value, base + col)),
                            }
                        }
                    }
                    break :blk out.toOwnedSlice(self.allocator);
                }
                return error.Unsupported;
            },
            else => error.Internal,
        };
    }

    fn renderHostNumericArray(self: *Session, handle: *const NumericArray, array: *const HostDenseArray) anyerror![]u8 {
        if (handle.rank <= 1) return self.renderHostArray(array);
        if (handle.rank != 2) return error.Unsupported;

        const rows: usize = @intCast(handle.shape[0]);
        const cols: usize = @intCast(handle.shape[1]);
        if (rows * cols != array.len()) return error.Internal;

        if (cols == 0) switch (array.storage) {
            .int8, .int16, .int32, .int64 => {
                var out = std.ArrayList(u8).empty;
                errdefer out.deinit(self.allocator);
                for (0..rows) |row| {
                    if (row != 0) try out.append(self.allocator, '\n');
                    try out.appendSlice(self.allocator, "!0");
                }
                return try out.toOwnedSlice(self.allocator);
            },
            else => {},
        };

        var out = std.ArrayList(u8).empty;
        errdefer out.deinit(self.allocator);

        switch (array.storage) {
            .bit => |words| {
                for (0..rows) |row| {
                    if (row != 0) try out.append(self.allocator, '\n');
                    const base = row * cols;
                    for (0..cols) |col| try out.append(self.allocator, if (bitGet(words, base + col)) '1' else '0');
                    try out.append(self.allocator, 'b');
                }
            },
            .int8, .int16, .int32, .int64 => {
                const view = hostIntArrayView(array) orelse return error.Type;
                for (0..rows) |row| {
                    if (row != 0) try out.append(self.allocator, '\n');
                    const base = row * cols;
                    for (0..cols) |col| {
                        if (col != 0) try out.append(self.allocator, ' ');
                        try out.writer(self.allocator).print("{d}", .{hostIntViewItem(view, base + col)});
                    }
                }
            },
            .float64 => |items| {
                for (0..rows) |row| {
                    if (row != 0) try out.append(self.allocator, '\n');
                    const base = row * cols;
                    for (0..cols) |col| {
                        if (col != 0) try out.append(self.allocator, ' ');
                        const part = try formatFloat(self.allocator, items[base + col]);
                        defer self.allocator.free(part);
                        try out.appendSlice(self.allocator, part);
                    }
                }
            },
        }

        return try out.toOwnedSlice(self.allocator);
    }

    fn renderHostString(self: *Session, text: *const HostText) anyerror![]u8 {
        return std.fmt.allocPrint(self.allocator, "\"{s}\"", .{hostTextBytes(text)});
    }

    fn renderHostSymbol(self: *Session, text: *const HostText) anyerror![]u8 {
        return std.fmt.allocPrint(self.allocator, "`{s}", .{hostTextBytes(text)});
    }

    fn renderHostStringView(self: *Session, view: *const HostStringView) anyerror![]u8 {
        return std.fmt.allocPrint(self.allocator, "\"{s}\"", .{hostStringViewBytes(view)});
    }

    fn renderHostRelation(self: *Session, relation: *const HostRelation) anyerror![]u8 {
        return switch (relation.origin) {
            .file => |file| std.fmt.allocPrint(
                self.allocator,
                "relation[{s};\"{s}\"]",
                .{ file.source_kind.text(), file.path },
            ),
            .sql => |sql_info| std.fmt.allocPrint(
                self.allocator,
                "relation[sql;\"{s}\"]",
                .{sql_info.text},
            ),
        };
    }

    fn renderHostTableScalar(self: *Session, scalar: *const HostTableScalar) anyerror![]u8 {
        if (scalar.is_null) return try self.allocator.dupe(u8, "null");
        return switch (scalar.kind) {
            .boolean, .int, .float, .string => try self.renderValue(scalar.value),
            .date => try self.renderDateCell(scalar.value.asInt()),
            .time => try self.renderTimeCell(scalar.value.asInt()),
            .time_ns => try self.renderTimeNsCell(scalar.value.asInt()),
            .time_tz => try self.renderTimeTzCell(scalar.value.asInt()),
            .timestamp => try self.renderTimestampMicrosCell(scalar.value.asInt(), null),
            .timestamp_s => try self.renderTimestampScaledCell(scalar.value.asInt(), 1_000_000, null),
            .timestamp_ms => try self.renderTimestampScaledCell(scalar.value.asInt(), 1_000, null),
            .timestamp_ns => try self.renderTimestampNsCell(scalar.value.asInt(), null),
            .timestamp_tz => try self.renderTimestampMicrosCell(scalar.value.asInt(), "Z"),
        };
    }

    fn keyedStoreValues(store: *const HostKeyedStore) *const HostBoxedArray {
        std.debug.assert(store.values.tag() == .array and store.values.arrayKind() == .host_boxed_array);
        return store.values.asHostBoxedArray();
    }

    fn keyedStoreNameCount(store: *const HostKeyedStore) usize {
        return switch (store.names.arrayKind()) {
            .host_boxed_array => store.names.asHostBoxedArray().items.len,
            .host_string_list => store.names.asHostStringList().len,
            else => unreachable,
        };
    }

    fn keyedStoreNameValue(self: *Session, store: *const HostKeyedStore, idx: usize) KError!Value {
        return switch (store.names.arrayKind()) {
            .host_boxed_array => blk: {
                const items = store.names.asHostBoxedArray().items;
                if (idx >= items.len) return error.Type;
                break :blk try self.retainEscapedValue(items[idx]);
            },
            .host_string_list => try self.frozenHostString(try hostStringListItemBytes(store.names.asHostStringList(), idx)),
            else => error.Internal,
        };
    }

    fn keyedStoreUsesDenseValueFastPath(store: *const HostKeyedStore) bool {
        return store.layout == .dict and store.column_metadata == null;
    }

    fn keyedStoreTableMetadata(store: *const HostKeyedStore) []const HostKeyedColumnMetadata {
        std.debug.assert(store.layout == .table);
        return store.column_metadata orelse unreachable;
    }

    fn keyedStoreColumnNameBytes(store: *const HostKeyedStore, column_idx: usize) []const u8 {
        return switch (store.names.arrayKind()) {
            .host_boxed_array => blk: {
                const names = store.names.asHostBoxedArray().items;
                if (column_idx >= names.len) return "";
                break :blk symbolBytes(names[column_idx]) orelse stringBytes(names[column_idx]) orelse "";
            },
            .host_string_list => hostStringListItemBytes(store.names.asHostStringList(), column_idx) catch "",
            else => "",
        };
    }

    fn tableColumnData(store: *const HostKeyedStore, column_idx: usize) Value {
        return keyedStoreValues(store).items[column_idx];
    }

    fn tableColumnKind(store: *const HostKeyedStore, column_idx: usize) HostTableColumnKind {
        return keyedStoreTableMetadata(store)[column_idx].kind;
    }

    fn keyedStoreTableCellIsValid(store: *const HostKeyedStore, column_idx: usize, row: usize) bool {
        const validity = keyedStoreTableMetadata(store)[column_idx].validity orelse return true;
        return (numericIntAt(validity, @intCast(row)) catch 0) != 0;
    }

    fn tableColumnNameBytes(column: *const HostTableColumn) []const u8 {
        return symbolBytes(column.name) orelse stringBytes(column.name) orelse "";
    }

    fn tableCellIsValid(column: *const HostTableColumn, row: usize) bool {
        const validity = column.validity orelse return true;
        return (numericIntAt(validity, @intCast(row)) catch 0) != 0;
    }

    fn nonFiniteTemporalText(self: *Session, raw: i64) ![]u8 {
        return try self.allocator.dupe(u8, if (raw < 0) "-inf" else "inf");
    }

    fn appendIsoYear(self: *Session, out: *std.ArrayList(u8), year: i32) !void {
        if (year < 0) {
            try out.append(self.allocator, '-');
            try out.writer(self.allocator).print("{d:0>4}", .{@as(u32, @intCast(-year))});
            return;
        }
        try out.writer(self.allocator).print("{d:0>4}", .{@as(u32, @intCast(year))});
    }

    fn appendTrimmedFractional(
        self: *Session,
        out: *std.ArrayList(u8),
        comptime width: comptime_int,
        value: u32,
    ) !void {
        if (value == 0) return;

        var buf: [width]u8 = undefined;
        const fmt = comptime std.fmt.comptimePrint("{{d:0>{}}}", .{width});
        const text = try std.fmt.bufPrint(&buf, fmt, .{value});

        var end = text.len;
        while (end > 0 and text[end - 1] == '0') : (end -= 1) {}
        if (end == 0) return;

        try out.append(self.allocator, '.');
        try out.appendSlice(self.allocator, text[0..end]);
    }

    const DivFloorResult = struct {
        quot: i64,
        rem: i64,
    };

    fn divFloorI64(value: i64, denom: i64) DivFloorResult {
        std.debug.assert(denom > 0);

        var quot = @divTrunc(value, denom);
        var rem = @rem(value, denom);
        if (rem < 0) {
            quot -= 1;
            rem += denom;
        }
        return .{ .quot = quot, .rem = rem };
    }

    fn renderDateCell(self: *Session, raw_days: i64) anyerror![]u8 {
        if (comptime !runtime_has_duckdb) return error.Unsupported;

        const days = std.math.cast(i32, raw_days) orelse return error.Unsupported;
        const date: duckdb_runtime.c.duckdb_date = .{ .days = days };
        if (!duckdb_runtime.c.duckdb_is_finite_date(date)) return try self.nonFiniteTemporalText(raw_days);

        const parts = duckdb_runtime.c.duckdb_from_date(date);
        var out = std.ArrayList(u8).empty;
        errdefer out.deinit(self.allocator);

        try self.appendIsoYear(&out, parts.year);
        try out.writer(self.allocator).print(
            "-{d:0>2}-{d:0>2}",
            .{ @as(u32, @intCast(parts.month)), @as(u32, @intCast(parts.day)) },
        );
        return try out.toOwnedSlice(self.allocator);
    }

    fn renderTimeParts(self: *Session, parts: duckdb_runtime.c.duckdb_time_struct, fractional: ?u32, comptime width: comptime_int) anyerror![]u8 {
        var out = std.ArrayList(u8).empty;
        errdefer out.deinit(self.allocator);

        try out.writer(self.allocator).print(
            "{d:0>2}:{d:0>2}:{d:0>2}",
            .{
                @as(u32, @intCast(parts.hour)),
                @as(u32, @intCast(parts.min)),
                @as(u32, @intCast(parts.sec)),
            },
        );
        if (fractional) |value| try self.appendTrimmedFractional(&out, width, value);
        return try out.toOwnedSlice(self.allocator);
    }

    fn renderTimeCell(self: *Session, raw_micros: i64) anyerror![]u8 {
        if (comptime !runtime_has_duckdb) return error.Unsupported;

        const parts = duckdb_runtime.c.duckdb_from_time(.{ .micros = raw_micros });
        return try self.renderTimeParts(parts, @intCast(parts.micros), 6);
    }

    fn renderTimeNsCell(self: *Session, raw_nanos: i64) anyerror![]u8 {
        if (comptime !runtime_has_duckdb) return error.Unsupported;

        const split = divFloorI64(raw_nanos, 1_000);
        const parts = duckdb_runtime.c.duckdb_from_time(.{ .micros = split.quot });
        const fractional = @as(u32, @intCast(parts.micros)) * 1_000 + @as(u32, @intCast(split.rem));
        return try self.renderTimeParts(parts, fractional, 9);
    }

    fn appendUtcOffset(self: *Session, out: *std.ArrayList(u8), raw_offset_seconds: i32) !void {
        const sign: u8 = if (raw_offset_seconds < 0) '-' else '+';
        const abs_seconds: u32 = @intCast(if (raw_offset_seconds < 0) -raw_offset_seconds else raw_offset_seconds);
        const hours = abs_seconds / 3_600;
        const minutes = (abs_seconds % 3_600) / 60;
        const seconds = abs_seconds % 60;

        try out.append(self.allocator, sign);
        try out.writer(self.allocator).print("{d:0>2}:{d:0>2}", .{ hours, minutes });
        if (seconds != 0) try out.writer(self.allocator).print(":{d:0>2}", .{seconds});
    }

    fn renderTimeTzCell(self: *Session, raw_bits: i64) anyerror![]u8 {
        if (comptime !runtime_has_duckdb) return error.Unsupported;

        const parts = duckdb_runtime.c.duckdb_from_time_tz(.{ .bits = @bitCast(raw_bits) });
        var out = std.ArrayList(u8).empty;
        errdefer out.deinit(self.allocator);

        try out.writer(self.allocator).print(
            "{d:0>2}:{d:0>2}:{d:0>2}",
            .{
                @as(u32, @intCast(parts.time.hour)),
                @as(u32, @intCast(parts.time.min)),
                @as(u32, @intCast(parts.time.sec)),
            },
        );
        try self.appendTrimmedFractional(&out, 6, @intCast(parts.time.micros));
        try self.appendUtcOffset(&out, parts.offset);
        return try out.toOwnedSlice(self.allocator);
    }

    fn renderTimestampParts(
        self: *Session,
        parts: duckdb_runtime.c.duckdb_timestamp_struct,
        fractional: ?u32,
        comptime width: comptime_int,
        suffix: ?[]const u8,
    ) anyerror![]u8 {
        var out = std.ArrayList(u8).empty;
        errdefer out.deinit(self.allocator);

        try self.appendIsoYear(&out, parts.date.year);
        try out.writer(self.allocator).print(
            "-{d:0>2}-{d:0>2}T{d:0>2}:{d:0>2}:{d:0>2}",
            .{
                @as(u32, @intCast(parts.date.month)),
                @as(u32, @intCast(parts.date.day)),
                @as(u32, @intCast(parts.time.hour)),
                @as(u32, @intCast(parts.time.min)),
                @as(u32, @intCast(parts.time.sec)),
            },
        );
        if (fractional) |value| try self.appendTrimmedFractional(&out, width, value);
        if (suffix) |text| try out.appendSlice(self.allocator, text);
        return try out.toOwnedSlice(self.allocator);
    }

    fn renderTimestampMicrosCell(self: *Session, raw_micros: i64, suffix: ?[]const u8) anyerror![]u8 {
        if (comptime !runtime_has_duckdb) return error.Unsupported;

        const ts: duckdb_runtime.c.duckdb_timestamp = .{ .micros = raw_micros };
        if (!duckdb_runtime.c.duckdb_is_finite_timestamp(ts)) return try self.nonFiniteTemporalText(raw_micros);

        const parts = duckdb_runtime.c.duckdb_from_timestamp(ts);
        return try self.renderTimestampParts(parts, @intCast(parts.time.micros), 6, suffix);
    }

    fn renderTimestampScaledCell(
        self: *Session,
        raw_value: i64,
        scale_to_micros: i64,
        suffix: ?[]const u8,
    ) anyerror![]u8 {
        if (comptime !runtime_has_duckdb) return error.Unsupported;

        const micros = std.math.mul(i64, raw_value, scale_to_micros) catch return error.Unsupported;
        return try self.renderTimestampMicrosCell(micros, suffix);
    }

    fn renderTimestampNsCell(self: *Session, raw_nanos: i64, suffix: ?[]const u8) anyerror![]u8 {
        if (comptime !runtime_has_duckdb) return error.Unsupported;

        const split = divFloorI64(raw_nanos, 1_000);
        const ts: duckdb_runtime.c.duckdb_timestamp = .{ .micros = split.quot };
        if (!duckdb_runtime.c.duckdb_is_finite_timestamp(ts)) return try self.nonFiniteTemporalText(raw_nanos);

        const parts = duckdb_runtime.c.duckdb_from_timestamp(ts);
        const fractional = @as(u32, @intCast(parts.time.micros)) * 1_000 + @as(u32, @intCast(split.rem));
        return try self.renderTimestampParts(parts, fractional, 9, suffix);
    }

    fn renderTableCell(self: *Session, store: *const HostKeyedStore, column_idx: usize, row: usize) anyerror![]u8 {
        if (!keyedStoreTableCellIsValid(store, column_idx, row)) return try self.allocator.dupe(u8, "null");
        const kind = keyedStoreTableMetadata(store)[column_idx].kind;
        const data = tableColumnData(store, column_idx);
        return switch (kind) {
            .boolean => std.fmt.allocPrint(self.allocator, "{d}b", .{@intFromBool((try numericIntAt(data, @intCast(row))) != 0)}),
            .int => std.fmt.allocPrint(self.allocator, "{d}", .{try numericIntAt(data, @intCast(row))}),
            .float => formatFloat(self.allocator, try numericFloatAt(data, @intCast(row))),
            .string => blk: {
                const value = try self.hostStringListItemValue(data.asHostStringList(), row);
                defer self.releaseValue(value);
                break :blk try self.renderValue(value);
            },
            .date => try self.renderDateCell(try numericIntAt(data, @intCast(row))),
            .time => try self.renderTimeCell(try numericIntAt(data, @intCast(row))),
            .time_ns => try self.renderTimeNsCell(try numericIntAt(data, @intCast(row))),
            .time_tz => try self.renderTimeTzCell(try numericIntAt(data, @intCast(row))),
            .timestamp => try self.renderTimestampMicrosCell(try numericIntAt(data, @intCast(row)), null),
            .timestamp_s => try self.renderTimestampScaledCell(try numericIntAt(data, @intCast(row)), 1_000_000, null),
            .timestamp_ms => try self.renderTimestampScaledCell(try numericIntAt(data, @intCast(row)), 1_000, null),
            .timestamp_ns => try self.renderTimestampNsCell(try numericIntAt(data, @intCast(row)), null),
            .timestamp_tz => try self.renderTimestampMicrosCell(try numericIntAt(data, @intCast(row)), "Z"),
        };
    }

    fn renderTableStore(self: *Session, store: *const HostKeyedStore) anyerror![]u8 {
        std.debug.assert(store.layout == .table);
        const column_count = keyedStoreNameCount(store);
        var widths = try self.allocator.alloc(usize, column_count);
        defer self.allocator.free(widths);

        for (0..column_count) |idx| {
            widths[idx] = keyedStoreColumnNameBytes(store, idx).len;
        }
        for (0..store.row_count) |row| {
            for (0..column_count) |idx| {
                const cell = try self.renderTableCell(store, idx, row);
                defer self.allocator.free(cell);
                widths[idx] = @max(widths[idx], cell.len);
            }
        }

        var out = std.ArrayList(u8).empty;
        errdefer out.deinit(self.allocator);

        for (0..column_count) |idx| {
            if (idx != 0) try out.append(self.allocator, ' ');
            const name = keyedStoreColumnNameBytes(store, idx);
            try out.appendSlice(self.allocator, name);
            if (idx + 1 != column_count and widths[idx] > name.len) {
                try out.appendNTimes(self.allocator, ' ', widths[idx] - name.len);
            }
        }

        if (column_count != 0) {
            try out.append(self.allocator, '\n');
            for (widths, 0..) |width, idx| {
                if (idx != 0) try out.append(self.allocator, ' ');
                try out.appendNTimes(self.allocator, '-', width);
            }
        }

        for (0..store.row_count) |row| {
            if (column_count != 0 or row != 0) try out.append(self.allocator, '\n');
            for (0..column_count) |idx| {
                if (idx != 0) try out.append(self.allocator, ' ');
                const cell = try self.renderTableCell(store, idx, row);
                defer self.allocator.free(cell);
                try out.appendSlice(self.allocator, cell);
                if (idx + 1 != column_count and widths[idx] > cell.len) {
                    try out.appendNTimes(self.allocator, ' ', widths[idx] - cell.len);
                }
            }
        }

        return try out.toOwnedSlice(self.allocator);
    }

    fn renderHostKeyedStore(self: *Session, store: *const HostKeyedStore) anyerror![]u8 {
        if (store.layout == .table) return try self.renderTableStore(store);
        return try self.allocator.dupe(u8, "dict[]");
    }

    fn renderHostStringList(self: *Session, list: *const HostStringList) anyerror![]u8 {
        var out = std.ArrayList(u8).empty;
        errdefer out.deinit(self.allocator);
        try out.append(self.allocator, '(');
        switch (list.storage) {
            .eager => |items| {
                for (items, 0..) |item, idx| {
                    if (idx != 0) try out.append(self.allocator, ';');
                    try out.writer(self.allocator).print("\"{s}\"", .{hostStringPieceBytes(list.base, item)});
                }
            },
            .split_scalar => |lazy| {
                const base = list.base orelse unreachable;
                const src = hostTextBytes(base);
                var idx: usize = 0;
                var start: usize = 0;
                while (std.mem.indexOfScalarPos(u8, src, start, lazy.sep)) |sep_idx| {
                    if (idx != 0) try out.append(self.allocator, ';');
                    try out.writer(self.allocator).print("\"{s}\"", .{src[start..sep_idx]});
                    idx += 1;
                    start = sep_idx + 1;
                }
                if (idx != 0) try out.append(self.allocator, ';');
                try out.writer(self.allocator).print("\"{s}\"", .{src[start..]});
            },
        }
        try out.append(self.allocator, ')');
        return try out.toOwnedSlice(self.allocator);
    }

    fn renderHostArray(self: *Session, array: *const HostDenseArray) anyerror![]u8 {
        if (array.logical_len == 0) switch (array.storage) {
            .int8, .int16, .int32, .int64 => return try self.allocator.dupe(u8, "!0"),
            else => {},
        };

        var out = std.ArrayList(u8).empty;
        errdefer out.deinit(self.allocator);

        switch (array.storage) {
            .bit => |words| {
                for (0..array.logical_len) |idx| try out.append(self.allocator, if (bitGet(words, idx)) '1' else '0');
                try out.append(self.allocator, 'b');
            },
            .int8 => |items| {
                for (hostDenseLogicalItems(i8, array, items), 0..) |item, idx| {
                    if (idx != 0) try out.append(self.allocator, ' ');
                    try out.writer(self.allocator).print("{d}", .{item});
                }
            },
            .int16 => |items| {
                for (hostDenseLogicalItems(i16, array, items), 0..) |item, idx| {
                    if (idx != 0) try out.append(self.allocator, ' ');
                    try out.writer(self.allocator).print("{d}", .{item});
                }
            },
            .int32 => |items| {
                for (hostDenseLogicalItems(i32, array, items), 0..) |item, idx| {
                    if (idx != 0) try out.append(self.allocator, ' ');
                    try out.writer(self.allocator).print("{d}", .{item});
                }
            },
            .int64 => |items| {
                for (hostDenseLogicalItems(i64, array, items), 0..) |item, idx| {
                    if (idx != 0) try out.append(self.allocator, ' ');
                    try out.writer(self.allocator).print("{d}", .{item});
                }
            },
            .float64 => |items| {
                for (hostDenseLogicalItems(f64, array, items), 0..) |item, idx| {
                    if (idx != 0) try out.append(self.allocator, ' ');
                    const part = try formatFloat(self.allocator, item);
                    defer self.allocator.free(part);
                    try out.appendSlice(self.allocator, part);
                }
            },
        }

        return try out.toOwnedSlice(self.allocator);
    }

    fn renderHostBoxedArray(self: *Session, array: *const HostBoxedArray) anyerror![]u8 {
        var out = std.ArrayList(u8).empty;
        errdefer out.deinit(self.allocator);

        if (array.items.len == 1) {
            try out.append(self.allocator, ',');
            const item = array.items[0];
            const wrap = valueNonVectorNumericShape(item) != null;
            if (wrap) try out.append(self.allocator, '(');
            const part = try self.renderValue(item);
            defer self.allocator.free(part);
            try out.appendSlice(self.allocator, part);
            if (wrap) try out.append(self.allocator, ')');
        } else if (isRenderableMatrix(array.items)) {
            for (array.items, 0..) |item, idx| {
                if (idx != 0) try out.append(self.allocator, '\n');
                const part = try self.renderValue(item);
                defer self.allocator.free(part);
                try out.appendSlice(self.allocator, part);
            }
        } else {
            try out.append(self.allocator, '(');
            for (array.items, 0..) |item, idx| {
                if (idx != 0) try out.append(self.allocator, ';');
                const part = try self.renderValue(item);
                defer self.allocator.free(part);
                try out.appendSlice(self.allocator, part);
            }
            try out.append(self.allocator, ')');
        }

        return try out.toOwnedSlice(self.allocator);
    }

    fn renderBackendArray(self: *Session, array: *const BackendArray) anyerror![]u8 {
        return runtime_backend_render.renderBackendArray(.{
            .Session = Session,
            .BackendArray = BackendArray,
            .c = c,
            .formatFloat = formatFloat,
        }, self, array);
    }

    fn managedFloat(self: *Session, value: f64) !Value {
        _ = self;
        return Value.float(value);
    }

    fn scratchFloat(self: *Session, value: f64) !Value {
        _ = self;
        return Value.float(value);
    }

    fn managedInt(self: *Session, value: i64) !Value {
        const box = if (self.free_boxed_int_len != 0) blk: {
            self.free_boxed_int_len -= 1;
            break :blk self.free_boxed_ints[self.free_boxed_int_len].?;
        } else try self.allocator.create(BoxedInt);
        box.* = .{
            .header = HeapHeader.init(.boxed_int, .managed),
            .value = value,
        };
        return Value.boxedInt(box);
    }

    fn enlistValue(self: *Session, value: Value) !Value {
        return try self.createManagedHostBoxedArray(&.{value});
    }

    fn scratchInt(self: *Session, value: i64) !Value {
        return try allocBoxedInt(self.scratch_arena.allocator(), .scratch, value);
    }

    fn allocManagedClosure(self: *Session, kind: ClosureKind, code: *const Code, captures: []const Value) !*Closure {
        const closure = if (self.free_closure_len != 0) blk: {
            self.free_closure_len -= 1;
            break :blk self.free_closures[self.free_closure_len].?;
        } else try self.allocator.create(Closure);
        closure.* = .{
            .header = HeapHeader.init(.closure, .managed),
            .kind = kind,
            .code = code,
            .captures = captures,
        };
        return closure;
    }

    fn allocManagedProjectionClosure(self: *Session, callee: Value, slot_count: u8, hole_mask: u64, slot_values: []const Value) !Value {
        std.debug.assert(slot_values.len == slot_count);
        const captures = try self.allocator.alloc(Value, 3 + slot_values.len);
        errdefer self.allocator.free(captures);
        var initialized: usize = 0;
        errdefer {
            while (initialized > 0) {
                initialized -= 1;
                self.releaseValue(captures[initialized]);
            }
        }

        captures[0] = try self.retainEscapedValue(callee);
        initialized += 1;
        captures[1] = try self.intValue(@intCast(slot_count));
        initialized += 1;
        captures[2] = try self.intValue(std.math.cast(i64, hole_mask) orelse return error.Unsupported);
        initialized += 1;
        for (slot_values, 0..) |value, idx| {
            captures[3 + idx] = try self.retainEscapedValue(value);
            initialized += 1;
        }

        if (comptime enable_probe_instrumentation) self.debug_projection_closure_alloc_count += 1;
        return Value.closure(try self.allocManagedClosure(.projection, &projection_code, captures));
    }

    fn allocFrozenDerivedClosure(self: *Session, kind: DerivedVerbKind, base: Value) !*Closure {
        const captures = try self.arena.allocator().alloc(Value, 1);
        captures[0] = try self.freezeConstantValue(base);
        const closure = try self.arena.allocator().create(Closure);
        closure.* = .{
            .header = HeapHeader.init(.closure, .frozen),
            .kind = ClosureKind.fromDerived(kind),
            .code = derivedCode(kind),
            .captures = captures,
        };
        return closure;
    }

    fn allocManagedDerivedClosure(self: *Session, kind: DerivedVerbKind, base: Value) !*Closure {
        const captures = try self.allocator.alloc(Value, 1);
        errdefer self.allocator.free(captures);
        captures[0] = try self.retainEscapedValue(base);
        errdefer self.releaseValue(captures[0]);
        return try self.allocManagedClosure(ClosureKind.fromDerived(kind), derivedCode(kind), captures);
    }

    fn adverbBaseCanStayFrozen(base: Value) bool {
        return switch (base.tag()) {
            .builtin => true,
            .closure => base.asClosure().header.owner == .frozen or base.asClosure().captures.len == 0,
            .array => base.arrayOwner() == .frozen,
            else => false,
        };
    }

    fn allocDerivedClosure(self: *Session, kind: DerivedVerbKind, base: Value) !*Closure {
        if (adverbBaseCanStayFrozen(base)) return try self.allocFrozenDerivedClosure(kind, base);
        return try self.allocManagedDerivedClosure(kind, base);
    }

    fn allocFrozenInnerProductClosure(self: *Session, reduce: BuiltinId, map: BuiltinId) !*Closure {
        const captures = try self.arena.allocator().alloc(Value, 2);
        captures[0] = try self.freezeConstantValue(Value.builtin(reduce));
        captures[1] = try self.freezeConstantValue(Value.builtin(map));
        const closure = try self.arena.allocator().create(Closure);
        closure.* = .{
            .header = HeapHeader.init(.closure, .frozen),
            .kind = .inner_product,
            .code = &inner_product_code,
            .captures = captures,
        };
        return closure;
    }

    fn allocFrozenDerivedClosureWithCaptures(self: *Session, kind: DerivedVerbKind, captures_in: []const Value) !*Closure {
        const captures = try self.arena.allocator().alloc(Value, captures_in.len);
        for (captures_in, 0..) |capture, idx| {
            captures[idx] = try self.freezeConstantValue(capture);
        }
        const closure = try self.arena.allocator().create(Closure);
        closure.* = .{
            .header = HeapHeader.init(.closure, .frozen),
            .kind = ClosureKind.fromDerived(kind),
            .code = derivedCode(kind),
            .captures = captures,
        };
        return closure;
    }

    fn freeManagedHostDenseBuffer(self: *Session, kind: HostDenseStorageKind, entry: ManagedHostDenseBufferEntry) void {
        switch (kind) {
            .bit => {
                const ptr: [*]u64 = @ptrCast(@alignCast(entry.ptr));
                self.allocator.free(ptr[0..entry.len]);
            },
            .int8 => {
                const ptr: [*]i8 = @ptrCast(@alignCast(entry.ptr));
                self.allocator.free(ptr[0..entry.len]);
            },
            .int16 => {
                const ptr: [*]i16 = @ptrCast(@alignCast(entry.ptr));
                self.allocator.free(ptr[0..entry.len]);
            },
            .int32 => {
                const ptr: [*]i32 = @ptrCast(@alignCast(entry.ptr));
                self.allocator.free(ptr[0..entry.len]);
            },
            .int64 => {
                const ptr: [*]i64 = @ptrCast(@alignCast(entry.ptr));
                self.allocator.free(ptr[0..entry.len]);
            },
            .float64 => {
                const ptr: [*]f64 = @ptrCast(@alignCast(entry.ptr));
                self.allocator.free(ptr[0..entry.len]);
            },
        }
    }

    fn takeManagedHostDenseBuffer(self: *Session, comptime T: type, comptime kind: HostDenseStorageKind, len: usize) ?[]T {
        if (len == 0) return null;
        const pool_idx = @intFromEnum(kind);
        const count = self.free_host_dense_buffer_len[pool_idx];
        if (count == 0) return null;

        var idx = count;
        while (idx > 0) {
            idx -= 1;
            const entry = self.free_host_dense_buffers[pool_idx][idx].?;
            if (entry.len != len) continue;
            const last_idx = count - 1;
            self.free_host_dense_buffers[pool_idx][idx] = self.free_host_dense_buffers[pool_idx][last_idx];
            self.free_host_dense_buffers[pool_idx][last_idx] = null;
            self.free_host_dense_buffer_len[pool_idx] -= 1;
            const ptr: [*]T = @ptrCast(@alignCast(entry.ptr));
            return ptr[0..len];
        }

        return null;
    }

    fn recycleManagedHostDenseBuffer(self: *Session, comptime T: type, comptime kind: HostDenseStorageKind, items: []T) void {
        if (items.len == 0) {
            self.allocator.free(items);
            return;
        }
        const pool_idx = @intFromEnum(kind);
        const count = self.free_host_dense_buffer_len[pool_idx];
        if (count >= max_pooled_objects) {
            self.allocator.free(items);
            return;
        }
        self.free_host_dense_buffers[pool_idx][count] = .{
            .ptr = @ptrCast(items.ptr),
            .len = items.len,
        };
        self.free_host_dense_buffer_len[pool_idx] = count + 1;
    }

    fn recycleManagedHostDenseStorage(self: *Session, storage: HostDenseStorage) void {
        switch (storage) {
            .bit => |words| self.recycleManagedHostDenseBuffer(u64, .bit, words),
            .int8 => |items| self.recycleManagedHostDenseBuffer(i8, .int8, items),
            .int16 => |items| self.recycleManagedHostDenseBuffer(i16, .int16, items),
            .int32 => |items| self.recycleManagedHostDenseBuffer(i32, .int32, items),
            .int64 => |items| self.recycleManagedHostDenseBuffer(i64, .int64, items),
            .float64 => |items| self.recycleManagedHostDenseBuffer(f64, .float64, items),
        }
    }

    fn allocManagedHostDenseStorage(self: *Session, kind: HostDenseStorageKind, capacity_len: usize) !HostDenseStorage {
        return switch (kind) {
            .bit => blk: {
                const word_count = bitWordCount(capacity_len);
                const words = self.takeManagedHostDenseBuffer(u64, .bit, word_count) orelse try self.allocator.alloc(u64, word_count);
                @memset(words, 0);
                break :blk .{ .bit = words };
            },
            .int8 => .{ .int8 = self.takeManagedHostDenseBuffer(i8, .int8, capacity_len) orelse try self.allocator.alloc(i8, capacity_len) },
            .int16 => .{ .int16 = self.takeManagedHostDenseBuffer(i16, .int16, capacity_len) orelse try self.allocator.alloc(i16, capacity_len) },
            .int32 => .{ .int32 = self.takeManagedHostDenseBuffer(i32, .int32, capacity_len) orelse try self.allocator.alloc(i32, capacity_len) },
            .int64 => .{ .int64 = self.takeManagedHostDenseBuffer(i64, .int64, capacity_len) orelse try self.allocator.alloc(i64, capacity_len) },
            .float64 => .{ .float64 = self.takeManagedHostDenseBuffer(f64, .float64, capacity_len) orelse try self.allocator.alloc(f64, capacity_len) },
        };
    }

    fn copyHostDenseIntToStorage(array: *const HostDenseArray, storage: HostDenseStorage, len: usize) KError!void {
        switch (storage) {
            .bit => |words| {
                for (0..len) |idx| {
                    const value = try hostDenseIntAt(array, idx);
                    if (value != 0 and value != 1) return error.Unsupported;
                    bitSet(words, idx, value == 1);
                }
            },
            .int8 => |items| {
                for (0..len) |idx| items[idx] = std.math.cast(i8, try hostDenseIntAt(array, idx)) orelse return error.Unsupported;
            },
            .int16 => |items| {
                for (0..len) |idx| items[idx] = std.math.cast(i16, try hostDenseIntAt(array, idx)) orelse return error.Unsupported;
            },
            .int32 => |items| {
                for (0..len) |idx| items[idx] = std.math.cast(i32, try hostDenseIntAt(array, idx)) orelse return error.Unsupported;
            },
            .int64 => |items| {
                for (0..len) |idx| items[idx] = try hostDenseIntAt(array, idx);
            },
            .float64 => return error.Type,
        }
    }

    fn ensureManagedHostDenseIntCapacity(self: *Session, array: *HostDenseArray, result_kind: HostIntStorageKind, required_len: usize) KError!void {
        const target_storage_kind = hostDenseStorageKindForIntKind(result_kind);
        const current_storage_kind = std.meta.activeTag(array.storage);
        if (current_storage_kind == target_storage_kind and hostDenseStorageCapacityLen(array) >= required_len) return;

        const old_len = array.logical_len;
        const new_capacity_len = hostDenseGrowCapacityLen(target_storage_kind, hostDenseStorageCapacityLen(array), required_len);
        const new_storage = try self.allocManagedHostDenseStorage(target_storage_kind, new_capacity_len);
        errdefer self.recycleManagedHostDenseStorage(new_storage);

        try copyHostDenseIntToStorage(array, new_storage, old_len);
        const old_storage = array.storage;
        array.storage = new_storage;
        self.recycleManagedHostDenseStorage(old_storage);
    }

    fn allocHostArrayTypedCapacity(self: *Session, comptime T: type, comptime kind: HostDenseStorageKind, owner: HeapOwner, len: usize, capacity_len: usize) !HostDenseAlloc(T) {
        std.debug.assert(capacity_len >= len);
        const allocator = switch (owner) {
            .managed => self.allocator,
            .scratch => self.scratch_arena.allocator(),
            .frozen => self.arena.allocator(),
        };
        if (comptime enable_probe_instrumentation) {
            if (owner == .scratch) self.debug_scratch_host_array_alloc_count += 1;
        }
        const array = if (owner == .managed and self.free_host_array_len != 0) blk: {
            self.free_host_array_len -= 1;
            break :blk self.free_host_arrays[self.free_host_array_len].?;
        } else try allocator.create(HostDenseArray);
        const storage_items = if (owner == .managed)
            self.takeManagedHostDenseBuffer(T, kind, capacity_len) orelse try allocator.alloc(T, capacity_len)
        else
            try allocator.alloc(T, capacity_len);
        array.header = HeapHeader.init(.host_dense_array, owner);
        array.logical_handle = null;
        array.logical_len = len;
        array.flags = 0;
        hostDenseClearCachedIntRange(array);
        hostDenseResetFindCacheState(array);
        array.storage = switch (kind) {
            .bit => unreachable,
            .int8 => .{ .int8 = storage_items },
            .int16 => .{ .int16 = storage_items },
            .int32 => .{ .int32 = storage_items },
            .int64 => .{ .int64 = storage_items },
            .float64 => .{ .float64 = storage_items },
        };
        return .{ .array = array, .items = storage_items[0..len] };
    }

    fn allocHostArrayTyped(self: *Session, comptime T: type, comptime kind: HostDenseStorageKind, owner: HeapOwner, len: usize) !HostDenseAlloc(T) {
        return self.allocHostArrayTypedCapacity(T, kind, owner, len, len);
    }

    fn allocHostBitArrayWithInitCapacity(self: *Session, owner: HeapOwner, len: usize, capacity_len: usize, zero: bool) !HostBitAlloc {
        std.debug.assert(capacity_len >= len);
        const allocator = switch (owner) {
            .managed => self.allocator,
            .scratch => self.scratch_arena.allocator(),
            .frozen => self.arena.allocator(),
        };
        if (comptime enable_probe_instrumentation) {
            if (owner == .scratch) self.debug_scratch_host_array_alloc_count += 1;
        }
        const array = if (owner == .managed and self.free_host_array_len != 0) blk: {
            self.free_host_array_len -= 1;
            break :blk self.free_host_arrays[self.free_host_array_len].?;
        } else try allocator.create(HostDenseArray);
        const word_count = bitWordCount(len);
        const storage_word_count = bitWordCount(capacity_len);
        const words = if (owner == .managed)
            self.takeManagedHostDenseBuffer(u64, .bit, storage_word_count) orelse try allocator.alloc(u64, storage_word_count)
        else
            try allocator.alloc(u64, storage_word_count);
        if (zero) @memset(words, 0);
        array.header = HeapHeader.init(.host_dense_array, owner);
        array.logical_handle = null;
        array.logical_len = len;
        array.flags = 0;
        hostDenseClearCachedIntRange(array);
        hostDenseResetFindCacheState(array);
        array.storage = .{ .bit = words };
        return .{ .array = array, .words = words[0..word_count], .len = len };
    }

    fn allocHostBitArrayWithInit(self: *Session, owner: HeapOwner, len: usize, zero: bool) !HostBitAlloc {
        return self.allocHostBitArrayWithInitCapacity(owner, len, len, zero);
    }

    fn allocHostBitArray(self: *Session, owner: HeapOwner, len: usize) !HostBitAlloc {
        return try self.allocHostBitArrayWithInit(owner, len, true);
    }

    fn allocHostBitArrayUninitialized(self: *Session, owner: HeapOwner, len: usize) !HostBitAlloc {
        return try self.allocHostBitArrayWithInit(owner, len, false);
    }

    fn allocManagedHostIntResult(self: *Session, kind: HostIntStorageKind, len: usize) !HostIntResult {
        return switch (kind) {
            .bit => .{ .bit = try self.allocHostBitArray(.managed, len) },
            .int8 => .{ .int8 = try self.allocHostArrayTyped(i8, .int8, .managed, len) },
            .int16 => .{ .int16 = try self.allocHostArrayTyped(i16, .int16, .managed, len) },
            .int32 => .{ .int32 = try self.allocHostArrayTyped(i32, .int32, .managed, len) },
            .int64 => .{ .int64 = try self.allocHostArrayTyped(i64, .int64, .managed, len) },
        };
    }

    fn allocScratchHostIntResult(self: *Session, kind: HostIntStorageKind, len: usize) !HostIntResult {
        return switch (kind) {
            .bit => .{ .bit = try self.allocHostBitArray(.scratch, len) },
            .int8 => .{ .int8 = try self.allocHostArrayTyped(i8, .int8, .scratch, len) },
            .int16 => .{ .int16 = try self.allocHostArrayTyped(i16, .int16, .scratch, len) },
            .int32 => .{ .int32 = try self.allocHostArrayTyped(i32, .int32, .scratch, len) },
            .int64 => .{ .int64 = try self.allocHostArrayTyped(i64, .int64, .scratch, len) },
        };
    }

    fn allocFrozenHostIntResult(self: *Session, kind: HostIntStorageKind, len: usize) !HostIntResult {
        return switch (kind) {
            .bit => .{ .bit = try self.allocHostBitArray(.frozen, len) },
            .int8 => .{ .int8 = try self.allocHostArrayTyped(i8, .int8, .frozen, len) },
            .int16 => .{ .int16 = try self.allocHostArrayTyped(i16, .int16, .frozen, len) },
            .int32 => .{ .int32 = try self.allocHostArrayTyped(i32, .int32, .frozen, len) },
            .int64 => .{ .int64 = try self.allocHostArrayTyped(i64, .int64, .frozen, len) },
        };
    }

    fn allocManagedHostFloatResult(self: *Session, len: usize) !HostFloatResult {
        const out = try self.allocHostArrayTyped(f64, .float64, .managed, len);
        return .{ .array = out.array, .items = out.items };
    }

    fn allocScratchHostFloatResult(self: *Session, len: usize) !HostFloatResult {
        const out = try self.allocHostArrayTyped(f64, .float64, .scratch, len);
        return .{ .array = out.array, .items = out.items };
    }

    fn allocFrozenHostFloatResult(self: *Session, len: usize) !HostFloatResult {
        const out = try self.allocHostArrayTyped(f64, .float64, .frozen, len);
        return .{ .array = out.array, .items = out.items };
    }

    fn allocOwnedHostIntResult(self: *Session, owner: HeapOwner, kind: HostIntStorageKind, len: usize) !HostIntResult {
        return switch (owner) {
            .managed => try self.allocManagedHostIntResult(kind, len),
            .scratch => try self.allocScratchHostIntResult(kind, len),
            .frozen => try self.allocFrozenHostIntResult(kind, len),
        };
    }

    fn allocOwnedHostIntCloneResult(self: *Session, owner: HeapOwner, kind: HostIntStorageKind, len: usize) !HostIntResult {
        if (kind == .bit) return .{ .bit = try self.allocHostBitArrayUninitialized(owner, len) };
        return try self.allocOwnedHostIntResult(owner, kind, len);
    }

    fn allocOwnedHostFloatResult(self: *Session, owner: HeapOwner, len: usize) !HostFloatResult {
        return switch (owner) {
            .managed => try self.allocManagedHostFloatResult(len),
            .scratch => try self.allocScratchHostFloatResult(len),
            .frozen => try self.allocFrozenHostFloatResult(len),
        };
    }

    fn planHostIntUnaryOutput(
        self: *Session,
        source_value: Value,
        input_kind: HostIntStorageKind,
        result_kind: HostIntStorageKind,
        len: usize,
        allow_reuse: bool,
        unchecked_safe: bool,
    ) !HostIntOutputPlan {
        const maybe_reused = if (allow_reuse and result_kind == input_kind)
            self.tryReuseHostIntArrayResult(source_value, result_kind)
        else
            null;
        return .{
            .output = maybe_reused orelse try self.allocScratchHostIntResult(result_kind, len),
            .kind = result_kind,
            .reused = maybe_reused != null,
            .unchecked_safe = unchecked_safe,
            .shape = valueNonVectorNumericShape(source_value),
        };
    }

    fn planHostIntDyadOutput(
        self: *Session,
        left_value: Value,
        right_value: Value,
        left_kind: HostIntStorageKind,
        right_kind: HostIntStorageKind,
        result_kind: HostIntStorageKind,
        len: usize,
        allow_reuse: bool,
        unchecked_safe: bool,
    ) !HostIntOutputPlan {
        const maybe_reused = if (allow_reuse and (result_kind == left_kind or result_kind == right_kind))
            self.tryReuseHostIntDyadResult(left_value, right_value, result_kind)
        else
            null;
        return .{
            .output = maybe_reused orelse try self.allocScratchHostIntResult(result_kind, len),
            .kind = result_kind,
            .reused = maybe_reused != null,
            .unchecked_safe = unchecked_safe,
            .shape = try nonVectorNumericShapeForDyad(left_value, right_value),
        };
    }

    fn finishHostIntOutput(self: *Session, plan: HostIntOutputPlan, flags: u8) KError!Value {
        const result_value = try plan.output.value(self);
        const host = plan.output.arrayPtr();
        if (plan.kind == .bit) {
            bitClearUnusedTail(host.storage.bit, host.logical_len);
        }
        hostDenseSetFlags(host, flags);
        self.invalidateHostDenseCachesForMutation(host);
        const result = try applyNonVectorNumericShapeToValue(self, result_value, plan.shape);
        return if (plan.reused) self.shareValue(result) else result;
    }

    fn finishManagedHostBitAlloc(self: *Session, out: HostBitAlloc, flags: u8, range: HostIntRange) KError!Value {
        bitClearUnusedTail(out.words, out.len);
        const value = try wrapOwnedHostArrayValue(self, out.array);
        const host = try mutableNumericHostArrayValue(self, value);
        hostDenseSetFlags(host, flags);
        hostDenseSetCachedIntRange(host, range);
        return value;
    }

    fn planHostFloatUnaryOutput(self: *Session, source_value: Value, len: usize, allow_reuse: bool) !HostFloatOutputPlan {
        const maybe_reused = if (allow_reuse) self.tryReuseHostFloatArrayResult(source_value) else null;
        return .{
            .output = maybe_reused orelse try self.allocScratchHostFloatResult(len),
            .reused = maybe_reused != null,
            .shape = valueNonVectorNumericShape(source_value),
        };
    }

    fn planHostFloatDyadOutput(self: *Session, left_value: Value, right_value: Value, len: usize, allow_reuse: bool) !HostFloatOutputPlan {
        const maybe_reused = if (allow_reuse) self.tryReuseHostFloatDyadResult(left_value, right_value) else null;
        return .{
            .output = maybe_reused orelse try self.allocScratchHostFloatResult(len),
            .reused = maybe_reused != null,
            .shape = try nonVectorNumericShapeForDyad(left_value, right_value),
        };
    }

    fn finishHostFloatOutput(self: *Session, plan: HostFloatOutputPlan, flags: u8) KError!Value {
        const result_value = try plan.output.value(self);
        hostDenseSetFlags(plan.output.array, flags);
        self.invalidateHostDenseCachesForMutation(plan.output.array);
        const result = try applyNonVectorNumericShapeToValue(self, result_value, plan.shape);
        return if (plan.reused) self.shareValue(result) else result;
    }

    fn tryReuseHostIntArrayResult(self: *Session, value: Value, kind: HostIntStorageKind) ?HostIntResult {
        _ = self;
        const array = if (hostDenseIfPresent(value)) |host|
            @constCast(host)
        else
            return null;
        switch (numericPayloadOwner(array)) {
            .scratch => {},
            .managed => if (numericPayloadManagedRefCount(array) != 1) return null,
            .frozen => return null,
        }
        return switch (kind) {
            .bit => switch (array.storage) {
                .bit => |words| .{ .bit = .{ .array = array, .words = words, .len = array.logical_len } },
                else => null,
            },
            .int8 => switch (array.storage) {
                .int8 => |items| .{ .int8 = .{ .array = array, .items = hostDenseMutableLogicalItems(i8, array, items) } },
                else => null,
            },
            .int16 => switch (array.storage) {
                .int16 => |items| .{ .int16 = .{ .array = array, .items = hostDenseMutableLogicalItems(i16, array, items) } },
                else => null,
            },
            .int32 => switch (array.storage) {
                .int32 => |items| .{ .int32 = .{ .array = array, .items = hostDenseMutableLogicalItems(i32, array, items) } },
                else => null,
            },
            .int64 => switch (array.storage) {
                .int64 => |items| .{ .int64 = .{ .array = array, .items = hostDenseMutableLogicalItems(i64, array, items) } },
                else => null,
            },
        };
    }

    fn tryReuseHostFloatArrayResult(self: *Session, value: Value) ?HostFloatResult {
        _ = self;
        const array = if (hostDenseIfPresent(value)) |host|
            @constCast(host)
        else
            return null;
        if (hostDenseNumericMode(array) != .float) return null;
        switch (numericPayloadOwner(array)) {
            .scratch => {},
            .managed => if (numericPayloadManagedRefCount(array) != 1) return null,
            .frozen => return null,
        }
        return switch (array.storage) {
            .float64 => |items| .{ .array = array, .items = hostDenseMutableLogicalItems(f64, array, items) },
            else => null,
        };
    }

    fn tryReuseHostIntDyadResult(self: *Session, left_value: Value, right_value: Value, kind: HostIntStorageKind) ?HostIntResult {
        const left = self.tryReuseHostIntArrayResult(left_value, kind);
        const right = self.tryReuseHostIntArrayResult(right_value, kind);
        if (left) |left_out| {
            if (right) |right_out| {
                return if (hostDenseReusePriority(right_out.arrayPtr()) > hostDenseReusePriority(left_out.arrayPtr())) right_out else left_out;
            }
            return left_out;
        }
        return right;
    }

    fn tryReuseHostFloatDyadResult(self: *Session, left_value: Value, right_value: Value) ?HostFloatResult {
        const left = self.tryReuseHostFloatArrayResult(left_value);
        const right = self.tryReuseHostFloatArrayResult(right_value);
        if (left) |left_out| {
            if (right) |right_out| {
                return if (hostDenseReusePriority(right_out.array) > hostDenseReusePriority(left_out.array)) right_out else left_out;
            }
            return left_out;
        }
        return right;
    }

    fn ownedConstantFloat(self: *Session, allocator: std.mem.Allocator, owner: HeapOwner, value: f64) !Value {
        _ = self;
        _ = allocator;
        _ = owner;
        return Value.float(value);
    }

    fn ownedConstantInt(self: *Session, allocator: std.mem.Allocator, owner: HeapOwner, value: i64) !Value {
        _ = self;
        return Value.int(value) catch |err| switch (err) {
            error.Unsupported => allocBoxedInt(allocator, owner, value),
            else => err,
        };
    }

    fn intValue(self: *Session, value: i64) !Value {
        return Value.int(value) catch |err| switch (err) {
            error.Unsupported => self.scratchInt(value),
            else => err,
        };
    }

    fn floatValue(self: *Session, value: f64) !Value {
        return try self.scratchFloat(value);
    }

    fn internedHostTextMap(self: *Session, kind: HeapKind) *std.StringHashMap(*HostText) {
        return switch (kind) {
            .host_string => &self.interned_strings,
            .host_symbol => &self.interned_symbols,
            else => unreachable,
        };
    }

    fn shouldInternManagedHostText(self: *Session, kind: HeapKind, bytes: []const u8) bool {
        _ = self;
        return switch (kind) {
            .host_string, .host_symbol => bytes.len <= managed_host_text_intern_limit,
            else => false,
        };
    }

    fn findInternedHostText(self: *Session, kind: HeapKind, bytes: []const u8) ?Value {
        const text = self.internedHostTextMap(kind).get(bytes) orelse return null;
        return Value.array(text);
    }

    fn rememberInternedHostText(self: *Session, kind: HeapKind, text: *HostText) !void {
        try self.internedHostTextMap(kind).put(hostTextBytes(text), text);
    }

    fn forgetInternedHostText(self: *Session, kind: HeapKind, text: *HostText) void {
        const map = self.internedHostTextMap(kind);
        const bytes = hostTextBytes(text);
        if (map.get(bytes)) |found| {
            if (found == text) _ = map.remove(bytes);
        }
    }

    fn managedHostString(self: *Session, bytes: []const u8) !Value {
        if (self.findInternedHostText(.host_string, bytes)) |value| {
            if (value.arrayOwner() == .managed) _ = self.retainValue(value);
            return value;
        }
        const value = try allocHostText(self.allocator, .host_string, .managed, bytes);
        if (self.shouldInternManagedHostText(.host_string, bytes)) {
            try self.rememberInternedHostText(.host_string, @constCast(value.asHostString()));
        }
        return value;
    }

    fn frozenHostString(self: *Session, bytes: []const u8) !Value {
        if (self.findInternedHostText(.host_string, bytes)) |value| return value;
        const value = try allocHostText(self.arena.allocator(), .host_string, .frozen, bytes);
        try self.rememberInternedHostText(.host_string, @constCast(value.asHostString()));
        return value;
    }

    fn managedHostSymbol(self: *Session, bytes: []const u8) !Value {
        if (self.findInternedHostText(.host_symbol, bytes)) |value| {
            if (value.arrayOwner() == .managed) _ = self.retainValue(value);
            return value;
        }
        const value = try allocHostText(self.allocator, .host_symbol, .managed, bytes);
        if (self.shouldInternManagedHostText(.host_symbol, bytes)) {
            try self.rememberInternedHostText(.host_symbol, @constCast(value.asHostSymbol()));
        }
        return value;
    }

    fn frozenHostSymbol(self: *Session, bytes: []const u8) !Value {
        if (self.findInternedHostText(.host_symbol, bytes)) |value| return value;
        const value = try allocHostText(self.arena.allocator(), .host_symbol, .frozen, bytes);
        try self.rememberInternedHostText(.host_symbol, @constCast(value.asHostSymbol()));
        return value;
    }

    fn managedHostStringView(self: *Session, base: *HostText, span: HostTextSpan) !Value {
        return try self.managedHostStringViewWithReason(base, span, .generic);
    }

    fn managedHostStringViewWithReason(self: *Session, base: *HostText, span: HostTextSpan, reason: DebugHostStringViewReason) !Value {
        if (span.start == 0 and span.len == base.len and base.header.kind == .host_string) {
            return try self.retainEscapedValue(Value.array(base));
        }
        const view = try self.allocator.create(HostStringView);
        errdefer self.allocator.destroy(view);
        const retained_base = try self.retainEscapedValue(Value.array(base));
        errdefer self.releaseValue(retained_base);
        view.* = .{
            .header = HeapHeader.init(.host_string_view, .managed),
            .base = @constCast(retained_base.asHostString()),
            .span = span,
        };
        if (comptime enable_probe_instrumentation) {
            self.debug_host_string_view_alloc_count += 1;
            self.debug_host_string_view_reason_counts[@intFromEnum(reason)] += 1;
            self.debug_host_string_view_len_bucket_counts[@intFromEnum(debugProbeLenBucket(span.len))] += 1;
        }
        return Value.array(view);
    }

    fn canonicalizeEscapedNumericValue(self: *Session, value: Value) !Value {
        if (value.tag() != .array) return value;
        return switch (value.arraySubkind()) {
            .numeric_array => value,
            .host_dense_array => (try ensureLogicalNumericValue(self, value)).value,
            .backend_array => (try ensureLogicalNumericValue(self, value)).value,
            else => value,
        };
    }

    fn retainEscapedValue(self: *Session, value: Value) !Value {
        const canonical = try self.canonicalizeEscapedNumericValue(value);
        return switch (canonical.raw & Value.tag_mask) {
            Value.boxed_int_tag => switch (canonical.asBoxedInt().header.owner) {
                .managed => self.retainValue(canonical),
                .frozen => canonical,
                .scratch => self.managedInt(canonical.asInt()),
            },
            Value.closure_tag => switch (canonical.asClosure().header.owner) {
                .managed => self.retainValue(canonical),
                .frozen => canonical,
                .scratch => self.promoteScratchClosure(canonical.asClosure()),
            },
            Value.array_tag => switch (canonical.arrayOwner()) {
                .managed => self.retainValue(canonical),
                .frozen => canonical,
                .scratch => switch (canonical.arraySubkind()) {
                    .host_string, .host_symbol, .host_string_view => error.Internal,
                    else => self.promoteScratchArray(canonical),
                },
            },
            else => canonical,
        };
    }

    fn moveEscapedValue(self: *Session, value: Value) !Value {
        const canonical = try self.canonicalizeEscapedNumericValue(value);
        return switch (canonical.raw & Value.tag_mask) {
            Value.boxed_int_tag => switch (canonical.asBoxedInt().header.owner) {
                .managed, .frozen => canonical,
                .scratch => self.managedInt(canonical.asInt()),
            },
            Value.closure_tag => switch (canonical.asClosure().header.owner) {
                .managed, .frozen => canonical,
                .scratch => self.promoteScratchClosure(canonical.asClosure()),
            },
            Value.array_tag => switch (canonical.arrayOwner()) {
                .managed, .frozen => canonical,
                .scratch => self.promoteScratchArray(canonical),
            },
            else => canonical,
        };
    }

    fn finishResult(self: *Session, value: Value) !Value {
        const canonical = try self.canonicalizeEscapedNumericValue(value);
        if (self.last_result) |rooted| self.releaseValue(rooted);
        self.last_result = null;

        const rooted = switch (canonical.raw & Value.tag_mask) {
            Value.boxed_int_tag => switch (canonical.asBoxedInt().header.owner) {
                .managed => canonical,
                .frozen => canonical,
                .scratch => try self.managedInt(canonical.asInt()),
            },
            Value.closure_tag => switch (canonical.asClosure().header.owner) {
                .managed => canonical,
                .frozen => canonical,
                .scratch => try self.promoteScratchClosure(canonical.asClosure()),
            },
            Value.array_tag => switch (canonical.arrayOwner()) {
                .managed => canonical,
                .frozen => canonical,
                .scratch => try self.promoteScratchArray(canonical),
            },
            else => canonical,
        };

        if (isManagedValue(rooted)) self.last_result = rooted;
        return rooted;
    }

    fn finishFrame(self: *Session, frame_index: usize, result: Value) KError!?Value {
        if (comptime enable_probe_instrumentation) self.debug_frame_finish_count += 1;
        const frame = self.frames[frame_index];
        const owner = frame.owner;
        self.frame_len -= 1;
        const escaped_result = if (self.frame_len == 0)
            result
        else switch (frame.resultTarget()) {
            .stack => if (valueMayNeedRelease(result)) try self.retainEscapedValue(result) else result,
            .parent_local, .parent_local_tail_global_slots => if (valueMayNeedRelease(result)) try self.moveEscapedValue(result) else result,
        };
        defer if (self.frame_len != 0 and frame.resultTargetIsStack() and valueMayNeedRelease(result)) self.releaseValue(result);
        self.dropFrameStack(&frame);
        if (owner) |owned| self.releaseValue(owned);
        if (self.frame_len == 0) {
            if (comptime enable_sampling_profile) {
                self.profile_current_label.store(@intFromEnum(SamplingProfileLabel.idle), .unordered);
                self.profile_current_op.store(sampling_profile_no_op, .unordered);
                self.profile_current_code_id.store(sampling_profile_no_code, .unordered);
                self.profile_current_callable_slot.store(sampling_profile_no_callable_slot, .unordered);
            }
            if (self.root_results) return try self.finishResult(result);
            return result;
        }
        switch (frame.resultTarget()) {
            .stack => try self.push(escaped_result),
            .parent_local => |slot| {
                const parent_index = self.frame_len - 1;
                const parent = &self.frames[parent_index];
                try self.writeLocalValue(parent, slot, escaped_result);
                if (try self.tryExecParentTailGlobalSlotsContinuation(parent_index, parent)) |final| return final;
            },
            .parent_local_tail_global_slots => |slot| {
                const parent_index = self.frame_len - 1;
                const parent = &self.frames[parent_index];
                if (try self.execParentLocalTailGlobalSlotsContinuation(parent_index, parent, slot, escaped_result)) |final| return final;
            },
        }
        return null;
    }

    fn tryExecParentTailGlobalSlotsContinuation(self: *Session, frame_index: usize, frame: *CallFrame) KError!?Value {
        if (frame.ip >= frame.code.bytes.len) return null;
        const next_op: Op = std.meta.intToEnum(Op, frame.code.bytes[frame.ip]) catch return null;
        if (next_op != .tail_call_global_slots) return null;
        frame.ip += 1;
        const slot = try readGlobalSlot(frame);
        const argc = try readByte(frame);
        return try self.execTailGlobalCallSlots(frame_index, frame, slot, argc);
    }

    fn execParentLocalTailGlobalSlotsContinuation(
        self: *Session,
        frame_index: usize,
        frame: *CallFrame,
        local_slot: u8,
        value: Value,
    ) KError!?Value {
        if (frame.ip >= frame.code.bytes.len) {
            try self.writeLocalValue(frame, local_slot, value);
            return null;
        }
        const next_op: Op = std.meta.intToEnum(Op, frame.code.bytes[frame.ip]) catch {
            try self.writeLocalValue(frame, local_slot, value);
            return null;
        };
        if (next_op != .tail_call_global_slots) {
            try self.writeLocalValue(frame, local_slot, value);
            return null;
        }

        frame.ip += 1;
        const slot = try readGlobalSlot(frame);
        const argc = try readByte(frame);
        const callee = try self.loadGlobalSlot(slot);
        if (callee.tag() == .closure) {
            const closure = callee.asClosure();
            if (closureIsCompactPlainGlobal(closure) and closure.code.arity == argc) {
                var sources_buf: [max_shaped_call_args]GlobalCallArgSource = undefined;
                const sources = try readGlobalCallArgSources(frame, argc, &sources_buf);
                try self.replaceCurrentFrameWithCompactPlainClosureFromGlobalCallSourcesWithOverride(frame_index, frame, callee, closure, slot, sources, local_slot, value);
                return null;
            }
        }

        try self.writeLocalValue(frame, local_slot, value);
        return try self.execTailGlobalCallSlots(frame_index, frame, slot, argc);
    }

    fn parentLocalResultTarget(frame: *const CallFrame, slot: u8) CallResultTarget {
        if (frame.ip < frame.code.bytes.len) {
            const next_op = std.meta.intToEnum(Op, frame.code.bytes[frame.ip]) catch null;
            if (next_op == .tail_call_global_slots) return .{ .parent_local_tail_global_slots = slot };
        }
        return .{ .parent_local = slot };
    }

    fn freezeZeroCaptureClosure(self: *Session, closure: *const Closure) KError!Value {
        if (closure.captures.len != 0) return error.Internal;
        const frozen = try self.arena.allocator().create(Closure);
        frozen.* = .{
            .header = HeapHeader.init(.closure, .frozen),
            .kind = closure.kind,
            .code = try self.stableCode(closure.code),
            .captures = &[_]Value{},
        };
        return Value.closure(frozen);
    }

    fn promoteScratchClosure(self: *Session, closure: *const Closure) KError!Value {
        const allocator = self.allocator;
        const captures = try allocator.alloc(Value, closure.captures.len);
        errdefer allocator.free(captures);
        for (closure.captures, 0..) |capture, idx| {
            captures[idx] = try self.retainEscapedValue(capture);
        }

        return Value.closure(try self.allocManagedClosure(closure.kind, try self.stableCode(closure.code), captures));
    }

    fn stableCode(self: *Session, code: *const Code) KError!*const Code {
        const arena_allocator = self.arena.allocator();
        const stable = try arena_allocator.create(Code);
        const constants = try arena_allocator.alloc(Value, code.constants.len);
        const profile_source = if (code.profile_source.len == 0)
            ""
        else
            try arena_allocator.dupe(u8, code.profile_source);

        for (code.constants, 0..) |value, idx| {
            constants[idx] = try self.freezeConstantValue(value);
        }

        const compact_k = if (code.compact_k) |compact|
            try cloneCompactKCode(arena_allocator, compact, constants)
        else
            try compileCompactKCode(arena_allocator, code.arity, code.frame_slot_count, code.bytes, constants);

        stable.* = .{
            .arity = code.arity,
            .frame_slot_count = code.frame_slot_count,
            .operand_stack_slot_count = code.operand_stack_slot_count,
            .bytes = try arena_allocator.dupe(u8, code.bytes),
            .constants = constants,
            .compact_k = compact_k,
            .direct_closure_mask = code.direct_closure_mask,
            .references_globals = code.references_globals,
            .profile_id = code.profile_id,
            .profile_kind = code.profile_kind,
            .profile_source = profile_source,
        };
        if (comptime enable_sampling_profile) {
            self.rememberSamplingProfileCodeInfo(stable.profile_id, stable.profile_kind, stable.profile_source);
        }
        return stable;
    }

    fn freezeHostArrayConstant(self: *Session, array: *const HostDenseArray) KError!Value {
        return switch (array.storage) {
            .bit, .int8, .int16, .int32, .int64 => blk: {
                const view = hostIntArrayView(array) orelse return error.Type;
                var out = try self.allocFrozenHostIntResult(hostIntArrayViewKind(view), hostIntArrayViewLen(view));
                try copyHostIntViewToResult(&out, view);
                const result = try out.value(self);
                const frozen_host = try mutableNumericHostArrayValue(self, result);
                hostDenseSetFlags(frozen_host, array.flags);
                if (array.int_range_known) {
                    hostDenseSetCachedIntRange(frozen_host, .{
                        .min = array.int_range_min,
                        .max = array.int_range_max,
                    });
                } else {
                    hostDenseClearCachedIntRange(frozen_host);
                }
                break :blk result;
            },
            .float64 => |items| blk: {
                const out = try self.allocFrozenHostFloatResult(items.len);
                @memcpy(out.items, items);
                const result = try out.value(self);
                hostDenseSetFlags(try mutableNumericHostArrayValue(self, result), array.flags);
                break :blk result;
            },
        };
    }

    fn freezeHostBoxedArrayConstant(self: *Session, array: *const HostBoxedArray) KError!Value {
        const arena_allocator = self.arena.allocator();
        const frozen_array = try arena_allocator.create(HostBoxedArray);
        const frozen_items = try arena_allocator.alloc(Value, array.items.len);
        for (array.items, 0..) |item, idx| {
            frozen_items[idx] = try self.freezeConstantValue(item);
        }
        frozen_array.* = .{
            .header = HeapHeader.init(.host_boxed_array, .frozen),
            .logical_len = array.items.len,
            .items = frozen_items,
        };
        return Value.array(frozen_array);
    }

    fn freezeArrayConstant(self: *Session, value: Value) KError!Value {
        std.debug.assert(value.tag() == .array);
        return switch (value.arraySubkind()) {
            .host_string => switch (value.asHostString().header.owner) {
                .frozen => value,
                .scratch, .managed => try self.frozenHostString(hostTextBytes(value.asHostString())),
            },
            .host_string_view => switch (value.arrayKind()) {
                .host_string_view => try self.frozenHostString(hostStringViewBytes(value.asHostStringView())),
                else => unreachable,
            },
            .host_symbol => switch (value.asHostSymbol().header.owner) {
                .frozen => value,
                .scratch, .managed => try self.frozenHostSymbol(hostTextBytes(value.asHostSymbol())),
            },
            .host_string_list => error.Unsupported,
            .host_dense_array => blk: {
                const frozen = try self.freezeHostArrayConstant(value.asHostDenseArray());
                const shaped = try applyNonVectorNumericShapeToValue(self, frozen, valueNonVectorNumericShape(value));
                break :blk shaped;
            },
            .host_boxed_array => switch (value.asHostBoxedArray().header.owner) {
                .frozen => value,
                .scratch, .managed => try self.freezeHostBoxedArrayConstant(value.asHostBoxedArray()),
            },
            .host_relation, .host_keyed_store, .host_table_scalar => error.Unsupported,
            .backend_array => blk: {
                const frozen_host = Value.array(try createHostDenseArrayFromBackendArray(self, .frozen, value.asBackendArray().array));
                const shaped = try applyNonVectorNumericShapeToValue(self, frozen_host, valueNonVectorNumericShape(value));
                break :blk shaped;
            },
            .numeric_array => blk: {
                const handle = value.asNumericArray();
                if (handle.header.owner == .frozen) break :blk value;
                if (numericArrayIsRangeIota(handle) and !numericHasHostAttachment(handle) and !numericHasBackendAttachment(handle)) {
                    break :blk try newRangeIotaValueWithShape(
                        self,
                        .frozen,
                        numericArrayRangeLen(handle),
                        numericArrayRangeIota(handle).start,
                        numericArrayRangeIota(handle).step,
                        valueNonVectorNumericShape(value),
                    );
                }
                const frozen_host = try self.freezeHostArrayConstant(try hostStructuralArrayForHandle(self, @constCast(handle)));
                const shaped = try applyNonVectorNumericShapeToValue(self, frozen_host, valueNonVectorNumericShape(value));
                break :blk shaped;
            },
        };
    }

    fn freezeConstantValue(self: *Session, value: Value) KError!Value {
        return switch (value.raw & Value.tag_mask) {
            Value.boxed_int_tag => switch (value.asBoxedInt().header.owner) {
                .frozen => value,
                .scratch, .managed => try allocBoxedInt(self.arena.allocator(), .frozen, value.asInt()),
            },
            Value.closure_tag => switch (value.asClosure().header.owner) {
                .frozen => value,
                .scratch, .managed => blk: {
                    const closure = value.asClosure();
                    const frozen_captures = try self.arena.allocator().alloc(Value, closure.captures.len);
                    for (closure.captures, 0..) |capture, idx| {
                        frozen_captures[idx] = try self.freezeConstantValue(capture);
                    }
                    const frozen = try self.arena.allocator().create(Closure);
                    frozen.* = .{
                        .header = HeapHeader.init(.closure, .frozen),
                        .kind = closure.kind,
                        .code = try self.stableCode(closure.code),
                        .captures = frozen_captures,
                    };
                    break :blk Value.closure(frozen);
                },
            },
            Value.array_tag => try self.freezeArrayConstant(value),
            else => value,
        };
    }

    fn retainGlobalStoredValue(self: *Session, value: Value) !Value {
        return switch (value.raw & Value.tag_mask) {
            Value.closure_tag => switch (value.asClosure().header.owner) {
                .frozen => value,
                .managed, .scratch => blk: {
                    const closure = value.asClosure();
                    if (closure.captures.len == 0) break :blk try self.freezeZeroCaptureClosure(closure);
                    break :blk try self.retainEscapedValue(value);
                },
            },
            else => try self.retainEscapedValue(value),
        };
    }

    fn planHostArrayNormalization(self: *Session, array: *const HostDenseArray) !HostArrayNormalizationPlan {
        _ = self;
        return switch (array.storage) {
            .bit, .int8, .int16, .int32, .int64 => blk: {
                const view = hostIntArrayView(array).?;
                const normalized = hostDenseHasFlag(array, host_dense_flag_normalized);
                const target_kind = if (normalized)
                    hostIntArrayViewKind(view)
                else blk2: {
                    const range = hostDenseCachedIntRange(array) orelse hostIntArrayViewEndpointRange(view, array.flags) orelse hostIntArrayViewRange(view);
                    break :blk2 hostIntStorageKindForRange(range.min, range.max);
                };
                break :blk .{ .int = .{
                    .view = view,
                    .kind = target_kind,
                    .flags = if (normalized)
                        (array.flags | host_dense_flag_normalized)
                    else
                        (host_dense_flag_normalized | monotonicFlags(array.flags)),
                } };
            },
            .float64 => |items| blk: {
                if (hostDenseHasFlag(array, host_dense_flag_normalized)) {
                    break :blk .{ .float = .{
                        .items = items,
                        .flags = array.flags | host_dense_flag_normalized,
                    } };
                }

                const analysis = analyzeFloatSlice(items);
                if (analysis.int_analysis) |int_analysis| {
                    break :blk .{ .float_to_int = .{
                        .items = items,
                        .kind = int_analysis.kind,
                        .flags = int_analysis.flags,
                    } };
                }

                break :blk .{ .float = .{
                    .items = items,
                    .flags = analysis.flags,
                } };
            },
        };
    }

    fn normalizeHostArrayForPromotion(self: *Session, array: *const HostDenseArray) !Value {
        const plan = try self.planHostArrayNormalization(array);
        return switch (plan) {
            .int => |int_plan| blk: {
                var out = try self.allocManagedHostIntResult(int_plan.kind, hostIntArrayViewLen(int_plan.view));
                try copyHostIntViewToResult(&out, int_plan.view);
                const result = try out.value(self);
                hostDenseSetFlags(try mutableNumericHostArrayValue(self, result), int_plan.flags);
                break :blk result;
            },
            .float => |float_plan| blk: {
                const out = try self.allocManagedHostFloatResult(float_plan.items.len);
                @memcpy(out.items, float_plan.items);
                const result = try out.value(self);
                hostDenseSetFlags(try mutableNumericHostArrayValue(self, result), float_plan.flags);
                break :blk result;
            },
            .float_to_int => |int_plan| blk: {
                var out = try self.allocManagedHostIntResult(int_plan.kind, int_plan.items.len);
                try copyExactFloatSliceToIntResult(&out, int_plan.items);
                const result = try out.value(self);
                hostDenseSetFlags(try mutableNumericHostArrayValue(self, result), int_plan.flags);
                break :blk result;
            },
        };
    }

    fn promoteScratchArray(self: *Session, value: Value) !Value {
        return switch (value.activeArrayKind()) {
            .host_dense_array => blk: {
                const shape = valueNonVectorNumericShape(value);
                const promoted = try self.normalizeHostArrayForPromotion(hostDenseIfPresent(value) orelse return error.Type);
                break :blk try applyNonVectorNumericShapeToValue(self, promoted, shape);
            },
            .backend_array => try self.cloneManagedBackendArray(value.asBackendArray().array),
            .numeric_array => {
                const handle = value.asNumericArray();
                if (numericArrayIsRangeIota(handle)) {
                    return try newRangeIotaValueWithShape(
                        self,
                        .managed,
                        numericArrayRangeLen(handle),
                        numericArrayRangeIota(handle).start,
                        numericArrayRangeIota(handle).step,
                        valueNonVectorNumericShape(value),
                    );
                }
                if (numericHostAttachment(handle)) |host| {
                    const shape = valueNonVectorNumericShape(value);
                    const promoted = try self.normalizeHostArrayForPromotion(host);
                    return try applyNonVectorNumericShapeToValue(self, promoted, shape);
                }
                if (numericBackendAttachment(handle)) |array| return try self.cloneManagedBackendArray(array.array);
                return error.Internal;
            },
            else => error.Internal,
        };
    }

    fn makeArrayFromValues(self: *Session, values: []const Value) KError!Value {
        var normalized_storage: ?[]Value = null;
        defer if (normalized_storage) |items| {
            for (items, values) |item, original| {
                if (item.raw != original.raw) self.releaseValue(item);
            }
            self.allocator.free(items);
        };

        for (values, 0..) |value, idx| {
            const scalarized = try self.scalarizeRankZeroNumericArray(value) orelse continue;
            if (normalized_storage == null) {
                normalized_storage = try self.allocator.alloc(Value, values.len);
                @memcpy(normalized_storage.?, values);
            }
            normalized_storage.?[idx] = scalarized;
        }
        const normalized = normalized_storage orelse values;

        if (normalized.len != 0) {
            var all_host_strings = true;
            for (normalized) |value| {
                if (stringBytes(value) == null) {
                    all_host_strings = false;
                    break;
                }
            }
            if (all_host_strings) return try self.createManagedHostStringList(normalized);
        }

        var needs_float = false;
        var saw_numeric_array = false;
        var saw_scalar = false;
        var saw_non_numeric_item = false;
        var saw_irregular_numeric_array = false;
        var first_numeric_mode: ?HostDenseElem = null;
        var first_numeric_shape: ?NumericShapeSnapshot = null;
        for (normalized) |value| {
            switch (value.tag()) {
                .int, .bool => {
                    saw_scalar = true;
                    if (saw_numeric_array) saw_irregular_numeric_array = true;
                },
                .float => {
                    needs_float = true;
                    saw_scalar = true;
                    if (saw_numeric_array) saw_irregular_numeric_array = true;
                },
                else => {
                    if (valueNumericBuilderShape(value)) |shape| {
                        const mode = valueNumericMode(value) orelse {
                            saw_non_numeric_item = true;
                            continue;
                        };
                        if (saw_scalar) saw_irregular_numeric_array = true;
                        if (!saw_numeric_array) {
                            saw_numeric_array = true;
                            first_numeric_mode = mode;
                            first_numeric_shape = shape;
                        } else if (first_numeric_mode.? != mode or !numericShapeSnapshotEqual(first_numeric_shape.?, shape)) {
                            saw_irregular_numeric_array = true;
                        }
                    } else {
                        saw_non_numeric_item = true;
                    }
                },
            }
        }

        if (saw_numeric_array and !saw_non_numeric_item and !saw_irregular_numeric_array) {
            if (comptime enable_probe_instrumentation) switch (first_numeric_mode.?) {
                .int => self.debug_make_array_int_result_count += 1,
                .float => self.debug_make_array_float_result_count += 1,
            };
            return try createManagedStackedNumericArray(self, normalized, first_numeric_mode.?, first_numeric_shape.?);
        }

        if (saw_numeric_array or saw_non_numeric_item) {
            const reason: DebugMakeArrayBoxedReason = if (saw_non_numeric_item)
                .non_numeric_item
            else if (saw_irregular_numeric_array)
                .irregular_numeric_array
            else
                .uniform_numeric_array_unstacked;
            if (comptime enable_probe_instrumentation) {
                self.debug_make_array_boxed_fallback_count += 1;
                self.debug_make_array_boxed_reason_counts[@intFromEnum(reason)] += 1;
                self.debug_make_array_boxed_len_bucket_counts[@intFromEnum(debugProbeLenBucket(normalized.len))] += 1;
            }
            return try self.createManagedHostBoxedArray(normalized);
        }

        if (!needs_float) {
            if (comptime enable_probe_instrumentation) self.debug_make_array_int_result_count += 1;
            return try self.createManagedHostIntArrayFromValues(normalized);
        }

        if (comptime enable_probe_instrumentation) self.debug_make_array_float_result_count += 1;
        return try self.createManagedHostFloatArrayFromValues(normalized);
    }

    fn scalarizeRankZeroNumericArray(self: *Session, value: Value) KError!?Value {
        const handle = valueNumericHandle(value) orelse return null;
        if (handle.rank != 0) return null;
        const host = try tryEnsureHostRealizationForHandle(self, @constCast(handle)) orelse return error.Type;
        return switch (hostDenseNumericMode(host)) {
            .int => try self.intValue(try hostDenseIntAt(host, 0)),
            .float => try self.floatValue(try hostDenseFloatAt(host, 0)),
        };
    }

    fn compileCached(self: *Session, source: []const u8) KError!*const Code {
        var profile_scope = self.beginSamplingProfileScope(.compile);
        defer profile_scope.end();
        if (self.code_cache.get(source)) |cached| return cached;

        const compiled = try self.compileIntoArena(self.arena.allocator(), source, true);
        try self.code_cache.put(compiled.source, compiled.code);
        return compiled.code;
    }

    fn compileScratch(self: *Session, compile_arena: *std.heap.ArenaAllocator, source: []const u8) KError!*const Code {
        _ = compile_arena.reset(.retain_capacity);
        self.scratch_code.reset();
        if (try tryCompileSimpleTopLevelInto(self, source, compile_arena.allocator(), .scratch, &self.scratch_code.instructions)) {
            const code = self.scratch_code.finalize(0, 0);
            self.compilerAssignTopLevelProfile(code, source, .scratch);
            return code;
        }
        var compiler = try Compiler.init(self, source, compile_arena.allocator(), .scratch);
        return try compiler.compileTopLevelScratch(&self.scratch_code);
    }

    fn compileIntoArena(self: *Session, code_allocator: std.mem.Allocator, source: []const u8, own_source: bool) KError!CompiledSource {
        const compile_source = if (own_source) try code_allocator.dupe(u8, source) else source;
        var fast = InstructionBuffer{};
        if (try tryCompileSimpleTopLevelInto(self, compile_source, code_allocator, .frozen, &fast)) {
            const code = try duplicateCodeFromInstructions(code_allocator, 0, 0, &fast);
            self.compilerAssignTopLevelProfile(code, compile_source, .frozen);
            return .{
                .source = compile_source,
                .code = code,
            };
        }
        var compiler = try Compiler.init(self, compile_source, code_allocator, .frozen);
        return .{
            .source = compile_source,
            .code = try compiler.compileTopLevel(),
        };
    }

    fn ensureManagedHostDenseFindCache(self: *Session, array: *HostDenseArray) !*HostDenseFindCache {
        std.debug.assert(array.header.owner == .managed);
        if (array.find_cache) |cache| return cache;
        const cache = try self.allocator.create(HostDenseFindCache);
        cache.* = .{};
        array.find_cache = cache;
        return cache;
    }

    fn clearManagedHostDenseFindCache(self: *Session, array: *HostDenseArray) void {
        const cache = array.find_cache orelse return;
        if (cache.keys) |keys| self.allocator.free(keys);
        if (cache.slots) |slots| self.allocator.free(slots);
        cache.* = .{};
    }

    fn destroyManagedHostDenseFindCache(self: *Session, array: *HostDenseArray) void {
        const cache = array.find_cache orelse return;
        self.clearManagedHostDenseFindCache(array);
        self.allocator.destroy(cache);
        array.find_cache = null;
    }

    fn invalidateHostDenseCachesForMutation(self: *Session, array: *HostDenseArray) void {
        hostDenseClearCachedIntRange(array);
        if (numericPayloadOwner(array) == .managed) self.clearManagedHostDenseFindCache(array);
    }

    fn recycleManagedHostArray(self: *Session, array: *HostDenseArray) void {
        self.destroyManagedHostDenseFindCache(array);
        array.logical_handle = null;
        self.recycleManagedHostDenseStorage(array.storage);
        if (self.free_host_array_len < self.free_host_arrays.len) {
            self.free_host_arrays[self.free_host_array_len] = array;
            self.free_host_array_len += 1;
        } else {
            self.allocator.destroy(array);
        }
    }

    fn recycleManagedHostBoxedArray(self: *Session, array: *HostBoxedArray) void {
        for (array.items) |item| self.releaseValue(item);
        self.allocator.free(array.items);
        if (self.free_host_boxed_array_len < self.free_host_boxed_arrays.len) {
            self.free_host_boxed_arrays[self.free_host_boxed_array_len] = array;
            self.free_host_boxed_array_len += 1;
        } else {
            self.allocator.destroy(array);
        }
    }

    fn recycleManagedHostKeyedStore(self: *Session, store: *HostKeyedStore) void {
        self.releaseValue(store.names);
        self.releaseValue(store.values);
        if (store.column_metadata) |metadata| {
            for (metadata) |entry| {
                if (entry.validity) |mask| self.releaseValue(mask);
            }
            self.allocator.free(metadata);
        }
        store.lookup.deinit(self.allocator);
        if (store.owns_path) self.allocator.free(store.path);
        self.allocator.destroy(store);
    }

    fn recycleManagedBackendArray(self: *Session, array: *BackendArray) void {
        array.logical_handle = null;
        array.array.deinit();
        if (self.free_mlx_array_len < self.free_mlx_arrays.len) {
            self.free_mlx_arrays[self.free_mlx_array_len] = array;
            self.free_mlx_array_len += 1;
        } else {
            self.allocator.destroy(array);
        }
    }

    fn nextAttachmentTouchTick(self: *Session) usize {
        const tick = self.attachment_touch_clock;
        self.attachment_touch_clock += 1;
        return tick;
    }

    // Managed numeric handles stay in a session-local registry only for
    // residency policy, debug counters, and final teardown bookkeeping.
    // Ordinary numeric lifetime no longer depends on registry sweeps.
    fn registerManagedNumericHandle(self: *Session, handle: *NumericArray) void {
        if (handle.header.owner != .managed or handle.tracked_in_session) return;
        handle.registry_prev = null;
        handle.registry_next = self.managed_numeric_registry_head;
        if (self.managed_numeric_registry_head) |head| head.registry_prev = handle;
        self.managed_numeric_registry_head = handle;
        handle.tracked_in_session = true;
        handle.last_host_touch = 0;
        handle.last_mlx_touch = 0;
        if (handle.host != null) handle.last_host_touch = self.nextAttachmentTouchTick();
        if (handle.mlx != null) handle.last_mlx_touch = self.nextAttachmentTouchTick();
    }

    fn unregisterManagedNumericHandle(self: *Session, handle: *NumericArray) void {
        if (!handle.tracked_in_session) return;
        if (handle.registry_prev) |prev| {
            prev.registry_next = handle.registry_next;
        } else {
            self.managed_numeric_registry_head = handle.registry_next;
        }
        if (handle.registry_next) |next| next.registry_prev = handle.registry_prev;
        handle.registry_prev = null;
        handle.registry_next = null;
        handle.tracked_in_session = false;
        handle.last_host_touch = 0;
        handle.last_mlx_touch = 0;
    }

    fn touchHostAttachment(self: *Session, handle: *NumericArray) void {
        handle.last_host_touch = self.nextAttachmentTouchTick();
    }

    fn touchBackendAttachment(self: *Session, handle: *NumericArray) void {
        handle.last_mlx_touch = self.nextAttachmentTouchTick();
    }

    fn isDualResidentManagedHandle(handle: *const NumericArray) bool {
        return handle.header.owner == .managed and handle.host != null and handle.mlx != null;
    }

    fn dualResidentTouchScore(handle: *const NumericArray) usize {
        return @max(handle.last_host_touch, handle.last_mlx_touch);
    }

    fn dualResidentHandleCount(self: *const Session) usize {
        var count: usize = 0;
        var current = self.managed_numeric_registry_head;
        while (current) |handle| : (current = handle.registry_next) {
            if (isDualResidentManagedHandle(handle)) count += 1;
        }
        return count;
    }

    fn noteDualResidentPeak(self: *Session) void {
        if (comptime !enable_probe_instrumentation) return;
        const count = self.dualResidentHandleCount();
        if (count > self.debug_dual_resident_peak_count) self.debug_dual_resident_peak_count = count;
    }

    fn evictHostAttachment(self: *Session, handle: *NumericArray) void {
        const host = handle.host orelse return;
        self.recycleManagedHostArray(host);
        handle.host = null;
        if (comptime enable_probe_instrumentation) self.debug_host_eviction_count += 1;
        syncNumericArrayChildren(handle);
    }

    fn evictBackendAttachment(self: *Session, handle: *NumericArray) void {
        const array = handle.mlx orelse return;
        self.recycleManagedBackendArray(array);
        handle.mlx = null;
        if (comptime enable_probe_instrumentation) self.debug_mlx_eviction_count += 1;
        syncNumericArrayChildren(handle);
    }

    fn evictLeastRecentAttachment(self: *Session, handle: *NumericArray) void {
        if (!isDualResidentManagedHandle(handle)) return;
        const evict_host = if (handle.last_host_touch == handle.last_mlx_touch)
            handle.preferred == .mlx
        else
            handle.last_host_touch < handle.last_mlx_touch;
        if (evict_host) {
            self.evictHostAttachment(handle);
        } else {
            self.evictBackendAttachment(handle);
        }
    }

    fn enforceDualResidentBudget(self: *Session, exempt: ?*NumericArray) void {
        self.noteDualResidentPeak();
        while (self.dualResidentHandleCount() > dual_resident_numeric_budget) {
            var candidate: ?*NumericArray = null;
            var candidate_score: usize = std.math.maxInt(usize);
            var current = self.managed_numeric_registry_head;
            while (current) |handle| : (current = handle.registry_next) {
                if (!isDualResidentManagedHandle(handle)) continue;
                if (exempt) |skip| {
                    if (handle == skip) continue;
                }
                const score = dualResidentTouchScore(handle);
                if (candidate == null or score < candidate_score) {
                    candidate = handle;
                    candidate_score = score;
                }
            }
            if (candidate) |handle| {
                self.evictLeastRecentAttachment(handle);
            } else break;
        }
    }

    fn recycleManagedNumericArray(self: *Session, handle: *NumericArray) void {
        self.unregisterManagedNumericHandle(handle);
        const structural_tag = numericArrayStructuralTag(handle);
        if (comptime enable_probe_instrumentation) self.noteNumericStructuralRelease(structural_tag);
        switch (handle.structural) {
            .materialized, .range_iota => {},
            .flat_slice => |slice| self.releaseValue(slice.source),
            .flat_concat => |concat| {
                self.releaseValue(concat.left);
                self.releaseValue(concat.right);
            },
            .flat_segments => |segments| {
                for (segments.values) |value| self.releaseValue(value);
                self.allocator.free(segments.values);
            },
            .first_axis_slice => |slice| self.releaseValue(slice.source),
            .first_axis_index => |index| {
                self.releaseValue(index.source);
                self.releaseValue(index.row_indices);
            },
            .first_axis_concat => |concat| {
                self.releaseValue(concat.left);
                self.releaseValue(concat.right);
            },
            .reshape_view => |reshape| self.releaseValue(reshape.source),
            .transpose_view => |transpose| self.releaseValue(transpose.source),
        }
        handle.structural = .{ .materialized = {} };
        if (handle.host) |array| self.recycleManagedHostArray(array);
        handle.host = null;
        if (handle.mlx) |array| self.recycleManagedBackendArray(array);
        handle.mlx = null;
        if (self.free_numeric_array_len < self.free_numeric_arrays.len) {
            self.free_numeric_arrays[self.free_numeric_array_len] = handle;
            self.free_numeric_array_len += 1;
        } else {
            self.allocator.destroy(handle);
        }
    }

    fn shareValue(self: *Session, value: Value) Value {
        _ = self;
        if (isManagedValue(value)) retainHeapValue(value);
        return value;
    }

    fn retainValue(self: *Session, value: Value) Value {
        return self.shareValue(value);
    }

    fn releaseManagedNumericHandle(self: *Session, handle: *NumericArray) void {
        std.debug.assert(handle.header.owner == .managed);
        std.debug.assert(handle.header.ref_count != 0);
        handle.header.ref_count -= 1;
        if (handle.header.ref_count == 0) self.recycleManagedNumericArray(handle);
    }

    fn releaseCanonicalManagedNumericValue(self: *Session, value: Value) void {
        if (valueNumericHandle(value)) |handle| {
            if (handle.header.owner == .managed) {
                self.releaseManagedNumericHandle(@constCast(handle));
                return;
            }
        }
        self.releaseValue(value);
    }

    fn releaseValue(self: *Session, value: Value) void {
        switch (value.raw & Value.tag_mask) {
            Value.boxed_int_tag => {
                const box = @constCast(value.asBoxedInt());
                if (box.header.owner != .managed) return;
                std.debug.assert(box.header.ref_count != 0);
                box.header.ref_count -= 1;
                if (box.header.ref_count == 0) {
                    if (self.free_boxed_int_len < self.free_boxed_ints.len) {
                        self.free_boxed_ints[self.free_boxed_int_len] = box;
                        self.free_boxed_int_len += 1;
                    } else {
                        self.allocator.destroy(box);
                    }
                }
            },
            Value.closure_tag => {
                const closure = @constCast(value.asClosure());
                if (closure.header.owner != .managed) return;
                std.debug.assert(closure.header.ref_count != 0);
                closure.header.ref_count -= 1;
                if (closure.header.ref_count == 0) {
                    if (comptime enable_probe_instrumentation) {
                        if (closureIsProjection(closure)) self.debug_projection_closure_release_count += 1;
                    }
                    for (closure.captures) |capture| self.releaseValue(capture);
                    self.allocator.free(closure.captures);
                    if (self.free_closure_len < self.free_closures.len) {
                        self.free_closures[self.free_closure_len] = closure;
                        self.free_closure_len += 1;
                    } else {
                        self.allocator.destroy(closure);
                    }
                }
            },
            Value.array_tag => switch (value.arraySubkind()) {
                .numeric_array => {
                    const handle = @constCast(value.asNumericArray());
                    if (handle.header.owner != .managed) return;
                    self.releaseManagedNumericHandle(handle);
                },
                .host_dense_array => {
                    if (logicalHandleForNumericPayloadValue(value)) |handle| {
                        if (handle.header.owner != .managed) return;
                        self.releaseManagedNumericHandle(handle);
                    } else {
                        const array = @constCast(value.asHostDenseArray());
                        if (array.header.owner != .managed) return;
                        std.debug.assert(array.header.ref_count != 0);
                        array.header.ref_count -= 1;
                        if (array.header.ref_count == 0) self.recycleManagedHostArray(array);
                    }
                },
                .host_boxed_array => {
                    const array = @constCast(value.asHostBoxedArray());
                    if (array.header.owner != .managed) return;
                    std.debug.assert(array.header.ref_count != 0);
                    array.header.ref_count -= 1;
                    if (array.header.ref_count == 0) self.recycleManagedHostBoxedArray(array);
                },
                .host_keyed_store => {
                    const store = @constCast(value.asHostKeyedStore());
                    if (store.header.owner != .managed) return;
                    std.debug.assert(store.header.ref_count != 0);
                    store.header.ref_count -= 1;
                    if (store.header.ref_count == 0) self.recycleManagedHostKeyedStore(store);
                },
                .host_string, .host_symbol => {
                    const text = switch (value.arrayKind()) {
                        .host_string => @constCast(value.asHostString()),
                        .host_symbol => @constCast(value.asHostSymbol()),
                        else => unreachable,
                    };
                    if (text.header.owner != .managed) return;
                    std.debug.assert(text.header.ref_count != 0);
                    text.header.ref_count -= 1;
                    if (text.header.ref_count == 0) {
                        self.forgetInternedHostText(value.arrayKind(), text);
                        freeHostTextAlloc(self.allocator, text);
                    }
                },
                .host_string_view => {
                    const view = @constCast(value.asHostStringView());
                    if (view.header.owner != .managed) return;
                    std.debug.assert(view.header.ref_count != 0);
                    view.header.ref_count -= 1;
                    if (view.header.ref_count == 0) {
                        if (comptime enable_probe_instrumentation) self.debug_host_string_view_release_count += 1;
                        self.releaseValue(Value.array(view.base));
                        self.allocator.destroy(view);
                    }
                },
                .host_relation => {
                    const relation = @constCast(value.asHostRelation());
                    if (relation.header.owner != .managed) return;
                    std.debug.assert(relation.header.ref_count != 0);
                    relation.header.ref_count -= 1;
                    if (relation.header.ref_count == 0) {
                        destroyManagedHostRelationNoPool(self.allocator, relation);
                    }
                },
                .host_table_scalar => {
                    const scalar = @constCast(valueAsHostTableScalar(value));
                    if (scalar.header.owner != .managed) return;
                    std.debug.assert(scalar.header.ref_count != 0);
                    scalar.header.ref_count -= 1;
                    if (scalar.header.ref_count == 0) {
                        self.releaseValue(scalar.value);
                        self.allocator.destroy(scalar);
                    }
                },
                .host_string_list => {
                    const list = @constCast(value.asHostStringList());
                    if (list.header.owner != .managed) return;
                    std.debug.assert(list.header.ref_count != 0);
                    list.header.ref_count -= 1;
                    if (list.header.ref_count == 0) {
                        if (list.base) |base| self.releaseValue(Value.array(base));
                        switch (list.storage) {
                            .eager => |items| {
                                for (items) |item| self.releaseHostStringPiece(item);
                                freeHostStringListAlloc(self.allocator, list);
                            },
                            .split_scalar => self.allocator.destroy(list),
                        }
                    }
                },
                .backend_array => {
                    if (logicalHandleForNumericPayloadValue(value)) |handle| {
                        if (handle.header.owner != .managed) return;
                        self.releaseManagedNumericHandle(handle);
                    } else {
                        const array = @constCast(value.asBackendArray());
                        if (array.header.owner != .managed) return;
                        std.debug.assert(array.header.ref_count != 0);
                        array.header.ref_count -= 1;
                        if (array.header.ref_count == 0) self.recycleManagedBackendArray(array);
                    }
                },
            },
            else => {},
        }
    }

    fn backendContext(self: *Session) KError!*mlx.Context {
        if (comptime !runtime_has_mlx) return error.Unsupported;
        if (self.mlx_ctx == null) {
            self.mlx_ctx = mlx.initContext(self.device_preference) catch |err| return mapMlxError(err);
        }
        return &self.mlx_ctx.?;
    }

    fn cloneManagedBackendArray(self: *Session, array: mlx.Array) KError!Value {
        var cloned = array.clone() catch |err| return mapMlxError(err);
        errdefer cloned.deinit();
        return try self.wrapManagedBackendArray(cloned);
    }

    fn allocManagedBackendPayload(self: *Session, array: mlx.Array) KError!*BackendArray {
        const owned = if (self.free_mlx_array_len != 0) blk: {
            self.free_mlx_array_len -= 1;
            break :blk self.free_mlx_arrays[self.free_mlx_array_len].?;
        } else try self.allocator.create(BackendArray);
        owned.* = .{
            .header = HeapHeader.init(.backend_array, .managed),
            .logical_handle = null,
            .array = array,
        };
        return owned;
    }

    fn wrapManagedBackendArray(self: *Session, array: mlx.Array) KError!Value {
        const owned = try self.allocManagedBackendPayload(array);
        return try wrapOwnedBackendArrayValue(self, owned);
    }

    fn castOwnedBackendArrayToDtype(self: *Session, array: *mlx.Array, target_dtype: c.mlx_dtype) KError!void {
        if (array.dtype() == target_dtype) return;
        const ctx = try self.backendContext();
        const casted = mlx.Array.cast(ctx.*, array.*, target_dtype) catch |err| return mapMlxError(err);
        array.deinit();
        array.* = casted;
    }

    fn bfloat16BitsToFloat32(bit_pattern: u16) f32 {
        const wide: u32 = @as(u32, bit_pattern) << 16;
        return @bitCast(wide);
    }

    pub fn setGlobalMlxFloatMatrix(self: *Session, name: []const u8, rows: usize, cols: usize, data: []const f32) !void {
        if (comptime !runtime_has_mlx) return error.Unsupported;
        if (rows * cols != data.len) return error.Internal;
        const dims = [_]i32{ @intCast(rows), @intCast(cols) };
        const value = try self.wrapManagedBackendArray(mlx.Array.fromFloatSlice(data, &dims));
        defer self.releaseValue(value);
        try self.storeGlobalSlot(try self.internGlobalSlot(name), value);
    }

    pub fn setGlobalMlxFloatVector(self: *Session, name: []const u8, data: []const f32) !void {
        if (comptime !runtime_has_mlx) return error.Unsupported;
        const dims = [_]i32{@intCast(data.len)};
        const value = try self.wrapManagedBackendArray(mlx.Array.fromFloatSlice(data, &dims));
        defer self.releaseValue(value);
        try self.storeGlobalSlot(try self.internGlobalSlot(name), value);
    }

    pub fn setGlobalMlxFloatArray(self: *Session, name: []const u8, data: []const f32, dims: []const i32) !void {
        if (comptime !runtime_has_mlx) return error.Unsupported;
        var elem_count: usize = 1;
        for (dims) |dim| elem_count *= @intCast(dim);
        if (elem_count != data.len) return error.Internal;
        const value = try self.wrapManagedBackendArray(mlx.Array.fromFloatSlice(data, dims));
        defer self.releaseValue(value);
        try self.storeGlobalSlot(try self.internGlobalSlot(name), value);
    }

    pub fn setGlobalMlxBfloat16Matrix(self: *Session, name: []const u8, rows: usize, cols: usize, data: []const u16) !void {
        if (comptime !runtime_has_mlx) return error.Unsupported;
        if (rows * cols != data.len) return error.Internal;
        const dims = [_]i32{ @intCast(rows), @intCast(cols) };
        const decoded = try self.allocator.alloc(f32, data.len);
        defer self.allocator.free(decoded);
        for (data, 0..) |item, idx| decoded[idx] = bfloat16BitsToFloat32(item);
        var array = mlx.Array.fromFloatSlice(decoded, &dims);
        errdefer array.deinit();
        try self.castOwnedBackendArrayToDtype(&array, c.MLX_BFLOAT16);
        const value = try self.wrapManagedBackendArray(array);
        defer self.releaseValue(value);
        try self.storeGlobalSlot(try self.internGlobalSlot(name), value);
    }

    pub fn setGlobalMlxBfloat16Vector(self: *Session, name: []const u8, data: []const u16) !void {
        if (comptime !runtime_has_mlx) return error.Unsupported;
        const dims = [_]i32{@intCast(data.len)};
        const decoded = try self.allocator.alloc(f32, data.len);
        defer self.allocator.free(decoded);
        for (data, 0..) |item, idx| decoded[idx] = bfloat16BitsToFloat32(item);
        var array = mlx.Array.fromFloatSlice(decoded, &dims);
        errdefer array.deinit();
        try self.castOwnedBackendArrayToDtype(&array, c.MLX_BFLOAT16);
        const value = try self.wrapManagedBackendArray(array);
        defer self.releaseValue(value);
        try self.storeGlobalSlot(try self.internGlobalSlot(name), value);
    }

