    inline fn readOp(frame: *CallFrame) KError!Op {
        const byte = try readByte(frame);
        return std.meta.intToEnum(Op, byte) catch error.Internal;
    }

    inline fn readByte(frame: *CallFrame) KError!u8 {
        if (frame.ip >= frame.code.bytes.len) return error.Internal;
        const value = frame.code.bytes[frame.ip];
        frame.ip += 1;
        return value;
    }

    inline fn readU64(frame: *CallFrame) KError!u64 {
        const end = frame.ip + 8;
        if (end > frame.code.bytes.len) return error.Internal;
        var value: u64 = 0;
        var idx: usize = 0;
        while (idx < 8) : (idx += 1) {
            value |= @as(u64, frame.code.bytes[frame.ip + idx]) << @intCast(idx * 8);
        }
        frame.ip = end;
        return value;
    }

    inline fn readI64(frame: *CallFrame) KError!i64 {
        return @bitCast(try readU64(frame));
    }

    inline fn readU16(frame: *CallFrame) KError!usize {
        const lo = try readByte(frame);
        const hi = try readByte(frame);
        return @as(usize, lo) | (@as(usize, hi) << 8);
    }

    inline fn readGlobalSlot(frame: *CallFrame) KError!u16 {
        return @intCast(try readU16(frame));
    }

    inline fn readConstant(frame: *CallFrame) KError!Value {
        const slot = try readByte(frame);
        if (slot >= frame.code.constants.len) return error.Internal;
        return frame.code.constants[slot];
    }

    fn readLocal(self: *Session, frame: *const CallFrame, slot: u8) KError!Value {
        const index = frame.base + slot;
        if (index >= self.stack_len) return error.Internal;
        return self.stack[index];
    }

    fn storeLocal(self: *Session, frame: *const CallFrame, slot: u8) KError!void {
        if (self.stack_len == 0) return error.Internal;
        const value = self.pop();
        try self.writeLocalValue(frame, slot, value);
    }

    fn writeLocalValue(self: *Session, frame: *const CallFrame, slot: u8, value: Value) KError!void {
        const index = frame.base + slot;
        if (index >= self.stack_len) return error.Internal;
        const mutable_frame = @constCast(frame);
        if (frameLocalMayNeedRelease(frame, slot)) {
            if (comptime enable_probe_instrumentation) self.debug_local_release_taken_count += 1;
            self.releaseCanonicalManagedNumericValue(self.stack[index]);
        } else if (comptime enable_probe_instrumentation) {
            self.debug_local_release_skip_count += 1;
        }
        self.stack[index] = value;
        updateFrameLocalReleaseState(mutable_frame, slot, value);
    }

    fn takeLocal(self: *Session, frame: *const CallFrame, slot: u8) KError!Value {
        const index = frame.base + slot;
        if (index >= self.stack_len) return error.Internal;
        const value = self.stack[index];
        self.stack[index] = Value.fromBool(false);
        clearFrameLocalReleaseState(@constCast(frame), slot);
        return value;
    }

    fn writeInlineLocalValue(self: *Session, slot: u8, value: Value) KError!void {
        const base = self.currentInlineBase() orelse return error.Internal;
        const index = base + slot;
        if (index >= self.stack_len) return error.Internal;
        self.releaseCanonicalManagedNumericValue(self.stack[index]);
        self.stack[index] = value;
    }

    fn readInlineLocal(self: *Session, slot: u8) KError!Value {
        const base = self.currentInlineBase() orelse return error.Internal;
        const index = base + slot;
        if (index >= self.stack_len) return error.Internal;
        return self.stack[index];
    }

    fn takeInlineLocal(self: *Session, slot: u8) KError!Value {
        const base = self.currentInlineBase() orelse return error.Internal;
        const index = base + slot;
        if (index >= self.stack_len) return error.Internal;
        const value = self.stack[index];
        self.stack[index] = Value.fromBool(false);
        return value;
    }

    fn tryFastLocalConstDyadValue(self: *Session, left: Value, op: BuiltinId, rhs_const: i64, const_first: bool) KError!?Value {
        if (inlineIntBoolValue(left)) |left_value| {
            if (comptime enable_probe_instrumentation) self.debug_inline_scalar_dyad_attempt_count += 1;
            const lhs = if (const_first) rhs_const else left_value;
            const rhs = if (const_first) left_value else rhs_const;
            const result: ?Value = switch (op) {
                .add => blk: {
                    const added = @addWithOverflow(lhs, rhs);
                    if (added[1] != 0) break :blk null;
                    break :blk try self.intValue(added[0]);
                },
                .sub => blk: {
                    const subbed = @subWithOverflow(lhs, rhs);
                    if (subbed[1] != 0) break :blk null;
                    break :blk try self.intValue(subbed[0]);
                },
                .mul => blk: {
                    const multiplied = @mulWithOverflow(lhs, rhs);
                    if (multiplied[1] != 0) break :blk null;
                    break :blk try self.intValue(multiplied[0]);
                },
                .div => try self.floatValue(@as(f64, @floatFromInt(lhs)) / @as(f64, @floatFromInt(rhs))),
                .minimum => try self.intValue(@min(lhs, rhs)),
                .maximum => try self.intValue(@max(lhs, rhs)),
                .less => Value.fromBool(lhs < rhs),
                .more => Value.fromBool(lhs > rhs),
                .equal => Value.fromBool(lhs == rhs),
                else => null,
            };
            if (comptime enable_probe_instrumentation) {
                if (result != null) self.debug_inline_scalar_dyad_hit_count += 1 else self.debug_inline_scalar_dyad_fallback_count += 1;
            }
            return result;
        }

        const left_float = inlineNumericFloatValue(left) orelse return null;
        if (comptime enable_probe_instrumentation) self.debug_inline_scalar_dyad_attempt_count += 1;
        const rhs_float: f64 = @floatFromInt(rhs_const);
        const lhs = if (const_first) rhs_float else left_float;
        const rhs = if (const_first) left_float else rhs_float;
        const result: ?Value = switch (op) {
            .add => try self.floatValue(lhs + rhs),
            .sub => try self.floatValue(lhs - rhs),
            .mul => try self.floatValue(lhs * rhs),
            .div => try self.floatValue(lhs / rhs),
            .minimum => try self.floatValue(@min(lhs, rhs)),
            .maximum => try self.floatValue(@max(lhs, rhs)),
            .less => Value.fromBool(lhs < rhs),
            .more => Value.fromBool(lhs > rhs),
            .equal => Value.fromBool(lhs == rhs),
            else => null,
        };
        if (comptime enable_probe_instrumentation) {
            if (result != null) self.debug_inline_scalar_dyad_hit_count += 1 else self.debug_inline_scalar_dyad_fallback_count += 1;
        }
        return result;
    }

    fn applyLocalConstOpValue(self: *Session, left: Value, op: BuiltinId, rhs: i64) KError!Value {
        if (try self.tryFastLocalConstDyadValue(left, op, rhs, false)) |result| return result;
        if (scalarIntLikeValue(left)) |lhs| {
            switch (op) {
                .add => {
                    const result = @addWithOverflow(lhs, rhs);
                    if (result[1] == 0) return try self.intValue(result[0]);
                },
                .sub => {
                    const result = @subWithOverflow(lhs, rhs);
                    if (result[1] == 0) return try self.intValue(result[0]);
                },
                .mul => {
                    const result = @mulWithOverflow(lhs, rhs);
                    if (result[1] == 0) return try self.intValue(result[0]);
                },
                else => return error.Unsupported,
            }
        }

        const right = try self.intValue(rhs);
        defer self.releaseValue(right);
        return switch (op) {
            .add => try self.addValues(left, right),
            .sub => try self.subValues(left, right),
            .mul => try self.mulValues(left, right),
            else => error.Unsupported,
        };
    }

    fn applyConstLocalOpValue(self: *Session, lhs: i64, op: BuiltinId, right: Value) KError!Value {
        if (try self.tryFastLocalConstDyadValue(right, op, lhs, true)) |result| return result;
        const left = try self.intValue(lhs);
        defer self.releaseValue(left);
        return switch (op) {
            .add => try self.addValues(left, right),
            .sub => try self.subValues(left, right),
            .mul => try self.mulValues(left, right),
            else => error.Unsupported,
        };
    }

    fn applyBorrowedDyadValue(self: *Session, op: BuiltinId, left: Value, right: Value) KError!Value {
        if (try self.tryFastInlineScalarDyad(op, left, right)) |result| return result;
        return switch (op) {
            .add => try self.addValues(left, right),
            .sub => try self.subValues(left, right),
            .mul => try self.mulValues(left, right),
            .div => try self.divValues(left, right),
            .minimum => try self.minimumValues(left, right),
            .maximum => try self.maximumValues(left, right),
            .less => try self.lessValues(left, right),
            .more => try self.moreValues(left, right),
            .equal => try self.equalValues(left, right),
            else => error.Unsupported,
        };
    }

    fn applyShapedBorrowedDyadValue(self: *Session, op: BuiltinId, left: Value, right: Value) KError!Value {
        if (comptime enable_probe_instrumentation) self.debug_shaped_scalar_dyad_count += 1;
        return try self.applyBorrowedDyadValue(op, left, right);
    }

    fn applyLocalConstDyadValue(self: *Session, left: Value, op: BuiltinId, rhs: i64) KError!Value {
        if (comptime enable_probe_instrumentation) self.debug_shaped_scalar_dyad_count += 1;
        if (try self.tryFastLocalConstDyadValue(left, op, rhs, false)) |result| return result;
        const right = try self.intValue(rhs);
        defer self.releaseValue(right);
        return try self.applyBorrowedDyadValue(op, left, right);
    }

    fn applyConstLocalDyadValue(self: *Session, lhs: i64, op: BuiltinId, right: Value) KError!Value {
        if (comptime enable_probe_instrumentation) self.debug_shaped_scalar_dyad_count += 1;
        if (try self.tryFastLocalConstDyadValue(right, op, lhs, true)) |result| return result;
        const left = try self.intValue(lhs);
        defer self.releaseValue(left);
        return try self.applyBorrowedDyadValue(op, left, right);
    }

    fn compareLocalConstBranch(self: *Session, frame: *const CallFrame, slot: u8, op: BuiltinId, rhs: i64) KError!FusedBranchResult {
        const left = try self.readLocal(frame, slot);
        if (comptime enable_probe_instrumentation) self.debug_shaped_scalar_dyad_count += 1;
        if (try self.tryFastLocalConstDyadValue(left, op, rhs, false)) |condition| {
            const truthy = boolLikeValue(condition) orelse return error.Type;
            return .{ .truthy = truthy, .scalar = true };
        }

        const right = try self.intValue(rhs);
        defer self.releaseValue(right);
        const condition = try self.applyBorrowedDyadValue(op, left, right);
        defer self.releaseValue(condition);
        const truthy = boolLikeValue(condition) orelse return error.Type;
        return .{
            .truthy = truthy,
            .scalar = switch (condition.tag()) {
                .bool, .int, .float => true,
                else => false,
            },
        };
    }

    fn currentInlineBase(self: *const Session) ?usize {
        if (self.inline_len == 0) return null;
        return self.inline_bases[self.inline_len - 1];
    }

    fn retainedFrameOwner(self: *Session, value: Value) ?Value {
        if (value.tag() == .closure and value.asClosure().kind == .plain) return null;
        return if (isManagedValue(value)) self.retainValue(value) else null;
    }

    fn pushInlineBase(self: *Session, argc: u8) KError!void {
        const argc_usize: usize = argc;
        if (self.stack_len < argc_usize) return error.Internal;
        if (self.inline_len >= self.inline_bases.len) return error.Unsupported;
        self.inline_bases[self.inline_len] = self.stack_len - argc_usize;
        self.inline_len += 1;
    }

    fn leaveInline(self: *Session, argc: u8) KError!void {
        _ = argc;
        if (self.inline_len == 0 or self.stack_len == 0) return error.Internal;
        const base = self.inline_bases[self.inline_len - 1];
        self.inline_len -= 1;
        const result = self.pop();
        if (base > self.stack_len) return error.Internal;
        self.dropFrameStackFrom(base);
        try self.push(result);
    }

    fn replaceCurrentFrameWithClosure1(self: *Session, frame_index: usize, owner: Value, closure: *const Closure, arg0: Value) KError!void {
        const retained_owner = self.retainValue(owner);
        const retained_arg0 = self.retainValue(arg0);
        const base = self.frames[frame_index].base;
        const old_owner = self.frames[frame_index].owner;
        const result_target = self.frames[frame_index].result_target;
        self.dropFrameStackFrom(base);
        if (old_owner) |owned| self.releaseValue(owned);
        self.stack_len = base;
        try self.push(retained_arg0);
        self.frames[frame_index] = .{
            .code = closure.code,
            .ip = 0,
            .base = base,
            .owner = retained_owner,
            .callable_global_slot = sampling_profile_no_callable_slot,
            .result_target = result_target,
        };
        var state = FrameLocalReleaseState{};
        noteLocalReleaseState(&state, 0, retained_arg0);
        try self.prepareReusedFrameActivationWithReleaseState(frame_index, state, true);
    }

    const TailClosureOwnerMode = enum {
        borrowed_global,
        consumed_stack,
    };

    fn replaceCurrentFrameWithTrailingClosureArgs(
        self: *Session,
        frame_index: usize,
        callee: Value,
        closure: *const Closure,
        callable_slot: u16,
        arg_count: usize,
        owner_mode: TailClosureOwnerMode,
    ) KError!void {
        if (arg_count == 0 or arg_count > max_shaped_call_args) return error.Unsupported;
        const consumed_callee_count: usize = if (owner_mode == .consumed_stack) 1 else 0;
        if (self.stack_len < arg_count + consumed_callee_count) return error.Internal;

        const base = self.frames[frame_index].base;
        const args_start = self.stack_len - arg_count;
        const consumed_callee_index = if (owner_mode == .consumed_stack) args_start - 1 else std.math.maxInt(usize);
        const old_owner = self.frames[frame_index].owner;
        const result_target = self.frames[frame_index].result_target;

        var args_buf: [max_shaped_call_args]Value = undefined;
        var arg_idx: usize = 0;
        while (arg_idx < arg_count) : (arg_idx += 1) {
            args_buf[arg_idx] = self.stack[args_start + arg_idx];
        }
        const state = frameReleaseStateFromValues(args_buf[0..arg_count]);

        var idx = self.stack_len;
        while (idx > base) {
            idx -= 1;
            if ((idx >= args_start and idx < args_start + arg_count) or idx == consumed_callee_index) continue;
            self.releaseValue(self.stack[idx]);
        }

        for (args_buf[0..arg_count], 0..) |arg, idx_out| self.stack[base + idx_out] = arg;
        self.stack_len = base + arg_count;
        if (old_owner) |owned| self.releaseValue(owned);

        const owner = switch (owner_mode) {
            .borrowed_global => self.retainedFrameOwner(callee),
            .consumed_stack => callee,
        };
        self.frames[frame_index] = .{
            .code = closure.code,
            .ip = 0,
            .base = base,
            .owner = owner,
            .callable_global_slot = if (owner_mode == .borrowed_global) callable_slot else sampling_profile_no_callable_slot,
            .result_target = result_target,
        };
        try self.prepareReusedFrameActivationWithReleaseState(frame_index, state, true);
    }

    inline fn directBinaryArg(arg0: Value, arg1: Value, slot: u8) ?Value {
        return switch (slot) {
            0 => arg0,
            1 => arg1,
            else => null,
        };
    }

    inline fn directReadI64(bytes: []const u8, start: usize) ?i64 {
        const end = start + 8;
        if (end > bytes.len) return null;
        var value: u64 = 0;
        var idx: usize = 0;
        while (idx < 8) : (idx += 1) {
            value |= @as(u64, bytes[start + idx]) << @intCast(idx * 8);
        }
        return @bitCast(value);
    }

    inline fn directReadU16(bytes: []const u8, start: usize) ?u16 {
        const end = start + 2;
        if (end > bytes.len) return null;
        return @as(u16, bytes[start]) | (@as(u16, bytes[start + 1]) << 8);
    }

    const ArgmaxBytecodeKind = enum {
        find_of_max_fold,
        first_of_grade_down,
    };

    fn valueIsMaximumFoldCallable(value: Value) bool {
        return switch (value.tag()) {
            .closure => blk: {
                const closure = value.asClosure();
                if (closureDerivedKind(closure) != .fold) break :blk false;
                if (closure.captures.len != 1) break :blk false;
                if (closure.captures[0].tag() != .builtin) break :blk false;
                break :blk closure.captures[0].asBuiltin() == .maximum;
            },
            .builtin => value.asBuiltin() == .maximum,
            else => false,
        };
    }

    fn classifyArgmaxBytecode(bytes: []const u8, constants: []const Value) ?ArgmaxBytecodeKind {
        if (bytes.len >= 4 and bytes[bytes.len - 1] == @intFromEnum(Op.find) and bytes[bytes.len - 2] == @intFromEnum(Op.call1)) {
            const fold_lens = [_]usize{ 4, 2 };
            for (fold_lens) |fold_len| {
                if (bytes.len < fold_len + 2) continue;
                const operand_len_x2 = bytes.len - (fold_len + 2);
                if ((operand_len_x2 & 1) == 0) {
                    const operand_len = operand_len_x2 / 2;
                    if (operand_len == 0) continue;

                    const middle = bytes[operand_len .. operand_len + fold_len];
                    const middle_matches = switch (fold_len) {
                        4 => middle[0] == @intFromEnum(Op.const_builtin) and
                            middle[1] == @intFromEnum(BuiltinId.maximum) and
                            middle[2] == @intFromEnum(Op.make_adverb) and
                            middle[3] == @intFromEnum(DerivedVerbKind.fold),
                        2 => blk: {
                            if (middle[0] != @intFromEnum(Op.const_value)) break :blk false;
                            const slot = middle[1];
                            break :blk slot < constants.len and valueIsMaximumFoldCallable(constants[slot]);
                        },
                        else => false,
                    };
                    if (middle_matches and std.mem.eql(u8, bytes[0..operand_len], bytes[operand_len + fold_len .. bytes.len - 2])) {
                        return .find_of_max_fold;
                    }
                }
            }
        }

        if (bytes.len >= 11 and
            bytes[bytes.len - 11] == @intFromEnum(Op.grade_down) and
            bytes[bytes.len - 10] == @intFromEnum(Op.const_int) and
            bytes[bytes.len - 1] == @intFromEnum(Op.call1))
        {
            const zero = directReadI64(bytes, bytes.len - 9) orelse return null;
            if (zero == 0) return .first_of_grade_down;
        }

        return null;
    }

    fn argmaxBytecodeOperandLen(bytes: []const u8, constants: []const Value, kind: ArgmaxBytecodeKind) usize {
        return switch (kind) {
            .find_of_max_fold => blk: {
                const fold_lens = [_]usize{ 4, 2 };
                for (fold_lens) |fold_len| {
                    if (bytes.len < fold_len + 2) continue;
                    const operand_len_x2 = bytes.len - (fold_len + 2);
                    if ((operand_len_x2 & 1) != 0) continue;
                    const operand_len = operand_len_x2 / 2;
                    if (operand_len == 0) continue;

                    const middle = bytes[operand_len .. operand_len + fold_len];
                    const middle_matches = switch (fold_len) {
                        4 => middle[0] == @intFromEnum(Op.const_builtin) and
                            middle[1] == @intFromEnum(BuiltinId.maximum) and
                            middle[2] == @intFromEnum(Op.make_adverb) and
                            middle[3] == @intFromEnum(DerivedVerbKind.fold),
                        2 => blk2: {
                            if (middle[0] != @intFromEnum(Op.const_value)) break :blk2 false;
                            const slot = middle[1];
                            break :blk2 slot < constants.len and valueIsMaximumFoldCallable(constants[slot]);
                        },
                        else => false,
                    };
                    if (middle_matches and std.mem.eql(u8, bytes[0..operand_len], bytes[operand_len + fold_len .. bytes.len - 2])) {
                        break :blk operand_len;
                    }
                }
                unreachable;
            },
            .first_of_grade_down => bytes.len - 11,
        };
    }

    const DirectConditionalAtom = enum {
        arg0,
        arg1,
        zero,
    };

    const DirectConditionalCompare = struct {
        lhs: DirectConditionalAtom,
        rhs: DirectConditionalAtom,
        cmp: Op,
    };

    const DenseElementwiseKind = union(enum) {
        dyad: struct {
            op: BuiltinId,
            swap: bool,
        },
        keep_left_if_more,
    };

    const DirectUnarySelfTransform = enum {
        grade_up,
        grade_down,
    };

    const DirectUnaryLiftedKind = struct {
        base: Value,
        transform: DirectUnarySelfTransform,
    };

    const DirectRowReduceKind = enum {
        sum,
        product,
        minimum,
        maximum,
        mean,
    };

    const DirectRowReduceBase = struct {
        kind: DirectRowReduceKind,
        has_explicit_each: bool,
    };

    fn classifyDenseBuiltin(op: BuiltinId) ?DenseElementwiseKind {
        return switch (op) {
            .add, .sub, .mul, .div, .pow, .minimum, .maximum, .less, .more => .{ .dyad = .{ .op = op, .swap = false } },
            else => null,
        };
    }

    fn applyDenseElementwiseKind(self: *Session, kind: DenseElementwiseKind, arg0: Value, arg1: Value) KError!Value {
        return switch (kind) {
            .dyad => |dyad| blk: {
                const left = if (dyad.swap) arg1 else arg0;
                const right = if (dyad.swap) arg0 else arg1;
                break :blk switch (dyad.op) {
                    .add => try self.addValues(left, right),
                    .sub => try self.subValues(left, right),
                    .mul => try self.mulValues(left, right),
                    .div => try self.divValues(left, right),
                    .pow => try self.powValues(left, right),
                    .minimum => blk2: {
                        const mask = try self.lessValues(left, right);
                        defer self.releaseValue(mask);
                        const delta = try self.subValues(left, right);
                        defer self.releaseValue(delta);
                        const kept = try self.mulValues(mask, delta);
                        defer self.releaseValue(kept);
                        break :blk2 try self.addValues(right, kept);
                    },
                    .maximum => blk2: {
                        const mask = try self.moreValues(left, right);
                        defer self.releaseValue(mask);
                        const delta = try self.subValues(left, right);
                        defer self.releaseValue(delta);
                        const kept = try self.mulValues(mask, delta);
                        defer self.releaseValue(kept);
                        break :blk2 try self.addValues(right, kept);
                    },
                    .less => try self.lessValues(left, right),
                    .more => try self.moreValues(left, right),
                    else => return error.Internal,
                };
            },
            .keep_left_if_more => blk: {
                const mask = try self.moreValues(arg0, arg1);
                defer self.releaseValue(mask);
                break :blk try self.mulValues(arg0, mask);
            },
        };
    }

    fn classifyDirectCompareClosure2(bytes: []const u8) ?DenseElementwiseKind {
        if (bytes.len != 6 or bytes[5] != @intFromEnum(Op.@"return")) return null;
        const left_load: Op = std.meta.intToEnum(Op, bytes[0]) catch return null;
        const right_load: Op = std.meta.intToEnum(Op, bytes[2]) catch return null;
        if (left_load != .load_local or right_load != .load_local) return null;
        const left_slot = bytes[1];
        const right_slot = bytes[3];
        if (!((left_slot == 0 and right_slot == 1) or (left_slot == 1 and right_slot == 0))) return null;
        const cmp: Op = std.meta.intToEnum(Op, bytes[4]) catch return null;
        const op: BuiltinId = switch (cmp) {
            .less => .less,
            .more => .more,
            else => return null,
        };
        return .{ .dyad = .{
            .op = op,
            .swap = left_slot == 1,
        } };
    }

    fn directReadConditionalAtom(bytes: []const u8, idx: *usize) ?DirectConditionalAtom {
        if (idx.* >= bytes.len) return null;
        const op: Op = std.meta.intToEnum(Op, bytes[idx.*]) catch return null;
        switch (op) {
            .load_local => {
                if (idx.* + 2 > bytes.len) return null;
                const slot = bytes[idx.* + 1];
                idx.* += 2;
                return switch (slot) {
                    0 => .arg0,
                    1 => .arg1,
                    else => null,
                };
            },
            .const_int => {
                const value = directReadI64(bytes, idx.* + 1) orelse return null;
                if (value != 0) return null;
                idx.* += 9;
                return .zero;
            },
            else => return null,
        }
    }

    fn directConditionalAtomFromSlot(slot: u8) ?DirectConditionalAtom {
        return switch (slot) {
            0 => .arg0,
            1 => .arg1,
            else => null,
        };
    }

    fn directReadConditionalCompare(bytes: []const u8, idx: *usize) ?DirectConditionalCompare {
        if (idx.* >= bytes.len) return null;
        const op: Op = std.meta.intToEnum(Op, bytes[idx.*]) catch return null;
        switch (op) {
            .more_local_local, .less_local_local => {
                if (idx.* + 3 > bytes.len) return null;
                const lhs = directConditionalAtomFromSlot(bytes[idx.* + 1]) orelse return null;
                const rhs = directConditionalAtomFromSlot(bytes[idx.* + 2]) orelse return null;
                idx.* += 3;
                return .{
                    .lhs = lhs,
                    .rhs = rhs,
                    .cmp = if (op == .more_local_local) .more else .less,
                };
            },
            else => {
                const lhs = directReadConditionalAtom(bytes, idx) orelse return null;
                const rhs = directReadConditionalAtom(bytes, idx) orelse return null;
                if (idx.* >= bytes.len) return null;
                const cmp: Op = std.meta.intToEnum(Op, bytes[idx.*]) catch return null;
                if (cmp != .more and cmp != .less) return null;
                idx.* += 1;
                return .{ .lhs = lhs, .rhs = rhs, .cmp = cmp };
            },
        }
    }

    fn tryApplyDirectConditionalClosure2(self: *Session, bytes: []const u8, arg0: Value, arg1: Value) KError!?Value {
        if (bytes.len < 2 or bytes[bytes.len - 1] != @intFromEnum(Op.@"return")) return null;

        var idx: usize = 0;
        const compare = directReadConditionalCompare(bytes, &idx) orelse return null;
        if (compare.lhs != .arg0 or compare.rhs != .arg1) return null;

        if (idx + 3 > bytes.len or bytes[idx] != @intFromEnum(Op.jump_if_false)) return null;
        const false_target = directReadU16(bytes, idx + 1) orelse return null;
        idx += 3;

        const when_true = directReadConditionalAtom(bytes, &idx) orelse return null;
        if (idx + 3 > bytes.len or bytes[idx] != @intFromEnum(Op.jump)) return null;
        const end_target = directReadU16(bytes, idx + 1) orelse return null;
        idx += 3;
        if (false_target != idx) return null;

        const when_false = directReadConditionalAtom(bytes, &idx) orelse return null;
        if (end_target != idx or idx != bytes.len - 1) return null;

        return switch (when_true) {
            .arg0 => switch (when_false) {
                .arg1 => blk: {
                    const mask = switch (compare.cmp) {
                        .more => try self.moreValues(arg0, arg1),
                        .less => try self.lessValues(arg0, arg1),
                        else => unreachable,
                    };
                    defer self.releaseValue(mask);
                    const delta = try self.subValues(arg0, arg1);
                    defer self.releaseValue(delta);
                    const kept = try self.mulValues(mask, delta);
                    defer self.releaseValue(kept);
                    break :blk try self.addValues(arg1, kept);
                },
                .zero => if (compare.cmp == .more) blk: {
                    const mask = try self.moreValues(arg0, arg1);
                    defer self.releaseValue(mask);
                    break :blk try self.mulValues(arg0, mask);
                } else null,
                else => null,
            },
            else => null,
        };
    }

    fn classifyDenseConditionalClosure2(bytes: []const u8) ?DenseElementwiseKind {
        if (bytes.len < 2 or bytes[bytes.len - 1] != @intFromEnum(Op.@"return")) return null;

        var idx: usize = 0;
        const compare = directReadConditionalCompare(bytes, &idx) orelse return null;
        if (compare.lhs != .arg0 or compare.rhs != .arg1) return null;

        if (idx + 3 > bytes.len or bytes[idx] != @intFromEnum(Op.jump_if_false)) return null;
        const false_target = directReadU16(bytes, idx + 1) orelse return null;
        idx += 3;

        const when_true = directReadConditionalAtom(bytes, &idx) orelse return null;
        if (idx + 3 > bytes.len or bytes[idx] != @intFromEnum(Op.jump)) return null;
        const end_target = directReadU16(bytes, idx + 1) orelse return null;
        idx += 3;
        if (false_target != idx) return null;

        const when_false = directReadConditionalAtom(bytes, &idx) orelse return null;
        if (end_target != idx or idx != bytes.len - 1) return null;

        return switch (when_true) {
            .arg0 => switch (when_false) {
                .arg1 => switch (compare.cmp) {
                    .more => .{ .dyad = .{ .op = .maximum, .swap = false } },
                    .less => .{ .dyad = .{ .op = .minimum, .swap = false } },
                    else => null,
                },
                .zero => if (compare.cmp == .more) .keep_left_if_more else null,
                else => null,
            },
            else => null,
        };
    }

    fn isLocalReadOp(op: Op) bool {
        return op == .load_local or op == .take_local;
    }

    fn classifyDenseElementwiseClosure(closure: *const Closure) ?DenseElementwiseKind {
        if (closure.header.owner != .frozen or closure.captures.len != 0) return null;
        const bytes = closure.code.bytes;
        if (bytes.len < 2 or bytes[bytes.len - 1] != @intFromEnum(Op.@"return")) return null;

        const op: Op = std.meta.intToEnum(Op, bytes[0]) catch return null;
        switch (op) {
            .add_local_local, .sub_local_local, .mul_local_local, .minimum_local_local, .maximum_local_local, .less_local_local, .more_local_local => {
                if (bytes.len != 4) return switch (op) {
                    .less_local_local, .more_local_local => classifyDenseConditionalClosure2(bytes),
                    else => null,
                };
                const left_slot = bytes[1];
                const right_slot = bytes[2];
                if (!((left_slot == 0 and right_slot == 1) or (left_slot == 1 and right_slot == 0))) return null;
                return .{ .dyad = .{
                    .op = switch (op) {
                        .add_local_local => .add,
                        .sub_local_local => .sub,
                        .mul_local_local => .mul,
                        .minimum_local_local => .minimum,
                        .maximum_local_local => .maximum,
                        .less_local_local => .less,
                        .more_local_local => .more,
                        else => unreachable,
                    },
                    .swap = left_slot == 1,
                } };
            },
            .load_local, .take_local => {
                if (bytes.len == 6) {
                    const right_load: Op = std.meta.intToEnum(Op, bytes[2]) catch return null;
                    if (!isLocalReadOp(right_load)) return null;
                    const left_slot = bytes[1];
                    const right_slot = bytes[3];
                    if (!((left_slot == 0 and right_slot == 1) or (left_slot == 1 and right_slot == 0))) return null;
                    const dyad_op: Op = std.meta.intToEnum(Op, bytes[4]) catch return null;
                    const builtin: BuiltinId = switch (dyad_op) {
                        .add => .add,
                        .sub => .sub,
                        .mul => .mul,
                        .div => .div,
                        else => return classifyDenseConditionalClosure2(bytes),
                    };
                    return .{ .dyad = .{
                        .op = builtin,
                        .swap = left_slot == 1,
                    } };
                }
                return classifyDenseConditionalClosure2(bytes);
            },
            else => return null,
        }
    }

    fn classifyDenseElementwiseWrapperClosure(self: *Session, closure: *const Closure) KError!?DenseElementwiseKind {
        if (closure.header.owner != .frozen or closure.captures.len != 0) return null;
        const bytes = closure.code.bytes;
        if (bytes.len < 8 or bytes[bytes.len - 1] != @intFromEnum(Op.@"return")) return null;

        var idx: usize = 0;
        const base_value = blk: {
            const op: Op = std.meta.intToEnum(Op, bytes[idx]) catch return null;
            switch (op) {
                .const_builtin => {
                    if (idx + 2 > bytes.len) return null;
                    const builtin: BuiltinId = @enumFromInt(bytes[idx + 1]);
                    idx += 2;
                    break :blk Value.builtin(builtin);
                },
                .const_value => {
                    if (idx + 2 > bytes.len) return null;
                    const slot = bytes[idx + 1];
                    if (slot >= closure.code.constants.len) return null;
                    idx += 2;
                    break :blk closure.code.constants[slot];
                },
                .load_global => {
                    if (idx + 3 > bytes.len) return null;
                    const slot = directReadU16(bytes, idx + 1) orelse return null;
                    idx += 3;
                    break :blk try self.loadGlobalSlot(slot);
                },
                else => return null,
            }
        };

        if (idx + 8 != bytes.len) return null;
        if (bytes[idx] != @intFromEnum(Op.make_adverb)) return null;
        const kind: DerivedVerbKind = @enumFromInt(bytes[idx + 1]);
        if (kind != .each) return null;
        idx += 2;
        if (bytes[idx] != @intFromEnum(Op.load_local) or bytes[idx + 1] != 0) return null;
        idx += 2;
        if (bytes[idx] != @intFromEnum(Op.load_local) or bytes[idx + 1] != 1) return null;
        idx += 2;
        const call_op: Op = std.meta.intToEnum(Op, bytes[idx]) catch return null;
        if (call_op != .call2 and call_op != .tail_call2) return null;

        return try self.classifyDenseElementwiseBaseRuntime(base_value);
    }

    fn classifyDenseElementwiseClosureRuntime(self: *Session, closure: *const Closure) KError!?DenseElementwiseKind {
        if (classifyDenseElementwiseClosure(closure)) |kind| return kind;
        if (classifyDirectCompareClosure2(closure.code.bytes)) |kind| return kind;
        return try self.classifyDenseElementwiseWrapperClosure(closure);
    }

    fn classifyDenseElementwiseBaseRuntime(self: *Session, base: Value) KError!?DenseElementwiseKind {
        return switch (base.tag()) {
            .builtin => classifyDenseBuiltin(base.asBuiltin()),
            .closure => try self.classifyDenseElementwiseClosureRuntime(base.asClosure()),
            else => null,
        };
    }

    fn directReadClosureBaseValue(self: *Session, closure: *const Closure, bytes: []const u8, idx: *usize) KError!?Value {
        if (idx.* >= bytes.len) return null;
        const op: Op = std.meta.intToEnum(Op, bytes[idx.*]) catch return null;
        return switch (op) {
            .const_builtin => blk: {
                if (idx.* + 2 > bytes.len) return null;
                const builtin: BuiltinId = @enumFromInt(bytes[idx.* + 1]);
                idx.* += 2;
                break :blk Value.builtin(builtin);
            },
            .const_value => blk: {
                if (idx.* + 2 > bytes.len) return null;
                const slot = bytes[idx.* + 1];
                if (slot >= closure.code.constants.len) return null;
                idx.* += 2;
                break :blk closure.code.constants[slot];
            },
            .load_global => blk: {
                if (idx.* + 3 > bytes.len) return null;
                const slot = directReadU16(bytes, idx.* + 1) orelse return null;
                idx.* += 3;
                break :blk try self.loadGlobalSlot(slot);
            },
            else => null,
        };
    }

    fn directReadScalarValue(self: *Session, closure: *const Closure, bytes: []const u8, idx: *usize) KError!?Value {
        if (idx.* >= bytes.len) return null;
        const op: Op = std.meta.intToEnum(Op, bytes[idx.*]) catch return null;
        return switch (op) {
            .const_false => blk: {
                idx.* += 1;
                break :blk Value.fromBool(false);
            },
            .const_true => blk: {
                idx.* += 1;
                break :blk Value.fromBool(true);
            },
            .const_int => blk: {
                const value = directReadI64(bytes, idx.* + 1) orelse return null;
                idx.* += 9;
                break :blk try self.intValue(value);
            },
            .const_value, .load_global => blk: {
                const value = (try self.directReadClosureBaseValue(closure, bytes, idx)) orelse return null;
                break :blk switch (value.tag()) {
                    .int, .bool, .float => value,
                    else => null,
                };
            },
            else => null,
        };
    }

    fn directReadUnarySelfTransform(bytes: []const u8, idx: *usize) ?DirectUnarySelfTransform {
        if (idx.* + 3 > bytes.len) return null;
        if (bytes[idx.*] != @intFromEnum(Op.load_local) or bytes[idx.* + 1] != 0) return null;
        const op: Op = std.meta.intToEnum(Op, bytes[idx.* + 2]) catch return null;
        idx.* += 3;
        return switch (op) {
            .grade_up => .grade_up,
            .grade_down => .grade_down,
            else => null,
        };
    }

    fn classifyDirectUnaryLiftedClosure(self: *Session, closure: *const Closure) KError!?DirectUnaryLiftedKind {
        if (closure.header.owner != .frozen or closure.captures.len != 0) return null;
        const bytes = closure.code.bytes;
        if (bytes.len < 10 or bytes[bytes.len - 1] != @intFromEnum(Op.@"return")) return null;

        var idx: usize = 0;
        const base_value = (try self.directReadClosureBaseValue(closure, bytes, &idx)) orelse return null;
        if (idx >= bytes.len or bytes[idx] != @intFromEnum(Op.make_adverb)) return null;
        if (idx + 2 > bytes.len) return null;
        const kind: DerivedVerbKind = @enumFromInt(bytes[idx + 1]);
        if (kind != .each_right) return null;
        idx += 2;

        const transform = directReadUnarySelfTransform(bytes, &idx) orelse return null;
        const second = directReadUnarySelfTransform(bytes, &idx) orelse return null;
        if (transform != second) return null;

        if (idx + 2 != bytes.len) return null;
        const call_op: Op = std.meta.intToEnum(Op, bytes[idx]) catch return null;
        if (call_op != .call2 and call_op != .tail_call2) return null;

        _ = try self.classifyDenseElementwiseBaseRuntime(base_value) orelse return null;
        return .{ .base = base_value, .transform = transform };
    }

    fn applyDirectUnaryLiftedKind(self: *Session, kind: DirectUnaryLiftedKind, arg0: Value) KError!Value {
        const transformed = switch (kind.transform) {
            .grade_up => try self.gradeValue(arg0, true),
            .grade_down => try self.gradeValue(arg0, false),
        };
        defer self.releaseValue(transformed);
        return try self.applyEachRightDerived(kind.base, &[_]Value{ transformed, transformed });
    }

    fn directReadRowReduceBase(self: *Session, closure: *const Closure, bytes: []const u8, idx: *usize) KError!?DirectRowReduceBase {
        const base_value = (try self.directReadClosureBaseValue(closure, bytes, idx)) orelse return null;
        if (base_value.tag() == .closure) {
            const base_closure = base_value.asClosure();
            if (closureDerivedKind(base_closure) == .each and base_closure.captures.len == 1) {
                const inner = base_closure.captures[0];
                if (isDerivedBuiltinClosure(inner, .fold, .add)) return .{ .kind = .sum, .has_explicit_each = false };
                if (isDerivedBuiltinClosure(inner, .fold, .mul)) return .{ .kind = .product, .has_explicit_each = false };
                if (isDerivedBuiltinClosure(inner, .fold, .minimum)) return .{ .kind = .minimum, .has_explicit_each = false };
                if (isDerivedBuiltinClosure(inner, .fold, .maximum)) return .{ .kind = .maximum, .has_explicit_each = false };
            }
        }
        if (isDerivedBuiltinClosure(base_value, .fold, .add)) return .{ .kind = .sum, .has_explicit_each = true };
        if (isDerivedBuiltinClosure(base_value, .fold, .mul)) return .{ .kind = .product, .has_explicit_each = true };
        if (isDerivedBuiltinClosure(base_value, .fold, .minimum)) return .{ .kind = .minimum, .has_explicit_each = true };
        if (isDerivedBuiltinClosure(base_value, .fold, .maximum)) return .{ .kind = .maximum, .has_explicit_each = true };
        return null;
    }

    fn classifyDirectRowReduceClosure1(self: *Session, closure: *const Closure) KError!?DirectRowReduceKind {
        const bytes = closure.code.bytes;
        if (bytes.len < 5 or bytes[bytes.len - 1] != @intFromEnum(Op.@"return")) return null;

        var idx: usize = 0;
        const base = (try self.directReadRowReduceBase(closure, bytes, &idx)) orelse return null;
        if (base.has_explicit_each) {
            if (idx + 2 > bytes.len or
                bytes[idx] != @intFromEnum(Op.make_adverb) or
                bytes[idx + 1] != @intFromEnum(DerivedVerbKind.each)) return null;
            idx += 2;
        }

        if (idx + 4 == bytes.len and
            bytes[idx] == @intFromEnum(Op.load_local) and
            bytes[idx + 1] == 0)
        {
            const call_op: Op = std.meta.intToEnum(Op, bytes[idx + 2]) catch return null;
            if (call_op == .call1 or call_op == .tail_call1) return base.kind;
        }

        if (base.kind == .sum and idx + 9 == bytes.len and
            bytes[idx] == @intFromEnum(Op.load_local) and
            bytes[idx + 1] == 0)
        {
            const call_op: Op = std.meta.intToEnum(Op, bytes[idx + 2]) catch return null;
            if ((call_op == .call1 or call_op == .tail_call1) and
                bytes[idx + 3] == @intFromEnum(Op.load_local) and
                bytes[idx + 4] == 0 and
                bytes[idx + 5] == @intFromEnum(Op.transpose) and
                bytes[idx + 6] == @intFromEnum(Op.count) and
                bytes[idx + 7] == @intFromEnum(Op.div))
            {
                return .mean;
            }
        }

        return null;
    }

    fn directRowReduceBuiltin(kind: DirectRowReduceKind) ?BuiltinId {
        return switch (kind) {
            .sum => .add,
            .product => .mul,
            .minimum => .minimum,
            .maximum => .maximum,
            .mean => .add,
        };
    }

    fn tryApplyDirectRowReduceKind(self: *Session, kind: DirectRowReduceKind, arg0: Value) KError!?Value {
        const op = directRowReduceBuiltin(kind) orelse return null;
        const reduced = (try self.tryFastBackendMatrixRowFoldBuiltin(op, arg0)) orelse return null;
        if (kind != .mean) return reduced;

        errdefer self.releaseValue(reduced);
        const shape = valueNumericMatrixShape(arg0) orelse return null;
        const cols = try self.intValue(std.math.cast(i64, shape.cols) orelse return error.Unsupported);
        return try self.divValues(reduced, cols);
    }

    fn tryApplyDirectUnaryScaledGlobalCall1(self: *Session, closure: *const Closure, arg0: Value) KError!?Value {
        const bytes = closure.code.bytes;
        if (bytes.len < 9 or bytes[bytes.len - 1] != @intFromEnum(Op.@"return")) return null;

        var idx: usize = 0;
        if (bytes[idx] != @intFromEnum(Op.load_local) or bytes[idx + 1] != 0) return null;
        idx += 2;

        const scale = (try self.directReadScalarValue(closure, bytes, &idx)) orelse return null;

        if (idx + 5 > bytes.len) return null;
        const global_slot = blk: {
            const next_op: Op = std.meta.intToEnum(Op, bytes[idx]) catch return null;
            switch (next_op) {
                .load_local => {
                    if (bytes[idx + 1] != 0) return null;
                    idx += 2;
                    const call_op: Op = std.meta.intToEnum(Op, bytes[idx]) catch return null;
                    switch (call_op) {
                        .call_global1, .tail_call_global1 => {
                            if (idx + 3 > bytes.len) return null;
                            const slot = directReadU16(bytes, idx + 1) orelse return null;
                            idx += 3;
                            break :blk slot;
                        },
                        .call_global_slots, .tail_call_global_slots => {
                            if (idx + 6 > bytes.len) return null;
                            const slot = directReadU16(bytes, idx + 1) orelse return null;
                            if (bytes[idx + 3] != 1) return null;
                            const arg_kind = bytes[idx + 4] & ~global_call_arg_consume_bit;
                            if (arg_kind != @intFromEnum(GlobalCallArgKind.local) or bytes[idx + 5] != 0) return null;
                            idx += 6;
                            break :blk slot;
                        },
                        .index_global_source, .tail_index_global_source => {
                            if (idx + 5 > bytes.len) return null;
                            const slot = directReadU16(bytes, idx + 1) orelse return null;
                            const arg_kind = bytes[idx + 3] & ~global_call_arg_consume_bit;
                            if (arg_kind != @intFromEnum(GlobalCallArgKind.local) or bytes[idx + 4] != 0) return null;
                            idx += 5;
                            break :blk slot;
                        },
                        else => return null,
                    }
                },
                .call_global1, .tail_call_global1 => {
                    if (idx + 3 > bytes.len) return null;
                    const slot = directReadU16(bytes, idx + 1) orelse return null;
                    idx += 3;
                    break :blk slot;
                },
                .call_global_slots, .tail_call_global_slots => {
                    if (idx + 6 > bytes.len) return null;
                    const slot = directReadU16(bytes, idx + 1) orelse return null;
                    if (bytes[idx + 3] != 1) return null;
                    const arg_kind = bytes[idx + 4] & ~global_call_arg_consume_bit;
                    if (arg_kind != @intFromEnum(GlobalCallArgKind.local) or bytes[idx + 5] != 0) return null;
                    idx += 6;
                    break :blk slot;
                },
                .index_global_source, .tail_index_global_source => {
                    if (idx + 5 > bytes.len) return null;
                    const slot = directReadU16(bytes, idx + 1) orelse return null;
                    const arg_kind = bytes[idx + 3] & ~global_call_arg_consume_bit;
                    if (arg_kind != @intFromEnum(GlobalCallArgKind.local) or bytes[idx + 4] != 0) return null;
                    idx += 5;
                    break :blk slot;
                },
                else => return null,
            }
        };
        if (idx + 3 != bytes.len) return null;

        const mul_op: Op = std.meta.intToEnum(Op, bytes[idx]) catch return null;
        if (mul_op != .mul) return null;
        idx += 1;

        const final_op: Op = std.meta.intToEnum(Op, bytes[idx]) catch return null;
        if (final_op != .add and final_op != .sub) return null;

        const called = (try self.tryApplyDirectGlobalCall1(global_slot, arg0)) orelse return null;
        defer self.releaseValue(called);
        const scaled = try self.mulValues(scale, called);
        defer self.releaseValue(scaled);
        return switch (final_op) {
            .add => try self.addValues(arg0, scaled),
            .sub => try self.subValues(arg0, scaled),
            else => unreachable,
        };
    }

    fn tryApplyDirectGlobalCall1(self: *Session, slot: u16, arg0: Value) KError!?Value {
        const callee = try self.loadGlobalSlot(slot);
        return switch (callee.tag()) {
            .builtin => try self.applyBuiltinCall(callee.asBuiltin(), &[_]Value{arg0}),
            .closure => blk: {
                const closure = callee.asClosure();
                if (closure.code.arity == 1) {
                    if (try self.tryApplyDirectClosure1(closure, arg0)) |result| break :blk result;
                }
                if (try self.applyDerivedClosure(closure, &[_]Value{arg0})) |result| break :blk result;
                if (closure.code.arity != 1) return error.Arity;
                break :blk null;
            },
            .array => try self.applyArrayCall1(callee, arg0),
            else => error.Type,
        };
    }

    fn tryApplyDirectGlobalCall2(self: *Session, slot: u16, arg0: Value, arg1: Value) KError!?Value {
        const callee = try self.loadGlobalSlot(slot);
        return switch (callee.tag()) {
            .builtin => try self.applyBuiltinCall(callee.asBuiltin(), &[_]Value{ arg0, arg1 }),
            .closure => blk: {
                const closure = callee.asClosure();
                if (try self.tryApplyDirectDerivedClosure2(closure, arg0, arg1)) |result| break :blk result;
                if (try self.applyDerivedClosure(closure, &[_]Value{ arg0, arg1 })) |result| break :blk result;
                if (closure.code.arity != 2) return error.Arity;
                break :blk try self.tryApplyDirectClosure2(closure, arg0, arg1);
            },
            .array => error.Arity,
            else => error.Type,
        };
    }

    fn tryApplyDirectClosure1(self: *Session, closure: *const Closure, arg0: Value) KError!?Value {
        if (closure.kind != .plain) return null;
        if (closure.header.owner != .frozen) {
            if (self.debugDetailedProbeActive()) self.debug_direct_closure_miss_not_frozen_count += 1;
            return null;
        }
        if (closure.captures.len != 0) {
            if (self.debugDetailedProbeActive()) self.debug_direct_closure_miss_captures_count += 1;
            return null;
        }
        if ((closure.code.direct_closure_mask & directClosureMaskBit(1)) == 0) {
            if (self.debugDetailedProbeActive()) self.debug_direct_closure_miss_unsupported_shape_count += 1;
            return null;
        }
        const bytes = closure.code.bytes;
        if (bytes.len < 2 or bytes[bytes.len - 1] != @intFromEnum(Op.@"return")) {
            if (self.debugDetailedProbeActive()) self.debug_direct_closure_miss_unsupported_shape_count += 1;
            return null;
        }
        const op: Op = std.meta.intToEnum(Op, bytes[0]) catch return null;
        var result: ?Value = switch (op) {
            .load_local => blk: {
                if (bytes.len != 4 or bytes[1] != 0 or bytes[2] != @intFromEnum(Op.argmax)) break :blk null;
                break :blk try self.argmaxValue(arg0);
            },
            .neg_local => blk: {
                if (bytes.len != 3 or bytes[1] != 0) break :blk null;
                break :blk try self.negateValue(arg0);
            },
            .sqrt_local => blk: {
                if (bytes.len != 3 or bytes[1] != 0) break :blk null;
                break :blk try self.sqrtValue(arg0);
            },
            .add_local_const, .sub_local_const, .mul_local_const, .minimum_local_const, .maximum_local_const, .less_local_const, .more_local_const, .equal_local_const => blk: {
                if (bytes.len != 11 or bytes[1] != 0) break :blk null;
                const rhs = directReadI64(bytes, 2) orelse break :blk null;
                const right = try self.intValue(rhs);
                defer self.releaseValue(right);
                break :blk switch (op) {
                    .add_local_const => try self.applyShapedBorrowedDyadValue(.add, arg0, right),
                    .sub_local_const => try self.applyShapedBorrowedDyadValue(.sub, arg0, right),
                    .mul_local_const => try self.applyShapedBorrowedDyadValue(.mul, arg0, right),
                    .minimum_local_const => try self.applyShapedBorrowedDyadValue(.minimum, arg0, right),
                    .maximum_local_const => try self.applyShapedBorrowedDyadValue(.maximum, arg0, right),
                    .less_local_const => try self.applyShapedBorrowedDyadValue(.less, arg0, right),
                    .more_local_const => try self.applyShapedBorrowedDyadValue(.more, arg0, right),
                    .equal_local_const => try self.applyShapedBorrowedDyadValue(.equal, arg0, right),
                    else => unreachable,
                };
            },
            .add_const_local, .sub_const_local, .mul_const_local, .minimum_const_local, .maximum_const_local, .less_const_local, .more_const_local, .equal_const_local => blk: {
                if (bytes.len != 11 or bytes[9] != 0) break :blk null;
                const lhs = directReadI64(bytes, 1) orelse break :blk null;
                const left = try self.intValue(lhs);
                defer self.releaseValue(left);
                break :blk switch (op) {
                    .add_const_local => try self.applyShapedBorrowedDyadValue(.add, left, arg0),
                    .sub_const_local => try self.applyShapedBorrowedDyadValue(.sub, left, arg0),
                    .mul_const_local => try self.applyShapedBorrowedDyadValue(.mul, left, arg0),
                    .minimum_const_local => try self.applyShapedBorrowedDyadValue(.minimum, left, arg0),
                    .maximum_const_local => try self.applyShapedBorrowedDyadValue(.maximum, left, arg0),
                    .less_const_local => try self.applyShapedBorrowedDyadValue(.less, left, arg0),
                    .more_const_local => try self.applyShapedBorrowedDyadValue(.more, left, arg0),
                    .equal_const_local => try self.applyShapedBorrowedDyadValue(.equal, left, arg0),
                    else => unreachable,
                };
            },
            .tail_call_global1 => blk: {
                if (bytes.len != 4) break :blk null;
                const slot = directReadU16(bytes, 1) orelse break :blk null;
                break :blk try self.tryApplyDirectGlobalCall1(slot, arg0);
            },
            .tail_index_global_source => blk: {
                if (bytes.len != 6) break :blk null;
                const slot = directReadU16(bytes, 1) orelse break :blk null;
                const arg_kind = bytes[3] & ~global_call_arg_consume_bit;
                if (arg_kind != @intFromEnum(GlobalCallArgKind.local) or bytes[4] != 0) break :blk null;
                break :blk try self.tryApplyDirectGlobalCall1(slot, arg0);
            },
            else => null,
        };
        if (result == null) {
            if (try self.classifyDirectRowReduceClosure1(closure)) |kind| {
                result = try self.tryApplyDirectRowReduceKind(kind, arg0);
            }
        }
        if (result == null) {
            result = try self.tryApplyDirectUnaryScaledGlobalCall1(closure, arg0);
        }
        if (result == null) {
            if (try self.classifyDirectUnaryLiftedClosure(closure)) |kind| {
                result = try self.applyDirectUnaryLiftedKind(kind, arg0);
            }
        }
        if (self.debugDetailedProbeActive()) {
            if (result != null) self.debug_direct_closure1_hit_count += 1 else self.debug_direct_closure_miss_unsupported_shape_count += 1;
        }
        return result;
    }

    fn tryApplyDirectClosure2(self: *Session, closure: *const Closure, arg0: Value, arg1: Value) KError!?Value {
        if (closure.kind != .plain) return null;
        if (closure.header.owner != .frozen) {
            if (self.debugDetailedProbeActive()) self.debug_direct_closure_miss_not_frozen_count += 1;
            return null;
        }
        if (closure.captures.len != 0) {
            if (self.debugDetailedProbeActive()) self.debug_direct_closure_miss_captures_count += 1;
            return null;
        }
        if ((closure.code.direct_closure_mask & directClosureMaskBit(2)) == 0) {
            if (self.debugDetailedProbeActive()) self.debug_direct_closure_miss_unsupported_shape_count += 1;
            return null;
        }
        const bytes = closure.code.bytes;
        if (bytes.len < 2 or bytes[bytes.len - 1] != @intFromEnum(Op.@"return")) {
            if (self.debugDetailedProbeActive()) self.debug_direct_closure_miss_unsupported_shape_count += 1;
            return null;
        }
        const op: Op = std.meta.intToEnum(Op, bytes[0]) catch return null;
        var result: ?Value = switch (op) {
            .add_local_local, .sub_local_local, .mul_local_local, .minimum_local_local, .maximum_local_local, .less_local_local, .more_local_local, .equal_local_local => blk: {
                if (bytes.len != 4) break :blk null;
                const left = directBinaryArg(arg0, arg1, bytes[1]) orelse break :blk null;
                const right = directBinaryArg(arg0, arg1, bytes[2]) orelse break :blk null;
                break :blk switch (op) {
                    .add_local_local => try self.applyShapedBorrowedDyadValue(.add, left, right),
                    .sub_local_local => try self.applyShapedBorrowedDyadValue(.sub, left, right),
                    .mul_local_local => try self.applyShapedBorrowedDyadValue(.mul, left, right),
                    .minimum_local_local => try self.applyShapedBorrowedDyadValue(.minimum, left, right),
                    .maximum_local_local => try self.applyShapedBorrowedDyadValue(.maximum, left, right),
                    .less_local_local => try self.applyShapedBorrowedDyadValue(.less, left, right),
                    .more_local_local => try self.applyShapedBorrowedDyadValue(.more, left, right),
                    .equal_local_local => try self.applyShapedBorrowedDyadValue(.equal, left, right),
                    else => unreachable,
                };
            },
            .tail_call_global2 => blk: {
                if (bytes.len != 4) break :blk null;
                const slot = directReadU16(bytes, 1) orelse break :blk null;
                break :blk try self.tryApplyDirectGlobalCall2(slot, arg0, arg1);
            },
            else => null,
        };
        if (result == null and (op == .load_local or op == .more_local_local or op == .less_local_local)) {
            result = try self.tryApplyDirectConditionalClosure2(bytes, arg0, arg1);
            if (result == null) {
                if (classifyDirectCompareClosure2(bytes)) |kind| {
                    result = try self.applyDenseElementwiseKind(kind, arg0, arg1);
                }
            }
        }
        if (self.debugDetailedProbeActive()) {
            if (result != null) self.debug_direct_closure2_hit_count += 1 else self.debug_direct_closure_miss_unsupported_shape_count += 1;
        }
        return result;
    }

    fn tryApplyDirectClosure3(self: *Session, closure: *const Closure, arg0: Value, arg1: Value, arg2: Value) KError!?Value {
        if (closure.kind != .plain) return null;
        if (closure.header.owner != .frozen) {
            if (self.debugDetailedProbeActive()) self.debug_direct_closure_miss_not_frozen_count += 1;
            return null;
        }
        if (closure.captures.len != 0) {
            if (self.debugDetailedProbeActive()) self.debug_direct_closure_miss_captures_count += 1;
            return null;
        }
        if ((closure.code.direct_closure_mask & directClosureMaskBit(3)) == 0) {
            if (self.debugDetailedProbeActive()) self.debug_direct_closure_miss_unsupported_shape_count += 1;
            return null;
        }
        const bytes = closure.code.bytes;
        if (bytes.len < 2 or bytes[bytes.len - 1] != @intFromEnum(Op.@"return")) {
            if (self.debugDetailedProbeActive()) self.debug_direct_closure_miss_unsupported_shape_count += 1;
            return null;
        }
        const op: Op = std.meta.intToEnum(Op, bytes[0]) catch return null;
        const result: ?Value = switch (op) {
            .add_local_local => blk: {
                if (bytes.len != 7 or bytes[1] != 0 or bytes[2] != 1) break :blk null;
                if (bytes[3] != @intFromEnum(Op.load_local) or bytes[4] != 2 or bytes[5] != @intFromEnum(Op.add)) break :blk null;
                const tmp = try self.addValues(arg0, arg1);
                defer self.releaseValue(tmp);
                break :blk try self.addValues(tmp, arg2);
            },
            else => null,
        };
        if (self.debugDetailedProbeActive()) {
            if (result != null) self.debug_direct_closure3_hit_count += 1 else self.debug_direct_closure_miss_unsupported_shape_count += 1;
        }
        return result;
    }

    fn hostStringListItemValue(self: *Session, list: *const HostStringList, idx: usize) KError!Value {
        if (idx >= list.len) return error.Type;
        if (comptime enable_probe_instrumentation) self.debug_host_string_list_item_value_count += 1;
        return switch (list.storage) {
            .eager => |items| switch (items[idx]) {
                .owned => |text| blk: {
                    if (comptime enable_probe_instrumentation) self.debug_host_string_list_item_eager_owned_count += 1;
                    break :blk try self.retainEscapedValue(Value.array(text));
                },
                .view => |view| blk: {
                    if (comptime enable_probe_instrumentation) self.debug_host_string_list_item_eager_view_count += 1;
                    const base = list.base orelse return error.Internal;
                    break :blk try self.managedHostStringViewWithReason(base, view, .string_list_eager_view);
                },
            },
            .split_scalar => |lazy| blk: {
                if (comptime enable_probe_instrumentation) self.debug_host_string_list_item_split_scalar_count += 1;
                const base = list.base orelse return error.Internal;
                const src = hostTextBytes(base);
                var piece_idx: usize = 0;
                var start: usize = 0;
                var scanned_bytes: usize = 0;
                var scanned_seps: usize = 0;
                while (std.mem.indexOfScalarPos(u8, src, start, lazy.sep)) |sep_idx| {
                    scanned_bytes += sep_idx - start + 1;
                    scanned_seps += 1;
                    if (piece_idx == idx) {
                        if (comptime enable_probe_instrumentation) {
                            self.debug_host_string_list_item_split_scalar_scan_byte_count += scanned_bytes;
                            self.debug_host_string_list_item_split_scalar_scan_sep_count += scanned_seps;
                        }
                        break :blk try self.managedHostStringViewWithReason(base, .{
                            .start = start,
                            .len = sep_idx - start,
                        }, .string_list_split_scalar);
                    }
                    piece_idx += 1;
                    start = sep_idx + 1;
                }
                if (piece_idx != idx) return error.Type;
                scanned_bytes += src.len - start;
                if (comptime enable_probe_instrumentation) {
                    self.debug_host_string_list_item_split_scalar_scan_byte_count += scanned_bytes;
                    self.debug_host_string_list_item_split_scalar_scan_sep_count += scanned_seps;
                }
                break :blk try self.managedHostStringViewWithReason(base, .{
                    .start = start,
                    .len = src.len - start,
                }, .string_list_split_scalar);
            },
        };
    }

    fn derivedSequenceLen(value: Value) ?usize {
        if (value.tag() != .array) return null;
        if (value.arrayKind() == .host_keyed_store) return null;
        if (valueNumericHandle(value)) |handle| {
            if (handle.rank == 0) return null;
            return @intCast(handle.shape[0]);
        }
        if (numericVectorLen(value)) |len| return len;
        if (value.arraySubkind() == .host_string_list) return value.asHostStringList().len;
        if (value.arraySubkind() == .host_boxed_array) {
            return value.asHostBoxedArray().len();
        }
        return null;
    }

    fn derivedSequenceItemValue(self: *Session, value: Value, idx: usize) KError!Value {
        if (value.tag() != .array) return error.Type;
        if (value.arrayKind() == .host_keyed_store) return error.Type;
        if (valueNumericHandle(value)) |handle| {
            if (handle.rank > 1) {
                return (try numericValueScalarIndexValue(self, value, @intCast(idx))) orelse error.Type;
            }
        }
        if (valueNumericMatrixShape(value) != null) {
            return (try numericValueScalarIndexValue(self, value, @intCast(idx))) orelse error.Type;
        }
        if (numericVectorLen(value) != null) {
            return try self.derivedDenseVectorItemValue(value, idx);
        }
        if (value.arraySubkind() == .host_string_list) {
            return try self.hostStringListItemValue(value.asHostStringList(), idx);
        }
        if (value.arraySubkind() == .host_boxed_array) {
            return try self.hostBoxedArrayIndexScalar(value.asHostBoxedArray(), @intCast(idx));
        }
        return error.Type;
    }

    fn derivedDenseVectorItemValue(self: *Session, value: Value, idx: usize) KError!Value {
        const view = try hostDenseView(self, value);
        return switch (valueNumericMode(value) orelse return error.Type) {
            .int => switch (view) {
                .scalar_int => |item| blk: {
                    if (idx != 0) return error.Internal;
                    break :blk try self.intValue(item);
                },
                .int_array => |items| try self.intValue(try hostIntDenseViewItem(items, idx)),
                else => error.Type,
            },
            .float => switch (view) {
                .scalar_float => |item| blk: {
                    if (idx != 0) return error.Internal;
                    break :blk try self.floatValue(item);
                },
                .float_array => |items| try self.floatValue(try hostFloatDenseViewItem(items, idx)),
                else => error.Type,
            },
        };
    }

    fn releaseDerivedStepArgs(self: *Session, source_args: []const Value, step_args: []const Value, start_idx: usize) void {
        for (source_args[start_idx..], start_idx..) |arg, arg_idx| {
            if (derivedSequenceLen(arg) != null) self.releaseValue(step_args[arg_idx]);
        }
    }

    fn createManagedArrayLikeFromValues(self: *Session, values: []const Value) KError!Value {
        return try self.makeArrayFromValues(values);
    }

    fn nextSamplingProfileCodeId(self: *Session) u16 {
        if (comptime !enable_sampling_profile) {
            return sampling_profile_no_code;
        }
        if (self.next_profile_code_id >= sampling_profile_max_code_count) return sampling_profile_no_code;
        const id = self.next_profile_code_id;
        self.next_profile_code_id += 1;
        return id;
    }

    fn rememberSamplingProfileCodeInfo(self: *Session, id: u16, kind: SamplingProfileCodeKind, source: []const u8) void {
        if (comptime !enable_sampling_profile) {
            return;
        }
        if (id == sampling_profile_no_code) return;
        if (staticSamplingProfileCodeInfo(id) != null) return;
        if (id >= self.profile_dynamic_code_used.len) return;
        self.profile_dynamic_code_infos[id] = .{
            .id = id,
            .kind = kind,
            .source = source,
        };
        self.profile_dynamic_code_used[id] = true;
    }

    fn invokeValueInCurrentRun(self: *Session, callee: Value, args: []const Value) KError!Value {
        const call_base = self.stack_len;
        const prior_frame_len = self.frame_len;

        try self.push(self.retainValue(callee));
        for (args) |arg| try self.push(self.retainValue(arg));

        switch (args.len) {
            1 => try self.execCall1(),
            2 => try self.execCall2(),
            else => {
                const argc = std.math.cast(u8, args.len) orelse return error.Unsupported;
                try self.execCall(argc);
            },
        }

        if (self.frame_len > prior_frame_len) {
            if (try self.runFramesUntil(prior_frame_len)) |final| return final;
        }

        if (self.stack_len != call_base + 1) return error.Internal;
        return self.pop();
    }

    fn invokeClosureInCurrentRun(self: *Session, callee: Value, closure: *const Closure, args: []const Value) KError!Value {
        if (closure.code.arity != args.len) return error.Arity;

        const call_base = self.stack_len;
        const prior_frame_len = self.frame_len;

        try self.pushRetainedClosureArgs(callee, closure, sampling_profile_no_callable_slot, args, .stack);

        if (self.frame_len > prior_frame_len) {
            if (try self.runFramesUntil(prior_frame_len)) |final| return final;
        }

        if (self.stack_len != call_base + 1) return error.Internal;
        return self.pop();
    }

    fn applyDerivedBase(self: *Session, callee: Value, args: []const Value) KError!Value {
        return switch (callee.tag()) {
            .builtin => try self.applyBuiltinCall(callee.asBuiltin(), args),
            .array => try self.applyArrayCall(callee, args),
            .closure => blk: {
                const closure = callee.asClosure();
                if (try self.tryApplyOwnedClosureArgs(closure, args)) |result| break :blk result;
                break :blk try self.invokeClosureInCurrentRun(callee, closure, args);
            },
            else => error.Type,
        };
    }

    fn projectionInfoFromClosure(self: *Session, closure: *const Closure) KError!?ProjectionInfo {
        _ = self;
        if (!closureIsProjection(closure)) return null;
        if (closure.captures.len < 3) return error.Internal;
        const slot_count_i64 = scalarIntLikeValue(closure.captures[1]) orelse return error.Internal;
        const hole_mask_i64 = scalarIntLikeValue(closure.captures[2]) orelse return error.Internal;
        if (slot_count_i64 < 0) return error.Internal;
        const slot_count = std.math.cast(usize, slot_count_i64) orelse return error.Internal;
        if (slot_count > 63) return error.Unsupported;
        const hole_mask = std.math.cast(u64, hole_mask_i64) orelse return error.Internal;
        if ((hole_mask >> @intCast(slot_count)) != 0) return error.Internal;
        if (closure.captures.len != 3 + slot_count) return error.Internal;
        return .{
            .callee = closure.captures[0],
            .slot_count = slot_count,
            .hole_mask = hole_mask,
            .slot_values = closure.captures[3..],
        };
    }

    fn innerProductInfoFromClosure(self: *Session, closure: *const Closure) KError!?InnerProductInfo {
        _ = self;
        if (!closureIsInnerProduct(closure)) return null;
        if (closure.captures.len != 2) return error.Internal;
        if (closure.captures[0].tag() != .builtin or closure.captures[1].tag() != .builtin) return error.Internal;
        return .{
            .reduce = closure.captures[0].asBuiltin(),
            .map = closure.captures[1].asBuiltin(),
        };
    }

    fn tryApplyDirectDerivedClosure2(self: *Session, closure: *const Closure, arg0: Value, arg1: Value) KError!?Value {
        if (try self.innerProductInfoFromClosure(closure)) |info| {
            if (info.reduce != .add or info.map != .mul) return null;
            if (self.debugDetailedProbeActive()) self.debug_direct_closure2_hit_count += 1;
            return try self.applyMatmulValues(arg0, arg1);
        }

        const kind = closureDerivedKind(closure) orelse return null;
        if (kind != .each_left or closure.captures.len != 1) return null;
        const base = closure.captures[0];
        if (base.tag() != .closure) return null;
        const base_info = (try self.innerProductInfoFromClosure(base.asClosure())) orelse return null;
        if (base_info.reduce != .add or base_info.map != .mul) return null;
        if (!valueIsRenderableMatrixLike(arg0)) return null;
        if (self.debugDetailedProbeActive()) self.debug_direct_closure2_hit_count += 1;
        return try self.applyMatmulValues(arg0, arg1);
    }

    fn materializeSequenceItems(self: *Session, value: Value) KError![]Value {
        var items = std.ArrayList(Value).empty;
        errdefer {
            for (items.items) |item| self.releaseValue(item);
            items.deinit(self.allocator);
        }

        if (derivedSequenceLen(value)) |len| {
            try items.ensureTotalCapacity(self.allocator, len);
            for (0..len) |idx| try items.append(self.allocator, try self.derivedSequenceItemValue(value, idx));
        } else {
            try items.append(self.allocator, try self.retainEscapedValue(value));
        }

        return try items.toOwnedSlice(self.allocator);
    }

    fn deepIndexValue(self: *Session, base: Value, selectors: []const Value) KError!Value {
        if (selectors.len == 0) return self.shareValue(base);
        var current = try self.applyArrayCall1(base, selectors[0]);
        var idx: usize = 1;
        while (idx < selectors.len) : (idx += 1) {
            const next = try self.applyArrayCall1(current, selectors[idx]);
            self.releaseValue(current);
            current = next;
        }
        return current;
    }

    const AmendKind = enum {
        unary,
        assign,
        binary,
        deep_unary,
        deep_assign,
        deep_binary,
    };

    const IndexedAssignTarget = union(enum) {
        global: u16,
        local: u8,
        inline_local: u8,
    };

    fn applyAmend(self: *Session, base: Value, selector: Value, kind: AmendKind, func_or_value: Value, arg: Value) KError!Value {
        return switch (kind) {
            .unary => try self.applyShallowAmend(base, selector, .unary, func_or_value, arg),
            .assign => try self.applyShallowAmend(base, selector, .assign, func_or_value, arg),
            .binary => try self.applyShallowAmend(base, selector, .binary, func_or_value, arg),
            .deep_unary, .deep_assign, .deep_binary => blk: {
                const mode: ShallowAmendMode = switch (kind) {
                    .deep_unary => .unary,
                    .deep_assign => .assign,
                    .deep_binary => .binary,
                    else => unreachable,
                };
                const selectors = try self.materializeSelectorPath(selector);
                defer self.releaseArgs(selectors);
                break :blk try self.applyDeepAmend(base, selectors, mode, func_or_value, arg);
            },
        };
    }

    fn applyAmendOwned(self: *Session, base: Value, selector: Value, kind: AmendKind, func_or_value: Value, arg: Value) KError!Value {
        if (comptime enable_probe_instrumentation) self.debug_owned_amend_count += 1;
        errdefer self.releaseCanonicalManagedNumericValue(base);
        const result = try self.applyAmend(base, selector, kind, func_or_value, arg);
        self.releaseCanonicalManagedNumericValue(base);
        return result;
    }

    const ShallowAmendMode = enum {
        unary,
        assign,
        binary,
    };

    fn materializeSelectorPath(self: *Session, selector: Value) KError![]Value {
        var items = std.ArrayList(Value).empty;
        errdefer {
            for (items.items) |value| self.releaseValue(value);
            items.deinit(self.allocator);
        }

        switch (selector.tag()) {
            .int, .bool => {
                try items.append(self.allocator, try self.retainEscapedValue(selector));
            },
            .array => if (boxedArrayItems(selector)) |boxed| {
                for (boxed) |value| try items.append(self.allocator, try self.retainEscapedValue(value));
            } else switch (selector.arrayKind()) {
                .host_dense_array, .backend_array, .numeric_array => {
                    const array = try numericHostArrayValue(self, selector);
                    const len = array.len();
                    for (0..len) |idx| {
                        try items.append(self.allocator, try self.hostDenseIndexScalar(array, @intCast(idx)));
                    }
                },
                else => return error.Type,
            },
            else => return error.Type,
        }

        return try items.toOwnedSlice(self.allocator);
    }

    fn applyDeepAmend(self: *Session, base: Value, selectors: []const Value, mode: ShallowAmendMode, func_or_value: Value, arg: Value) KError!Value {
        if (selectors.len == 0) return error.Type;
        if (selectors.len == 1) return try self.applyShallowAmend(base, selectors[0], mode, func_or_value, arg);

        const selected = try self.applyArrayCall1(base, selectors[0]);
        defer self.releaseValue(selected);
        const amended = try self.applyDeepAmend(selected, selectors[1..], mode, func_or_value, arg);
        defer self.releaseValue(amended);
        return try self.applyShallowAmend(base, selectors[0], .assign, amended, Value.fromBool(false));
    }

    const DenseAssignRhs = union(enum) {
        int_scalar: i64,
        float_scalar: f64,
        int_vector: HostIntArrayView,
        float_vector: []const f64,
    };

    const DenseAssignTargets = union(enum) {
        scalar: usize,
        slice: []const usize,
    };

    fn amendCloneOwner(base: Value) HeapOwner {
        std.debug.assert(base.tag() == .array);
        return switch (base.arrayOwner()) {
            .scratch => .scratch,
            .managed, .frozen => .managed,
        };
    }

    fn hostIntKindCanRepresent(kind: HostIntStorageKind, value: i64) bool {
        return switch (kind) {
            .bit => value == 0 or value == 1,
            .int8 => std.math.cast(i8, value) != null,
            .int16 => std.math.cast(i16, value) != null,
            .int32 => std.math.cast(i32, value) != null,
            .int64 => true,
        };
    }

    fn denseAssignRhs(self: *Session, rhs_source: Value, selectors_len: usize) KError!?DenseAssignRhs {
        if (scalarIntLikeValue(rhs_source)) |value| return .{ .int_scalar = value };
        if (rhs_source.tag() == .float) return .{ .float_scalar = rhs_source.asFloat() };
        if (rhs_source.tag() != .array) return null;
        if (valueNonVectorNumericShape(rhs_source) != null) return null;
        const rhs_array = try numericHostArrayValue(self, rhs_source);
        if (rhs_array.len() != selectors_len) return null;
        return switch (hostDenseNumericMode(rhs_array)) {
            .int => .{ .int_vector = hostIntArrayView(rhs_array) orelse return null },
            .float => .{ .float_vector = rhs_array.storage.float64 },
        };
    }

    fn denseAssignRhsFitsIntKind(kind: HostIntStorageKind, selectors_len: usize, rhs: DenseAssignRhs) bool {
        return switch (rhs) {
            .int_scalar => |value| hostIntKindCanRepresent(kind, value),
            .float_scalar => |value| blk: {
                const int_value = exactIntFromFloat(value) orelse break :blk false;
                break :blk hostIntKindCanRepresent(kind, int_value);
            },
            .int_vector => |view| blk: {
                std.debug.assert(hostIntArrayViewLen(view) == selectors_len);
                for (0..selectors_len) |idx| {
                    if (!hostIntKindCanRepresent(kind, hostIntViewItem(view, idx))) break :blk false;
                }
                break :blk true;
            },
            .float_vector => |items| blk: {
                std.debug.assert(items.len == selectors_len);
                for (items) |item| {
                    const int_value = exactIntFromFloat(item) orelse break :blk false;
                    if (!hostIntKindCanRepresent(kind, int_value)) break :blk false;
                }
                break :blk true;
            },
        };
    }

    fn denseAssignTargetsLen(targets: DenseAssignTargets) usize {
        return switch (targets) {
            .scalar => 1,
            .slice => |selectors| selectors.len,
        };
    }

    fn recordFastDenseAssignHit(self: *Session, targets: DenseAssignTargets, rhs: DenseAssignRhs, reused: bool) void {
        if (comptime !enable_probe_instrumentation) return;
        self.debug_fast_dense_assign_hit_count += 1;
        if (reused) self.debug_fast_dense_assign_reuse_count += 1;
        self.debug_fast_dense_assign_target_element_count += denseAssignTargetsLen(targets);
        switch (targets) {
            .scalar => self.debug_fast_dense_assign_scalar_target_count += 1,
            .slice => self.debug_fast_dense_assign_vector_target_count += 1,
        }
        switch (rhs) {
            .int_scalar, .float_scalar => self.debug_fast_dense_assign_scalar_rhs_count += 1,
            .int_vector, .float_vector => self.debug_fast_dense_assign_vector_rhs_count += 1,
        }
    }

    fn denseAssignIntScalarValue(rhs: DenseAssignRhs) KError!i64 {
        return switch (rhs) {
            .int_scalar => |value| value,
            .float_scalar => |value| exactIntFromFloat(value) orelse return error.Unsupported,
            .int_vector => |view| blk: {
                std.debug.assert(hostIntArrayViewLen(view) == 1);
                break :blk hostIntViewItem(view, 0);
            },
            .float_vector => |items| blk: {
                std.debug.assert(items.len == 1);
                break :blk exactIntFromFloat(items[0]) orelse return error.Unsupported;
            },
        };
    }

    fn denseAssignFloatScalarValue(rhs: DenseAssignRhs) f64 {
        return switch (rhs) {
            .int_scalar => |value| @as(f64, @floatFromInt(value)),
            .float_scalar => |value| value,
            .int_vector => |view| blk: {
                std.debug.assert(hostIntArrayViewLen(view) == 1);
                break :blk @as(f64, @floatFromInt(hostIntViewItem(view, 0)));
            },
            .float_vector => |items| blk: {
                std.debug.assert(items.len == 1);
                break :blk items[0];
            },
        };
    }

    fn denseAssignScalarIntLike(rhs_source: Value) ?i64 {
        if (scalarIntLikeValue(rhs_source)) |value| return value;
        if (rhs_source.tag() == .float) return exactIntFromFloat(rhs_source.asFloat());
        return null;
    }

    fn denseAssignScalarFloatLike(rhs_source: Value) ?f64 {
        if (scalarIntLikeValue(rhs_source)) |value| return @floatFromInt(value);
        if (rhs_source.tag() == .float) return rhs_source.asFloat();
        return null;
    }

    fn applyDenseAssignIntScalar(out: *HostIntResult, target_idx: usize, item_value: i64) KError!void {
        switch (out.*) {
            .bit => |*bits| switch (item_value) {
                0 => bitSet(bits.words, target_idx, false),
                1 => bitSet(bits.words, target_idx, true),
                else => return error.Unsupported,
            },
            .int8 => |*items| items.items[target_idx] = std.math.cast(i8, item_value) orelse return error.Unsupported,
            .int16 => |*items| items.items[target_idx] = std.math.cast(i16, item_value) orelse return error.Unsupported,
            .int32 => |*items| items.items[target_idx] = std.math.cast(i32, item_value) orelse return error.Unsupported,
            .int64 => |*items| items.items[target_idx] = item_value,
        }
    }

    fn applyDenseAssignIntRhs(out: *HostIntResult, targets: DenseAssignTargets, rhs: DenseAssignRhs) KError!void {
        switch (targets) {
            .scalar => |target_idx| try applyDenseAssignIntScalar(out, target_idx, try denseAssignIntScalarValue(rhs)),
            .slice => |selectors| switch (rhs) {
                .int_scalar => |value| {
                    for (selectors) |target_idx| try applyDenseAssignIntScalar(out, target_idx, value);
                },
                .float_scalar => |value| {
                    const int_value = exactIntFromFloat(value) orelse return error.Unsupported;
                    for (selectors) |target_idx| try applyDenseAssignIntScalar(out, target_idx, int_value);
                },
                .int_vector => |view| {
                    std.debug.assert(hostIntArrayViewLen(view) == selectors.len);
                    for (selectors, 0..) |target_idx, idx| try applyDenseAssignIntScalar(out, target_idx, hostIntViewItem(view, idx));
                },
                .float_vector => |items| {
                    std.debug.assert(items.len == selectors.len);
                    for (selectors, 0..) |target_idx, idx| {
                        const int_value = exactIntFromFloat(items[idx]) orelse return error.Unsupported;
                        try applyDenseAssignIntScalar(out, target_idx, int_value);
                    }
                },
            },
        }
    }

    fn applyDenseAssignFloatRhs(out: []f64, targets: DenseAssignTargets, rhs: DenseAssignRhs) void {
        switch (targets) {
            .scalar => |target_idx| out[target_idx] = denseAssignFloatScalarValue(rhs),
            .slice => |selectors| switch (rhs) {
                .int_scalar => |value| {
                    const float_value = @as(f64, @floatFromInt(value));
                    for (selectors) |target_idx| out[target_idx] = float_value;
                },
                .float_scalar => |value| {
                    for (selectors) |target_idx| out[target_idx] = value;
                },
                .int_vector => |view| {
                    std.debug.assert(hostIntArrayViewLen(view) == selectors.len);
                    for (selectors, 0..) |target_idx, idx| out[target_idx] = @as(f64, @floatFromInt(hostIntViewItem(view, idx)));
                },
                .float_vector => |items| {
                    std.debug.assert(items.len == selectors.len);
                    for (selectors, 0..) |target_idx, idx| out[target_idx] = items[idx];
                },
            },
        }
    }

    fn prepareReusableHostDenseForMutation(self: *Session, source: Value) bool {
        const handle = valueNumericHandle(source) orelse return true;
        const mutable_handle = @constCast(handle);
        if (numericBackendAttachment(handle) != null) {
            if (mutable_handle.header.owner != .managed) return false;
            self.evictBackendAttachment(mutable_handle);
        }
        mutable_handle.preferred = .host;
        syncNumericArrayChildren(mutable_handle);
        return true;
    }

    fn recordFastDenseAssignMiss(self: *Session) void {
        if (comptime enable_probe_instrumentation) self.debug_fast_dense_assign_miss_count += 1;
    }

    fn recordFastDenseAssignClone(self: *Session, base: Value) void {
        if (comptime !enable_probe_instrumentation) return;
        self.debug_fast_dense_assign_clone_count += 1;

        if (mutableNumericHandle(base)) |handle| {
            switch (handle.header.owner) {
                .managed => {
                    if (handle.header.ref_count != 1) {
                        self.debug_fast_dense_assign_clone_reason_counts[@intFromEnum(DebugFastDenseAssignCloneReason.non_unique)] += 1;
                        return;
                    }
                },
                .frozen => {
                    self.debug_fast_dense_assign_clone_reason_counts[@intFromEnum(DebugFastDenseAssignCloneReason.frozen)] += 1;
                    return;
                },
                .scratch => {},
            }
        } else if (hostDenseIfPresent(base)) |host| {
            switch (host.header.owner) {
                .managed => {
                    if (host.header.ref_count != 1) {
                        self.debug_fast_dense_assign_clone_reason_counts[@intFromEnum(DebugFastDenseAssignCloneReason.non_unique)] += 1;
                        return;
                    }
                },
                .frozen => {
                    self.debug_fast_dense_assign_clone_reason_counts[@intFromEnum(DebugFastDenseAssignCloneReason.frozen)] += 1;
                    return;
                },
                .scratch => {},
            }
        }

        self.debug_fast_dense_assign_clone_reason_counts[@intFromEnum(DebugFastDenseAssignCloneReason.other)] += 1;
    }

    fn finishFastDenseScalarIntAssign(self: *Session, target_idx: usize, rhs: DenseAssignRhs, out: *HostIntResult, reused: bool) KError!Value {
        const host = out.arrayPtr();
        hostDenseSetFlags(host, host_dense_flag_normalized);
        self.invalidateHostDenseCachesForMutation(host);
        const value = try out.value(self);
        self.recordFastDenseAssignHit(.{ .scalar = target_idx }, rhs, reused);
        return if (reused) self.shareValue(value) else value;
    }

    fn finishFastDenseScalarFloatAssign(self: *Session, target_idx: usize, rhs: DenseAssignRhs, out: HostFloatResult, reused: bool) KError!Value {
        hostDenseSetFlags(out.array, host_dense_flag_normalized);
        self.invalidateHostDenseCachesForMutation(out.array);
        const value = try out.value(self);
        self.recordFastDenseAssignHit(.{ .scalar = target_idx }, rhs, reused);
        return if (reused) self.shareValue(value) else value;
    }

    fn tryFastDenseScalarAssignDirect(self: *Session, base: Value, target_idx: usize, rhs_source: Value) KError!?Value {
        if (valueNonVectorNumericShape(base) != null) return null;
        const base_array = try numericHostArrayValue(self, base);

        switch (base_array.storage) {
            .bit => {
                const rhs_int = denseAssignScalarIntLike(rhs_source) orelse return null;
                if (rhs_int != 0 and rhs_int != 1) return null;
                if (comptime enable_probe_instrumentation) self.debug_fast_dense_assign_attempt_count += 1;

                var reused = false;
                var out = if (self.tryReuseHostIntArrayResult(base, .bit)) |existing| blk: {
                    if (!self.prepareReusableHostDenseForMutation(base)) {
                        self.recordFastDenseAssignMiss();
                        return null;
                    }
                    reused = true;
                    break :blk existing;
                } else blk: {
                    self.recordFastDenseAssignClone(base);
                    var allocated = try self.allocOwnedHostIntCloneResult(amendCloneOwner(base), .bit, base_array.len());
                    errdefer self.releaseValue(Value.array(allocated.arrayPtr()));
                    @memcpy(allocated.bit.words, hostDenseLogicalBitWords(base_array, base_array.storage.bit));
                    break :blk allocated;
                };
                try applyDenseAssignIntScalar(&out, target_idx, rhs_int);
                return try self.finishFastDenseScalarIntAssign(target_idx, .{ .int_scalar = rhs_int }, &out, reused);
            },
            .int8, .int16, .int32, .int64 => {
                const rhs_int = denseAssignScalarIntLike(rhs_source) orelse return null;
                const view = hostIntArrayView(base_array) orelse return null;
                const kind = hostIntArrayViewKind(view);
                if (!hostIntKindCanRepresent(kind, rhs_int)) return null;
                if (comptime enable_probe_instrumentation) self.debug_fast_dense_assign_attempt_count += 1;

                var reused = false;
                var out = if (self.tryReuseHostIntArrayResult(base, kind)) |existing| blk: {
                    if (!self.prepareReusableHostDenseForMutation(base)) {
                        self.recordFastDenseAssignMiss();
                        return null;
                    }
                    reused = true;
                    break :blk existing;
                } else blk: {
                    self.recordFastDenseAssignClone(base);
                    var allocated = try self.allocOwnedHostIntCloneResult(amendCloneOwner(base), kind, base_array.len());
                    errdefer self.releaseValue(Value.array(allocated.arrayPtr()));
                    try copyHostIntViewToResult(&allocated, view);
                    break :blk allocated;
                };
                try applyDenseAssignIntScalar(&out, target_idx, rhs_int);
                return try self.finishFastDenseScalarIntAssign(target_idx, .{ .int_scalar = rhs_int }, &out, reused);
            },
            .float64 => |base_items| {
                const rhs_float = denseAssignScalarFloatLike(rhs_source) orelse return null;
                const rhs: DenseAssignRhs = if (scalarIntLikeValue(rhs_source)) |rhs_int|
                    .{ .int_scalar = rhs_int }
                else
                    .{ .float_scalar = rhs_float };
                if (comptime enable_probe_instrumentation) self.debug_fast_dense_assign_attempt_count += 1;

                var reused = false;
                const out = if (self.tryReuseHostFloatArrayResult(base)) |existing| blk: {
                    if (!self.prepareReusableHostDenseForMutation(base)) {
                        self.recordFastDenseAssignMiss();
                        return null;
                    }
                    reused = true;
                    break :blk existing;
                } else blk: {
                    self.recordFastDenseAssignClone(base);
                    const allocated = try self.allocOwnedHostFloatResult(amendCloneOwner(base), base_array.len());
                    errdefer self.releaseValue(Value.array(allocated.array));
                    @memcpy(allocated.items, base_items);
                    break :blk allocated;
                };
                out.items[target_idx] = rhs_float;
                return try self.finishFastDenseScalarFloatAssign(target_idx, rhs, out, reused);
            },
        }
    }

    fn tryFastDenseAssignAmendImpl(self: *Session, base: Value, targets: DenseAssignTargets, rhs_source: Value) KError!?Value {
        const targets_len = denseAssignTargetsLen(targets);
        if (targets_len == 0) {
            self.recordFastDenseAssignMiss();
            return null;
        }
        if (valueNonVectorNumericShape(base) != null) {
            self.recordFastDenseAssignMiss();
            return null;
        }

        const rhs = (try self.denseAssignRhs(rhs_source, targets_len)) orelse {
            self.recordFastDenseAssignMiss();
            return null;
        };
        const base_array = try numericHostArrayValue(self, base);

        return switch (hostDenseNumericMode(base_array)) {
            .int => blk: {
                const view = hostIntArrayView(base_array) orelse {
                    self.recordFastDenseAssignMiss();
                    return null;
                };
                const kind = hostIntArrayViewKind(view);
                if (!denseAssignRhsFitsIntKind(kind, targets_len, rhs)) {
                    self.recordFastDenseAssignMiss();
                    return null;
                }

                var reused = false;
                var out = if (self.tryReuseHostIntArrayResult(base, kind)) |existing| blk_out: {
                    if (!self.prepareReusableHostDenseForMutation(base)) {
                        self.recordFastDenseAssignMiss();
                        return null;
                    }
                    reused = true;
                    break :blk_out existing;
                } else blk_out: {
                    self.recordFastDenseAssignClone(base);
                    var allocated = try self.allocOwnedHostIntCloneResult(amendCloneOwner(base), kind, base_array.len());
                    errdefer self.releaseValue(Value.array(allocated.arrayPtr()));
                    try copyHostIntViewToResult(&allocated, view);
                    break :blk_out allocated;
                };
                try applyDenseAssignIntRhs(&out, targets, rhs);
                const host = out.arrayPtr();
                hostDenseSetFlags(host, host_dense_flag_normalized);
                self.invalidateHostDenseCachesForMutation(host);
                const value = try out.value(self);
                self.recordFastDenseAssignHit(targets, rhs, reused);
                break :blk if (reused) self.shareValue(value) else value;
            },
            .float => blk: {
                const base_items = base_array.storage.float64;
                var reused = false;
                var out = if (self.tryReuseHostFloatArrayResult(base)) |existing| blk_out: {
                    if (!self.prepareReusableHostDenseForMutation(base)) {
                        self.recordFastDenseAssignMiss();
                        return null;
                    }
                    reused = true;
                    break :blk_out existing;
                } else blk_out: {
                    self.recordFastDenseAssignClone(base);
                    const allocated = try self.allocOwnedHostFloatResult(amendCloneOwner(base), base_array.len());
                    errdefer self.releaseValue(Value.array(allocated.array));
                    @memcpy(allocated.items, base_items);
                    break :blk_out allocated;
                };
                applyDenseAssignFloatRhs(out.items, targets, rhs);
                hostDenseSetFlags(out.array, host_dense_flag_normalized);
                self.invalidateHostDenseCachesForMutation(out.array);
                const value = try out.value(self);
                self.recordFastDenseAssignHit(targets, rhs, reused);
                break :blk if (reused) self.shareValue(value) else value;
            },
        };
    }

    fn tryFastDenseAssignScalarAmend(self: *Session, base: Value, target_idx: usize, rhs_source: Value) KError!?Value {
        if (comptime enable_probe_instrumentation) self.debug_fast_dense_assign_attempt_count += 1;
        return try self.tryFastDenseAssignAmendImpl(base, .{ .scalar = target_idx }, rhs_source);
    }

    fn tryFastIndexedDenseScalarAssignOwned(self: *Session, base: Value, selector: Value, rhs_source: Value) KError!?Value {
        if (base.tag() != .array) return null;
        const raw_index = scalarIntLikeValue(selector) orelse return null;
        errdefer self.releaseCanonicalManagedNumericValue(base);
        const target_idx = try normalizeIndex(raw_index, try self.topLevelLen(base));
        if (try self.tryFastDenseScalarAssignDirect(base, target_idx, rhs_source)) |amended| {
            if (comptime enable_probe_instrumentation) self.debug_owned_amend_count += 1;
            self.releaseCanonicalManagedNumericValue(base);
            return amended;
        }
        const amended = (try self.tryFastDenseAssignScalarAmend(base, target_idx, rhs_source)) orelse return null;
        if (comptime enable_probe_instrumentation) self.debug_owned_amend_count += 1;
        self.releaseCanonicalManagedNumericValue(base);
        return amended;
    }

    const DirectGlobalIndexedAssignResult = struct {
        result: ?Value = null,
    };

    fn tryFastGlobalDenseScalarAssignInPlace(
        self: *Session,
        slot: u16,
        selector: Value,
        rhs_source: Value,
        want_result: bool,
    ) KError!?DirectGlobalIndexedAssignResult {
        const cell = try self.loadGlobalCell(slot);
        const base = cell.value;
        if (!cell.class.isArray()) return null;
        const raw_index = scalarIntLikeValue(selector) orelse return null;
        if (comptime enable_probe_instrumentation) self.debug_fast_dense_assign_attempt_count += 1;
        if (valueNonVectorNumericShape(base) != null) {
            self.recordFastDenseAssignMiss();
            return null;
        }
        const base_array = hostDenseIfPresent(base) orelse {
            self.recordFastDenseAssignMiss();
            return null;
        };
        const target_idx = try normalizeIndex(raw_index, base_array.len());
        const rhs = (try self.denseAssignRhs(rhs_source, 1)) orelse {
            self.recordFastDenseAssignMiss();
            return null;
        };

        switch (hostDenseNumericMode(base_array)) {
            .int => {
                const view = hostIntArrayView(base_array) orelse {
                    self.recordFastDenseAssignMiss();
                    return null;
                };
                const kind = hostIntArrayViewKind(view);
                if (!denseAssignRhsFitsIntKind(kind, 1, rhs)) {
                    self.recordFastDenseAssignMiss();
                    return null;
                }
                var out = self.tryReuseHostIntArrayResult(base, kind) orelse {
                    self.recordFastDenseAssignMiss();
                    return null;
                };
                if (!self.prepareReusableHostDenseForMutation(base)) {
                    self.recordFastDenseAssignMiss();
                    return null;
                }
                try applyDenseAssignIntRhs(&out, .{ .scalar = target_idx }, rhs);
                const host = out.arrayPtr();
                hostDenseSetFlags(host, host_dense_flag_normalized);
                self.invalidateHostDenseCachesForMutation(host);
            },
            .float => {
                const out = self.tryReuseHostFloatArrayResult(base) orelse {
                    self.recordFastDenseAssignMiss();
                    return null;
                };
                if (!self.prepareReusableHostDenseForMutation(base)) {
                    self.recordFastDenseAssignMiss();
                    return null;
                }
                applyDenseAssignFloatRhs(out.items, .{ .scalar = target_idx }, rhs);
                hostDenseSetFlags(out.array, host_dense_flag_normalized);
                self.invalidateHostDenseCachesForMutation(out.array);
            },
        }

        cell.class = classifyGlobalValue(base);
        if (comptime enable_probe_instrumentation) {
            self.recordFastDenseAssignHit(.{ .scalar = target_idx }, rhs, true);
            self.debug_owned_amend_count += 1;
        }
        return .{
            .result = if (want_result) try self.applyArrayCall1Scalar(base, raw_index) else null,
        };
    }

    fn tryFastDenseAssignAmend(self: *Session, base: Value, selectors: []const usize, rhs_source: Value) KError!?Value {
        if (comptime enable_probe_instrumentation) self.debug_fast_dense_assign_attempt_count += 1;
        return try self.tryFastDenseAssignAmendImpl(base, .{ .slice = selectors }, rhs_source);
    }

    fn applyShallowAmend(self: *Session, base: Value, selector: Value, mode: ShallowAmendMode, func_or_value: Value, arg: Value) KError!Value {
        if (base.tag() != .array) return error.Type;
        var tried_scalar_fast_assign = false;
        if (mode == .assign) {
            if (scalarIntLikeValue(selector)) |raw_index| {
                tried_scalar_fast_assign = true;
                const target_idx = try normalizeIndex(raw_index, try self.topLevelLen(base));
                if (try self.tryFastDenseAssignScalarAmend(base, target_idx, func_or_value)) |fast| return fast;
            }
        }
        const selectors = try self.collectSelectorIndices(base, selector);
        defer self.allocator.free(selectors);

        if (mode == .assign and !tried_scalar_fast_assign) {
            if (try self.tryFastDenseAssignAmend(base, selectors, func_or_value)) |fast| return fast;
        }

        const items = try self.materializeTopLevelItems(base);
        defer {
            for (items) |value| self.releaseValue(value);
            self.allocator.free(items);
        }

        if (selectors.len == 0) return try self.rebuildTopLevelItems(base, items);

        var rhs_items: ?[]Value = null;
        defer if (rhs_items) |values| {
            for (values) |value| self.releaseValue(value);
            self.allocator.free(values);
        };

        const rhs_source = switch (mode) {
            .assign => func_or_value,
            .binary => arg,
            .unary => Value.fromBool(false),
        };
        if (mode != .unary and rhs_source.tag() == .array) {
            const maybe = try self.tryMaterializeTopLevelItems(rhs_source);
            if (maybe) |values| rhs_items = values;
        }

        var idx: usize = 0;
        while (idx < selectors.len) : (idx += 1) {
            const target_idx = selectors[idx];
            const current = items[target_idx];
            const next = switch (mode) {
                .assign => if (rhs_items) |values|
                    if (values.len == selectors.len) values[idx] else try self.retainEscapedValue(func_or_value)
                else
                    try self.retainEscapedValue(func_or_value),
                .unary => try self.applyValue(func_or_value, &[_]Value{current}),
                .binary => blk: {
                    const rhs = if (rhs_items) |values|
                        if (values.len == selectors.len) values[idx] else arg
                    else
                        arg;
                    break :blk try self.applyValue(func_or_value, &[_]Value{ current, rhs });
                },
            };
            self.releaseValue(items[target_idx]);
            items[target_idx] = next;
        }

        return try self.rebuildTopLevelItems(base, items);
    }

    fn collectSelectorIndices(self: *Session, base: Value, selector: Value) KError![]usize {
        const top_len = try self.topLevelLen(base);
        var indices = std.ArrayList(usize).empty;
        defer indices.deinit(self.allocator);

        switch (selector.tag()) {
            .int, .bool => {
                try indices.append(self.allocator, try normalizeIndex(scalarIntLikeValue(selector).?, top_len));
            },
            .array => {
                const array = try numericHostArrayValue(self, selector);
                if (hostIntArrayView(array)) |view| switch (view) {
                    .bit => |bits| {
                        if (bits.len != top_len) return error.Type;
                        for (0..bits.len) |idx| {
                            if (!bitGet(bits.words, idx)) continue;
                            try indices.append(self.allocator, idx);
                        }
                    },
                    else => {
                        const len = hostIntArrayViewLen(view);
                        try indices.ensureTotalCapacity(self.allocator, len);
                        for (0..len) |idx| {
                            try indices.append(self.allocator, try normalizeIndex(hostIntViewItem(view, idx), top_len));
                        }
                    },
                } else return error.Type;
            },
            else => return error.Type,
        }

        return try indices.toOwnedSlice(self.allocator);
    }

    fn topLevelLen(self: *Session, value: Value) KError!usize {
        const array = try numericHostArrayValue(self, value);
        if (hostDenseNonVectorShape(array)) |shape| {
            if (shape.rank != 2) return error.Unsupported;
            return @intCast(shape.shape[0]);
        }
        return array.len();
    }

    fn materializeTopLevelItems(self: *Session, value: Value) KError![]Value {
        const array = try numericHostArrayValue(self, value);
        const len = try self.topLevelLen(value);
        const items = try self.allocator.alloc(Value, len);
        errdefer self.allocator.free(items);
        var initialized: usize = 0;
        errdefer {
            for (items[0..initialized]) |item| self.releaseValue(item);
        }
        for (0..len) |idx| {
            items[idx] = try self.hostDenseIndexScalar(array, @intCast(idx));
            initialized += 1;
        }
        return items;
    }

    fn tryMaterializeTopLevelItems(self: *Session, value: Value) KError!?[]Value {
        if (value.tag() != .array) return null;
        return try self.materializeTopLevelItems(value);
    }

    fn rebuildTopLevelItems(self: *Session, base: Value, items: []const Value) KError!Value {
        const rebuilt = try self.makeArrayFromValues(items);
        if (try self.promoteRenderableMatrixValue(rebuilt)) |promoted| {
            if (promoted.raw != rebuilt.raw and isManagedValue(rebuilt)) self.releaseValue(rebuilt);
            return promoted;
        }
        if (valueNumericMatrixShape(base)) |shape| {
            return try applyNonVectorNumericShapeToValue(self, rebuilt, numericShapeSnapshotMatrix(shape.rows, shape.cols));
        }
        return rebuilt;
    }

    fn applyDot(self: *Session, left: Value, right: Value) KError!Value {
        const items = try self.materializeSequenceItems(right);
        defer self.releaseArgs(items);
        return switch (left.tag()) {
            .builtin, .closure => try self.invokeValueInCurrentRun(left, items),
            .array => try self.deepIndexValue(left, items),
            else => error.Type,
        };
    }

    fn applyProjectionClosure(self: *Session, info: ProjectionInfo, args: []const Value) KError!Value {
        var profile_scope = self.beginSamplingProfileScope(.apply_projection);
        defer profile_scope.end();
        if (self.debugDetailedProbeActive()) self.debug_apply_projection_count += 1;
        const full_slot_values = try self.scratch_arena.allocator().alloc(Value, info.slot_count);
        var next_hole_mask: u64 = 0;
        var arg_idx: usize = 0;

        for (0..info.slot_count) |slot_idx| {
            if (((info.hole_mask >> @intCast(slot_idx)) & 1) != 0) {
                if (arg_idx < args.len) {
                    full_slot_values[slot_idx] = args[arg_idx];
                    arg_idx += 1;
                } else {
                    full_slot_values[slot_idx] = Value.fromBool(false);
                    next_hole_mask |= (@as(u64, 1) << @intCast(slot_idx));
                }
            } else {
                full_slot_values[slot_idx] = info.slot_values[slot_idx];
            }
        }

        if (next_hole_mask != 0) {
            return try self.allocManagedProjectionClosure(
                info.callee,
                std.math.cast(u8, info.slot_count) orelse return error.Unsupported,
                next_hole_mask,
                full_slot_values,
            );
        }

        const extra_count = args.len - arg_idx;
        const apply_args = try self.scratch_arena.allocator().alloc(Value, info.slot_count + extra_count);
        @memcpy(apply_args[0..info.slot_count], full_slot_values);
        for (args[arg_idx..], 0..) |arg, idx| apply_args[info.slot_count + idx] = arg;
        return try self.invokeValueInCurrentRun(info.callee, apply_args);
    }

    fn applyDerivedClosure(self: *Session, closure: *const Closure, args: []const Value) KError!?Value {
        if (!closureMayUseDerivedApply(closure)) return null;
        if (self.debugDetailedProbeActive()) self.debug_apply_derived_closure_count += 1;
        if (try self.projectionInfoFromClosure(closure)) |info| {
            return try self.applyProjectionClosure(info, args);
        }
        if (try self.innerProductInfoFromClosure(closure)) |info| {
            return try self.applyInnerProductClosure(info, args);
        }
        const kind = closureDerivedKind(closure) orelse return null;
        return try self.applyDerivedKind(kind, closure.captures, args);
    }

    fn builtinSupportsMonad(op: BuiltinId) bool {
        return switch (op) {
            .add,
            .sub,
            .mul,
            .div,
            .exp,
            .log,
            .sin,
            .cos,
            .tanh,
            .sigmoid,
            .iota,
            .minimum,
            .maximum,
            .reverse,
            .less,
            .more,
            .grade_up,
            .grade_down,
            .not,
            .count,
            .floor,
            .null_fill_without,
            .sort,
            .equal,
            .stringify,
            .bytes,
            .utf8,
            .char,
            .unique,
            .tokenize,
            .detokenize,
            .eval_string,
            .load,
            .sql,
            .rotcacheview,
            .layernorm,
            .gelu,
            .geluapprox,
            .softmax,
            => true,
            .concat, .take, .drop, .reshape, .cast, .contains, .split, .join, .find, .grad, .valuegrad, .prng, .save, .register, .rotcache, .rotcacheupdate, .rope, .ropeflat, .ropecisflat, .rmsnorm, .mlpdense, .conv2d, .convtranspose2d, .upsamplenearest2d, .groupnorm, .pow, .sdpa, .sam3boxrpb, .sdpamask, .sdpaflat => false,
        };
    }

    fn builtinSupportsDyad(op: BuiltinId) bool {
        return switch (op) {
            .add,
            .sub,
            .mul,
            .div,
            .pow,
            .minimum,
            .maximum,
            .less,
            .more,
            .not,
            .concat,
            .count,
            .floor,
            .null_fill_without,
            .sort,
            .equal,
            .stringify,
            .contains,
            .split,
            .join,
            .unique,
            .load,
            .save,
            .register,
            .rotcache,
            .rotcacheupdate,
            => true,
            .exp, .log, .sin, .cos, .tanh, .sigmoid, .iota, .reverse, .grade_up, .grade_down, .take, .drop, .reshape, .cast, .find, .bytes, .utf8, .char, .tokenize, .detokenize, .eval_string, .grad, .valuegrad, .prng, .sql, .rotcacheview, .rope, .ropeflat, .ropecisflat, .rmsnorm, .layernorm, .gelu, .geluapprox, .mlpdense, .conv2d, .convtranspose2d, .upsamplenearest2d, .groupnorm, .softmax, .sdpa, .sam3boxrpb, .sdpamask, .sdpaflat => false,
        };
    }

    fn convergeUsesMonadicBase(base: Value) bool {
        return switch (base.tag()) {
            .builtin => builtinSupportsMonad(base.asBuiltin()) and !builtinSupportsDyad(base.asBuiltin()),
            .closure => blk: {
                const closure = base.asClosure();
                if (projectionHoleCount(closure)) |hole_count| break :blk hole_count == 1;
                if (closureDerivedKind(closure) != null) break :blk false;
                break :blk closure.code.arity == 1;
            },
            .array => true,
            else => false,
        };
    }

    fn projectionHoleCount(closure: *const Closure) ?u8 {
        if (!closureIsProjection(closure)) return null;
        if (closure.captures.len < 3) return null;
        const slot_count_i64 = scalarIntLikeValue(closure.captures[1]) orelse return null;
        const hole_mask_i64 = scalarIntLikeValue(closure.captures[2]) orelse return null;
        if (slot_count_i64 < 0 or slot_count_i64 > 63 or hole_mask_i64 < 0) return null;
        const slot_count: u6 = @intCast(slot_count_i64);
        const hole_mask: u64 = @intCast(hole_mask_i64);
        if ((hole_mask >> slot_count) != 0) return null;
        if (closure.captures.len != 3 + @as(usize, slot_count)) return null;
        return @intCast(@popCount(hole_mask));
    }

    fn valueIsCallable(value: Value) bool {
        return switch (value.tag()) {
            .builtin, .closure, .array => true,
            else => false,
        };
    }

    fn eachPriorUsesMonadicBase(base: Value) bool {
        return switch (base.tag()) {
            .builtin => builtinSupportsMonad(base.asBuiltin()) and !builtinSupportsDyad(base.asBuiltin()),
            .closure => blk: {
                const closure = base.asClosure();
                if (closureDerivedKind(closure)) |kind| {
                    break :blk switch (kind) {
                        .each => closure.captures.len == 1 and eachPriorUsesMonadicBase(closure.captures[0]),
                        .fold, .scan, .each_right, .each_left, .each_prior, .grad, .valuegrad => true,
                    };
                }
                break :blk closure.code.arity == 1;
            },
            else => false,
        };
    }

    fn eachPriorImplicitSeedValue(self: *Session, base: Value, vector: Value) KError!Value {
        return switch (base.tag()) {
            .builtin => switch (base.asBuiltin()) {
                .add, .sub => try self.intValue(0),
                .mul, .div => try self.intValue(1),
                .minimum, .maximum => try self.derivedSequenceItemValue(vector, 0),
                .concat => try self.createManagedHostBoxedArray(&.{}),
                else => try self.floatValue(std.math.nan(f64)),
            },
            else => try self.derivedSequenceItemValue(vector, 0),
        };
    }

    fn applyDerivedKind(self: *Session, kind: DerivedVerbKind, captures: []const Value, args: []const Value) KError!Value {
        if (try self.tryApplyStringDerivedKind(kind, captures, args)) |value| return value;
        return switch (kind) {
            .each => blk: {
                if (captures.len != 1) return error.Internal;
                break :blk try self.applyEachDerived(captures[0], args);
            },
            .fold => blk: {
                if (captures.len != 1) return error.Internal;
                break :blk if (args.len == 1 and convergeUsesMonadicBase(captures[0]))
                    try self.applyConvergeDerived(captures[0], args[0], false)
                else
                    try self.applyFoldDerived(captures[0], args, false);
            },
            .scan => blk: {
                if (captures.len != 1) return error.Internal;
                break :blk if (args.len == 1 and convergeUsesMonadicBase(captures[0]))
                    try self.applyConvergeDerived(captures[0], args[0], true)
                else
                    try self.applyFoldDerived(captures[0], args, true);
            },
            .each_right => blk: {
                if (captures.len != 1) return error.Internal;
                break :blk try self.applyEachRightDerived(captures[0], args);
            },
            .each_left => blk: {
                if (captures.len != 1) return error.Internal;
                break :blk try self.applyEachLeftDerived(captures[0], args);
            },
            .each_prior => blk: {
                if (captures.len != 1) return error.Internal;
                break :blk try self.applyEachPriorDerived(captures[0], args);
            },
            .grad => try self.applyAutogradDerived(.grad, captures, args),
            .valuegrad => try self.applyAutogradDerived(.valuegrad, captures, args),
        };
    }

    fn tryApplyStringDerivedKind(self: *Session, kind: DerivedVerbKind, captures: []const Value, args: []const Value) KError!?Value {
        if (captures.len != 1) return null;
        if (captures[0].tag() == .builtin and captures[0].asBuiltin() == .concat) {
            return switch (kind) {
                .fold => try self.tryApplyStringJoinDerived(args),
                .scan => try self.tryApplyStringSplitDerived(args),
                else => null,
            };
        }
        if (stringBytes(captures[0]) != null) {
            return switch (kind) {
                .fold => if (args.len == 1 and isJoinableStringSequence(args[0]))
                    try self.joinValues(captures[0], args[0])
                else
                    null,
                .scan => if (args.len == 1 and stringBytes(args[0]) != null)
                    try self.splitValues(captures[0], args[0])
                else
                    null,
                else => null,
            };
        }
        return switch (kind) {
            else => null,
        };
    }

    fn tryApplyStringJoinDerived(self: *Session, args: []const Value) KError!?Value {
        if (args.len == 1) {
            if (!isJoinableStringSequence(args[0])) return null;
            const empty = try self.frozenHostString(&.{});
            defer self.releaseValue(empty);
            return try self.joinValues(empty, args[0]);
        }
        if (args.len == 2 and stringBytes(args[0]) != null and isJoinableStringSequence(args[1])) {
            return try self.joinValues(args[0], args[1]);
        }
        return null;
    }

    fn tryApplyStringSplitDerived(self: *Session, args: []const Value) KError!?Value {
        if (args.len == 2 and stringBytes(args[0]) != null and stringBytes(args[1]) != null) {
            return try self.splitValues(args[0], args[1]);
        }
        return null;
    }

    fn valuesExactlyEqual(self: *Session, left: Value, right: Value) KError!bool {
        if (left.tag() != .array and right.tag() != .array) {
            const eq = try self.equalValues(left, right);
            return eq.asBool();
        }
        if (left.tag() != .array or right.tag() != .array) return false;

        const left_shape = valueNonVectorNumericShape(left);
        const right_shape = valueNonVectorNumericShape(right);
        if (left_shape == null and right_shape != null) return false;
        if (left_shape != null and right_shape == null) return false;
        if (left_shape) |lhs| {
            const rhs = right_shape.?;
            if (lhs.rank != rhs.rank or !std.mem.eql(i32, lhs.shapeSlice(), rhs.shapeSlice())) return false;
        }

        if (valueNumericMode(left) != null and valueNumericMode(right) != null) {
            const left_len = numericVectorLen(left) orelse return false;
            const right_len = numericVectorLen(right) orelse return false;
            if (left_len != right_len) return false;
            for (0..left_len) |idx| {
                if (try numericFloatAt(left, idx) != try numericFloatAt(right, idx)) return false;
            }
            return true;
        }

        const left_array = try numericHostArrayValue(self, left);
        const right_array = try numericHostArrayValue(self, right);
        if (left_array.len() != right_array.len()) return false;
        for (0..left_array.len()) |idx| {
            const lhs = try self.hostDenseIndexScalar(left_array, @intCast(idx));
            const rhs = try self.hostDenseIndexScalar(right_array, @intCast(idx));
            defer self.releaseValue(lhs);
            defer self.releaseValue(rhs);
            if (!(try self.valuesExactlyEqual(lhs, rhs))) return false;
        }
        return true;
    }

    fn applyConvergeDerived(self: *Session, base: Value, input: Value, collect: bool) KError!Value {
        var current = self.shareValue(input);
        errdefer self.releaseValue(current);

        var results = std.ArrayList(Value).empty;
        defer {
            for (results.items) |value| self.releaseValue(value);
            results.deinit(self.allocator);
        }

        if (collect) try results.append(self.allocator, self.shareValue(current));

        while (true) {
            const next = try self.applyDerivedBase(base, &[_]Value{current});
            const converged = try self.valuesExactlyEqual(current, next);
            if (converged) {
                self.releaseValue(current);
                if (!collect) return next;
                self.releaseValue(next);
                return try self.createManagedArrayLikeFromValues(results.items);
            }
            self.releaseValue(current);
            current = next;
            if (collect) try results.append(self.allocator, self.shareValue(current));
        }
    }

    fn tryApplyControlledFoldDerived(self: *Session, base: Value, args: []const Value, collect: bool) KError!?Value {
        if (args.len != 2 or !convergeUsesMonadicBase(base)) return null;
        if (scalarIntLikeValue(args[0])) |count| {
            return try self.applyCountedOverDerived(base, count, args[1], collect);
        }
        if (valueIsCallable(args[0])) {
            return try self.applyWhileOverDerived(base, args[0], args[1], collect);
        }
        return null;
    }

    fn applyCountedOverDerived(self: *Session, base: Value, raw_count: i64, input: Value, collect: bool) KError!Value {
        const count: usize = if (raw_count <= 0)
            0
        else
            std.math.cast(usize, raw_count) orelse return error.Unsupported;

        var current = self.shareValue(input);
        var current_owned = true;
        errdefer if (current_owned) self.releaseValue(current);

        var results = std.ArrayList(Value).empty;
        defer {
            for (results.items) |value| self.releaseValue(value);
            results.deinit(self.allocator);
        }

        if (collect) {
            try results.ensureTotalCapacity(self.allocator, std.math.add(usize, count, 1) catch return error.Unsupported);
            try results.append(self.allocator, self.shareValue(current));
        }

        for (0..count) |_| {
            const next = try self.applyDerivedBase(base, &[_]Value{current});
            self.releaseValue(current);
            current = next;
            if (collect) try results.append(self.allocator, self.shareValue(current));
        }

        if (collect) {
            current_owned = false;
            defer self.releaseValue(current);
            return try self.createManagedArrayLikeFromValues(results.items);
        }
        current_owned = false;
        return current;
    }

    fn applyWhileOverDerived(self: *Session, base: Value, predicate: Value, input: Value, collect: bool) KError!Value {
        var current = self.shareValue(input);
        var current_owned = true;
        errdefer if (current_owned) self.releaseValue(current);

        var results = std.ArrayList(Value).empty;
        defer {
            for (results.items) |value| self.releaseValue(value);
            results.deinit(self.allocator);
        }

        if (collect) try results.append(self.allocator, self.shareValue(current));

        while (true) {
            const condition = try self.applyDerivedBase(predicate, &[_]Value{current});
            const keep_going = boolLikeValue(condition) orelse {
                self.releaseValue(condition);
                return error.Type;
            };
            self.releaseValue(condition);
            if (!keep_going) break;

            const next = try self.applyDerivedBase(base, &[_]Value{current});
            self.releaseValue(current);
            current = next;
            if (collect) try results.append(self.allocator, self.shareValue(current));
        }

        if (collect) {
            current_owned = false;
            defer self.releaseValue(current);
            return try self.createManagedArrayLikeFromValues(results.items);
        }
        current_owned = false;
        return current;
    }

    fn applyEachDerived(self: *Session, base: Value, args: []const Value) KError!Value {
        var profile_scope = self.beginSamplingProfileScope(.apply_each);
        defer profile_scope.end();
        if (try self.tryFastTransposeEachDerived(base, args)) |value| return value;
        if (try self.tryFastBatchedMatmulEachDerived(base, args)) |value| return value;
        if (try self.tryFastUnaryLiftedEachDerived(base, args)) |value| return value;
        if (try self.tryFastBackendMatrixRowFoldEachDerived(base, args)) |value| return value;
        if (try self.tryFastDenseEachDerived(base, args)) |value| return value;
        var len: ?usize = null;
        var saw_array = false;
        for (args) |arg| {
            if (derivedSequenceLen(arg)) |arg_len| {
                saw_array = true;
                if (len) |existing| {
                    if (existing != arg_len) return error.Type;
                } else {
                    len = arg_len;
                }
            }
        }
        if (!saw_array) return try self.applyDerivedBase(base, args);
        if (comptime enable_probe_instrumentation) self.debug_apply_each_generic_count += 1;

        var results = std.ArrayList(Value).empty;
        defer {
            for (results.items) |value| self.releaseValue(value);
            results.deinit(self.allocator);
        }

        const out_len = len.?;
        try results.ensureTotalCapacity(self.allocator, out_len);
        for (0..out_len) |idx| {
            var step_args_buf: [8]Value = undefined;
            if (args.len > step_args_buf.len) return error.Unsupported;
            for (args, 0..) |arg, arg_idx| {
                step_args_buf[arg_idx] = if (derivedSequenceLen(arg) != null) try self.derivedSequenceItemValue(arg, idx) else arg;
            }
            const result = blk: {
                defer self.releaseDerivedStepArgs(args, step_args_buf[0..args.len], 0);
                break :blk try self.applyDerivedBase(base, step_args_buf[0..args.len]);
            };
            try results.append(self.allocator, result);
        }
        return try self.createManagedArrayLikeFromValues(results.items);
    }

    fn tryFastTransposeEachDerived(self: *Session, base: Value, args: []const Value) KError!?Value {
        if (args.len != 1 or base.tag() != .builtin or base.asBuiltin() != .add) return null;
        const handle = shapedNumericHandle(args[0]) orelse return null;
        if (handle.rank < 3 or valueNumericMode(args[0]) == null) return null;
        return try self.transposeDenseNumericValueSwapAxes(args[0], handle, 1, 2);
    }

    fn tryFastBatchedMatmulEachDerived(self: *Session, base: Value, args: []const Value) KError!?Value {
        if (args.len != 2 or base.tag() != .closure) return null;
        const closure = base.asClosure();
        if (try self.innerProductInfoFromClosure(closure)) |info| {
            if (info.reduce == .add and info.map == .mul) {
                return try self.applyBatchedMatmulValues(args[0], args[1]);
            }
        }
        if (closureDerivedKind(closure) != .each_left or closure.captures.len != 1) return null;
        const inner = closure.captures[0];
        if (inner.tag() != .closure) return null;
        const info = (try self.innerProductInfoFromClosure(inner.asClosure())) orelse return null;
        if (info.reduce != .add or info.map != .mul) return null;
        return try self.applyBatchedMatmulValues(args[0], args[1]);
    }

    fn tryFastBackendMatrixRowFoldEachDerived(self: *Session, base: Value, args: []const Value) KError!?Value {
        return runtime_backend_exec.tryFastBackendMatrixRowFoldEachDerived(.{
            .Session = Session,
            .Value = Value,
            .NumericArray = NumericArray,
            .BuiltinId = BuiltinId,
            .DenseExecBackend = DenseExecBackend,
            .KError = KError,
            .c = c,
            .mlx = mlx,
            .runtime_has_mlx = runtime_has_mlx,
            .isDerivedBuiltinClosure = isDerivedBuiltinClosure,
            .valueNumericMatrixShape = valueNumericMatrixShape,
            .valueNumericHandle = valueNumericHandle,
            .numericIntAt = numericIntAt,
            .numericArrayIsFirstAxisSlice = numericArrayIsFirstAxisSlice,
            .numericArrayFirstAxisSliceSource = numericArrayFirstAxisSliceSource,
            .numericArrayFirstAxisSliceRowStart = numericArrayFirstAxisSliceRowStart,
            .numericArrayFirstAxisSliceRowStep = numericArrayFirstAxisSliceRowStep,
            .numericArrayIsFirstAxisIndex = numericArrayIsFirstAxisIndex,
            .numericArrayFirstAxisIndexSource = numericArrayFirstAxisIndexSource,
            .numericArrayFirstAxisIndexRows = numericArrayFirstAxisIndexRows,
            .numericArrayIsFirstAxisConcat = numericArrayIsFirstAxisConcat,
            .numericArrayFirstAxisConcatLeft = numericArrayFirstAxisConcatLeft,
            .numericArrayFirstAxisConcatRight = numericArrayFirstAxisConcatRight,
