    fn tryFastUnaryLiftedEachDerived(self: *Session, base: Value, args: []const Value) KError!?Value {
        if (args.len != 1 or base.tag() != .closure) return null;
        const closure = base.asClosure();
        const kind = (try self.classifyDirectUnaryLiftedClosure(closure)) orelse return null;
        const len = derivedSequenceLen(args[0]) orelse return null;
        if (self.debugDetailedProbeActive()) self.debug_apply_each_fast_unary_lifted_count += 1;

        var results = std.ArrayList(Value).empty;
        defer {
            for (results.items) |value| self.releaseValue(value);
            results.deinit(self.allocator);
        }
        try results.ensureTotalCapacity(self.allocator, len);
        for (0..len) |idx| {
            const item = try self.derivedSequenceItemValue(args[0], idx);
            const result = blk: {
                defer self.releaseValue(item);
                break :blk try self.applyDirectUnaryLiftedKind(kind, item);
            };
            try results.append(self.allocator, result);
        }
        return try self.createManagedArrayLikeFromValues(results.items);
    }

    fn tryFastDenseEachDerived(self: *Session, base: Value, args: []const Value) KError!?Value {
        if (args.len != 2) return null;
        const kind = try self.classifyDenseElementwiseBaseRuntime(base) orelse {
            self.noteDenseEachMiss(.unsupported_base);
            return null;
        };
        if (args[0].tag() != .array and args[1].tag() != .array) {
            self.noteDenseEachMiss(.non_dense_args_or_shape);
            return null;
        }
        if (!wholeArrayEachDyadSafe(args[0], args[1])) {
            self.noteDenseEachMiss(.non_dense_args_or_shape);
            return null;
        }
        if (self.debugDetailedProbeActive()) self.debug_apply_each_fast_dense_count += 1;
        return try self.applyDenseElementwiseKind(kind, args[0], args[1]);
    }

    fn wholeArrayEachDyadSafe(left: Value, right: Value) bool {
        if (left.tag() != .array or right.tag() != .array) return true;
        if (valueNumericMode(left) == null or valueNumericMode(right) == null) return false;
        if (rowwiseMatrixVectorDyad(left, right) != null) return true;
        const left_shape = valueNonVectorNumericShape(left);
        const right_shape = valueNonVectorNumericShape(right);
        if (left_shape == null and right_shape == null) return true;
        if (left_shape == null or right_shape == null) return false;
        const lhs = left_shape.?;
        const rhs = right_shape.?;
        return lhs.rank == rhs.rank and std.mem.eql(i32, lhs.shapeSlice(), rhs.shapeSlice());
    }

    fn tryFastHostFoldDerived(self: *Session, base: Value, args: []const Value, collect: bool) KError!?Value {
        if (base.tag() != .builtin) return null;
        if (!collect) {
            if (try self.tryFastHostShapedFold(base.asBuiltin(), args)) |value| return value;
        }
        return switch (base.asBuiltin()) {
            .add => try self.tryFastHostAddFoldScan(args, collect),
            .sub => if (!collect) try self.tryFastHostSubFold(args) else null,
            .mul => try self.tryFastHostMulFoldScan(args, collect),
            .minimum, .maximum => if (!collect) try self.tryFastHostMinMaxFold(base.asBuiltin(), args) else null,
            else => null,
        };
    }

