    fn fastRangeIotaAddFoldScan(self: *Session, handle: *const NumericArray, seed: ?i64, collect: bool) KError!Value {
        const len = numericArrayRangeLen(handle);
        if (seed == null and len == 0) return error.Type;

        if (!collect) {
            const len_i128: i128 = @intCast(len);
            const last_idx_i128: i128 = @intCast(if (len == 0) 0 else len - 1);
            const start_i128: i128 = numericArrayRangeIota(handle).start;
            const step_i128: i128 = numericArrayRangeIota(handle).step;
            var total_i128 = start_i128 * len_i128;
            total_i128 += step_i128 * @divTrunc(len_i128 * last_idx_i128, 2);
            if (seed) |seed_value| total_i128 += seed_value;
            const total_i64 = std.math.cast(i64, total_i128) orelse return error.Unsupported;
            return try self.intValue(total_i64);
        }

        var out = std.ArrayList(i64).empty;
        defer out.deinit(self.allocator);
        try out.ensureTotalCapacity(self.allocator, len);

        var current = numericArrayRangeIota(handle).start;
        if (seed) |seed_value| {
            var acc = seed_value;
            for (0..len) |_| {
                acc = try checkedIntOp(.add, acc, current);
                try out.append(self.allocator, acc);
                current = try checkedIntOp(.add, current, numericArrayRangeIota(handle).step);
            }
        } else {
            var acc = current;
            try out.append(self.allocator, acc);
            current = try checkedIntOp(.add, current, numericArrayRangeIota(handle).step);
            for (1..len) |_| {
                acc = try checkedIntOp(.add, acc, current);
                try out.append(self.allocator, acc);
                current = try checkedIntOp(.add, current, numericArrayRangeIota(handle).step);
            }
        }
        return try self.createManagedHostIntArray(out.items);
    }

    fn tryFastHostAddFoldScan(self: *Session, args: []const Value, collect: bool) KError!?Value {
        if (args.len == 0 or args.len > 2) return null;
        if (self.dense_backend_override == .mlx) return null;

        const vector = args[args.len - 1];
        if (valueNonVectorNumericShape(vector) != null) return null;
        if (vector.tag() == .array and vector.arrayKind() == .numeric_array) {
            const handle = vector.asNumericArray();
            if (numericArrayIsVectorRangeIota(handle)) {
                const len = numericArrayRangeLen(handle);
                if (args.len == 1 and len == 0) return null;

                if (len <= 1) return null;

                if (args.len == 2) {
                    if (scalarIntLikeValue(args[0])) |seed_int| {
                        noteDensePlanDecision(self, if (collect) .scan else .reduce, .host, .host, .host_fast_kernel);
                        return try self.fastRangeIotaAddFoldScan(handle, seed_int, collect);
                    }
                    return null;
                }
                noteDensePlanDecision(self, if (collect) .scan else .reduce, .host, .host, .host_fast_kernel);
                return try self.fastRangeIotaAddFoldScan(handle, null, collect);
            }
        }
        const array = hostDenseIfPresent(vector) orelse return null;
        const len = array.len();

        if (args.len == 1 and len == 0) return null;

        if (len <= 1) return null;

        if (hostIntArrayView(array)) |int_view| {
            if (args.len == 2) {
                if (scalarIntLikeValue(args[0])) |seed_int| {
                    noteDensePlanDecision(self, if (collect) .scan else .reduce, .host, .host, .host_fast_kernel);
                    return if (collect)
                        try self.fastHostAddScanInt(vector, int_view, seed_int)
                    else
                        try self.fastHostAddFoldInt(array, int_view, seed_int);
                }
                const seed_float = scalarNumericValue(args[0]) catch return null;
                noteDensePlanDecision(self, if (collect) .scan else .reduce, .host, .host, .host_fast_kernel);
                return if (collect)
                    try self.fastHostAddScanFloatFromInt(vector, int_view, seed_float)
                else
                    try self.fastHostAddFoldFloatFromInt(int_view, seed_float);
            }

            noteDensePlanDecision(self, if (collect) .scan else .reduce, .host, .host, .host_fast_kernel);
            return if (collect)
                try self.fastHostAddScanIntUnseeded(vector, int_view)
            else
                try self.fastHostAddFoldIntUnseeded(array, int_view);
        }

        return switch (array.storage) {
            .float64 => |items| blk: {
                if (args.len == 2) {
                    const seed = scalarNumericValue(args[0]) catch break :blk null;
                    noteDensePlanDecision(self, if (collect) .scan else .reduce, .host, .host, .host_fast_kernel);
                    break :blk if (collect)
                        try self.fastHostAddScanFloat(vector, items, seed)
                    else
                        try self.fastHostAddFoldFloat(items, seed);
                }
                noteDensePlanDecision(self, if (collect) .scan else .reduce, .host, .host, .host_fast_kernel);
                break :blk if (collect)
                    try self.fastHostAddScanFloatUnseeded(vector, items)
                else
                    try self.fastHostAddFoldFloatUnseeded(items);
            },
            else => null,
        };
    }

    fn fastRangeIotaSubFold(self: *Session, handle: *const NumericArray, seed: ?i64) KError!Value {
        const len = numericArrayRangeLen(handle);
        if (seed == null and len == 0) return error.Type;

        var acc = seed orelse numericArrayRangeIota(handle).start;
        var current = if (seed == null)
            try checkedIntOp(.add, numericArrayRangeIota(handle).start, numericArrayRangeIota(handle).step)
        else
            numericArrayRangeIota(handle).start;
        const start_idx: usize = if (seed == null) 1 else 0;
        for (start_idx..len) |_| {
            acc = try checkedIntOp(.sub, acc, current);
            current = try checkedIntOp(.add, current, numericArrayRangeIota(handle).step);
        }
        return try self.intValue(acc);
    }

    fn fastHostSubFoldIntUnseeded(self: *Session, view: HostIntArrayView) KError!Value {
        var acc = hostIntViewItem(view, 0);
        for (1..hostIntArrayViewLen(view)) |idx| {
            acc = try checkedIntOp(.sub, acc, hostIntViewItem(view, idx));
        }
        return try self.intValue(acc);
    }

    fn fastHostSubFoldInt(self: *Session, view: HostIntArrayView, seed: i64) KError!Value {
        var acc = seed;
        for (0..hostIntArrayViewLen(view)) |idx| {
            acc = try checkedIntOp(.sub, acc, hostIntViewItem(view, idx));
        }
        return try self.intValue(acc);
    }

    fn fastHostSubFoldFloatUnseeded(self: *Session, items: []const f64) KError!Value {
        var acc = items[0];
        for (items[1..]) |item| acc -= item;
        return try self.floatValue(acc);
    }

    fn fastHostSubFoldFloat(self: *Session, items: []const f64, seed: f64) KError!Value {
        var acc = seed;
        for (items) |item| acc -= item;
        return try self.floatValue(acc);
    }

    fn fastHostSubFoldFloatFromInt(self: *Session, view: HostIntArrayView, seed: f64) KError!Value {
        var acc = seed;
        switch (view) {
            .bit => |items| {
                for (0..items.len) |idx| acc -= @floatFromInt(@intFromBool(bitGet(items.words, idx)));
            },
            .int8 => |items| {
                for (items) |item| acc -= @floatFromInt(item);
            },
            .int16 => |items| {
                for (items) |item| acc -= @floatFromInt(item);
            },
            .int32 => |items| {
                for (items) |item| acc -= @floatFromInt(item);
            },
            .int64 => |items| {
                for (items) |item| acc -= @floatFromInt(item);
            },
        }
        return try self.floatValue(acc);
    }

    fn tryFastHostSubFold(self: *Session, args: []const Value) KError!?Value {
        if (args.len == 0 or args.len > 2) return null;
        if (self.dense_backend_override == .mlx) return null;

        const vector = args[args.len - 1];
        if (valueNonVectorNumericShape(vector) != null) return null;
        if (vector.tag() == .array and vector.arrayKind() == .numeric_array) {
            const handle = vector.asNumericArray();
            if (numericArrayIsVectorRangeIota(handle)) {
                const len = numericArrayRangeLen(handle);
                if (args.len == 1 and len == 0) return error.Type;
                if (len <= 1) return null;

                if (args.len == 2) {
                    if (scalarIntLikeValue(args[0])) |seed_int| {
                        noteDensePlanDecision(self, .reduce, .host, .host, .host_fast_kernel);
                        return try self.fastRangeIotaSubFold(handle, seed_int);
                    }
                    return null;
                }
                noteDensePlanDecision(self, .reduce, .host, .host, .host_fast_kernel);
                return try self.fastRangeIotaSubFold(handle, null);
            }
        }

        const array = hostDenseIfPresent(vector) orelse return null;
        const len = array.len();
        if (args.len == 1 and len == 0) return error.Type;
        if (len <= 1) return null;

        if (hostIntArrayView(array)) |int_view| {
            if (args.len == 2) {
                if (scalarIntLikeValue(args[0])) |seed_int| {
                    noteDensePlanDecision(self, .reduce, .host, .host, .host_fast_kernel);
                    return try self.fastHostSubFoldInt(int_view, seed_int);
                }
                const seed_float = scalarNumericValue(args[0]) catch return null;
                noteDensePlanDecision(self, .reduce, .host, .host, .host_fast_kernel);
                return try self.fastHostSubFoldFloatFromInt(int_view, seed_float);
            }

            noteDensePlanDecision(self, .reduce, .host, .host, .host_fast_kernel);
            return try self.fastHostSubFoldIntUnseeded(int_view);
        }

        return switch (array.storage) {
            .float64 => |items| blk: {
                if (args.len == 2) {
                    const seed = scalarNumericValue(args[0]) catch break :blk null;
                    noteDensePlanDecision(self, .reduce, .host, .host, .host_fast_kernel);
                    break :blk try self.fastHostSubFoldFloat(items, seed);
                }
                noteDensePlanDecision(self, .reduce, .host, .host, .host_fast_kernel);
                break :blk try self.fastHostSubFoldFloatUnseeded(items);
            },
            else => null,
        };
    }

    fn tryFastHostMulFoldScan(self: *Session, args: []const Value, collect: bool) KError!?Value {
        if (collect or args.len == 0 or args.len > 2) return null;
        if (self.dense_backend_override == .mlx) return null;

        const vector = args[args.len - 1];
        if (valueNonVectorNumericShape(vector) != null) return null;
        const array = hostDenseIfPresent(vector) orelse return null;
        if (array.storage != .bit) return null;

        const len = array.len();
        if (args.len == 1 and len == 0) return null;

        if (len <= 1) return null;

        const bits = HostBitSlice{ .words = array.storage.bit, .len = len };
        if (args.len == 2) {
            if (scalarIntLikeValue(args[0])) |seed_int| {
                noteDensePlanDecision(self, .reduce, .host, .host, .host_fast_kernel);
                return try self.fastHostMulFoldBit(bits, seed_int);
            }
            const seed_float = scalarNumericValue(args[0]) catch return null;
            noteDensePlanDecision(self, .reduce, .host, .host, .host_fast_kernel);
            return try self.fastHostMulFoldFloatFromBit(bits, seed_float);
        }
        noteDensePlanDecision(self, .reduce, .host, .host, .host_fast_kernel);
        return try self.fastHostMulFoldBitUnseeded(bits);
    }

    fn tryFastHostMinMaxFold(self: *Session, op: BuiltinId, args: []const Value) KError!?Value {
        if (args.len == 0 or args.len > 2) return null;
        if (self.dense_backend_override == .mlx) return null;

        const vector = args[args.len - 1];
        if (valueNonVectorNumericShape(vector) != null) return null;
        if (planDenseRegionDecision(.reduce, denseReduceScanFacts(vector)).backend != .host) return null;

        const view = hostDenseView(self, vector) catch return null;
        const len = switch (view) {
            .int_array => |items| hostIntDenseViewLen(items),
            .float_array => |items| hostFloatDenseViewLen(items),
            else => return null,
        };

        if (args.len == 1 and len == 0) return error.Type;
        if (args.len == 2 and len == 0) {
            noteDensePlanDecision(self, .reduce, .host, .host, .host_fast_kernel);
            return self.shareValue(args[0]);
        }

        switch (view) {
            .int_array => |items| {
                const bounds = hostIntDenseViewRange(items);
                noteDensePlanDecision(self, .reduce, .host, .host, .host_fast_kernel);
                if (args.len == 1) {
                    return try self.intValue(switch (op) {
                        .minimum => bounds.min,
                        .maximum => bounds.max,
                        else => unreachable,
                    });
                }
                if (scalarIntLikeValue(args[0])) |seed_int| {
                    return try self.intValue(switch (op) {
                        .minimum => @min(seed_int, bounds.min),
                        .maximum => @max(seed_int, bounds.max),
                        else => unreachable,
                    });
                }
                const seed = scalarNumericValue(args[0]) catch return null;
                return try self.floatValue(switch (op) {
                    .minimum => @min(seed, @as(f64, @floatFromInt(bounds.min))),
                    .maximum => @max(seed, @as(f64, @floatFromInt(bounds.max))),
                    else => unreachable,
                });
            },
            .float_array => |items| {
                const bounds = try hostFloatDenseViewBounds(items);
                noteDensePlanDecision(self, .reduce, .host, .host, .host_fast_kernel);
                if (args.len == 1) {
                    return try self.floatValue(switch (op) {
                        .minimum => bounds.min,
                        .maximum => bounds.max,
                        else => unreachable,
                    });
                }
                const seed = scalarNumericValue(args[0]) catch return null;
                return try self.floatValue(switch (op) {
                    .minimum => @min(seed, bounds.min),
                    .maximum => @max(seed, bounds.max),
                    else => unreachable,
                });
            },
            else => return null,
        }
    }

    fn tryFastHostShapedFold(self: *Session, op: BuiltinId, args: []const Value) KError!?Value {
        if (args.len == 0 or args.len > 2) return null;
        if (self.dense_backend_override == .mlx) return null;

        const value = args[args.len - 1];
        const handle = shapedNumericHandle(value) orelse return null;
        if (planDenseRegionDecision(.reduce, denseReduceScanFacts(value)).backend != .host) return null;

        const outer_len: usize = @intCast(handle.shape[0]);
        if (args.len == 1 and outer_len == 0) {
            return switch (op) {
                .add, .mul => null,
                else => error.Type,
            };
        }

        if (outer_len <= 1) return null;

        const block_len = numericShapeInnerBlockLen(handle);
        const view = hostDenseView(self, value) catch return null;

        switch (view) {
            .int_array => |items| {
                if (args.len == 2) {
                    if (scalarIntLikeValue(args[0])) |seed_int| {
                        noteDensePlanDecision(self, .reduce, .host, .host, .host_fast_kernel);
                        return try self.fastHostShapedIntFold(handle, items, op, seed_int);
                    }
                    const seed = scalarNumericValue(args[0]) catch return null;
                    noteDensePlanDecision(self, .reduce, .host, .host, .host_fast_kernel);
                    return try self.fastHostShapedFloatFoldFromInt(handle, items, op, block_len, outer_len, seed);
                }
                noteDensePlanDecision(self, .reduce, .host, .host, .host_fast_kernel);
                return try self.fastHostShapedIntFoldUnseeded(handle, items, op);
            },
            .float_array => |items| {
                const seed = if (args.len == 2) scalarNumericValue(args[0]) catch return null else null;
                noteDensePlanDecision(self, .reduce, .host, .host, .host_fast_kernel);
                return try self.fastHostShapedFloatFold(handle, items, op, block_len, outer_len, seed);
            },
            else => return null,
        }
    }

    fn finishHostReducedIntResult(self: *Session, handle: *const NumericArray, items: []const i64) KError!Value {
        const value = try self.createManagedHostIntArray(items);
        return try applyNonVectorNumericShapeToValue(self, value, numericShapeTailSnapshot(handle));
    }

    fn finishHostReducedFloatResult(self: *Session, handle: *const NumericArray, items: []const f64) KError!Value {
        const value = try self.createManagedHostFloatArray(items);
        return try applyNonVectorNumericShapeToValue(self, value, numericShapeTailSnapshot(handle));
    }

    fn fillHostShapedIntFold(out: []i64, view: HostIntDenseView, op: BuiltinId, block_len: usize, outer_len: usize, seed: ?i64) KError!void {
        const start_row: usize = if (seed) |seed_value| blk: {
            @memset(out, seed_value);
            break :blk 0;
        } else blk: {
            for (0..block_len) |col_idx| out[col_idx] = try hostIntDenseViewItem(view, col_idx);
            break :blk 1;
        };

        for (start_row..outer_len) |row_idx| {
            const row_base = row_idx * block_len;
            for (0..block_len) |col_idx| {
                out[col_idx] = try checkedIntOp(op, out[col_idx], try hostIntDenseViewItem(view, row_base + col_idx));
            }
        }
    }

    fn fillHostShapedFloatFold(out: []f64, view: HostFloatDenseView, op: BuiltinId, block_len: usize, outer_len: usize, seed: ?f64) KError!void {
        const start_row: usize = if (seed) |seed_value| blk: {
            @memset(out, seed_value);
            break :blk 0;
        } else blk: {
            for (0..block_len) |col_idx| out[col_idx] = try hostFloatDenseViewItem(view, col_idx);
            break :blk 1;
        };

        for (start_row..outer_len) |row_idx| {
            const row_base = row_idx * block_len;
            for (0..block_len) |col_idx| {
                out[col_idx] = applyFloatOp(op, out[col_idx], try hostFloatDenseViewItem(view, row_base + col_idx));
            }
        }
    }

    fn fillHostShapedFloatFoldFromInt(out: []f64, view: HostIntDenseView, op: BuiltinId, block_len: usize, outer_len: usize, seed: f64) KError!void {
        @memset(out, seed);
        for (0..outer_len) |row_idx| {
            const row_base = row_idx * block_len;
            for (0..block_len) |col_idx| {
                out[col_idx] = applyFloatOp(op, out[col_idx], @floatFromInt(try hostIntDenseViewItem(view, row_base + col_idx)));
            }
        }
    }

    fn fastHostShapedIntFoldUnseeded(self: *Session, handle: *const NumericArray, view: HostIntDenseView, op: BuiltinId) KError!Value {
        const block_len = numericShapeInnerBlockLen(handle);
        const outer_len: usize = @intCast(handle.shape[0]);
        const out = try self.allocator.alloc(i64, block_len);
        defer self.allocator.free(out);
        try fillHostShapedIntFold(out, view, op, block_len, outer_len, null);
        return try self.finishHostReducedIntResult(handle, out);
    }

    fn fastHostShapedIntFold(self: *Session, handle: *const NumericArray, view: HostIntDenseView, op: BuiltinId, seed: i64) KError!Value {
        const block_len = numericShapeInnerBlockLen(handle);
        const outer_len: usize = @intCast(handle.shape[0]);
        const out = try self.allocator.alloc(i64, block_len);
