    fn fastHostAddScanFloatMaybeSeed(self: *Session, source_value: Value, items: []const f64, seed: ?f64) KError!Value {
        const len = items.len;
        const plan = try self.planHostFloatUnaryOutput(source_value, len, true);
        fillAddScanFloatSlice(plan.output.items, items, seed);
        return try self.finishHostFloatOutput(plan, addScanFloatFlags(items));
