    fn execGlobalCall(self: *Session, slot: u16, argc: u8) KError!void {
        const total = @as(usize, argc);
        if (self.stack_len < total) return error.Internal;

        self.noteGlobalCall(slot);
        const cell = try self.loadGlobalCell(slot);
        const callee = cell.value;
        const arg_start = self.stack_len - total;
        const args = self.stack[arg_start..self.stack_len];

        switch (callee.tag()) {
            .builtin => {
                const result = try self.applyBuiltinCall(callee.asBuiltin(), args);
                self.dropStackFrom(arg_start);
                try self.push(result);
            },
            .closure => {
                const closure = callee.asClosure();
                if (try self.applyDerivedClosure(closure, args)) |result| {
                    self.dropStackFrom(arg_start);
                    try self.push(result);
                    return;
                }
                if (argc != closure.code.arity) return error.Arity;
                if (compactKCodeForPlainClosure(closure, total)) |compact| return try self.execCompactGlobalCallFromStack(compact, arg_start, total);
                const state = frameReleaseStateFromValues(args);
                try self.pushClosureFrameAtBaseWithReleaseState(closure.code, self.retainedFrameOwner(callee), slot, arg_start, state, .stack);
            },
            .array => {
                const result = try self.applyArrayCall(callee, args);
                self.dropStackFrom(arg_start);
                try self.push(result);
            },
            else => return error.Type,
        }
    }

    fn execDyad(self: *Session, op: BuiltinId) KError!void {
        const op_start = stringPerfNow();
        const right = self.pop();
        const left = self.pop();
        errdefer self.releaseCanonicalManagedNumericValue(left);
        errdefer self.releaseCanonicalManagedNumericValue(right);
        if (try self.tryFastInlineScalarDyad(op, left, right)) |fast| {
            self.releaseCanonicalManagedNumericValue(left);
            self.releaseCanonicalManagedNumericValue(right);
            try self.push(fast);
            return;
        }
        const value = try self.applyDyad(op, left, right);
        self.releaseCanonicalManagedNumericValue(left);
        self.releaseCanonicalManagedNumericValue(right);
        try self.push(value);
        if (comptime enable_string_instrumentation) switch (op) {
            .contains => {
                self.string_perf.contains_calls += 1;
                self.string_perf.contains_opcode_ns += @intCast(stringPerfNow() - op_start);
            },
            .split => {
                self.string_perf.split_calls += 1;
                self.string_perf.split_opcode_ns += @intCast(stringPerfNow() - op_start);
            },
            .join => {
                self.string_perf.join_calls += 1;
                self.string_perf.join_opcode_ns += @intCast(stringPerfNow() - op_start);
            },
            else => {},
        };
    }

    fn execContainsOpcode(self: *Session) KError!void {
        const op_start = stringPerfNow();
        const right = self.pop();
        const left = self.pop();
        errdefer self.releaseCanonicalManagedNumericValue(left);
        errdefer self.releaseCanonicalManagedNumericValue(right);
        const value = if (stringBytes(left) != null and stringBytes(right) != null)
            try self.containsValues(left, right)
        else
            try self.applyDyad(.contains, left, right);
        self.releaseCanonicalManagedNumericValue(left);
        self.releaseCanonicalManagedNumericValue(right);
        try self.push(value);
        if (comptime enable_string_instrumentation) {
            self.string_perf.contains_calls += 1;
            self.string_perf.contains_opcode_ns += @intCast(stringPerfNow() - op_start);
        }
    }

