    fn argmaxValue(self: *Session, value: Value) KError!Value {
        if (valueNumericMode(value) == null or valueNumericMatrixShape(value) != null) return error.Type;
        const len = numericFlatLen(value) orelse return error.Type;
        if (len == 0) return error.Type;
        if (len == 1) return try self.intValue(0);
        if (try self.tryFastBackendArgmaxValue(value)) |result| return result;

        if (valueNumericHandle(value)) |handle| _ = try tryEnsureHostRealizationForHandle(self, @constCast(handle));
        switch (valueNumericMode(value).?) {
            .int => {
                var best_idx: usize = 0;
                var best_value = try numericIntAt(value, 0);
                for (1..len) |idx| {
                    const current = try numericIntAt(value, idx);
                    if (current > best_value) {
                        best_value = current;
                        best_idx = idx;
                    }
                }
                return try self.intValue(@intCast(best_idx));
            },
            .float => {
                var best_idx: usize = 0;
                var best_value = try numericFloatAt(value, 0);
                for (1..len) |idx| {
                    const current = try numericFloatAt(value, idx);
                    if (current > best_value) {
                        best_value = current;
                        best_idx = idx;
                    }
                }
                return try self.intValue(@intCast(best_idx));
            },
        }
    }

    const dense_backend_find_multi_host_len_cpu: usize = 131_072;
    const dense_backend_find_multi_host_len_gpu: usize = 65_536;
    const dense_backend_find_multi_host_query_len: usize = 256;

    fn valueHasHostDenseRealization(value: Value) bool {
        if (valueNumericHandle(value)) |handle| return numericHasHostAttachment(handle);
        return value.tag() == .array and value.arraySubkind() == .host_dense_array;
    }

    fn backendResidentNumericVectorFindPrefersHost(
        self: *Session,
        left: Value,
        right: Value,
        left_len: usize,
        query_len: usize,
    ) bool {
        if (query_len <= 1 or query_len > dense_backend_find_multi_host_query_len) return false;

        const left_facts = denseValuePlanFacts(left);
        const right_facts = denseValuePlanFacts(right);
        if (!(left_facts.has_backend_residency or right_facts.has_backend_residency)) return false;

        const left_host_limit = if (self.device_preference == .gpu)
            dense_backend_find_multi_host_len_gpu
        else
            dense_backend_find_multi_host_len_cpu;

        if (valueHasHostDenseRealization(left)) return true;
        return left_len <= left_host_limit;
    }

    fn findNumericVectorValue(self: *Session, left: Value, right: Value) KError!?Value {
        if (valueNumericMode(left) == null or valueNumericMatrixShape(left) != null) return null;
        const left_len = numericFlatLen(left) orelse return null;
        const query_len = numericRowQueryLen(right) orelse return null;
        if (!backendResidentNumericVectorFindPrefersHost(self, left, right, left_len, query_len)) {
            if (try self.tryFastBackendNumericVectorFindValue(left, right)) |result| return result;
        }
        if (query_len == 1 and
            numericValueSupportsStructuralFlatItemsWithoutHost(left) and
            numericValueSupportsStructuralFlatItemsWithoutHost(right))
        {
            if (try self.tryFastHostNumericVectorFindScalarIndex(left, right, left_len)) |idx| {
                return try self.intValue(@intCast(idx));
            }
        }
        if (valueNumericHandle(left)) |handle| _ = try tryEnsureHostRealizationForHandle(self, @constCast(handle));
        if (valueNumericHandle(right)) |handle| _ = try tryEnsureHostRealizationForHandle(self, @constCast(handle));
        if (query_len == 1) {
            if (try self.tryFastHostNumericVectorFindScalarIndex(left, right, left_len)) |idx| {
                return try self.intValue(@intCast(idx));
            }
        }
        if (query_len != 1) {
            if (try self.tryFastHostNumericVectorFindMultiValue(left, right, left_len)) |result| {
                return result;
            }
            var out = std.ArrayList(i64).empty;
            defer out.deinit(self.allocator);
            try out.ensureTotalCapacity(self.allocator, query_len);
            for (0..query_len) |query_idx| {
                var found_idx: usize = left_len;
                for (0..left_len) |idx| {
                    if (try numericValuesEqualAt(left, idx, right, query_idx)) {
                        found_idx = idx;
                        break;
                    }
                }
                try out.append(self.allocator, @intCast(found_idx));
            }
            return try self.createManagedHostIntArray(out.items);
        }
        for (0..left_len) |idx| {
            if (try numericValuesEqualAt(left, idx, right, 0)) return try self.intValue(@intCast(idx));
        }
        return try self.intValue(@intCast(left_len));
    }

    fn findValues(self: *Session, left: Value, right: Value) KError!Value {
        if (valueNumericMatrixShape(left)) |shape| {
            if (try self.findNumericMatrixRowValue(left, right, shape)) |result| return result;
        }
        if (try self.findNumericVectorValue(left, right)) |result| return result;
        if (left.tag() == .array and left.arrayKind() == .host_keyed_store) {
            const store = left.asHostKeyedStore();
            const key = keyedLookupNameBytes(right) orelse return error.Type;
            return try self.intValue(@intCast(store.lookup.get(key) orelse keyedStoreNameCount(store)));
        }
        if (boxedArrayItems(left)) |items| {
            if (symbolBytes(right) != null) {
                for (items, 0..) |item, idx| {
                    if (try self.valueStructuralEqual(item, right)) return try self.intValue(@intCast(idx));
                }
                return try self.intValue(@intCast(items.len));
            }
        }
        return error.Type;
    }

    fn countValue(self: *Session, value: Value) KError!Value {
        if (stringBytes(value)) |text| return try self.intValue(@intCast(text.len));
        return switch (value.tag()) {
            .array => blk: {
                if (valueNumericHandle(value)) |handle| {
                    if (handle.rank != 0) break :blk try self.intValue(@intCast(handle.shape[0]));
                }
                break :blk switch (value.arrayKind()) {
                    .host_dense_array => try self.intValue(@intCast(value.asHostDenseArray().len())),
                    .host_boxed_array => try self.intValue(@intCast(value.asHostBoxedArray().len())),
                    .host_string_list => try self.intValue(@intCast(value.asHostStringList().len)),
                    .host_relation => try self.intValue(@intCast(try self.relationRowCount(@constCast(value.asHostRelation())))),
                    .host_keyed_store => blk2: {
                        const store = value.asHostKeyedStore();
                        break :blk2 try self.intValue(@intCast(if (store.layout == .table) store.row_count else keyedStoreNameCount(store)));
                    },
                    .backend_array => try self.intValue(@intCast(value.asBackendArray().array.shape()[0])),
                    else => error.Internal,
                };
            },
            else => try self.intValue(1),
        };
    }

    fn floorValue(self: *Session, value: Value) KError!Value {
        return switch (value.tag()) {
            .int, .bool => self.shareValue(value),
            .float => blk: {
                const floored = @floor(value.asFloat());
                const int_value = std.math.lossyCast(i64, floored);
                break :blk try self.intValue(int_value);
            },
            .array => switch (value.arrayKind()) {
                .host_dense_array => if (valueHostIntStructuralView(value) != null)
                    self.shareValue(value)
                else switch (value.asHostDenseArray().storage) {
                    .float64 => |items| blk: {
                        var out = std.ArrayList(i64).empty;
                        defer out.deinit(self.allocator);
                        try out.ensureTotalCapacity(self.allocator, items.len);
                        for (items) |item| try out.append(self.allocator, std.math.lossyCast(i64, @floor(item)));
                        break :blk try self.createManagedHostIntArray(out.items);
                    },
                    else => self.shareValue(value),
                },
                .host_boxed_array => blk: {
                    const items = value.asHostBoxedArray().items;
                    if (items.len == 0) return error.Type;
                    break :blk self.shareValue(items[0]);
                },
                .backend_array, .numeric_array => if (valueHostIntStructuralView(value) != null)
                    self.shareValue(value)
                else switch ((try numericHostArrayValue(self, value)).storage) {
                    .float64 => |items| blk: {
                        var out = std.ArrayList(i64).empty;
                        defer out.deinit(self.allocator);
                        try out.ensureTotalCapacity(self.allocator, items.len);
                        for (items) |item| try out.append(self.allocator, std.math.lossyCast(i64, @floor(item)));
                        break :blk try self.createManagedHostIntArray(out.items);
                    },
                    else => self.shareValue(value),
                },
                else => error.Internal,
            },
            else => error.Type,
        };
    }

    fn iotaBitVectorValue(self: *Session, array: *const HostDenseArray) KError!Value {
        const bits: HostBitSlice = .{ .words = array.storage.bit, .len = array.len() };
        const count = bitCountTrue(bits);
        const out = try self.allocator.alloc(i64, count);
        defer self.allocator.free(out);

        var out_idx: usize = 0;
        for (bits.words, 0..) |_, word_idx| {
            const word_base = word_idx * host_bit_word_bits;
            var selected = bitWordMasked(bits.words, bits.len, word_idx);
            while (selected != 0) {
                const bit_idx: usize = @intCast(@ctz(selected));
                out[out_idx] = @intCast(word_base + bit_idx);
                out_idx += 1;
                selected &= selected - 1;
            }
        }
        return try self.createManagedHostIntArray(out);
    }

    fn iotaIntVectorValue(self: *Session, array: *const HostDenseArray) KError!Value {
        const view = hostIntArrayView(array) orelse return error.Type;
        const rank = hostIntArrayViewLen(view);

        var cols: usize = 1;
        for (0..rank) |idx| {
            const count_i64 = hostIntViewItem(view, idx);
            if (count_i64 < 0) return error.Type;
            const count: usize = @intCast(count_i64);
            cols = std.math.mul(usize, cols, count) catch return error.Unsupported;
        }

        if (cols == 0) {
            const empty = try self.createManagedHostIntArray(&.{});
            return try self.setNumericMatrixShapeOnValue(empty, rank, 0);
        }

        var out = std.ArrayList(i64).empty;
        defer out.deinit(self.allocator);
        try out.ensureTotalCapacity(self.allocator, std.math.mul(usize, rank, cols) catch return error.Unsupported);

        var stride = cols;
        for (0..rank) |axis| {
            const count: usize = @intCast(hostIntViewItem(view, axis));
            stride = @divExact(stride, count);
            for (0..cols) |idx| {
                const digit = @as(i64, @intCast((idx / stride) % count));
                try out.append(self.allocator, digit);
            }
        }

        const value = try self.createManagedHostIntArray(out.items);
        return try self.setNumericMatrixShapeOnValue(value, rank, cols);
    }

    fn whereScalarCountValue(self: *Session, count_value: i64) KError!Value {
        if (count_value < 0) return error.Type;
        const count: usize = @intCast(count_value);
        var out = std.ArrayList(i64).empty;
        defer out.deinit(self.allocator);
        try out.ensureTotalCapacity(self.allocator, count);
        for (0..count) |_| try out.append(self.allocator, 0);
        return try self.createManagedHostIntArray(out.items);
    }

    fn whereBitVectorValue(self: *Session, array: *const HostDenseArray) KError!Value {
        const bits: HostBitSlice = .{ .words = array.storage.bit, .len = array.len() };
        const count = bitCountTrue(bits);
        const out = try self.allocator.alloc(i64, count);
        defer self.allocator.free(out);

        var out_idx: usize = 0;
        for (bits.words, 0..) |_, word_idx| {
            const word_base = word_idx * host_bit_word_bits;
            var selected = bitWordMasked(bits.words, bits.len, word_idx);
            while (selected != 0) {
                const bit_idx: usize = @intCast(@ctz(selected));
                out[out_idx] = @intCast(word_base + bit_idx);
                out_idx += 1;
                selected &= selected - 1;
            }
        }
        return try self.createManagedHostIntArray(out);
    }

    fn whereIntVectorValue(self: *Session, array: *const HostDenseArray) KError!Value {
        const view = hostIntArrayView(array) orelse return error.Type;

        var total: usize = 0;
        for (0..hostIntArrayViewLen(view)) |idx| {
            const count_i64 = hostIntViewItem(view, idx);
            if (count_i64 < 0) return error.Type;
            const count: usize = @intCast(count_i64);
            total = std.math.add(usize, total, count) catch return error.Unsupported;
        }

        var out = std.ArrayList(i64).empty;
        defer out.deinit(self.allocator);
        try out.ensureTotalCapacity(self.allocator, total);

        for (0..hostIntArrayViewLen(view)) |idx| {
            const count: usize = @intCast(hostIntViewItem(view, idx));
            for (0..count) |_| try out.append(self.allocator, @intCast(idx));
        }
        return try self.createManagedHostIntArray(out.items);
    }

    fn whereValue(self: *Session, value: Value) KError!Value {
        if (scalarIntLikeValue(value)) |count_value| return try self.whereScalarCountValue(count_value);
        if (valueNumericMode(value) != null and valueNumericMatrixShape(value) == null) {
            const array = try numericHostArrayValue(self, value);
            return switch (array.storage) {
                .bit => try self.whereBitVectorValue(array),
                .int8, .int16, .int32, .int64 => try self.whereIntVectorValue(array),
                else => error.Type,
            };
        }
        return error.Type;
    }

    fn unitMatrixValue(self: *Session, value: Value) KError!Value {
        const count_i64 = scalarIntLikeValue(value) orelse return error.Type;
        if (count_i64 < 0) return error.Type;
        const count: usize = @intCast(count_i64);
        const len = std.math.mul(usize, count, count) catch return error.Unsupported;

        var out = std.ArrayList(i64).empty;
        defer out.deinit(self.allocator);
        try out.ensureTotalCapacity(self.allocator, len);

        for (0..count) |row| {
            for (0..count) |col| try out.append(self.allocator, if (row == col) 1 else 0);
        }

        const matrix = try self.createManagedHostIntArray(out.items);
        return try self.setNumericMatrixShapeOnValue(matrix, count, count);
    }

    fn iotaValue(self: *Session, value: Value) KError!Value {
        if (scalarIntLikeValue(value)) |count_value| {
            if (count_value < 0) return error.Type;
            const count: usize = @intCast(count_value);
            return try newRangeIotaValue(self, .managed, count);
        }
        if (value.tag() == .array and value.arrayKind() == .host_keyed_store) {
            return self.shareValue(value.asHostKeyedStore().names);
        }
        if (valueNumericMode(value) != null and valueNumericMatrixShape(value) == null) {
            const array = try numericHostArrayValue(self, value);
            return switch (array.storage) {
                .bit => try self.iotaBitVectorValue(array),
                .int8, .int16, .int32, .int64 => try self.iotaIntVectorValue(array),
                else => error.Type,
            };
        }
        return error.Type;
    }

    fn reverseValue(self: *Session, value: Value) KError!Value {
        if (value.tag() == .array) switch (value.arrayKind()) {
            .host_string => return try self.reverseHostString(value.asHostString()),
            .host_string_view => return try self.reverseStringBytes(hostStringViewBytes(value.asHostStringView())),
            .host_string_list => return try self.reverseHostStringList(value.asHostStringList()),
            .host_keyed_store => return try self.reverseKeyedStore(value.asHostKeyedStore()),
            else => {},
        };
        if (valueVectorRangeIotaHandle(value)) |handle| {
            const len = numericArrayRangeLen(handle);
            const start = if (len == 0)
                numericArrayRangeIota(handle).start
            else
                try numericArrayRangeIotaValueAt(handle, len - 1);
            const step = try checkedIntOp(.sub, 0, numericArrayRangeIota(handle).step);
            return try newRangeIotaValueWithParams(self, .managed, len, start, step);
        }
        if (shapedNumericHandle(value)) |handle| {
            const rows: usize = @intCast(handle.shape[0]);
            const start = if (rows == 0) 0 else rows - 1;
            if (try numericValueFirstAxisArithmeticSliceValue(self, value, .{
                .start = start,
                .len = rows,
                .step = -1,
            })) |result| return result;
        }
        if (boxedArrayItems(value)) |items| {
            var out = std.ArrayList(Value).empty;
            defer out.deinit(self.allocator);
            try out.ensureTotalCapacity(self.allocator, items.len);
            var idx = items.len;
            while (idx > 0) {
                idx -= 1;
                try out.append(self.allocator, items[idx]);
            }
            return try self.createManagedHostBoxedArray(out.items);
        }
        const array = try numericHostArrayValue(self, value);
        if (hostNumericMatrixShape(array)) |shape| {
            var row_indices = std.ArrayList(usize).empty;
            defer row_indices.deinit(self.allocator);
            try row_indices.ensureTotalCapacity(self.allocator, shape.rows);
            var idx = shape.rows;
            while (idx > 0) {
                idx -= 1;
                try row_indices.append(self.allocator, idx);
            }
            return try self.createManagedHostNumericMatrixRows(array, row_indices.items, shape.cols);
        }
        return try self.reverseDenseHostVectorValue(value, array);
    }

    fn reverseHostString(self: *Session, text: *const HostText) KError!Value {
        return try self.reverseStringBytes(hostTextBytes(text));
    }

    fn reverseDenseHostVectorValue(self: *Session, value: Value, array: *const HostDenseArray) KError!Value {
        return switch (array.storage) {
            .bit => |words| blk: {
                const out = try self.allocHostBitArray(.managed, array.len());
                bitReverseInto(out.words, .{ .words = words, .len = array.len() });
                break :blk try self.finishManagedHostBitAlloc(out, reversedDenseFlags(array.flags), sourceHostIntRange(value, array));
            },
            .int8 => |items| blk: {
                const out = try self.allocHostArrayTyped(i8, .int8, .managed, items.len);
                reverseTypedSlice(i8, out.items, items);
                const host = out.array;
                hostDenseSetFlags(host, reversedDenseFlags(array.flags));
                hostDenseSetCachedIntRange(host, sourceHostIntRange(value, array));
                break :blk try wrapOwnedHostArrayValue(self, host);
            },
            .int16 => |items| blk: {
                const out = try self.allocHostArrayTyped(i16, .int16, .managed, items.len);
                reverseTypedSlice(i16, out.items, items);
                const host = out.array;
                hostDenseSetFlags(host, reversedDenseFlags(array.flags));
                hostDenseSetCachedIntRange(host, sourceHostIntRange(value, array));
                break :blk try wrapOwnedHostArrayValue(self, host);
            },
            .int32 => |items| blk: {
                const out = try self.allocHostArrayTyped(i32, .int32, .managed, items.len);
                reverseTypedSlice(i32, out.items, items);
                const host = out.array;
                hostDenseSetFlags(host, reversedDenseFlags(array.flags));
                hostDenseSetCachedIntRange(host, sourceHostIntRange(value, array));
                break :blk try wrapOwnedHostArrayValue(self, host);
            },
            .int64 => |items| blk: {
                const out = try self.allocHostArrayTyped(i64, .int64, .managed, items.len);
                reverseTypedSlice(i64, out.items, items);
                const host = out.array;
                hostDenseSetFlags(host, reversedDenseFlags(array.flags));
                hostDenseSetCachedIntRange(host, sourceHostIntRange(value, array));
                break :blk try wrapOwnedHostArrayValue(self, host);
            },
            .float64 => |items| blk: {
                const out = try self.allocHostArrayTyped(f64, .float64, .managed, items.len);
                reverseTypedSlice(f64, out.items, items);
                const host = out.array;
                hostDenseSetFlags(host, reversedDenseFlags(array.flags));
                hostDenseCopyFloatBounds(host, array);
                break :blk try wrapOwnedHostArrayValue(self, host);
            },
        };
    }

    fn reverseStringBytes(self: *Session, src: []const u8) KError!Value {
        const buf = try hostTextAllocSlice(self.allocator, src.len);
        errdefer self.allocator.free(buf);
        const out = hostTextBytesFromAlloc(buf, src.len);
        var idx: usize = src.len;
        var out_idx: usize = 0;
        while (idx > 0) {
            idx -= 1;
            out[out_idx] = src[idx];
            out_idx += 1;
        }
        const owned = hostTextFromAlloc(buf);
        owned.* = .{
            .header = HeapHeader.init(.host_string, .managed),
            .len = src.len,
        };
        return Value.array(owned);
    }

    fn reverseHostStringList(self: *Session, list: *const HostStringList) KError!Value {
        return switch (list.storage) {
            .eager => |items| blk: {
                const reversed = try self.allocator.alloc(HostStringPiece, items.len);
                defer self.allocator.free(reversed);
                var idx: usize = items.len;
                var out_idx: usize = 0;
                while (idx > 0) {
                    idx -= 1;
                    reversed[out_idx] = items[idx];
                    out_idx += 1;
                }
                break :blk try self.createManagedHostStringListPieces(list.base, reversed);
            },
            .split_scalar => |lazy| blk: {
                const base = list.base orelse unreachable;
                const src = hostTextBytes(base);
                const reversed = try self.allocator.alloc(HostStringPiece, list.len);
                defer self.allocator.free(reversed);
                var piece_idx: usize = list.len;
                var start: usize = 0;
                while (std.mem.indexOfScalarPos(u8, src, start, lazy.sep)) |sep_idx| {
                    piece_idx -= 1;
                    reversed[piece_idx] = .{ .view = .{
                        .start = start,
                        .len = sep_idx - start,
                    } };
                    start = sep_idx + 1;
                }
                piece_idx -= 1;
                reversed[piece_idx] = .{ .view = .{
                    .start = start,
                    .len = src.len - start,
                } };
                break :blk try self.createManagedHostStringListPieces(base, reversed);
            },
        };
    }

    fn notValue(self: *Session, value: Value) KError!Value {
        if (boolLikeValue(value)) |truthy| return Value.fromBool(!truthy);
        if (valueHostIntStructuralView(value)) |view| {
            const len = hostIntDenseViewLen(view);
            const out = try self.allocHostBitArray(.managed, len);
            var stats = BitSequenceStats{};
            for (0..len) |idx| {
                const item = (try hostIntDenseViewItem(view, idx)) == 0;
                bitSet(out.words, idx, item);
                stats.note(item);
            }
            const metadata = stats.metadata();
            return try self.finishManagedHostBitAlloc(out, metadata.flags, metadata.range);
        }
        const array = try numericHostArrayValue(self, value);
        switch (array.storage) {
            .bit => |words| {
                const plan = try self.planHostIntUnaryOutput(hostDenseSourceValue(array), .bit, .bit, array.len(), true, true);
                fillBitNotWords(plan.output.bit.words, .{ .words = words, .len = array.len() });
                const result = try self.finishHostIntOutput(plan, host_dense_flag_normalized | invertMonotonicFlags(array.flags));
                hostDenseSetCachedIntRange(try mutableNumericHostArrayValue(self, result), .{ .min = 0, .max = 1 });
                return result;
            },
            .float64 => |items| {
                const out = try self.allocHostBitArray(.managed, items.len);
                var stats = BitSequenceStats{};
                for (items, 0..) |item, idx| {
                    const bit = item == 0.0;
                    bitSet(out.words, idx, bit);
                    stats.note(bit);
                }
                const metadata = stats.metadata();
                return try self.finishManagedHostBitAlloc(out, metadata.flags, metadata.range);
            },
            else => {
                const view = hostIntArrayView(array).?;
                const len = hostIntArrayViewLen(view);
                const out = try self.allocHostBitArray(.managed, len);
                var stats = BitSequenceStats{};
                for (0..len) |idx| {
                    const bit = hostIntViewItem(view, idx) == 0;
                    bitSet(out.words, idx, bit);
                    stats.note(bit);
                }
                const metadata = stats.metadata();
                return try self.finishManagedHostBitAlloc(out, metadata.flags, metadata.range);
            },
        }
    }

    fn scalarNullLikeValue(value: Value) bool {
        if (tableScalarValue(value)) |scalar| return scalar.is_null;
        return switch (value.tag()) {
            .int, .float, .bool, .builtin, .closure => false,
            .array => switch (value.arrayKind()) {
                .host_symbol => hostTextBytes(value.asHostSymbol()).len == 0,
                else => false,
            },
        };
    }

    fn valueIsAtomicForFillWithout(value: Value) bool {
        return switch (value.tag()) {
            .array => switch (value.arrayKind()) {
                .host_symbol, .host_table_scalar => true,
                else => false,
            },
            else => true,
        };
    }

    fn numericFalseMaskValue(self: *Session, value: Value) KError!Value {
        const total = numericFlatLen(value) orelse if (value.tag() == .array)
            (try numericHostArrayValue(self, value)).len()
        else
            return Value.fromBool(false);
        const bits = try self.allocator.alloc(bool, total);
        defer self.allocator.free(bits);
        @memset(bits, false);
        const mask = try self.createManagedHostBitArray(bits);
        if (valueNonVectorNumericShape(value)) |shape| return try applyNonVectorNumericShapeToValue(self, mask, shape);
        return mask;
    }

    fn nullValue(self: *Session, value: Value) KError!Value {
        if (scalarNullLikeValue(value)) return Value.fromBool(true);
        if (tableScalarValue(value)) |scalar| return Value.fromBool(scalar.is_null);
        if (value.tag() != .array) return Value.fromBool(false);

        if (stringBytes(value)) |text| {
            const bits = try self.allocator.alloc(bool, text.len);
            defer self.allocator.free(bits);
            @memset(bits, false);
            return try self.createManagedHostBitArray(bits);
        }
        if (valueNumericMode(value) != null) return try self.numericFalseMaskValue(value);
        if (boxedArrayItems(value)) |items| {
            var out = std.ArrayList(Value).empty;
            defer out.deinit(self.allocator);
            try out.ensureTotalCapacity(self.allocator, items.len);
            for (items) |item| try out.append(self.allocator, try self.nullValue(item));
            return try self.makeArrayFromValues(out.items);
        }
        return switch (value.arrayKind()) {
            .host_string_list => blk: {
                const bits = try self.allocator.alloc(bool, value.asHostStringList().len);
                defer self.allocator.free(bits);
                @memset(bits, false);
                break :blk try self.createManagedHostBitArray(bits);
            },
            .host_symbol => Value.fromBool(false),
            else => error.Type,
        };
    }

    fn fillValues(self: *Session, left: Value, right: Value) KError!Value {
        if (scalarNullLikeValue(right)) return self.shareValue(left);
        if (right.tag() != .array) return self.shareValue(right);
        if (boxedArrayItems(right)) |items| {
            var out = std.ArrayList(Value).empty;
            defer out.deinit(self.allocator);
            try out.ensureTotalCapacity(self.allocator, items.len);
            for (items) |item| try out.append(self.allocator, try self.fillValues(left, item));
            return try self.makeArrayFromValues(out.items);
        }
        return self.shareValue(right);
    }

    fn numericScalarItemValue(self: *Session, value: Value, idx: usize) KError!Value {
        const array = try numericHostArrayValue(self, value);
        return try self.hostDenseIndexScalar(array, @intCast(idx));
    }

    fn sequenceContainsValue(self: *Session, haystack: Value, needle: Value) KError!bool {
        if (valueNumericMatrixShape(haystack)) |shape| {
            for (0..shape.rows) |row_idx| {
                const item = try numericValueFirstAxisCellValue(self, haystack, shapedNumericHandle(haystack).?, @intCast(row_idx));
                defer self.releaseValue(item);
                if (try self.valueStructuralEqual(item, needle)) return true;
            }
            return false;
        }
        if (valueNumericMode(haystack) != null) {
            const len = numericFlatLen(haystack) orelse (try numericHostArrayValue(self, haystack)).len();
            for (0..len) |idx| {
                const item = try self.numericScalarItemValue(haystack, idx);
                defer self.releaseValue(item);
                if (try self.valueStructuralEqual(item, needle)) return true;
            }
            return false;
        }
        if (boxedArrayItems(haystack)) |items| {
            for (items) |item| {
                if (try self.valueStructuralEqual(item, needle)) return true;
            }
            return false;
        }
        return try self.valueStructuralEqual(haystack, needle);
    }

    fn withoutStringValues(self: *Session, left: []const u8, right: Value) KError!Value {
        const removed = stringBytes(right) orelse return error.Type;
        var lookup = [_]bool{false} ** 256;
        for (removed) |ch| lookup[ch] = true;
        var out = std.ArrayList(u8).empty;
        defer out.deinit(self.allocator);
        for (left) |ch| {
            if (!lookup[ch]) try out.append(self.allocator, ch);
        }
        return try self.managedHostString(out.items);
    }

    fn withoutNumericVectorValues(self: *Session, left: Value, right: Value) KError!Value {
        const source = try numericHostArrayValue(self, left);
        const len = source.len();
        var removed_any = false;

        switch (source.storage) {
            .bit => {
                const remove_false = try self.sequenceContainsValue(right, Value.fromBool(false));
                const remove_true = try self.sequenceContainsValue(right, Value.fromBool(true));
                if (!remove_false and !remove_true) return self.shareValue(left);

                const bits: HostBitSlice = .{ .words = source.storage.bit, .len = len };
                const count_true = bitCountTrue(bits);
                const count_false = len - count_true;
                const out_len = (if (remove_false) 0 else count_false) + (if (remove_true) 0 else count_true);
                const out = try self.allocHostBitArray(.managed, out_len);

                if (!remove_false and remove_true) {
                    const metadata = (BitSequenceStats{
                        .saw_zero = out_len != 0,
                        .has_prev = out_len != 0,
                        .prev = false,
                    }).metadata();
                    return try self.finishManagedHostBitAlloc(out, metadata.flags, metadata.range);
                }
                if (remove_false and !remove_true) {
                    bitFill(out.words, out.len, true);
                    const metadata = (BitSequenceStats{
                        .saw_one = out_len != 0,
                        .has_prev = out_len != 0,
                        .prev = true,
                    }).metadata();
                    return try self.finishManagedHostBitAlloc(out, metadata.flags, metadata.range);
                }
                removed_any = true;
                return try self.finishManagedHostBitAlloc(out, host_dense_flag_normalized | host_dense_flag_asc | host_dense_flag_dsc, .{ .min = 0, .max = 0 });
            },
            .float64 => |items| {
                var out = std.ArrayList(f64).empty;
                defer out.deinit(self.allocator);
                for (items) |item| {
                    const value = try self.floatValue(item);
                    if (try self.sequenceContainsValue(right, value)) {
                        removed_any = true;
                        continue;
                    }
                    try out.append(self.allocator, item);
                }
                if (!removed_any) return self.shareValue(left);
                return try self.createManagedHostFloatArray(out.items);
            },
            else => {
                const view = hostIntArrayView(source).?;
                var out = std.ArrayList(i64).empty;
                defer out.deinit(self.allocator);
                for (0..hostIntArrayViewLen(view)) |idx| {
                    const item_value = try self.intValue(hostIntViewItem(view, idx));
                    if (try self.sequenceContainsValue(right, item_value)) {
                        removed_any = true;
                        continue;
                    }
                    try out.append(self.allocator, item_value.asInt());
                }
                if (!removed_any) return self.shareValue(left);
                return try self.createManagedHostIntArray(out.items);
            },
        }
    }

    fn withoutNumericMatrixValues(self: *Session, left: Value, right: Value, shape: NumericMatrixShape) KError!Value {
        var row_indices = std.ArrayList(usize).empty;
        defer row_indices.deinit(self.allocator);
        try row_indices.ensureTotalCapacity(self.allocator, shape.rows);
        var removed_any = false;
        for (0..shape.rows) |row_idx| {
            const row = try numericValueFirstAxisCellValue(self, left, shapedNumericHandle(left).?, @intCast(row_idx));
            defer self.releaseValue(row);
            if (try self.sequenceContainsValue(right, row)) {
                removed_any = true;
                continue;
            }
            try row_indices.append(self.allocator, row_idx);
        }
        if (!removed_any) return self.shareValue(left);
        return try numericValueMatrixSelectRows(self, left, row_indices.items);
    }

    fn withoutBoxedValues(self: *Session, left: Value, right: Value, items: []const Value) KError!Value {
        var out = std.ArrayList(Value).empty;
        defer out.deinit(self.allocator);
        try out.ensureTotalCapacity(self.allocator, items.len);
        var removed_any = false;
        for (items) |item| {
            if (try self.sequenceContainsValue(right, item)) {
                removed_any = true;
                continue;
            }
            try out.append(self.allocator, item);
        }
        if (!removed_any) return self.shareValue(left);
        return try self.makeArrayFromValues(out.items);
    }

    fn withoutValues(self: *Session, left: Value, right: Value) KError!Value {
        if (stringBytes(left)) |text| return try self.withoutStringValues(text, right);
        if (valueNumericMatrixShape(left)) |shape| return try self.withoutNumericMatrixValues(left, right, shape);
        if (valueNumericMode(left) != null) return try self.withoutNumericVectorValues(left, right);
        if (boxedArrayItems(left)) |items| return try self.withoutBoxedValues(left, right, items);
        return error.Type;
    }

    fn fillWithoutValues(self: *Session, left: Value, right: Value) KError!Value {
        if (valueIsAtomicForFillWithout(left)) return try self.fillValues(left, right);
        return try self.withoutValues(left, right);
    }

    fn hostNumericMatrixRowOrder(array: *const HostDenseArray, lhs_row: usize, rhs_row: usize, cols: usize) std.math.Order {
        const left_base = lhs_row * cols;
        const right_base = rhs_row * cols;
        return switch (array.storage) {
            .bit => {
                for (0..cols) |col| {
                    const order = std.math.order(
                        @intFromBool(bitGet(array.storage.bit, left_base + col)),
                        @intFromBool(bitGet(array.storage.bit, right_base + col)),
                    );
                    if (order != .eq) return order;
                }
                return .eq;
            },
            .float64 => |items| {
                for (0..cols) |col| {
                    const order = std.math.order(items[left_base + col], items[right_base + col]);
                    if (order != .eq) return order;
                }
                return .eq;
            },
            else => {
                const view = hostIntArrayView(array).?;
                for (0..cols) |col| {
                    const order = std.math.order(hostIntViewItem(view, left_base + col), hostIntViewItem(view, right_base + col));
                    if (order != .eq) return order;
                }
                return .eq;
            },
        };
    }

    fn hostItemOrder(array: *const HostDenseArray, lhs: usize, rhs: usize) std.math.Order {
        if (hostNumericMatrixShape(array)) |shape| return hostNumericMatrixRowOrder(array, lhs, rhs, shape.cols);
        return switch (array.storage) {
            .bit => std.math.order(@intFromBool(bitGet(array.storage.bit, lhs)), @intFromBool(bitGet(array.storage.bit, rhs))),
            .float64 => std.math.order(array.storage.float64[lhs], array.storage.float64[rhs]),
            else => std.math.order(hostIntViewItem(hostIntArrayView(array).?, lhs), hostIntViewItem(hostIntArrayView(array).?, rhs)),
        };
    }

    fn orderComesBefore(order: std.math.Order, ascending: bool) bool {
        return if (ascending) order == .lt else order == .gt;
    }

    fn hostIndexedOrder(_: *Session, array: *const HostDenseArray, lhs: usize, rhs: usize) KError!std.math.Order {
        return hostItemOrder(array, lhs, rhs);
    }

    fn numericVectorIndexedOrder(_: *Session, value: Value, lhs: usize, rhs: usize) KError!std.math.Order {
        return switch (valueNumericMode(value) orelse return error.Type) {
            .float => std.math.order(try numericFloatAt(value, lhs), try numericFloatAt(value, rhs)),
            .int => std.math.order(try numericIntAt(value, lhs), try numericIntAt(value, rhs)),
        };
    }

    fn numericMatrixIndexedOrder(self: *Session, view: NumericMatrixView, lhs: usize, rhs: usize) KError!std.math.Order {
        return try numericMatrixRowOrder(self, view, lhs, rhs);
    }

    fn stableMergeSortIndices(
        self: *Session,
        idxs: []usize,
        ascending: bool,
        context: anytype,
        comptime orderFn: fn (*Session, @TypeOf(context), usize, usize) KError!std.math.Order,
    ) KError!void {
        if (idxs.len <= 1) return;
        const scratch = try self.allocator.alloc(usize, idxs.len);
        defer self.allocator.free(scratch);

        var src: []usize = idxs;
        var dst: []usize = scratch;
        var width: usize = 1;
        var flipped = false;
        while (width < idxs.len) {
            var start: usize = 0;
            while (start < src.len) : (start += width * 2) {
                const mid = @min(start + width, src.len);
                const end = @min(start + width * 2, src.len);
                var left = start;
                var right = mid;
                var out = start;
                while (left < mid and right < end) : (out += 1) {
                    const order = try orderFn(self, context, src[right], src[left]);
                    if (orderComesBefore(order, ascending)) {
                        dst[out] = src[right];
                        right += 1;
                    } else {
                        dst[out] = src[left];
                        left += 1;
                    }
                }
                while (left < mid) : ({
                    left += 1;
                    out += 1;
                }) dst[out] = src[left];
                while (right < end) : ({
                    right += 1;
                    out += 1;
                }) dst[out] = src[right];
            }
            const next_width = if (width > idxs.len / 2) idxs.len else width * 2;
            const tmp = src;
            src = dst;
            dst = tmp;
            width = next_width;
            flipped = !flipped;
        }
        if (flipped) @memcpy(idxs, src);
    }

    fn reverseIndexValue(self: *Session, len: usize) KError!Value {
        if (len == 0) return try newRangeIotaValue(self, .managed, 0);
        const start = std.math.cast(i64, len - 1) orelse return error.Unsupported;
        return try newRangeIotaValueWithParams(self, .managed, len, start, -1);
    }

    fn tryMonotonicGradeValue(self: *Session, len: usize, flags: u8, ascending: bool) KError!?Value {
        if (len <= 1) return try newRangeIotaValue(self, .managed, len);

        const mono = monotonicFlags(flags);
        if (mono == 0) return null;

        const direct_flag = if (ascending) host_dense_flag_asc else host_dense_flag_dsc;
        if ((mono & direct_flag) != 0) return try newRangeIotaValue(self, .managed, len);
        return null;
    }

    fn managedHostIndexArrayValue(self: *Session, idxs: []const usize) KError!Value {
        const max_value = if (idxs.len == 0)
            0
        else
            std.math.cast(i64, idxs.len - 1) orelse return error.Unsupported;

        var out = try self.allocManagedHostIntResult(hostIntStorageKindForRange(0, max_value), idxs.len);
        var asc = true;
        var dsc = true;
        var prev: i64 = 0;
        for (idxs, 0..) |idx, out_idx| {
            const value = std.math.cast(i64, idx) orelse return error.Unsupported;
            try out.set(out_idx, value);
            if (out_idx != 0) {
                if (prev > value) asc = false;
                if (prev < value) dsc = false;
            }
            prev = value;
        }

        const value = try out.value(self);
        const host = try mutableNumericHostArrayValue(self, value);
        hostDenseSetFlags(host, host_dense_flag_normalized | orderFlagsFromMonotonic(asc, dsc));
        hostDenseSetCachedIntRange(host, .{ .min = 0, .max = max_value });
        return value;
    }

    fn intGradeRangeLen(range: HostIntRange) ?usize {
        const len_i128 = @as(i128, range.max) - @as(i128, range.min) + 1;
        if (len_i128 <= 0 or len_i128 > std.math.maxInt(usize)) return null;
        return @intCast(len_i128);
    }

    fn preferBucketIntGrade(len: usize, range_len: usize) bool {
        if (range_len == 0) return false;
        if (range_len > (1 << 18)) return false;
        const scaled_len = std.math.mul(usize, len, 16) catch std.math.maxInt(usize);
        return range_len <= scaled_len;
    }

    const small_grade_stack_threshold: usize = 128;
    const small_dense_int8_grade_threshold: usize = 24;
    const small_dense_int16_grade_threshold: usize = 48;
    const small_dense_int32_grade_threshold: usize = 64;
    const small_dense_int64_grade_threshold: usize = 64;
    const small_dense_float_grade_threshold: usize = 64;

    fn gradeResultMaxValue(len: usize) KError!i64 {
        return if (len == 0)
            0
        else
            std.math.cast(i64, len - 1) orelse return error.Unsupported;
    }

    fn analyzeGradeIndexSlice(comptime T: type, items: []const T) u8 {
        if (items.len <= 1) return host_dense_flag_normalized | host_dense_flag_asc | host_dense_flag_dsc;

        var asc = true;
        var dsc = true;
        var prev: i64 = items[0];
        for (items[1..]) |item| {
            const value: i64 = item;
            if (prev > value) asc = false;
            if (prev < value) dsc = false;
            prev = value;
        }
        return host_dense_flag_normalized | orderFlagsFromMonotonic(asc, dsc);
    }

    fn finalizeManagedGradeResult(self: *Session, out: *HostIntResult, max_value: i64) KError!Value {
        const flags = switch (out.*) {
            .bit => unreachable,
            .int8 => |dest| analyzeGradeIndexSlice(i8, dest.items),
            .int16 => |dest| analyzeGradeIndexSlice(i16, dest.items),
            .int32 => |dest| analyzeGradeIndexSlice(i32, dest.items),
            .int64 => |dest| analyzeGradeIndexSlice(i64, dest.items),
        };

        const value = try out.value(self);
        const host = try mutableNumericHostArrayValue(self, value);
        hostDenseSetFlags(host, flags);
        hostDenseSetCachedIntRange(host, .{ .min = 0, .max = max_value });
        return value;
    }

    fn fillTypedBooleanGradeIndicesBitSlice(comptime IdxT: type, out: []IdxT, bits: HostBitSlice, ascending: bool) void {
        const count_one = bitCountTrue(bits);
        var zero_pos: usize = if (ascending) 0 else count_one;
        var one_pos: usize = if (ascending) bits.len - count_one else 0;

        for (bits.words, 0..) |_, word_idx| {
            const active_mask = if (word_idx + 1 == bits.words.len) bitTailMask(bits.len) else std.math.maxInt(u64);
            const word = bits.words[word_idx] & active_mask;
            const word_base = word_idx * host_bit_word_bits;

            var zeros = (~word) & active_mask;
            while (zeros != 0) {
                const bit_idx: usize = @intCast(@ctz(zeros));
                out[zero_pos] = @intCast(word_base + bit_idx);
                zero_pos += 1;
                zeros &= zeros - 1;
            }

            var ones = word;
            while (ones != 0) {
                const bit_idx: usize = @intCast(@ctz(ones));
                out[one_pos] = @intCast(word_base + bit_idx);
                one_pos += 1;
                ones &= ones - 1;
            }
        }
        std.debug.assert(zero_pos == (if (ascending) bits.len - count_one else bits.len));
        std.debug.assert(one_pos == (if (ascending) bits.len else count_one));
    }

    fn fillTypedBooleanGradeIndicesIntSlice(comptime T: type, comptime IdxT: type, out: []IdxT, items: []const T, ascending: bool) void {
        var count_one: usize = 0;
        for (items) |item| {
            if (item != 0) count_one += 1;
        }

        var zero_pos: usize = if (ascending) 0 else count_one;
        var one_pos: usize = if (ascending) out.len - count_one else 0;
        for (items, 0..) |item, idx| {
            if (item == 0) {
                out[zero_pos] = @intCast(idx);
                zero_pos += 1;
            } else {
                out[one_pos] = @intCast(idx);
                one_pos += 1;
            }
        }
    }

    fn fillTypedBooleanGradeResult(comptime IdxT: type, dest: []IdxT, items: HostIntArrayView, ascending: bool) void {
        switch (items) {
            .bit => |bits| fillTypedBooleanGradeIndicesBitSlice(IdxT, dest, bits, ascending),
            .int8 => |slice| fillTypedBooleanGradeIndicesIntSlice(i8, IdxT, dest, slice, ascending),
            .int16 => |slice| fillTypedBooleanGradeIndicesIntSlice(i16, IdxT, dest, slice, ascending),
            .int32 => |slice| fillTypedBooleanGradeIndicesIntSlice(i32, IdxT, dest, slice, ascending),
            .int64 => |slice| fillTypedBooleanGradeIndicesIntSlice(i64, IdxT, dest, slice, ascending),
        }
    }

    fn managedHostBooleanGradeValue(self: *Session, view: HostIntDenseView, len: usize, ascending: bool) KError!Value {
        switch (view) {
            .dense => |items| {
                const max_value = try gradeResultMaxValue(len);
                var out = try self.allocManagedHostIntResult(hostIntStorageKindForRange(0, max_value), len);
                switch (out) {
                    .bit => unreachable,
                    .int8 => |*dest| fillTypedBooleanGradeResult(i8, dest.items, items, ascending),
                    .int16 => |*dest| fillTypedBooleanGradeResult(i16, dest.items, items, ascending),
                    .int32 => |*dest| fillTypedBooleanGradeResult(i32, dest.items, items, ascending),
                    .int64 => |*dest| fillTypedBooleanGradeResult(i64, dest.items, items, ascending),
                }
                return try finalizeManagedGradeResult(self, &out, max_value);
            },
            else => {
                if (len <= small_grade_stack_threshold) {
                    var idxs_buf: [small_grade_stack_threshold]usize = undefined;
                    const idxs = idxs_buf[0..len];
                    try fillBooleanGradeIndices(idxs, view, ascending);
                    return try self.managedHostIndexArrayValue(idxs);
                }

                const idxs = try self.allocator.alloc(usize, len);
                defer self.allocator.free(idxs);
                try fillBooleanGradeIndices(idxs, view, ascending);
                return try self.managedHostIndexArrayValue(idxs);
            },
        }
    }

    fn int8GradeBucket(item: i8) u8 {
        return @as(u8, @bitCast(item)) ^ 0x80;
    }

    fn fillTypedReverseMonotonicGradeIndicesBitSlice(comptime IdxT: type, out: []IdxT, bits: HostBitSlice) bool {
        var out_idx: usize = 0;
        var scan = bits.len;
        var unique = true;
        while (scan > 0) {
            const run_end = scan;
            const run_value = bitGet(bits.words, run_end - 1);
            scan -= 1;
            while (scan > 0 and bitGet(bits.words, scan - 1) == run_value) : (scan -= 1) {
                unique = false;
            }
            for (scan..run_end) |idx| {
                out[out_idx] = @intCast(idx);
                out_idx += 1;
            }
        }
        return unique;
    }

    fn fillTypedReverseMonotonicGradeIndicesIntSlice(comptime T: type, comptime IdxT: type, out: []IdxT, items: []const T) bool {
        var out_idx: usize = 0;
        var scan = items.len;
        var unique = true;
        while (scan > 0) {
            const run_end = scan;
            const run_value = items[run_end - 1];
            scan -= 1;
            while (scan > 0 and items[scan - 1] == run_value) : (scan -= 1) {
                unique = false;
            }
            for (scan..run_end) |idx| {
                out[out_idx] = @intCast(idx);
                out_idx += 1;
            }
        }
        return unique;
    }

    fn fillTypedReverseMonotonicGradeIndicesFloatSlice(comptime IdxT: type, out: []IdxT, items: []const f64) bool {
        var out_idx: usize = 0;
        var scan = items.len;
        var unique = true;
        while (scan > 0) {
            const run_end = scan;
            const run_value = items[run_end - 1];
            scan -= 1;
            while (scan > 0 and std.math.order(items[scan - 1], run_value) == .eq) : (scan -= 1) {
                unique = false;
            }
            for (scan..run_end) |idx| {
                out[out_idx] = @intCast(idx);
                out_idx += 1;
            }
        }
        return unique;
    }

    fn fillTypedInsertionGradeIndicesIntSlice(comptime T: type, comptime IdxT: type, out: []IdxT, items: []const T, ascending: bool) void {
        for (out, 0..) |*slot, idx| slot.* = @intCast(idx);
        for (1..out.len) |idx| {
            const key_idx = @as(usize, @intCast(out[idx]));
            const key = items[key_idx];
            var scan = idx;
            while (scan > 0) {
                const prev_idx = @as(usize, @intCast(out[scan - 1]));
                if (!orderComesBefore(std.math.order(key, items[prev_idx]), ascending)) break;
                out[scan] = @intCast(prev_idx);
                scan -= 1;
            }
            out[scan] = @intCast(key_idx);
        }
    }

    fn fillTypedInsertionGradeIndicesFloatSlice(comptime IdxT: type, out: []IdxT, items: []const f64, ascending: bool) void {
        for (out, 0..) |*slot, idx| slot.* = @intCast(idx);
        for (1..out.len) |idx| {
            const key_idx = @as(usize, @intCast(out[idx]));
            const key = items[key_idx];
            var scan = idx;
            while (scan > 0) {
                const prev_idx = @as(usize, @intCast(out[scan - 1]));
                if (!orderComesBefore(std.math.order(key, items[prev_idx]), ascending)) break;
                out[scan] = @intCast(prev_idx);
                scan -= 1;
            }
            out[scan] = @intCast(key_idx);
        }
    }

    fn fillTypedInt8GradeResult(comptime T: type, dest: []T, items: []const i8, counts: *[256]usize) void {
        for (items, 0..) |item, idx| {
            const bucket = int8GradeBucket(item);
            const out_idx = counts[bucket];
            counts[bucket] = out_idx + 1;
            dest[out_idx] = @intCast(idx);
        }
    }

    fn managedHostInt8GradeValue(self: *Session, items: []const i8, ascending: bool) KError!Value {
        const max_value = try gradeResultMaxValue(items.len);

        var out = try self.allocManagedHostIntResult(hostIntStorageKindForRange(0, max_value), items.len);
        var counts: [256]usize = undefined;
        @memset(counts[0..], 0);

        for (items) |item| {
            counts[int8GradeBucket(item)] += 1;
        }

        var total: usize = 0;
        if (ascending) {
            for (counts[0..]) |*count| {
                const next = total + count.*;
                count.* = total;
                total = next;
            }
        } else {
            var bucket = counts.len;
            while (bucket > 0) {
                bucket -= 1;
                const next = total + counts[bucket];
                counts[bucket] = total;
                total = next;
            }
        }

        switch (out) {
            .bit => unreachable,
            .int8 => |*dest| fillTypedInt8GradeResult(i8, dest.items, items, &counts),
            .int16 => |*dest| fillTypedInt8GradeResult(i16, dest.items, items, &counts),
            .int32 => |*dest| fillTypedInt8GradeResult(i32, dest.items, items, &counts),
            .int64 => |*dest| fillTypedInt8GradeResult(i64, dest.items, items, &counts),
        }

        return try finalizeManagedGradeResult(self, &out, max_value);
    }

    fn fillBooleanGradeIndices(out: []usize, view: HostIntDenseView, ascending: bool) KError!void {
        switch (view) {
            .dense => |items| switch (items) {
                .bit => |bits| fillTypedBooleanGradeIndicesBitSlice(usize, out, bits, ascending),
                .int8 => |slice| fillTypedBooleanGradeIndicesIntSlice(i8, usize, out, slice, ascending),
                .int16 => |slice| fillTypedBooleanGradeIndicesIntSlice(i16, usize, out, slice, ascending),
                .int32 => |slice| fillTypedBooleanGradeIndicesIntSlice(i32, usize, out, slice, ascending),
                .int64 => |slice| fillTypedBooleanGradeIndicesIntSlice(i64, usize, out, slice, ascending),
            },
            else => {
                var count_one: usize = 0;
                for (0..out.len) |idx| {
                    if ((try hostIntDenseViewItem(view, idx)) != 0) count_one += 1;
                }

                var zero_pos: usize = if (ascending) 0 else count_one;
                var one_pos: usize = if (ascending) out.len - count_one else 0;
                for (0..out.len) |idx| {
                    if ((try hostIntDenseViewItem(view, idx)) == 0) {
                        out[zero_pos] = idx;
                        zero_pos += 1;
                    } else {
                        out[one_pos] = idx;
                        one_pos += 1;
                    }
                }
            },
        }
    }

    fn fillBucketGradeIndices(out: []usize, view: HostIntDenseView, range: HostIntRange, ascending: bool, allocator: std.mem.Allocator) KError!void {
        const bucket_count = intGradeRangeLen(range) orelse return error.Unsupported;
        const counts = try allocator.alloc(usize, bucket_count);
        defer allocator.free(counts);
        @memset(counts, 0);

        for (0..out.len) |idx| {
            const value = try hostIntDenseViewItem(view, idx);
            const bucket_i128 = if (ascending)
                @as(i128, value) - @as(i128, range.min)
            else
                @as(i128, range.max) - @as(i128, value);
            counts[@intCast(bucket_i128)] += 1;
        }

        var total: usize = 0;
        for (counts) |*count| {
            const next = total + count.*;
            count.* = total;
            total = next;
        }

        for (0..out.len) |idx| {
            const value = try hostIntDenseViewItem(view, idx);
            const bucket_i128 = if (ascending)
                @as(i128, value) - @as(i128, range.min)
            else
                @as(i128, range.max) - @as(i128, value);
            const bucket: usize = @intCast(bucket_i128);
            out[counts[bucket]] = idx;
            counts[bucket] += 1;
        }
    }

    fn intGradePassCount(kind: HostIntStorageKind) usize {
        return switch (kind) {
            .bit, .int8 => 1,
            .int16 => 2,
            .int32 => 4,
            .int64 => 8,
        };
    }

    fn intGradeKey(value: i64, kind: HostIntStorageKind, ascending: bool) u64 {
        const key = switch (kind) {
            .bit => @as(u64, @intCast(value)),
            .int8 => @as(u64, @as(u8, @bitCast(std.math.cast(i8, value) orelse unreachable)) ^ 0x80),
            .int16 => @as(u64, @as(u16, @bitCast(std.math.cast(i16, value) orelse unreachable)) ^ 0x8000),
            .int32 => @as(u64, @as(u32, @bitCast(std.math.cast(i32, value) orelse unreachable)) ^ 0x8000_0000),
            .int64 => @as(u64, @bitCast(value)) ^ 0x8000_0000_0000_0000,
        };
        return if (ascending) key else ~key;
    }

    fn intGradeKeyTyped(comptime T: type, value: T, ascending: bool) std.meta.Int(.unsigned, @bitSizeOf(T)) {
        const KeyT = std.meta.Int(.unsigned, @bitSizeOf(T));
        const sign_mask: KeyT = @as(KeyT, 1) << (@bitSizeOf(T) - 1);
        const key = @as(KeyT, @bitCast(value)) ^ sign_mask;
        return if (ascending) key else ~key;
    }

    fn floatGradeKey(value: f64, ascending: bool) ?u64 {
        if (std.math.isNan(value)) return null;
        const key = if (value == 0.0)
            @as(u64, 0x8000_0000_0000_0000)
        else blk: {
            const bits: u64 = @bitCast(value);
            break :blk if ((bits & 0x8000_0000_0000_0000) != 0)
                ~bits
            else
                bits ^ 0x8000_0000_0000_0000;
        };
        return if (ascending) key else ~key;
    }

    fn fillInsertionGradeIndicesIntSlice(comptime T: type, out: []usize, items: []const T, ascending: bool) void {
        for (out, 0..) |*slot, idx| slot.* = idx;
        for (1..out.len) |idx| {
            const key_idx = out[idx];
            const key = items[key_idx];
            var scan = idx;
            while (scan > 0) {
                const prev_idx = out[scan - 1];
                if (!orderComesBefore(std.math.order(key, items[prev_idx]), ascending)) break;
                out[scan] = prev_idx;
                scan -= 1;
            }
            out[scan] = key_idx;
        }
    }

