            const next = total + count.*;
            count.* = total;
            total = next;
        }

        for (items, 0..) |item, idx| {
            const value: i64 = item;
            const bucket_i128 = if (ascending)
                @as(i128, value) - @as(i128, range.min)
            else
                @as(i128, range.max) - @as(i128, value);
