    fn managedHostDenseFloatRadixGradeValue(self: *Session, items: []const f64, ascending: bool) KError!?Value {
        const len = items.len;
        const max_value = try gradeResultMaxValue(len);
        var out = try self.allocManagedHostIntResult(hostIntStorageKindForRange(0, max_value), len);
        if (!try fillManagedDenseFloatRadixGradeResult(self, &out, items, ascending)) return null;
        return try finalizeManagedGradeResult(self, &out, max_value);
    }

    fn tryFastHostFloatDenseGradeValue(self: *Session, value: Value, view: HostFloatDenseView, ascending: bool) KError!?Value {
        const len = hostFloatDenseViewLen(view);
        if (len <= 1) return try newRangeIotaValue(self, .managed, len);
        const flags = hostFloatDenseValueFlags(value, view);
        if (try self.tryMonotonicGradeValue(len, flags, ascending)) |result| return result;

        const mono = monotonicFlags(flags);
        const reverse_flag = if (ascending) host_dense_flag_dsc else host_dense_flag_asc;
        if ((mono & reverse_flag) != 0) {
            return switch (view) {
                .dense => |items| blk: {
                    const result = try self.managedHostDenseFloatReverseMonotonicGradeValue(items);
                    if (result.unique) break :blk try self.reverseIndexValue(len);
                    break :blk result.value;
                },
                else => blk: {
                    if (len <= small_grade_stack_threshold) {
                        var idxs_buf: [small_grade_stack_threshold]usize = undefined;
                        const idxs = idxs_buf[0..len];
                        const unique = try fillReverseMonotonicGradeIndicesFloatView(idxs, view);
                        if (unique) break :blk try self.reverseIndexValue(len);
                        break :blk try self.managedHostIndexArrayValue(idxs);
                    }

                    const idxs = try self.allocator.alloc(usize, len);
                    defer self.allocator.free(idxs);
                    const unique = try fillReverseMonotonicGradeIndicesFloatView(idxs, view);
                    if (unique) break :blk try self.reverseIndexValue(len);
                    break :blk try self.managedHostIndexArrayValue(idxs);
                },
            };
        }

        if (len <= small_dense_float_grade_threshold) {
            return switch (view) {
                .dense => |items| try self.managedHostDenseFloatInsertionGradeValue(items, ascending),
                else => blk: {
                    var idxs_buf: [small_grade_stack_threshold]usize = undefined;
                    const idxs = idxs_buf[0..len];
                    try fillInsertionGradeIndicesFloatView(idxs, view, ascending);
                    break :blk try self.managedHostIndexArrayValue(idxs);
                },
            };
        }

        return switch (view) {
            .dense => |items| try self.managedHostDenseFloatRadixGradeValue(items, ascending),
            else => blk: {
                const idxs = try self.allocator.alloc(usize, len);
                defer self.allocator.free(idxs);

                const fast = try fillRadixGradeIndicesFloatView(idxs, view, ascending, self.allocator);
                if (fast) break :blk try self.managedHostIndexArrayValue(idxs);
                break :blk null;
            },
        };
    }

    fn tryFastHostIntDenseGradeValue(self: *Session, value: Value, view: HostIntDenseView, ascending: bool) KError!?Value {
        const len = hostIntDenseViewLen(view);
        if (len <= 1) return try newRangeIotaValue(self, .managed, len);

        const flags = hostIntDenseValueFlags(value, view);
        if (try self.tryMonotonicGradeValue(len, flags, ascending)) |result| return result;

        const range = hostIntDenseValueRange(value, view);
        const mono = monotonicFlags(flags);
        const reverse_flag = if (ascending) host_dense_flag_dsc else host_dense_flag_asc;
        if ((mono & reverse_flag) != 0) {
            switch (view) {
                .dense => |items| {
                    const result = try self.managedHostDenseIntReverseMonotonicGradeValue(items);
                    if (result.unique) return try self.reverseIndexValue(len);
                    return result.value;
                },
                .range_iota => {
                    return try self.reverseIndexValue(len);
                },
                else => {
                    if (len <= small_grade_stack_threshold) {
                        var idxs_buf: [small_grade_stack_threshold]usize = undefined;
                        const idxs = idxs_buf[0..len];
                        const unique = try fillReverseMonotonicGradeIndicesIntView(idxs, view);
                        if (unique) return try self.reverseIndexValue(len);
                        return try self.managedHostIndexArrayValue(idxs);
                    }

                    const idxs = try self.allocator.alloc(usize, len);
                    defer self.allocator.free(idxs);
                    const unique = try fillReverseMonotonicGradeIndicesIntView(idxs, view);
                    if (unique) return try self.reverseIndexValue(len);
                    return try self.managedHostIndexArrayValue(idxs);
                },
            }
        }

        switch (view) {
            .dense => |items| {
                if (range.min >= 0 and range.max <= 1) {
                    return try self.managedHostBooleanGradeValue(view, len, ascending);
                }

                const small_dense_threshold = switch (items) {
                    .int8 => small_dense_int8_grade_threshold,
                    .int16 => small_dense_int16_grade_threshold,
                    .int32 => small_dense_int32_grade_threshold,
                    .int64 => small_dense_int64_grade_threshold,
                    .bit => small_grade_stack_threshold,
                };
                if (len <= small_dense_threshold) {
                    return try self.managedHostDenseIntInsertionGradeValue(items, ascending);
                }

                switch (items) {
                    .int8 => |slice| return try self.managedHostInt8GradeValue(slice, ascending),
                    else => {},
                }

                if (intGradeRangeLen(range)) |range_len| {
                    if (preferBucketIntGrade(len, range_len)) {
                        return try self.managedHostDenseIntBucketGradeValue(items, range, ascending);
                    }
                }

                return try self.managedHostDenseIntRadixGradeValue(items, ascending);
            },
            else => {
                if (range.min >= 0 and range.max <= 1) {
                    return try self.managedHostBooleanGradeValue(view, len, ascending);
                }

                if (len <= small_grade_stack_threshold) {
                    var idxs_buf: [small_grade_stack_threshold]usize = undefined;
                    const idxs = idxs_buf[0..len];
                    try fillInsertionGradeIndicesIntView(idxs, view, ascending);
                    return try self.managedHostIndexArrayValue(idxs);
                }

                const idxs = try self.allocator.alloc(usize, len);
                defer self.allocator.free(idxs);

                if (intGradeRangeLen(range)) |range_len| {
                    if (preferBucketIntGrade(len, range_len)) {
                        try fillBucketGradeIndices(idxs, view, range, ascending, self.allocator);
                        return try self.managedHostIndexArrayValue(idxs);
                    }
                }

                try fillRadixGradeIndices(idxs, view, hostIntStorageKindForRange(range.min, range.max), ascending, self.allocator);
                return try self.managedHostIndexArrayValue(idxs);
            },
        }
    }

    fn gradeValue(self: *Session, value: Value, ascending: bool) KError!Value {
        if (NumericStructuralView.init(value)) |structural| {
            if (try numericStructuralGradeValue(self, structural, ascending)) |result| {
                if (self.debugDetailedProbeActive()) self.debug_grade_structural_numeric_fast_count += 1;
                return result;
            }
        }
        if (valueNumericMode(value) != null) {
            if (numericVectorLen(value)) |len| {
                if (hostDenseIfPresent(value) != null or numericValueSupportsStructuralFlatItemsWithoutHost(value)) {
                    const view = try hostDenseView(self, value);
                    switch (view) {
                        .int_array => |items| {
                            if (try self.tryFastHostIntDenseGradeValue(value, items, ascending)) |result| {
                                if (self.debugDetailedProbeActive()) self.debug_grade_structural_numeric_fast_count += 1;
                                return result;
                            }
                        },
                        .float_array => |items| {
                            if (try self.tryFastHostFloatDenseGradeValue(value, items, ascending)) |result| {
                                if (self.debugDetailedProbeActive()) self.debug_grade_structural_numeric_fast_count += 1;
                                return result;
                            }
                        },
                        else => {},
                    }
                    const idxs = try self.allocator.alloc(usize, len);
                    defer self.allocator.free(idxs);
                    for (idxs, 0..) |*slot, idx| slot.* = idx;
                    try self.stableMergeSortIndices(idxs, ascending, value, numericVectorIndexedOrder);
                    if (self.debugDetailedProbeActive()) self.debug_grade_structural_numeric_fast_count += 1;
                    return try self.managedHostIndexArrayValue(idxs);
                }
            }
        }
        if (valueNumericMatrixView(value)) |matrix| {
            const idxs = try self.allocator.alloc(usize, matrix.shape.rows);
            defer self.allocator.free(idxs);
            for (idxs, 0..) |*slot, idx| slot.* = idx;
            try self.stableMergeSortIndices(idxs, ascending, matrix, numericMatrixIndexedOrder);
            if (self.debugDetailedProbeActive()) self.debug_grade_structural_numeric_fast_count += 1;
            return try self.managedHostIndexArrayValue(idxs);
        }
        const array = try numericHostArrayValue(self, value);
        const len = if (hostNumericMatrixShape(array)) |shape| shape.rows else array.len();
        const idxs = try self.allocator.alloc(usize, len);
        defer self.allocator.free(idxs);
        for (idxs, 0..) |*slot, idx| slot.* = idx;
        try self.stableMergeSortIndices(idxs, ascending, array, hostIndexedOrder);
        return try self.managedHostIndexArrayValue(idxs);
    }

    fn sortValue(self: *Session, value: Value) KError!Value {
        if (valueRangeIotaHandle(value)) |handle| {
            if (handle.rank > 1) {
                if (numericArrayRangeIota(handle).step >= 0) return self.shareValue(value);
            } else if (numericArrayRangeIota(handle).step >= 0) {
                return self.shareValue(value);
            } else {
                const len = numericArrayRangeLen(handle);
                const start = if (len == 0)
                    numericArrayRangeIota(handle).start
                else
                    try numericArrayRangeIotaValueAt(handle, len - 1);
                const step = try checkedIntOp(.sub, 0, numericArrayRangeIota(handle).step);
                return try newRangeIotaValueWithParams(self, .managed, len, start, step);
            }
        }
        if (valueNumericMatrixView(value)) |matrix| {
            const idxs = try self.allocator.alloc(usize, matrix.shape.rows);
            defer self.allocator.free(idxs);
            for (idxs, 0..) |*slot, idx| slot.* = idx;
            try self.stableMergeSortIndices(idxs, true, matrix, numericMatrixIndexedOrder);
            return try numericValueMatrixSelectRows(self, value, idxs);
        }
        const array = try numericHostArrayValue(self, value);
        if (hostNumericMatrixShape(array)) |shape| {
            const idxs = try self.allocator.alloc(usize, shape.rows);
            defer self.allocator.free(idxs);
            for (idxs, 0..) |*slot, idx| slot.* = idx;
            try self.stableMergeSortIndices(idxs, true, array, hostIndexedOrder);
            return try self.createManagedHostNumericMatrixRows(array, idxs, shape.cols);
        }
        return switch (array.storage) {
            .bit => blk: {
                const bits = HostBitSlice{ .words = array.storage.bit, .len = array.len() };
                const count_one = bitCountTrue(bits);
                const out = try self.allocHostBitArray(.managed, bits.len);
                bitFill(out.words, out.len, false);
                bitFillRange(out.words, bits.len - count_one, count_one, true);
                const all_equal = count_one == 0 or count_one == bits.len;
                break :blk try self.finishManagedHostBitAlloc(
                    out,
                    host_dense_flag_normalized | host_dense_flag_asc | (if (all_equal) host_dense_flag_dsc else 0),
                    .{
                        .min = if (count_one == bits.len and bits.len != 0) 1 else 0,
                        .max = if (count_one == 0) 0 else 1,
                    },
                );
            },
            .float64 => |items| blk: {
                var out = try self.allocator.dupe(f64, hostDenseLogicalItems(f64, array, items));
                defer self.allocator.free(out);
                var i: usize = 1;
                while (i < out.len) : (i += 1) {
                    const current = out[i];
                    var j = i;
                    while (j > 0 and current < out[j - 1]) : (j -= 1) out[j] = out[j - 1];
                    out[j] = current;
                }
                break :blk try self.createManagedHostFloatArray(out);
            },
            else => blk: {
                const view = hostIntArrayView(array).?;
                var out = std.ArrayList(i64).empty;
                defer out.deinit(self.allocator);
                try out.ensureTotalCapacity(self.allocator, hostIntArrayViewLen(view));
                for (0..hostIntArrayViewLen(view)) |idx| try out.append(self.allocator, hostIntViewItem(view, idx));
                var i: usize = 1;
                while (i < out.items.len) : (i += 1) {
                    const current = out.items[i];
                    var j = i;
                    while (j > 0 and current < out.items[j - 1]) : (j -= 1) out.items[j] = out.items[j - 1];
                    out.items[j] = current;
                }
                break :blk try self.createManagedHostIntArray(out.items);
            },
        };
    }

    fn canMutateHostDenseAppend(array: *const HostDenseArray) bool {
        if (numericPayloadOwner(array) != .managed) return false;
        if (numericPayloadManagedRefCount(array) != 1) return false;
        if (array.logical_handle) |handle| {
            if (handle.host != array) return false;
            if (handle.mlx != null) return false;
            if (numericArrayStructuralTag(handle) != .materialized) return false;
            if (handle.rank != 1) return false;
            if (@as(usize, @intCast(handle.shape[0])) != array.logical_len) return false;
        }
        return true;
    }

    fn writeHostDenseIntScalar(array: *HostDenseArray, kind: HostIntStorageKind, idx: usize, scalar_int: i64) KError!void {
        switch (kind) {
            .bit => {
                if (scalar_int != 0 and scalar_int != 1) return error.Unsupported;
                bitSet(array.storage.bit, idx, scalar_int == 1);
            },
            .int8 => array.storage.int8[idx] = std.math.cast(i8, scalar_int) orelse return error.Unsupported,
            .int16 => array.storage.int16[idx] = std.math.cast(i16, scalar_int) orelse return error.Unsupported,
            .int32 => array.storage.int32[idx] = std.math.cast(i32, scalar_int) orelse return error.Unsupported,
            .int64 => array.storage.int64[idx] = scalar_int,
        }
    }

    fn tryAppendIntVectorScalarInPlace(
        self: *Session,
        vector: Value,
        view: HostIntDenseView,
        result_kind: HostIntStorageKind,
        scalar_int: i64,
        range: HostIntRange,
        flags: u8,
    ) KError!?Value {
        switch (view) {
            .dense => {},
            else => return null,
        }
        const array = @constCast(hostDenseIfPresent(vector) orelse return null);
        if (!canMutateHostDenseAppend(array)) return null;

        const old_len = array.logical_len;
        const new_len = std.math.add(usize, old_len, 1) catch return error.Unsupported;
        try self.ensureManagedHostDenseIntCapacity(array, result_kind, new_len);
        try writeHostDenseIntScalar(array, result_kind, old_len, scalar_int);
        array.logical_len = new_len;
        if (array.logical_handle) |handle| numericArraySetVectorShape(handle, new_len);
        if (result_kind == .bit) bitClearUnusedTail(array.storage.bit, new_len);
        self.clearManagedHostDenseFindCache(array);
        hostDenseSetFlags(array, flags);
        hostDenseSetCachedIntRange(array, range);
        return self.shareValue(vector);
    }

    fn concatIntVectorScalar(self: *Session, vector: Value, view: HostIntDenseView, scalar: Value, scalar_int: i64, scalar_on_right: bool) KError!Value {
        const len = hostIntDenseViewLen(view);
        const total_len = std.math.add(usize, len, 1) catch return error.Unsupported;
        var range = if (len == 0) hostIntRangeForValue(scalar_int) else hostIntDenseValueRange(vector, view);
        if (len != 0) {
            range.min = @min(range.min, scalar_int);
            range.max = @max(range.max, scalar_int);
        }
        const vector_kind = hostIntDenseViewKind(view);
        const kind: HostIntStorageKind = if ((vector_kind == .bit or len == 0) and scalar.tag() == .bool)
            .bit
        else
            hostIntStorageKindForRange(range.min, range.max);
        const vector_flags = hostIntDenseValueFlags(vector, view);
        var asc = len <= 1 or (vector_flags & host_dense_flag_asc) != 0;
        var dsc = len <= 1 or (vector_flags & host_dense_flag_dsc) != 0;
        if (len != 0) {
            const first = try hostIntDenseViewItem(view, 0);
            const last = try hostIntDenseViewItem(view, len - 1);
            if (scalar_on_right) {
                asc = asc and last <= scalar_int;
                dsc = dsc and last >= scalar_int;
            } else {
                asc = asc and scalar_int <= first;
                dsc = dsc and scalar_int >= first;
            }
        }
        const flags = host_dense_flag_normalized | orderFlagsFromMonotonic(asc, dsc);

        if (scalar_on_right) {
            if (try self.tryAppendIntVectorScalarInPlace(vector, view, kind, scalar_int, range, flags)) |result| return result;
        }

        var out = try self.allocManagedHostIntResult(kind, total_len);

        var write_idx: usize = 0;
        if (!scalar_on_right) {
            try out.set(0, scalar_int);
            write_idx = 1;
        }
        for (0..len) |idx| try out.set(write_idx + idx, try hostIntDenseViewItem(view, idx));
        if (scalar_on_right) try out.set(len, scalar_int);

        const result = try out.value(self);
        const host = try mutableNumericHostArrayValue(self, result);
        hostDenseSetFlags(host, flags);
        hostDenseSetCachedIntRange(host, range);
        return result;
    }

    fn concatIntVectorFloatScalar(self: *Session, view: HostIntDenseView, scalar_float: f64, scalar_on_right: bool) KError!Value {
        const len = hostIntDenseViewLen(view);
        const total_len = std.math.add(usize, len, 1) catch return error.Unsupported;
        const out = try self.allocManagedHostFloatResult(total_len);
        var write_idx: usize = 0;
        if (!scalar_on_right) {
            out.items[0] = scalar_float;
            write_idx = 1;
        }
        for (0..len) |idx| out.items[write_idx + idx] = @floatFromInt(try hostIntDenseViewItem(view, idx));
        if (scalar_on_right) out.items[len] = scalar_float;

        const analysis = analyzeFloatSlice(out.items);
        const result = try out.value(self);
        hostDenseSetFlags(try mutableNumericHostArrayValue(self, result), analysis.flags);
        return result;
    }

    fn concatFloatVectorAsIntScalar(self: *Session, vector: Value, view: HostFloatDenseView, scalar_int: i64, range: HostIntRange, scalar_on_right: bool) KError!Value {
        const len = hostFloatDenseViewLen(view);
        const total_len = std.math.add(usize, len, 1) catch return error.Unsupported;
        var out = try self.allocManagedHostIntResult(hostIntStorageKindForRange(range.min, range.max), total_len);

        var write_idx: usize = 0;
        if (!scalar_on_right) {
            try out.set(0, scalar_int);
            write_idx = 1;
        }
        for (0..len) |idx| try out.set(write_idx + idx, exactIntFromFloat(try hostFloatDenseViewItem(view, idx)).?);
        if (scalar_on_right) try out.set(len, scalar_int);

        const vector_flags = hostFloatDenseValueFlags(vector, view);
        var asc = len <= 1 or (vector_flags & host_dense_flag_asc) != 0;
        var dsc = len <= 1 or (vector_flags & host_dense_flag_dsc) != 0;
        if (len != 0) {
            const first = exactIntFromFloat(try hostFloatDenseViewItem(view, 0)).?;
            const last = exactIntFromFloat(try hostFloatDenseViewItem(view, len - 1)).?;
            if (scalar_on_right) {
                asc = asc and last <= scalar_int;
                dsc = dsc and last >= scalar_int;
            } else {
                asc = asc and scalar_int <= first;
                dsc = dsc and scalar_int >= first;
            }
        }

        const result = try out.value(self);
        const host = try mutableNumericHostArrayValue(self, result);
        hostDenseSetFlags(host, host_dense_flag_normalized | orderFlagsFromMonotonic(asc, dsc));
        hostDenseSetCachedIntRange(host, range);
        return result;
    }

    fn concatFloatVectorScalar(self: *Session, vector: Value, view: HostFloatDenseView, scalar_float: f64, scalar_exact_int: ?i64, scalar_on_right: bool) KError!Value {
        const len = hostFloatDenseViewLen(view);
        const total_len = std.math.add(usize, len, 1) catch return error.Unsupported;
        if (scalar_exact_int) |scalar_int| {
            var range = hostIntRangeForValue(scalar_int);
            var all_int = true;
            for (0..len) |idx| {
                const item_int = exactIntFromFloat(try hostFloatDenseViewItem(view, idx)) orelse {
                    all_int = false;
                    break;
                };
                range.min = @min(range.min, item_int);
                range.max = @max(range.max, item_int);
            }
            if (all_int) return try self.concatFloatVectorAsIntScalar(vector, view, scalar_int, range, scalar_on_right);
        }

        const out = try self.allocManagedHostFloatResult(total_len);
        var write_idx: usize = 0;
        if (!scalar_on_right) {
            out.items[0] = scalar_float;
            write_idx = 1;
        }
        for (0..len) |idx| out.items[write_idx + idx] = try hostFloatDenseViewItem(view, idx);
        if (scalar_on_right) out.items[len] = scalar_float;

        const analysis = analyzeFloatSlice(out.items);
        const result = try out.value(self);
        hostDenseSetFlags(try mutableNumericHostArrayValue(self, result), analysis.flags);
        return result;
    }

    fn concatNumericVectorScalar(self: *Session, vector: Value, scalar: Value, scalar_on_right: bool) KError!?Value {
        if (numericVectorLen(vector) == null or valueNumericMatrixShape(vector) != null) return null;
        const scalar_float = inlineNumericFloatValue(scalar) orelse return null;
        const scalar_exact_int = inlineExactIntNumericValue(scalar);
        const vector_view = hostDenseView(self, vector) catch |err| switch (err) {
            error.Type => return null,
            else => return err,
        };
        return switch (vector_view) {
            .int_array => |view| if (scalar_exact_int) |scalar_int|
                try self.concatIntVectorScalar(vector, view, scalar, scalar_int, scalar_on_right)
            else
                try self.concatIntVectorFloatScalar(view, scalar_float, scalar_on_right),
            .float_array => |view| try self.concatFloatVectorScalar(vector, view, scalar_float, scalar_exact_int, scalar_on_right),
            else => null,
        };
    }

    fn concatValues(self: *Session, left: Value, right: Value) KError!Value {
        if (valueIsTextSequence(left) and valueIsTextSequence(right)) {
            return try self.concatTextSequenceValues(left, right);
        }
        if (left.tag() == .array and right.tag() == .array and
            left.arrayKind() == .host_keyed_store and right.arrayKind() == .host_keyed_store)
        {
            const left_store = left.asHostKeyedStore();
            const right_store = right.asHostKeyedStore();
            if (left_store.layout == .dict and right_store.layout == .dict) {
                return try self.concatKeyedDictValues(left_store, right_store);
            }
            if (left_store.layout == .table and right_store.layout == .table) {
                return try self.concatTableValues(left_store, right_store);
            }
            return error.Type;
        }
        if (try concatNumericMatrixShape(self, left, right)) |shape| {
            if (try concatNumericMatrixValue(self, left, right, shape)) |result| return result;
            var values = std.ArrayList(Value).empty;
            defer values.deinit(self.allocator);
            try self.appendConcatValue(&values, left);
            try self.appendConcatValue(&values, right);
            const result = try self.makeArrayFromValues(values.items);
            return try self.setNumericMatrixShapeOnValue(result, shape.rows, shape.cols);
        }
        if (try self.concatNumericVectorScalar(left, right, true)) |result| return result;
        if (try self.concatNumericVectorScalar(right, left, false)) |result| return result;
        if (left.tag() == .array and right.tag() == .array and
            valueNumericMode(left) != null and valueNumericMode(right) != null and
            numericVectorLen(left) != null and numericVectorLen(right) != null)
        {
            return try newFlatConcatValue(self, left, right);
        }
        var values = std.ArrayList(Value).empty;
        defer values.deinit(self.allocator);
        try self.appendConcatValue(&values, left);
        try self.appendConcatValue(&values, right);
        return try self.makeArrayFromValues(values.items);
    }

    fn appendConcatValue(self: *Session, values: *std.ArrayList(Value), value: Value) KError!void {
        if (value.tag() != .array) {
            switch (value.tag()) {
                .int, .bool, .float => try values.append(self.allocator, value),
                else => return error.Type,
            }
            return;
        }
        if (value.arraySubkind() == .host_boxed_array) {
            const array = value.asHostBoxedArray();
            for (array.items[0..array.len()]) |item| try values.append(self.allocator, item);
            return;
        }
        if (valueHostIntStructuralView(value)) |view| {
            for (0..hostIntDenseViewLen(view)) |idx| try values.append(self.allocator, try self.intValue(try hostIntDenseViewItem(view, idx)));
            return;
        }
        const array = try numericHostArrayValue(self, value);
        switch (array.storage) {
            .bit => |words| for (0..array.len()) |idx| try values.append(self.allocator, Value.fromBool(bitGet(words, idx))),
            .float64 => |items| for (hostDenseLogicalItems(f64, array, items)) |item| try values.append(self.allocator, try self.floatValue(item)),
            else => {
                const view = hostIntArrayView(array).?;
                for (0..hostIntArrayViewLen(view)) |idx| try values.append(self.allocator, try self.intValue(hostIntViewItem(view, idx)));
            },
        }
    }

    fn takeValues(self: *Session, left: Value, right: Value) KError!Value {
        if (try shapeVectorSnapshotValue(left)) |shape| {
            return try self.reshapeToSnapshotValue(shape, right);
        }
        if (try self.tryProjectKeyedStoreByKeys(left, right)) |projected| return projected;
        const raw_count = scalarIntLikeValue(left) orelse return error.Type;
        if (right.tag() == .array and right.arrayKind() == .host_string_list) {
            return try self.takeHostStringList(raw_count, right.asHostStringList());
        }
        if (right.tag() != .array) {
            if (right.tag() != .int and right.tag() != .bool and right.tag() != .float) return error.Type;
            return try self.takeScalarValue(raw_count, right);
        }
        if (right.arrayKind() == .host_keyed_store) {
            const store = right.asHostKeyedStore();
            return switch (store.layout) {
                .dict => try self.keyedDictTakeValue(raw_count, store),
                .table => try self.tableTakeValue(raw_count, store),
            };
        }
        if (right.arrayKind() == .host_relation) {
            return try self.materializeRelationTake(raw_count, right.asHostRelation());
        }
        if (right.arraySubkind() == .host_boxed_array) {
            return try self.takeHostBoxedArray(raw_count, right.asHostBoxedArray());
        }
        if (valueNumericMatrixView(right)) |matrix| {
            const count: usize = @intCast(@abs(raw_count));
            if (count == 0) return try numericValueMatrixSelectRows(self, right, &.{});
            if (matrix.shape.rows == 0) return error.Type;

            var row_indices = std.ArrayList(usize).empty;
            defer row_indices.deinit(self.allocator);
            try row_indices.ensureTotalCapacity(self.allocator, count);
            if (raw_count >= 0) {
                for (0..count) |idx| try row_indices.append(self.allocator, idx % matrix.shape.rows);
            } else {
                const pad = if (count > matrix.shape.rows) count - matrix.shape.rows else 0;
                for (0..pad) |_| try row_indices.append(self.allocator, 0);
                const start = if (count >= matrix.shape.rows) 0 else matrix.shape.rows - count;
                for (start..matrix.shape.rows) |idx| try row_indices.append(self.allocator, idx);
            }
            return try numericValueMatrixSelectRows(self, right, row_indices.items);
        }
        if (shapedNumericHandle(right)) |handle| {
            const rows: usize = @intCast(handle.shape[0]);
            const count: usize = @intCast(@abs(raw_count));
            if (count == 0) {
                if (try numericValueFirstAxisContiguousSliceValue(self, right, .{ .start = 0, .len = 0 })) |result| return result;
            } else if (count <= rows) {
                const start = if (raw_count >= 0) 0 else rows - count;
                if (try numericValueFirstAxisContiguousSliceValue(self, right, .{ .start = start, .len = count })) |result| return result;
            }
        }
        if (NumericStructuralView.init(right)) |structural| {
            if (try numericStructuralTakeValue(self, structural, raw_count)) |result| return result;
        }
        if (valueNumericMode(right) != null) {
            if (numericVectorLen(right)) |len| {
                const count: usize = @intCast(@abs(raw_count));
                if (count == 0) return try newFlatSliceValue(self, right, 0, 0);
                if (len == 0) return error.Type;
                if (count <= len) {
                    const start = if (raw_count >= 0) 0 else len - count;
                    return try newFlatSliceValue(self, right, start, count);
                }
            }
        }
        return try self.takeHostArray(raw_count, try numericHostArrayValue(self, right));
    }

    fn shapeVectorSnapshotValue(value: Value) KError!?NumericShapeSnapshot {
        const len = numericVectorLen(value) orelse return null;
        if (valueNumericMode(value) != .int) return null;
        if (len == 0) return error.Type;
        if (len > numeric_array_max_rank) return error.Unsupported;

        var dims_buf: [numeric_array_max_rank]i32 = [_]i32{0} ** numeric_array_max_rank;
        for (0..len) |idx| {
            const dim_i64 = try numericIntAt(value, idx);
            dims_buf[idx] = std.math.cast(i32, dim_i64) orelse return error.Unsupported;
        }
        return try numericShapeSnapshotFromDims(dims_buf[0..len]);
    }

    fn reshapeToSnapshotValue(self: *Session, shape: NumericShapeSnapshot, right: Value) KError!Value {
        const total = try numericShapeSnapshotElementCount(shape);

        if (right.tag() != .array) {
            return switch (right.tag()) {
                .int, .bool, .float => blk: {
                    const flat = try self.takeScalarValue(@intCast(total), right);
                    break :blk try applyNonVectorNumericShapeToValue(self, flat, shape);
                },
                else => error.Type,
            };
        }

        if (valueRangeIotaHandle(right)) |handle| {
            const source_total = numericArrayRangeLen(handle);
            if (source_total == 0 and total != 0) return error.Type;
            if (source_total == total) {
                return try newRangeIotaValueWithShape(
                    self,
                    .managed,
                    total,
                    numericArrayRangeIota(handle).start,
                    numericArrayRangeIota(handle).step,
                    shape,
                );
            }
        }

        if (valueNumericMode(right)) |mode| {
            const source_total = numericFlatLen(right) orelse if (right.tag() == .array)
                (try numericHostArrayValue(self, right)).len()
            else
                return error.Type;
            if (source_total == 0 and total != 0) return error.Type;
            if (source_total == total) {
                return try newReshapeViewValue(self, right, shape);
            }
            return switch (mode) {
                .float => blk: {
                    var out = std.ArrayList(f64).empty;
                    defer out.deinit(self.allocator);
                    try out.ensureTotalCapacity(self.allocator, total);
                    for (0..total) |idx| {
                        try out.append(self.allocator, try numericFloatAt(right, @intCast(idx % source_total)));
                    }
                    const reshaped = try self.createManagedHostFloatArray(out.items);
                    break :blk try applyNonVectorNumericShapeToValue(self, reshaped, shape);
                },
                .int => blk: {
                    var out = std.ArrayList(i64).empty;
                    defer out.deinit(self.allocator);
                    try out.ensureTotalCapacity(self.allocator, total);
                    for (0..total) |idx| {
                        try out.append(self.allocator, try numericIntAt(right, @intCast(idx % source_total)));
                    }
                    const reshaped = try self.createManagedHostIntArray(out.items);
                    break :blk try applyNonVectorNumericShapeToValue(self, reshaped, shape);
                },
            };
        }

        return error.Type;
    }

    fn takeScalarValue(self: *Session, raw_count: i64, value: Value) KError!Value {
        if (raw_count == 0) return try self.createManagedHostIntArray(&.{});
        const count: usize = @intCast(@abs(raw_count));
        switch (value.tag()) {
            .bool => {
                const out = try self.allocHostBitArray(.managed, count);
                bitFill(out.words, out.len, value.asBool());
                return try self.finishManagedHostBitAlloc(
                    out,
                    host_dense_flag_normalized | host_dense_flag_asc | host_dense_flag_dsc,
                    hostIntRangeForValue(@intFromBool(value.asBool())),
                );
            },
            .float => {
                var out = std.ArrayList(f64).empty;
                defer out.deinit(self.allocator);
                try out.ensureTotalCapacity(self.allocator, count);
                for (0..count) |_| try out.append(self.allocator, value.asFloat());
                return try self.createManagedHostFloatArray(out.items);
            },
            .int => {
                var out = std.ArrayList(i64).empty;
                defer out.deinit(self.allocator);
                try out.ensureTotalCapacity(self.allocator, count);
                for (0..count) |_| try out.append(self.allocator, value.asInt());
                return try self.createManagedHostIntArray(out.items);
            },
            else => return error.Type,
        }
    }

    fn takeHostArray(self: *Session, raw_count: i64, array: *const HostDenseArray) KError!Value {
        if (hostNumericMatrixShape(array)) |shape| {
            const count: usize = @intCast(@abs(raw_count));
            if (count == 0) {
                const value = switch (array.storage) {
                    .bit => try self.createManagedHostBitArray(&.{}),
                    .float64 => try self.createManagedHostFloatArray(&.{}),
                    else => try self.createManagedHostIntArray(&.{}),
                };
                return try self.setNumericMatrixShapeOnValue(value, 0, shape.cols);
            }
            if (shape.rows == 0) return error.Type;

            var row_indices = std.ArrayList(usize).empty;
            defer row_indices.deinit(self.allocator);
            try row_indices.ensureTotalCapacity(self.allocator, count);
            if (raw_count >= 0) {
                for (0..count) |idx| try row_indices.append(self.allocator, idx % shape.rows);
            } else {
                const pad = if (count > shape.rows) count - shape.rows else 0;
                for (0..pad) |_| try row_indices.append(self.allocator, 0);
                const start = if (count >= shape.rows) 0 else shape.rows - count;
                for (start..shape.rows) |idx| try row_indices.append(self.allocator, idx);
            }
            return try self.createManagedHostNumericMatrixRows(array, row_indices.items, shape.cols);
        }
        const count: usize = @intCast(@abs(raw_count));
        if (count == 0) {
            return switch (array.storage) {
                .bit => try self.createManagedHostBitArray(&.{}),
                .float64 => try self.createManagedHostFloatArray(&.{}),
                else => try self.createManagedHostIntArray(&.{}),
            };
        }
        if (array.len() == 0) return error.Type;
        if (raw_count >= 0) {
            return switch (array.storage) {
                .bit => blk: {
                    const source = HostBitSlice{ .words = array.storage.bit, .len = array.logical_len };
                    const out = try self.allocHostBitArray(.managed, count);
                    var dst_start: usize = 0;
                    while (dst_start < count) {
                        const chunk_len = @min(source.len, count - dst_start);
                        bitCopyRange(out.words, dst_start, source, 0, chunk_len);
                        dst_start += chunk_len;
                    }
                    break :blk try self.finishManagedHostBitAlloc(
                        out,
                        if (count <= array.len()) array.flags else host_dense_flag_normalized,
                        sourceHostIntRange(hostDenseSourceValue(array), array),
                    );
                },
                .float64 => |items| blk: {
                    var out = std.ArrayList(f64).empty;
                    defer out.deinit(self.allocator);
                    try out.ensureTotalCapacity(self.allocator, count);
                    for (0..count) |idx| try out.append(self.allocator, items[idx % items.len]);
                    break :blk try self.createManagedHostFloatArray(out.items);
                },
                else => blk: {
                    const view = hostIntArrayView(array).?;
                    var out = std.ArrayList(i64).empty;
                    defer out.deinit(self.allocator);
                    try out.ensureTotalCapacity(self.allocator, count);
                    for (0..count) |idx| try out.append(self.allocator, hostIntViewItem(view, idx % hostIntArrayViewLen(view)));
                    break :blk try self.createManagedHostIntArray(out.items);
                },
            };
        }
        return switch (array.storage) {
            .bit => blk: {
                const source = HostBitSlice{ .words = array.storage.bit, .len = array.logical_len };
                const out = try self.allocHostBitArray(.managed, count);
                const pad = if (count > array.len()) count - array.len() else 0;
                bitFillRange(out.words, 0, pad, bitGet(array.storage.bit, 0));
                const start = if (count >= array.len()) 0 else array.len() - count;
                bitCopyRange(out.words, pad, source, start, array.len() - start);
                break :blk try self.finishManagedHostBitAlloc(out, array.flags, sourceHostIntRange(hostDenseSourceValue(array), array));
            },
            .float64 => |items| blk: {
                const logical_items = hostDenseLogicalItems(f64, array, items);
                var out = std.ArrayList(f64).empty;
                defer out.deinit(self.allocator);
                try out.ensureTotalCapacity(self.allocator, count);
                const pad = if (count > logical_items.len) count - logical_items.len else 0;
                for (0..pad) |_| try out.append(self.allocator, logical_items[0]);
                const start = if (count >= logical_items.len) 0 else logical_items.len - count;
                for (logical_items[start..]) |item| try out.append(self.allocator, item);
                break :blk try self.createManagedHostFloatArray(out.items);
            },
            else => blk: {
                const view = hostIntArrayView(array).?;
                var out = std.ArrayList(i64).empty;
                defer out.deinit(self.allocator);
                try out.ensureTotalCapacity(self.allocator, count);
                const pad = if (count > hostIntArrayViewLen(view)) count - hostIntArrayViewLen(view) else 0;
                const first = hostIntViewItem(view, 0);
                for (0..pad) |_| try out.append(self.allocator, first);
                const start = if (count >= hostIntArrayViewLen(view)) 0 else hostIntArrayViewLen(view) - count;
                for (start..hostIntArrayViewLen(view)) |idx| try out.append(self.allocator, hostIntViewItem(view, idx));
                break :blk try self.createManagedHostIntArray(out.items);
            },
        };
    }

    fn takeHostBoxedArray(self: *Session, raw_count: i64, array: *const HostBoxedArray) KError!Value {
        const count: usize = @intCast(@abs(raw_count));
        if (count == 0) return try self.createManagedHostBoxedArray(&.{});
        if (array.len() == 0) return error.Type;

        var out = std.ArrayList(Value).empty;
        defer out.deinit(self.allocator);
        try out.ensureTotalCapacity(self.allocator, count);

        if (raw_count >= 0) {
            for (0..count) |idx| try out.append(self.allocator, array.items[idx % array.len()]);
        } else {
            const pad = if (count > array.len()) count - array.len() else 0;
            const first = array.items[0];
            for (0..pad) |_| try out.append(self.allocator, first);
            const start = if (count >= array.len()) 0 else array.len() - count;
            for (start..array.len()) |idx| try out.append(self.allocator, array.items[idx]);
        }
        return try self.createManagedHostBoxedArray(out.items);
    }

    fn takeHostStringList(self: *Session, raw_count: i64, list: *const HostStringList) KError!Value {
        const count: usize = @intCast(@abs(raw_count));
        if (count == 0) return try self.createManagedHostTextListFromValues(&.{});
        if (list.len == 0) return error.Type;

        var out = std.ArrayList(Value).empty;
        defer out.deinit(self.allocator);
        defer {
            for (out.items) |item| self.releaseValue(item);
        }
        try out.ensureTotalCapacity(self.allocator, count);

        if (raw_count >= 0) {
            for (0..count) |idx| try out.append(self.allocator, try self.hostStringListItemValue(list, idx % list.len));
        } else {
            const pad = if (count > list.len) count - list.len else 0;
            const first = try self.hostStringListItemValue(list, 0);
            defer self.releaseValue(first);
            for (0..pad) |_| try out.append(self.allocator, try self.retainEscapedValue(first));
            const start = if (count >= list.len) 0 else list.len - count;
            for (start..list.len) |idx| try out.append(self.allocator, try self.hostStringListItemValue(list, idx));
        }
        return try self.createManagedHostTextListFromValues(out.items);
    }

    fn dropValues(self: *Session, left: Value, right: Value) KError!Value {
        const raw_count = scalarIntLikeValue(left) orelse return error.Type;
        if (right.tag() == .array and right.arrayKind() == .host_string_list) {
            return try self.dropHostStringList(raw_count, right.asHostStringList());
        }
        if (right.tag() == .array and right.arrayKind() == .host_keyed_store) {
            const store = right.asHostKeyedStore();
            return switch (store.layout) {
                .dict => try self.keyedDictDropValue(raw_count, store),
                .table => try self.tableDropValue(raw_count, store),
            };
        }
        if (right.tag() == .array and right.arraySubkind() == .host_boxed_array) {
            return try self.dropHostBoxedArray(raw_count, right.asHostBoxedArray());
        }
        if (valueNumericMatrixView(right)) |matrix| {
            const drop_count: usize = if (raw_count >= 0)
                @min(@as(usize, @intCast(raw_count)), matrix.shape.rows)
            else
                matrix.shape.rows - @min(@as(usize, @intCast(-raw_count)), matrix.shape.rows);
            const start: usize = if (raw_count >= 0) drop_count else 0;
            const end: usize = if (raw_count >= 0) matrix.shape.rows else drop_count;
            var row_indices = std.ArrayList(usize).empty;
            defer row_indices.deinit(self.allocator);
            try row_indices.ensureTotalCapacity(self.allocator, end - start);
            for (start..end) |idx| try row_indices.append(self.allocator, idx);
            return try numericValueMatrixSelectRows(self, right, row_indices.items);
        }
        if (shapedNumericHandle(right)) |handle| {
            const rows: usize = @intCast(handle.shape[0]);
            const drop_count: usize = if (raw_count >= 0)
                @min(@as(usize, @intCast(raw_count)), rows)
            else
                rows - @min(@as(usize, @intCast(-raw_count)), rows);
            const start: usize = if (raw_count >= 0) drop_count else 0;
            const end: usize = if (raw_count >= 0) rows else drop_count;
            if (try numericValueFirstAxisContiguousSliceValue(self, right, .{ .start = start, .len = end - start })) |result| return result;
        }
        if (NumericStructuralView.init(right)) |structural| {
            if (try numericStructuralDropValue(self, structural, raw_count)) |result| return result;
        }
        if (valueNumericMode(right) != null) {
            if (numericVectorLen(right)) |len| {
                const drop_count: usize = if (raw_count >= 0)
                    @min(@as(usize, @intCast(raw_count)), len)
                else
                    len - @min(@as(usize, @intCast(-raw_count)), len);
                const start: usize = if (raw_count >= 0) drop_count else 0;
                const end: usize = if (raw_count >= 0) len else drop_count;
                return try newFlatSliceValue(self, right, start, end - start);
            }
        }
        const array = try numericHostArrayValue(self, right);
        if (hostNumericMatrixShape(array)) |shape| {
            const drop_count: usize = if (raw_count >= 0)
                @min(@as(usize, @intCast(raw_count)), shape.rows)
            else
                shape.rows - @min(@as(usize, @intCast(-raw_count)), shape.rows);
            const start: usize = if (raw_count >= 0) drop_count else 0;
            const end: usize = if (raw_count >= 0) shape.rows else drop_count;
            var row_indices = std.ArrayList(usize).empty;
            defer row_indices.deinit(self.allocator);
            try row_indices.ensureTotalCapacity(self.allocator, end - start);
            for (start..end) |idx| try row_indices.append(self.allocator, idx);
            return try self.createManagedHostNumericMatrixRows(array, row_indices.items, shape.cols);
        }
        const len = array.len();
        const drop_count: usize = if (raw_count >= 0)
            @min(@as(usize, @intCast(raw_count)), len)
        else
            len - @min(@as(usize, @intCast(-raw_count)), len);
        const start: usize = if (raw_count >= 0) drop_count else 0;
        const end: usize = if (raw_count >= 0) len else drop_count;
        return switch (array.storage) {
            .bit => blk: {
                const out = try self.allocHostBitArray(.managed, end - start);
                bitCopyRange(out.words, 0, .{ .words = array.storage.bit, .len = array.logical_len }, start, end - start);
                break :blk try self.finishManagedHostBitAlloc(out, array.flags, sourceHostIntRange(hostDenseSourceValue(array), array));
            },
            .float64 => |items| try self.createManagedHostFloatArray(hostDenseLogicalItems(f64, array, items)[start..end]),
            else => blk: {
                const view = hostIntArrayView(array).?;
                var out = std.ArrayList(i64).empty;
                defer out.deinit(self.allocator);
                try out.ensureTotalCapacity(self.allocator, end - start);
                for (start..end) |idx| try out.append(self.allocator, hostIntViewItem(view, idx));
                break :blk try self.createManagedHostIntArray(out.items);
            },
        };
    }

    fn dropHostBoxedArray(self: *Session, raw_count: i64, array: *const HostBoxedArray) KError!Value {
        const len = array.len();
        const drop_count: usize = if (raw_count >= 0)
            @min(@as(usize, @intCast(raw_count)), len)
        else
            len - @min(@as(usize, @intCast(-raw_count)), len);
        const start: usize = if (raw_count >= 0) drop_count else 0;
        const end: usize = if (raw_count >= 0) len else drop_count;
        return try self.createManagedHostBoxedArray(array.items[start..end]);
    }

    fn dropHostStringList(self: *Session, raw_count: i64, list: *const HostStringList) KError!Value {
        const drop_count: usize = if (raw_count >= 0)
            @min(@as(usize, @intCast(raw_count)), list.len)
        else
            list.len - @min(@as(usize, @intCast(-raw_count)), list.len);
        const start: usize = if (raw_count >= 0) drop_count else 0;
        const end: usize = if (raw_count >= 0) list.len else drop_count;

        var out = std.ArrayList(Value).empty;
        defer out.deinit(self.allocator);
        defer {
            for (out.items) |item| self.releaseValue(item);
        }
        try out.ensureTotalCapacity(self.allocator, end - start);
        for (start..end) |idx| try out.append(self.allocator, try self.hostStringListItemValue(list, idx));
        return try self.createManagedHostTextListFromValues(out.items);
    }

    fn reshapeValues(self: *Session, left: Value, right: Value) KError!Value {
        const row_len_value = scalarIntLikeValue(left) orelse return error.Type;
        if (row_len_value <= 0) return error.Type;

        const row_len: usize = @intCast(row_len_value);
        const total = numericFlatLen(right) orelse if (right.tag() == .array)
            (try numericHostArrayValue(self, right)).len()
        else
            return error.Type;
        if (total == 0 or total % row_len != 0) return error.Unsupported;

        const rows = total / row_len;
        if (valueRangeIotaHandle(right)) |handle| {
            return try newRangeIotaValueWithShape(
                self,
                .managed,
                total,
                numericArrayRangeIota(handle).start,
                numericArrayRangeIota(handle).step,
                numericShapeSnapshotMatrix(rows, row_len),
            );
        }
        if (valueNumericMode(right) != null) {
            return try newReshapeViewValue(self, right, numericShapeSnapshotMatrix(rows, row_len));
        }

        const source = try numericHostArrayValue(self, right);
        if (right.arraySubkind() != .host_boxed_array) {
            const value = switch (source.storage) {
                .bit => blk: {
                    const out = try self.allocHostBitArray(.managed, total);
                    bitCopyRange(out.words, 0, .{ .words = source.storage.bit, .len = source.logical_len }, 0, total);
                    break :blk try self.finishManagedHostBitAlloc(out, source.flags, sourceHostIntRange(hostDenseSourceValue(source), source));
                },
                .float64 => |items| try self.createManagedHostFloatArray(hostDenseLogicalItems(f64, source, items)),
                else => blk: {
                    const view = hostIntArrayView(source) orelse return error.Type;
                    var out = std.ArrayList(i64).empty;
                    defer out.deinit(self.allocator);
                    try out.ensureTotalCapacity(self.allocator, total);
                    for (0..total) |idx| try out.append(self.allocator, hostIntViewItem(view, idx));
                    break :blk try self.createManagedHostIntArray(out.items);
                },
            };
            return try self.setNumericMatrixShapeOnValue(value, rows, row_len);
        }

        var outer = std.ArrayList(Value).empty;
        defer {
            for (outer.items) |value| self.releaseValue(value);
            outer.deinit(self.allocator);
        }
        try outer.ensureTotalCapacity(self.allocator, rows);

        for (0..rows) |row_idx| {
            var inner = std.ArrayList(Value).empty;
            defer inner.deinit(self.allocator);
            try inner.ensureTotalCapacity(self.allocator, row_len);
            const start = row_idx * row_len;
            for (0..row_len) |col_idx| {
                try inner.append(self.allocator, try self.hostDenseIndexScalar(source, @intCast(start + col_idx)));
            }
            try outer.append(self.allocator, try self.createManagedArrayLikeFromValues(inner.items));
        }
        return try self.createManagedArrayLikeFromValues(outer.items);
    }

    fn equalValues(self: *Session, left: Value, right: Value) KError!Value {
        if (try self.tryFastInlineScalarDyad(.equal, left, right)) |result| return result;
        if (try self.promoteRenderableNumericDyadOperands(left, right)) |operands| {
            return try self.equalValues(operands.left, operands.right);
        }
        const left_table_scalar = tableScalarValue(left) != null;
        const right_table_scalar = tableScalarValue(right) != null;
        if ((left.tag() != .array and right.tag() != .array) or left_table_scalar or right_table_scalar) {
            if (left.tag() == .float or right.tag() == .float) {
                const lhs = switch (left.tag()) {
                    .float => left.asFloat(),
                    .int => @as(f64, @floatFromInt(left.asInt())),
                    .bool => @as(f64, @floatFromInt(@intFromBool(left.asBool()))),
                    else => scalarNumericFloatValue(left) orelse return error.Type,
                };
                const rhs = switch (right.tag()) {
                    .float => right.asFloat(),
                    .int => @as(f64, @floatFromInt(right.asInt())),
                    .bool => @as(f64, @floatFromInt(@intFromBool(right.asBool()))),
                    else => scalarNumericFloatValue(right) orelse return error.Type,
                };
                return Value.fromBool(lhs == rhs);
            }
            const lhs = scalarIntLikeValue(left) orelse return error.Type;
            const rhs = scalarIntLikeValue(right) orelse return error.Type;
            return Value.fromBool(lhs == rhs);
        }
        return try self.equalArrayValues(left, right);
    }

    fn compareScalars(self: *Session, op: BuiltinId, left: Value, right: Value) KError!Value {
        _ = self;
        if (left.tag() == .float or right.tag() == .float) {
            const lhs = switch (left.tag()) {
                .float => left.asFloat(),
                .int => @as(f64, @floatFromInt(left.asInt())),
                .bool => @as(f64, @floatFromInt(@intFromBool(left.asBool()))),
                else => return error.Type,
            };
            const rhs = switch (right.tag()) {
                .float => right.asFloat(),
                .int => @as(f64, @floatFromInt(right.asInt())),
                .bool => @as(f64, @floatFromInt(@intFromBool(right.asBool()))),
                else => return error.Type,
            };
            return Value.fromBool(switch (op) {
                .less => lhs < rhs,
                .more => lhs > rhs,
                else => return error.Internal,
            });
        }
        const lhs = scalarIntLikeValue(left) orelse return error.Type;
        const rhs = scalarIntLikeValue(right) orelse return error.Type;
        return Value.fromBool(switch (op) {
            .less => lhs < rhs,
            .more => lhs > rhs,
            else => return error.Internal,
        });
    }

    fn tryFastHostBitCompare(self: *Session, op: BuiltinId, left: Value, right: Value, shape: ?NumericShapeSnapshot) KError!?Value {
        const left_bits = valueNumericBitSlice(left) orelse return null;
        const right_bits = valueNumericBitSlice(right) orelse return null;
        if (left_bits.len != right_bits.len) return error.Type;

        if (enable_packed_bit_simd) {
            var out = try self.allocManagedHostIntResult(.bit, left_bits.len);
            fillBitWordsBinary(out.bit.words, op, left_bits.words, right_bits.words);
            bitClearUnusedTail(out.bit.words, out.bit.len);
            const result = try out.value(self);
            return try applyNonVectorNumericShapeToValue(self, result, shape);
        }
        return null;
    }

    fn compareNumericArrayValues(self: *Session, op: BuiltinId, left: Value, right: Value) KError!Value {
        if (planCompareMaskBackend(self, op, left, right) == .mlx) return try self.applyBackendArrayDyad(op, left, right);
        const shape = try nonVectorNumericShapeForDyad(left, right);
        if (try self.tryFastHostBitCompare(op, left, right, shape)) |result| return result;
        const len = try arrayResultLen(left, right);
        const rowwise = rowwiseMatrixVectorDyad(left, right);
        const out = try self.allocHostBitArray(.managed, len);
        var stats = BitSequenceStats{};
        for (0..len) |idx| {
            const lhs = if (left.tag() == .array)
                try numericFloatAt(left, if (rowwise) |info| info.operandIndex(true, idx) else idx)
            else
                scalarNumericFloatValue(left).?;
            const rhs = if (right.tag() == .array)
                try numericFloatAt(right, if (rowwise) |info| info.operandIndex(false, idx) else idx)
            else
                scalarNumericFloatValue(right).?;
            const bit = switch (op) {
                .less => lhs < rhs,
                .more => lhs > rhs,
                else => return error.Internal,
            };
            bitSet(out.words, idx, bit);
            stats.note(bit);
        }
        const metadata = stats.metadata();
        const result = try self.finishManagedHostBitAlloc(out, metadata.flags, metadata.range);
        return try applyNonVectorNumericShapeToValue(self, result, shape);
    }

    fn transposeHostDenseMatrixValue(self: *Session, value: Value, shape: NumericMatrixShape) KError!?Value {
        const out_shape = numericShapeSnapshotMatrix(shape.cols, shape.rows);
        const view = hostDenseView(self, value) catch |err| switch (err) {
            error.Type => return null,
            else => return err,
        };
        return switch (view) {
            .float_array => |items| blk: {
                const out = try self.allocManagedHostFloatResult(shape.rows * shape.cols);
                for (0..shape.cols) |col_idx| {
                    for (0..shape.rows) |row_idx| {
                        out.items[col_idx * shape.rows + row_idx] = try hostFloatDenseViewItem(items, row_idx * shape.cols + col_idx);
                    }
                }
                const transposed = try out.value(self);
                break :blk try applyNonVectorNumericShapeToValue(self, transposed, out_shape);
            },
            .int_array => |items| blk: {
                const range = hostIntDenseValueRange(value, items);
                const kind = hostIntStorageKindForRange(range.min, range.max);
                var out = try self.allocManagedHostIntResult(kind, shape.rows * shape.cols);
                for (0..shape.cols) |col_idx| {
                    for (0..shape.rows) |row_idx| {
                        try out.set(col_idx * shape.rows + row_idx, try hostIntDenseViewItem(items, row_idx * shape.cols + col_idx));
                    }
                }
                const transposed = try out.value(self);
                const transposed_host = try mutableNumericHostArrayValue(self, transposed);
                hostDenseSetFlags(transposed_host, if (range.min >= 0 and range.max <= 1) host_dense_flag_normalized else 0);
                hostDenseSetCachedIntRange(transposed_host, range);
                break :blk try applyNonVectorNumericShapeToValue(self, transposed, out_shape);
            },
            else => null,
        };
    }

