    fn divValues(self: *Session, left: Value, right: Value) KError!Value {
        if (try self.tryFastInlineScalarDyad(.div, left, right)) |result| return result;
        if (try self.promoteRenderableNumericDyadOperands(left, right)) |operands| {
            return try self.divValues(operands.left, operands.right);
        }
        if (try self.tryScalarIntBoolDyad(.div, left, right)) |result| return result;
        if (shouldUseGenericArrayDyad(left, right)) return try self.applyGenericArrayDyad(.div, left, right);
        if (hasArrayOperand(left, right) and canApplyNumericDyad(left, right)) return try self.applyNumericDyad(.div, left, right);
        const left_float = switch (left.tag()) {
            .int => @as(f64, @floatFromInt(left.asInt())),
            .bool => @as(f64, @floatFromInt(@intFromBool(left.asBool()))),
            .float => left.asFloat(),
            else => return error.Type,
        };
        const right_float = switch (right.tag()) {
            .int => @as(f64, @floatFromInt(right.asInt())),
            .bool => @as(f64, @floatFromInt(@intFromBool(right.asBool()))),
            .float => right.asFloat(),
            else => return error.Type,
        };
        return try self.floatValue(left_float / right_float);
    }

    fn powValues(self: *Session, left: Value, right: Value) KError!Value {
        if (try self.tryFastInlineScalarDyad(.pow, left, right)) |result| return result;
        if (try self.promoteRenderableNumericDyadOperands(left, right)) |operands| {
            return try self.powValues(operands.left, operands.right);
        }
        if (hasArrayOperand(left, right) and canApplyNumericDyad(left, right)) return try self.applyNumericDyad(.pow, left, right);
        if (shouldUseGenericArrayDyad(left, right)) return try self.applyGenericArrayDyad(.pow, left, right);
        if (scalarIntLikeValue(left)) |left_int| {
            if (scalarIntLikeValue(right)) |right_int| {
                return try self.intValue(try intPowLikeMlx(left_int, right_int));
            }
        }
        const left_float = scalarNumericFloatValue(left) orelse return error.Type;
        const right_float = scalarNumericFloatValue(right) orelse return error.Type;
        return try self.floatValue(std.math.pow(f64, left_float, right_float));
    }

    const MatmulShape = struct {
        left_rank: u8,
        right_rank: u8,
        result_rank: u8,
        left_rows: usize,
        left_cols: usize,
        right_rows: usize,
        right_cols: usize,
        result_rows: usize,
        result_cols: usize,
        result_len: usize,
        result_mode: HostDenseElem,
    };

    fn matmulShapeForValues(left: Value, right: Value) KError!?MatmulShape {
        const left_mode = valueNumericMode(left) orelse return null;
        const right_mode = valueNumericMode(right) orelse return null;

        const left_matrix = valueNumericMatrixShape(left);
        const right_matrix = valueNumericMatrixShape(right);
        const left_vector_len = numericVectorLen(left);
        const right_vector_len = numericVectorLen(right);

        if (left_matrix == null and left_vector_len == null) return null;
        if (right_matrix == null and right_vector_len == null) return null;

        const left_rank: u8 = if (left_matrix != null) 2 else 1;
        const right_rank: u8 = if (right_matrix != null) 2 else 1;
        const left_rows = if (left_matrix) |shape| shape.rows else 1;
        const left_cols = if (left_matrix) |shape| shape.cols else left_vector_len.?;
        const right_rows = if (right_matrix) |shape| shape.rows else right_vector_len.?;
        const right_cols = if (right_matrix) |shape| shape.cols else 1;
        if (left_cols != right_rows) return error.Type;

        const result_rank: u8 = if (left_rank == 1 and right_rank == 1) 0 else if (left_rank == 2 and right_rank == 2) 2 else 1;
        const result_rows = if (left_rank == 2) left_rows else 1;
        const result_cols = if (right_rank == 2) right_cols else 1;
        return .{
            .left_rank = left_rank,
            .right_rank = right_rank,
            .result_rank = result_rank,
            .left_rows = left_rows,
            .left_cols = left_cols,
            .right_rows = right_rows,
            .right_cols = right_cols,
            .result_rows = result_rows,
            .result_cols = result_cols,
            .result_len = result_rows * result_cols,
            .result_mode = if (left_mode == .float or right_mode == .float) .float else .int,
        };
    }

    fn hostDenseViewFloatItem(view: HostDenseView, idx: usize) KError!f64 {
        return switch (view) {
            .scalar_int => |value| @floatFromInt(value),
            .scalar_float => |value| value,
            .int_array => |items| @floatFromInt(try hostIntDenseViewItem(items, idx)),
            .float_array => |items| try hostFloatDenseViewItem(items, idx),
        };
    }

    fn hostDenseViewIntItem(view: HostDenseView, idx: usize) KError!i64 {
        return switch (view) {
            .scalar_int => |value| value,
            .int_array => |items| try hostIntDenseViewItem(items, idx),
            else => error.Type,
        };
    }

    fn finishHostMatmulFloatResult(self: *Session, shape: MatmulShape, out: HostFloatResult) KError!Value {
        if (shape.result_rank == 0) return try self.floatValue(out.items[0]);
        const value = try out.value(self);
        const analysis = analyzeFloatSlice(out.items);
        hostDenseSetFlags(try mutableNumericHostArrayValue(self, value), analysis.flags);
        if (shape.result_rank == 2) return try newReshapeViewValue(self, value, numericShapeSnapshotMatrix(shape.result_rows, shape.result_cols));
        return value;
    }

    fn finishHostMatmulIntResult(self: *Session, shape: MatmulShape, items: []const i64) KError!Value {
        if (shape.result_rank == 0) return try self.intValue(items[0]);
        const value = try self.createManagedHostIntArray(items);
        if (shape.result_rank == 2) return try newReshapeViewValue(self, value, numericShapeSnapshotMatrix(shape.result_rows, shape.result_cols));
        return value;
    }

    fn transposeDenseFloatMatrixBlocked(out: []f64, input: []const f64, rows: usize, cols: usize) void {
        const tile: usize = 32;
        var row0: usize = 0;
        while (row0 < rows) : (row0 += tile) {
            const row_end = @min(row0 + tile, rows);
            var col0: usize = 0;
            while (col0 < cols) : (col0 += tile) {
                const col_end = @min(col0 + tile, cols);
                var row_idx = row0;
                while (row_idx < row_end) : (row_idx += 1) {
                    const input_row = input[row_idx * cols ..][0..cols];
                    var col_idx = col0;
                    while (col_idx < col_end) : (col_idx += 1) {
                        out[col_idx * rows + row_idx] = input_row[col_idx];
                    }
                }
            }
        }
    }

    fn denseFloatDot(lhs: []const f64, rhs: []const f64) f64 {
        const lane_count = 4;
        const Vec = @Vector(lane_count, f64);
        var acc_vec: Vec = @splat(0.0);
        var idx: usize = 0;
        const vector_limit = lhs.len - (lhs.len % lane_count);
        while (idx < vector_limit) : (idx += lane_count) {
            const lhs_vec: Vec = lhs[idx..][0..lane_count].*;
            const rhs_vec: Vec = rhs[idx..][0..lane_count].*;
            acc_vec += lhs_vec * rhs_vec;
        }
        var acc = @reduce(.Add, acc_vec);
        while (idx < lhs.len) : (idx += 1) acc += lhs[idx] * rhs[idx];
        return acc;
    }

    fn applyHostMatmulFloatDense(self: *Session, left_items: []const f64, right_items: []const f64, shape: MatmulShape) KError!Value {
        if (shape.result_rank == 0) {
            return try self.floatValue(denseFloatDot(left_items[0..shape.left_cols], right_items[0..shape.left_cols]));
        }

        const right_t = try self.allocator.alloc(f64, right_items.len);
        defer self.allocator.free(right_t);
        transposeDenseFloatMatrixBlocked(right_t, right_items, shape.right_rows, shape.right_cols);

        const out = try self.allocManagedHostFloatResult(shape.result_len);
        for (0..shape.result_rows) |row_idx| {
            const out_row = out.items[row_idx * shape.result_cols ..][0..shape.result_cols];
            const left_row = left_items[row_idx * shape.left_cols ..][0..shape.left_cols];
            for (0..shape.result_cols) |col_idx| {
                const right_col = right_t[col_idx * shape.left_cols ..][0..shape.left_cols];
                out_row[col_idx] = denseFloatDot(left_row, right_col);
            }
        }
        return try self.finishHostMatmulFloatResult(shape, out);
    }

    fn applyHostMatmulGeneric(self: *Session, left: Value, right: Value, shape: MatmulShape) KError!Value {
        const left_view = try hostDenseView(self, left);
        const right_view = try hostDenseView(self, right);

        if (shape.result_mode == .float) {
            if (left_view == .float_array and left_view.float_array == .dense and right_view == .float_array and right_view.float_array == .dense) {
                return try self.applyHostMatmulFloatDense(left_view.float_array.dense, right_view.float_array.dense, shape);
            }

            if (shape.result_rank == 0) {
                var acc: f64 = 0.0;
                for (0..shape.left_cols) |inner_idx| {
                    acc += (try hostDenseViewFloatItem(left_view, inner_idx)) *
                        (try hostDenseViewFloatItem(right_view, inner_idx));
                }
                return try self.floatValue(acc);
            }

            const out = try self.allocManagedHostFloatResult(shape.result_len);
            @memset(out.items, 0.0);
            for (0..shape.result_rows) |row_idx| {
                const out_row = out.items[row_idx * shape.result_cols ..][0..shape.result_cols];
                for (0..shape.left_cols) |inner_idx| {
                    const left_value = try hostDenseViewFloatItem(left_view, row_idx * shape.left_cols + inner_idx);
                    const right_base = inner_idx * shape.right_cols;
                    for (0..shape.result_cols) |col_idx| {
                        out_row[col_idx] += left_value * (try hostDenseViewFloatItem(right_view, right_base + col_idx));
                    }
                }
            }
            return try self.finishHostMatmulFloatResult(shape, out);
        }

        var out_items = try self.allocator.alloc(i64, shape.result_len);
        defer self.allocator.free(out_items);

        if (shape.result_rank == 0) {
            var acc: i128 = 0;
            for (0..shape.left_cols) |inner_idx| {
                acc += @as(i128, try hostDenseViewIntItem(left_view, inner_idx)) *
                    @as(i128, try hostDenseViewIntItem(right_view, inner_idx));
            }
            out_items[0] = std.math.cast(i64, acc) orelse return error.Unsupported;
            return try self.finishHostMatmulIntResult(shape, out_items);
        }

        for (0..shape.result_rows) |row_idx| {
            for (0..shape.result_cols) |col_idx| {
                var acc: i128 = 0;
                for (0..shape.left_cols) |inner_idx| {
                    const left_value = @as(i128, try hostDenseViewIntItem(left_view, row_idx * shape.left_cols + inner_idx));
                    const right_value = @as(i128, try hostDenseViewIntItem(right_view, inner_idx * shape.right_cols + col_idx));
                    acc += left_value * right_value;
                }
                out_items[row_idx * shape.result_cols + col_idx] = std.math.cast(i64, acc) orelse return error.Unsupported;
            }
        }
        return try self.finishHostMatmulIntResult(shape, out_items);
    }

    fn promoteRenderableMatrixValue(self: *Session, value: Value) KError!?Value {
        if (valueNumericMatrixShape(value) != null) return value;
        _ = self;
        return null;
    }

    const NumericDyadOperands = struct {
        left: Value,
        right: Value,
    };

    fn promoteRenderableNumericDyadOperands(self: *Session, left: Value, right: Value) KError!?NumericDyadOperands {
        var promoted_left = left;
        var promoted_right = right;
        var changed = false;

        if (try self.promoteRenderableMatrixValue(left)) |value| {
            if (value.raw != left.raw) {
                promoted_left = value;
                changed = true;
            }
        }
        if (try self.promoteRenderableMatrixValue(right)) |value| {
            if (value.raw != right.raw) {
                promoted_right = value;
                changed = true;
            }
        }
        if (!changed) return null;
        return .{ .left = promoted_left, .right = promoted_right };
    }

    fn applyBackendMatmulValues(self: *Session, left: Value, right: Value) KError!Value {
        if (comptime runtime_has_mlx) {
            return runtime_backend_exec.applyBackendMatmulValues(.{
                .Session = Session,
                .Value = Value,
                .NumericArray = NumericArray,
                .KError = KError,
                .c = c,
                .mlx = mlx,
                .mapMlxError = mapMlxError,
                .backendContext = Session.backendContext,
                .valueNumericHandle = valueNumericHandle,
                .numericIntAt = numericIntAt,
                .numericArrayIsFirstAxisSlice = numericArrayIsFirstAxisSlice,
                .numericArrayFirstAxisSliceSource = numericArrayFirstAxisSliceSource,
                .numericArrayFirstAxisSliceRowStart = numericArrayFirstAxisSliceRowStart,
                .numericArrayFirstAxisSliceRowStep = numericArrayFirstAxisSliceRowStep,
                .numericArrayIsFirstAxisIndex = numericArrayIsFirstAxisIndex,
                .numericArrayFirstAxisIndexSource = numericArrayFirstAxisIndexSource,
                .numericArrayFirstAxisIndexRows = numericArrayFirstAxisIndexRows,
                .numericArrayIsFirstAxisConcat = numericArrayIsFirstAxisConcat,
                .numericArrayFirstAxisConcatLeft = numericArrayFirstAxisConcatLeft,
                .numericArrayFirstAxisConcatRight = numericArrayFirstAxisConcatRight,
                .numericArrayIsReshapeView = numericArrayIsReshapeView,
                .numericArrayReshapeSource = numericArrayReshapeSource,
                .numericArrayIsTransposeView = numericArrayIsTransposeView,
                .numericArrayTransposeSource = numericArrayTransposeSource,
                .numeric_array_max_rank = numeric_array_max_rank,
                .materializeBackendArray = Session.materializeBackendArray,
                .wrapManagedBackendArray = Session.wrapManagedBackendArray,
            }, self, left, right);
        }
        return error.Unsupported;
    }

    fn applyMatmulValues(self: *Session, left: Value, right: Value) KError!Value {
        const promoted_left = (try self.promoteRenderableMatrixValue(left)) orelse left;
        const promoted_right = (try self.promoteRenderableMatrixValue(right)) orelse right;
        const shape = (try matmulShapeForValues(promoted_left, promoted_right)) orelse return error.Type;
        return switch (planMatmulBackend(self, promoted_left, promoted_right)) {
            .host => try self.applyHostMatmulGeneric(promoted_left, promoted_right, shape),
            .mlx => try self.applyBackendMatmulValues(promoted_left, promoted_right),
        };
    }

    fn applyInnerProductClosure(self: *Session, info: InnerProductInfo, args: []const Value) KError!Value {
        if (args.len != 2) return error.Arity;
        if (info.reduce == .add and info.map == .mul) return try self.applyMatmulValues(args[0], args[1]);
        return error.Unsupported;
    }

    const BatchedMatmulShape = struct {
        batch_len: usize,
        left_rows: usize,
        inner_len: usize,
        right_cols: usize,
    };

    fn batchedMatmulShapeForValues(left: Value, right: Value) KError!?BatchedMatmulShape {
        _ = valueNumericMode(left) orelse return null;
        _ = valueNumericMode(right) orelse return null;

        const left_handle = shapedNumericHandle(left) orelse return null;
        const right_handle = shapedNumericHandle(right) orelse return null;
        if (left_handle.rank != 3 or right_handle.rank != 3) return null;

        const batch_len: usize = @intCast(left_handle.shape[0]);
        if (batch_len == 0) return null;
        if (batch_len != @as(usize, @intCast(right_handle.shape[0]))) return error.Type;

        const left_rows: usize = @intCast(left_handle.shape[1]);
        const inner_len: usize = @intCast(left_handle.shape[2]);
        if (inner_len != @as(usize, @intCast(right_handle.shape[1]))) return error.Type;

        return .{
            .batch_len = batch_len,
            .left_rows = left_rows,
            .inner_len = inner_len,
            .right_cols = @intCast(right_handle.shape[2]),
        };
    }

    fn planBatchedMatmulBackend(self: *Session, left: Value, right: Value, shape: BatchedMatmulShape) DenseExecBackend {
        const left_facts = denseValuePlanFacts(left);
        const right_facts = denseValuePlanFacts(right);
        return chooseDenseRegionBackend(self, .matmul, .{
            .elem_count = shape.batch_len * shape.left_rows * shape.inner_len * shape.right_cols,
            .matrix_rows = shape.batch_len * shape.left_rows,
            .matrix_cols = shape.right_cols,
            .has_backend_residency = left_facts.has_backend_residency or right_facts.has_backend_residency,
        });
    }

    fn applyHostBatchedMatmulValues(self: *Session, left: Value, right: Value, shape: BatchedMatmulShape) KError!Value {
        const left_handle = shapedNumericHandle(left) orelse return error.Type;
        const right_handle = shapedNumericHandle(right) orelse return error.Type;

        var results = std.ArrayList(Value).empty;
        defer {
            for (results.items) |value| self.releaseValue(value);
            results.deinit(self.allocator);
        }
        try results.ensureTotalCapacity(self.allocator, shape.batch_len);

        for (0..shape.batch_len) |idx| {
            const left_item = try numericValueFirstAxisCellValue(self, left, left_handle, @intCast(idx));
            defer self.releaseValue(left_item);
            const right_item = try numericValueFirstAxisCellValue(self, right, right_handle, @intCast(idx));
            defer self.releaseValue(right_item);

            const item_shape = (try matmulShapeForValues(left_item, right_item)) orelse return error.Type;
            if (item_shape.result_rank != 2) return error.Type;
            const result = try self.applyHostMatmulGeneric(left_item, right_item, item_shape);
            try results.append(self.allocator, result);
        }
        return try self.createManagedArrayLikeFromValues(results.items);
    }

    fn applyBatchedMatmulValues(self: *Session, left: Value, right: Value) KError!?Value {
        const shape = (try batchedMatmulShapeForValues(left, right)) orelse return null;
        return switch (self.planBatchedMatmulBackend(left, right, shape)) {
            .host => try self.applyHostBatchedMatmulValues(left, right, shape),
            .mlx => try self.applyBackendMatmulValues(left, right),
        };
    }

    fn dotValues(self: *Session, left: Value, right: Value) KError!Value {
        return try self.applyDot(left, right);
    }

    fn applyNumericMonad(self: *Session, op: BuiltinId, value: Value) KError!Value {
        if (NumericStructuralView.init(value)) |structural| {
            if (try numericStructuralDenseMonadValue(self, value, structural, op)) |result| return result;
        }
        if (valueNumericHandle(value)) |const_handle| {
            const handle = @constCast(const_handle);
            if (supportsBackendMonad(op) and !numericHasHostAttachment(handle) and hasBackendRealization(value)) {
                return try self.applyBackendArrayMonad(op, value);
            }
            if (!numericHasHostAttachment(handle) and numericArrayStructuralTag(handle) != .materialized) {
                const view = try hostDenseView(self, value);
                return try self.applyHostDenseViewMonad(op, value, view);
            }
            return self.applyHostArrayMonad(op, try hostStructuralArrayForHandle(self, handle));
        }
        if (value.tag() != .array) return error.Type;
        return switch (value.arrayKind()) {
            .host_dense_array => self.applyHostArrayMonad(op, value.asHostDenseArray()),
            .backend_array => self.applyBackendArrayMonad(op, value),
            else => error.Type,
        };
    }

    fn applyHostDenseViewMonad(self: *Session, op: BuiltinId, source_value: Value, view: HostDenseView) KError!Value {
        return switch (view) {
            .int_array => |items| switch (op) {
                .add, .mul => self.shareValue(source_value),
                .sub => blk: {
                    const input_kind = hostIntDenseViewKind(items);
                    const input_range = hostIntDenseValueRange(source_value, items);
                    const input_flags = hostIntDenseValueFlags(source_value, items);
                    const len = hostIntDenseViewLen(items);
                    if (hostIntNegRange(input_range)) |result_range| {
                        const result_kind = hostIntStorageKindForRange(result_range.min, result_range.max);
                        var plan = try self.planHostIntUnaryOutput(source_value, input_kind, result_kind, len, false, true);
                        try fillIntNegDenseResult(&plan.output, items, plan.unchecked_safe);
                        break :blk try self.finishHostIntOutput(plan, intNegResultFlags(input_flags));
                    }
                    var attempt_kind = hostNegInitialResultKind(input_kind);
                    while (true) {
                        var plan = try self.planHostIntUnaryOutput(
                            source_value,
                            input_kind,
                            attempt_kind,
                            len,
                            false,
                            hostNegUncheckedSafeForOutput(input_kind, attempt_kind),
                        );
                        fillIntNegDenseResult(&plan.output, items, plan.unchecked_safe) catch |err| switch (err) {
                            error.Unsupported => {
                                try retryWiderHostIntKind(&attempt_kind);
                                continue;
                            },
                            else => return err,
                        };
                        break :blk try self.finishHostIntOutput(plan, intNegResultFlags(input_flags));
                    }
                },
                .div => blk: {
                    const plan = try self.planHostFloatUnaryOutput(source_value, hostIntDenseViewLen(items), false);
                    fillFloatUnaryIntDenseView(plan.output.items, op, items);
                    break :blk try self.finishHostFloatOutput(plan, 0);
                },
                .exp, .log, .sin, .cos, .tanh, .sigmoid => blk: {
                    const plan = try self.planHostFloatUnaryOutput(source_value, hostIntDenseViewLen(items), false);
                    fillFloatUnaryIntDenseView(plan.output.items, op, items);
                    break :blk try self.finishHostFloatOutput(plan, 0);
                },
                else => error.Type,
            },
            .float_array => |items| switch (op) {
                .add, .mul => self.shareValue(source_value),
                .sub => blk: {
                    const plan = try self.planHostFloatUnaryOutput(source_value, hostFloatDenseViewLen(items), false);
                    fillFloatNegDenseView(plan.output.items, items);
                    break :blk try self.finishHostFloatOutput(plan, 0);
                },
                .div => blk: {
                    const plan = try self.planHostFloatUnaryOutput(source_value, hostFloatDenseViewLen(items), false);
                    fillFloatUnaryDenseView(plan.output.items, op, items);
                    break :blk try self.finishHostFloatOutput(plan, 0);
                },
                .exp, .log, .sin, .cos, .tanh, .sigmoid => blk: {
                    const plan = try self.planHostFloatUnaryOutput(source_value, hostFloatDenseViewLen(items), false);
                    fillFloatUnaryDenseView(plan.output.items, op, items);
                    break :blk try self.finishHostFloatOutput(plan, 0);
                },
                else => error.Type,
            },
            else => error.Type,
        };
    }

    fn applyNumericDyad(self: *Session, op: BuiltinId, left: Value, right: Value) KError!Value {
        const promoted_left = if (try self.promoteRenderableMatrixValue(left)) |value| value else left;
        const promoted_right = if (try self.promoteRenderableMatrixValue(right)) |value| value else right;
        if (planDenseNumericDyadBackend(self, op, promoted_left, promoted_right) == .mlx) {
            self.noteHostDenseDyadMiss(.planner_backend);
            return self.applyBackendArrayDyad(op, promoted_left, promoted_right);
        }
        return self.applyHostArrayDyad(op, promoted_left, promoted_right);
    }

    fn hasArrayOperand(left: Value, right: Value) bool {
        return left.tag() == .array or right.tag() == .array;
    }

    fn canApplyNumericDyad(left: Value, right: Value) bool {
        return valueNumericMode(left) != null and valueNumericMode(right) != null;
    }

    fn applyGenericArrayDyad(self: *Session, op: BuiltinId, left: Value, right: Value) KError!Value {
        const len = try arrayResultLen(left, right);
        const left_dense = if (left.tag() == .array and valueNumericMode(left) != null) try numericHostArrayValue(self, left) else null;
        const right_dense = if (right.tag() == .array and valueNumericMode(right) != null) try numericHostArrayValue(self, right) else null;
        const left_boxed = if (left.tag() == .array and left.arraySubkind() == .host_boxed_array) left.asHostBoxedArray() else null;
        const right_boxed = if (right.tag() == .array and right.arraySubkind() == .host_boxed_array) right.asHostBoxedArray() else null;
        var out = std.ArrayList(Value).empty;
        defer {
            for (out.items) |value| self.releaseValue(value);
            out.deinit(self.allocator);
        }
        try out.ensureTotalCapacity(self.allocator, len);
        for (0..len) |idx| {
            const lhs = if (left_dense) |array|
                try self.hostDenseIndexScalar(array, @intCast(idx))
            else if (left_boxed) |array|
                try self.hostBoxedArrayIndexScalar(array, @intCast(idx))
            else
                left;
            defer if (left_dense != null or left_boxed != null) self.releaseValue(lhs);
            const rhs = if (right_dense) |array|
                try self.hostDenseIndexScalar(array, @intCast(idx))
            else if (right_boxed) |array|
                try self.hostBoxedArrayIndexScalar(array, @intCast(idx))
            else
                right;
            defer if (right_dense != null or right_boxed != null) self.releaseValue(rhs);
            try out.append(self.allocator, switch (op) {
                .add => try self.addValues(lhs, rhs),
                .sub => try self.subValues(lhs, rhs),
                .mul => try self.mulValues(lhs, rhs),
                .div => try self.divValues(lhs, rhs),
                .pow => try self.powValues(lhs, rhs),
                .minimum => try self.minimumValues(lhs, rhs),
                .maximum => try self.maximumValues(lhs, rhs),
                .less => try self.lessValues(lhs, rhs),
                .more => try self.moreValues(lhs, rhs),
                .equal => try self.equalValues(lhs, rhs),
                else => return error.Unsupported,
            });
        }
        return try self.makeArrayFromValues(out.items);
    }

    fn applyHostArrayMonad(self: *Session, op: BuiltinId, array: *const HostDenseArray) KError!Value {
        return switch (op) {
            .add => self.shareValue(hostDenseSourceValue(array)),
            .sub => switch (array.storage) {
                .bit, .int8, .int16, .int32, .int64 => blk: {
                    const items = hostIntArrayView(array).?;
                    const input_kind = hostIntArrayViewKind(items);
                    const len = hostIntArrayViewLen(items);
                    if (hostIntNegRange(hostDenseCachedIntRange(array) orelse hostIntArrayViewEndpointRange(items, array.flags) orelse hostIntArrayViewRange(items))) |result_range| {
                        const result_kind = hostIntStorageKindForRange(result_range.min, result_range.max);
                        var plan = try self.planHostIntUnaryOutput(hostDenseSourceValue(array), input_kind, result_kind, len, true, true);
                        try fillIntNegArrayResult(&plan.output, items, plan.unchecked_safe);
                        break :blk try self.finishHostIntOutput(plan, intNegResultFlags(array.flags));
                    }
                    var attempt_kind = hostNegInitialResultKind(input_kind);
                    while (true) {
                        var plan = try self.planHostIntUnaryOutput(
                            hostDenseSourceValue(array),
                            input_kind,
                            attempt_kind,
                            len,
                            false,
                            hostNegUncheckedSafeForOutput(input_kind, attempt_kind),
                        );
                        fillIntNegArrayResult(&plan.output, items, plan.unchecked_safe) catch |err| switch (err) {
                            error.Unsupported => {
                                try retryWiderHostIntKind(&attempt_kind);
                                continue;
                            },
                            else => return err,
                        };
                        break :blk try self.finishHostIntOutput(plan, intNegResultFlags(array.flags));
                    }
                },
                .float64 => |items| blk: {
                    var plan = try self.planHostFloatUnaryOutput(hostDenseSourceValue(array), items.len, true);
                    for (items, 0..) |item, idx| plan.output.items[idx] = -item;
                    break :blk try self.finishHostFloatOutput(plan, 0);
                },
            },
            .mul => self.shareValue(hostDenseSourceValue(array)),
            .div, .exp, .log, .sin, .cos, .tanh, .sigmoid => switch (array.storage) {
                .bit => |words| blk: {
                    const plan = try self.planHostFloatUnaryOutput(hostDenseSourceValue(array), array.logical_len, false);
                    fillFloatUnaryBitArray(plan.output.items, op, .{ .words = words, .len = array.logical_len });
                    break :blk try self.finishHostFloatOutput(plan, 0);
                },
                .int8 => |items| blk: {
                    const plan = try self.planHostFloatUnaryOutput(hostDenseSourceValue(array), items.len, false);
                    fillFloatUnaryArray(i8, plan.output.items, op, items);
                    break :blk try self.finishHostFloatOutput(plan, 0);
                },
                .int16 => |items| blk: {
                    const plan = try self.planHostFloatUnaryOutput(hostDenseSourceValue(array), items.len, false);
                    fillFloatUnaryArray(i16, plan.output.items, op, items);
                    break :blk try self.finishHostFloatOutput(plan, 0);
                },
                .int32 => |items| blk: {
                    const plan = try self.planHostFloatUnaryOutput(hostDenseSourceValue(array), items.len, false);
                    fillFloatUnaryArray(i32, plan.output.items, op, items);
                    break :blk try self.finishHostFloatOutput(plan, 0);
                },
                .int64 => |items| blk: {
                    const plan = try self.planHostFloatUnaryOutput(hostDenseSourceValue(array), items.len, false);
                    fillFloatUnaryArray(i64, plan.output.items, op, items);
                    break :blk try self.finishHostFloatOutput(plan, 0);
                },
                .float64 => |items| blk: {
                    const plan = try self.planHostFloatUnaryOutput(hostDenseSourceValue(array), items.len, true);
                    fillFloatUnaryArray(f64, plan.output.items, op, items);
                    break :blk try self.finishHostFloatOutput(plan, 0);
                },
            },
            else => error.Type,
        };
    }

    fn applyHostArrayDyad(self: *Session, op: BuiltinId, left: Value, right: Value) KError!Value {
        const mode = arrayResultMode(op, left, right) orelse {
            self.noteHostDenseDyadMiss(.mode);
            return error.Type;
        };
        const len = try arrayResultLen(left, right);
        if (rowwiseMatrixVectorDyad(left, right)) |rowwise| {
            self.noteHostDenseDyadHost(op, left, right, len, true);
            return switch (mode) {
                .int => try self.applyHostArrayDyadRowwiseInt(op, left, right, rowwise, len),
                .float => try self.applyHostArrayDyadRowwiseFloat(op, left, right, rowwise, len),
            };
        }
        const left_view = hostDenseView(self, left) catch |err| {
            self.noteHostDenseDyadMiss(.view);
            return err;
        };
        const right_view = hostDenseView(self, right) catch |err| {
            self.noteHostDenseDyadMiss(.view);
            return err;
        };
        self.noteHostDenseDyadHost(op, left, right, len, false);
        return switch (mode) {
            .int => try self.applyHostArrayDyadInt(op, left, right, left_view, right_view, len),
            .float => try self.applyHostArrayDyadFloat(op, left, right, left_view, right_view, len),
        };
    }

    fn applyHostArrayDyadRowwiseInt(self: *Session, op: BuiltinId, left: Value, right: Value, rowwise: RowwiseMatrixVectorDyad, len: usize) KError!Value {
        var profile_scope = self.beginSamplingProfileScope(.dense_host);
        defer profile_scope.end();

        var out = std.ArrayList(i64).empty;
        defer out.deinit(self.allocator);
        try out.ensureTotalCapacity(self.allocator, len);
        for (0..len) |idx| {
            const lhs = try numericIntAt(left, rowwise.operandIndex(true, idx));
            const rhs = try numericIntAt(right, rowwise.operandIndex(false, idx));
            try out.append(self.allocator, switch (op) {
                .add => try checkedIntOp(.add, lhs, rhs),
                .sub => try checkedIntOp(.sub, lhs, rhs),
                .mul => try checkedIntOp(.mul, lhs, rhs),
                .pow => try checkedIntOp(.pow, lhs, rhs),
                .minimum => @min(lhs, rhs),
                .maximum => @max(lhs, rhs),
                else => return error.Type,
            });
        }
        const result = try self.createManagedHostIntArray(out.items);
        return try applyNonVectorNumericShapeToValue(self, result, numericShapeSnapshotMatrix(rowwise.rows, rowwise.cols));
    }

    fn applyHostArrayDyadRowwiseFloat(self: *Session, op: BuiltinId, left: Value, right: Value, rowwise: RowwiseMatrixVectorDyad, len: usize) KError!Value {
        var profile_scope = self.beginSamplingProfileScope(.dense_host);
        defer profile_scope.end();

        var out = std.ArrayList(f64).empty;
        defer out.deinit(self.allocator);
        try out.ensureTotalCapacity(self.allocator, len);
        for (0..len) |idx| {
            const lhs = try numericFloatAt(left, rowwise.operandIndex(true, idx));
            const rhs = try numericFloatAt(right, rowwise.operandIndex(false, idx));
            try out.append(self.allocator, switch (op) {
                .add => lhs + rhs,
                .sub => lhs - rhs,
                .mul => lhs * rhs,
                .div => lhs / rhs,
                .pow => std.math.pow(f64, lhs, rhs),
                .minimum => @min(lhs, rhs),
                .maximum => @max(lhs, rhs),
                else => return error.Type,
            });
        }
        const result = try self.createManagedHostFloatArray(out.items);
        return try applyNonVectorNumericShapeToValue(self, result, numericShapeSnapshotMatrix(rowwise.rows, rowwise.cols));
    }

    fn applyHostArrayDyadInt(self: *Session, op: BuiltinId, left_value: Value, right_value: Value, left: HostDenseView, right: HostDenseView, len: usize) KError!Value {
        var profile_scope = self.beginSamplingProfileScope(.dense_host);
        defer profile_scope.end();
        return switch (left) {
            .scalar_int => |li| switch (right) {
                .scalar_int => |ri| blk: {
                    const result = try checkedIntOp(op, li, ri);
                    break :blk try self.intValue(result);
                },
                .int_array => |items| blk: {
                    const left_kind = hostIntStorageKindForValue(li);
                    const right_kind = hostIntDenseViewKind(items);
                    const left_range = hostIntRangeForValue(li);
                    const right_range = hostIntDenseValueRange(right_value, items);
                    const right_flags = hostIntDenseValueFlags(right_value, items);
                    if (hostIntDyadRange(op, left_range, right_range)) |result_range| {
                        const result_kind = hostIntDyadResultKindForRange(op, left_kind, right_kind, result_range);
                        var plan = try self.planHostIntDyadOutput(left_value, right_value, left_kind, right_kind, result_kind, len, true, true);
                        try fillIntScalarDenseResult(&plan.output, op, li, items, true, plan.unchecked_safe);
                        break :blk try self.finishHostIntOutput(plan, intArrayScalarResultFlags(op, right_flags, li, true));
                    }
                    var attempt_kind = hostIntInitialResultKind(op, left_kind, right_kind);
                    while (true) {
                        var plan = try self.planHostIntDyadOutput(
                            left_value,
                            right_value,
                            left_kind,
                            right_kind,
                            attempt_kind,
                            len,
                            false,
                            hostIntUncheckedSafeForOutput(left_kind, right_kind, attempt_kind),
                        );
                        fillIntScalarDenseResult(&plan.output, op, li, items, true, plan.unchecked_safe) catch |err| switch (err) {
                            error.Unsupported => {
                                try retryWiderHostIntKind(&attempt_kind);
                                continue;
                            },
                            else => return err,
                        };
                        break :blk try self.finishHostIntOutput(plan, intArrayScalarResultFlags(op, right_flags, li, true));
                    }
                },
                else => error.Type,
            },
            .int_array => |items| switch (right) {
                .scalar_int => |ri| blk: {
                    const left_kind = hostIntDenseViewKind(items);
                    const right_kind = hostIntStorageKindForValue(ri);
                    const left_range = hostIntDenseValueRange(left_value, items);
                    const left_flags = hostIntDenseValueFlags(left_value, items);
                    const right_range = hostIntRangeForValue(ri);
                    if (hostIntDyadRange(op, left_range, right_range)) |result_range| {
                        const result_kind = hostIntDyadResultKindForRange(op, left_kind, right_kind, result_range);
                        var plan = try self.planHostIntDyadOutput(left_value, right_value, left_kind, right_kind, result_kind, len, true, true);
                        try fillIntScalarDenseResult(&plan.output, op, ri, items, false, plan.unchecked_safe);
                        break :blk try self.finishHostIntOutput(plan, intArrayScalarResultFlags(op, left_flags, ri, false));
                    }
                    var attempt_kind = hostIntInitialResultKind(op, left_kind, right_kind);
                    while (true) {
                        var plan = try self.planHostIntDyadOutput(
                            left_value,
                            right_value,
                            left_kind,
                            right_kind,
                            attempt_kind,
                            len,
                            false,
                            hostIntUncheckedSafeForOutput(left_kind, right_kind, attempt_kind),
                        );
                        fillIntScalarDenseResult(&plan.output, op, ri, items, false, plan.unchecked_safe) catch |err| switch (err) {
                            error.Unsupported => {
                                try retryWiderHostIntKind(&attempt_kind);
                                continue;
                            },
                            else => return err,
                        };
                        break :blk try self.finishHostIntOutput(plan, intArrayScalarResultFlags(op, left_flags, ri, false));
                    }
                },
                .int_array => |right_items| blk: {
                    const left_kind = hostIntDenseViewKind(items);
                    const right_kind = hostIntDenseViewKind(right_items);
                    const left_range = hostIntDenseValueRange(left_value, items);
                    const right_range = hostIntDenseValueRange(right_value, right_items);
                    const left_flags = hostIntDenseValueFlags(left_value, items);
                    const right_flags = hostIntDenseValueFlags(right_value, right_items);
                    if (hostIntDyadRange(op, left_range, right_range)) |result_range| {
                        const result_kind = hostIntDyadResultKindForRange(op, left_kind, right_kind, result_range);
                        var plan = try self.planHostIntDyadOutput(left_value, right_value, left_kind, right_kind, result_kind, len, true, true);
                        try fillIntDenseDenseResult(&plan.output, op, items, right_items, plan.unchecked_safe);
                        break :blk try self.finishHostIntOutput(plan, intArrayArrayResultFlags(op, left_flags, right_flags));
                    }
                    var attempt_kind = hostIntInitialResultKind(op, left_kind, right_kind);
                    while (true) {
                        var plan = try self.planHostIntDyadOutput(
                            left_value,
                            right_value,
                            left_kind,
                            right_kind,
                            attempt_kind,
                            len,
                            false,
                            hostIntUncheckedSafeForOutput(left_kind, right_kind, attempt_kind),
                        );
                        fillIntDenseDenseResult(&plan.output, op, items, right_items, plan.unchecked_safe) catch |err| switch (err) {
                            error.Unsupported => {
                                try retryWiderHostIntKind(&attempt_kind);
                                continue;
                            },
                            else => return err,
                        };
                        break :blk try self.finishHostIntOutput(plan, intArrayArrayResultFlags(op, left_flags, right_flags));
                    }
                },
                else => error.Type,
            },
            else => error.Type,
        };
    }

    fn applyHostArrayDyadFloat(self: *Session, op: BuiltinId, left_value: Value, right_value: Value, left: HostDenseView, right: HostDenseView, len: usize) KError!Value {
        var profile_scope = self.beginSamplingProfileScope(.dense_host);
        defer profile_scope.end();
        return switch (left) {
            .scalar_int => |li| switch (right) {
                .scalar_int => |ri| blk: {
                    const result = applyFloatOp(op, @floatFromInt(li), @floatFromInt(ri));
                    break :blk try self.floatValue(result);
                },
                .scalar_float => |rf| blk: {
                    const result = applyFloatOp(op, @floatFromInt(li), rf);
                    break :blk try self.floatValue(result);
                },
                .int_array => |right_items| blk: {
                    const plan = try self.planHostFloatDyadOutput(left_value, right_value, len, false);
                    fillFloatScalarIntDenseView(plan.output.items, op, @floatFromInt(li), right_items, true);
                    break :blk try self.finishHostFloatOutput(plan, 0);
                },
                .float_array => |right_items| blk: {
                    const plan = try self.planHostFloatDyadOutput(left_value, right_value, len, true);
                    fillFloatScalarDenseView(plan.output.items, op, @floatFromInt(li), right_items, true);
                    break :blk try self.finishHostFloatOutput(plan, 0);
                },
            },
            .scalar_float => |lf| switch (right) {
                .scalar_int => |ri| blk: {
                    const result = applyFloatOp(op, lf, @floatFromInt(ri));
                    break :blk try self.floatValue(result);
                },
                .scalar_float => |rf| blk: {
                    const result = applyFloatOp(op, lf, rf);
                    break :blk try self.floatValue(result);
                },
                .int_array => |right_items| blk: {
                    const plan = try self.planHostFloatDyadOutput(left_value, right_value, len, false);
                    fillFloatScalarIntDenseView(plan.output.items, op, lf, right_items, true);
                    break :blk try self.finishHostFloatOutput(plan, 0);
                },
                .float_array => |right_items| blk: {
                    const plan = try self.planHostFloatDyadOutput(left_value, right_value, len, true);
                    fillFloatScalarDenseView(plan.output.items, op, lf, right_items, true);
                    break :blk try self.finishHostFloatOutput(plan, 0);
                },
            },
            .int_array => |items| switch (right) {
                .scalar_int => |ri| blk: {
                    const plan = try self.planHostFloatDyadOutput(left_value, right_value, len, false);
                    fillFloatScalarIntDenseView(plan.output.items, op, @floatFromInt(ri), items, false);
                    break :blk try self.finishHostFloatOutput(plan, 0);
                },
                .scalar_float => |rf| blk: {
                    const plan = try self.planHostFloatDyadOutput(left_value, right_value, len, false);
                    fillFloatScalarIntDenseView(plan.output.items, op, rf, items, false);
                    break :blk try self.finishHostFloatOutput(plan, 0);
                },
                .int_array => |right_items| blk: {
                    const plan = try self.planHostFloatDyadOutput(left_value, right_value, len, false);
                    fillFloatIntDenseViewIntDenseView(plan.output.items, op, items, right_items);
                    break :blk try self.finishHostFloatOutput(plan, 0);
                },
                .float_array => |right_items| blk: {
                    const plan = try self.planHostFloatDyadOutput(left_value, right_value, len, true);
                    fillFloatIntDenseViewDenseView(plan.output.items, op, items, right_items);
                    break :blk try self.finishHostFloatOutput(plan, 0);
                },
            },
            .float_array => |items| switch (right) {
                .scalar_int => |ri| blk: {
                    const plan = try self.planHostFloatDyadOutput(left_value, right_value, len, true);
                    fillFloatScalarDenseView(plan.output.items, op, @floatFromInt(ri), items, false);
                    break :blk try self.finishHostFloatOutput(plan, 0);
                },
                .scalar_float => |rf| blk: {
                    const plan = try self.planHostFloatDyadOutput(left_value, right_value, len, true);
                    fillFloatScalarDenseView(plan.output.items, op, rf, items, false);
                    break :blk try self.finishHostFloatOutput(plan, 0);
                },
                .int_array => |right_items| blk: {
                    const plan = try self.planHostFloatDyadOutput(left_value, right_value, len, true);
                    fillFloatDenseViewIntDenseView(plan.output.items, op, items, right_items);
                    break :blk try self.finishHostFloatOutput(plan, 0);
                },
                .float_array => |right_items| blk: {
                    const plan = try self.planHostFloatDyadOutput(left_value, right_value, len, true);
                    fillFloatDenseViewDenseView(plan.output.items, op, items, right_items);
                    break :blk try self.finishHostFloatOutput(plan, 0);
                },
            },
        };
    }

