        prev = item;
    }
    return host_dense_flag_normalized | orderFlagsFromMonotonic(asc, dsc);
}

fn hostFlatSegmentsIntItem(view: HostFlatSegmentsView, idx: usize) KError!i64 {
    if (idx >= view.len) return error.Internal;
    var offset: usize = 0;
    for (view.values) |value| {
        const len = numericVectorLen(value) orelse return error.Type;
        if (idx < offset + len) return try numericIntAt(value, idx - offset);
        offset += len;
    }
    return error.Internal;
}

fn hostFlatSegmentsFloatItem(view: HostFlatSegmentsView, idx: usize) KError!f64 {
    if (idx >= view.len) return error.Internal;
