fn fillIntArrayArrayResultFromBit(comptime OutT: type, out: []OutT, op: BuiltinId, left_items: HostIntArrayView, right_items: HostIntArrayView, unchecked_safe: bool) KError!void {
    return switch (left_items) {
        .bit => |left_bits| switch (right_items) {
            .bit => |right_bits| fillIntBitArrayArrayTo(OutT, out, op, left_bits, right_bits, unchecked_safe),
            .int8 => |right_slice| fillIntBitArrayMixedTo(OutT, i8, out, op, left_bits, right_slice, true, unchecked_safe),
            .int16 => |right_slice| fillIntBitArrayMixedTo(OutT, i16, out, op, left_bits, right_slice, true, unchecked_safe),
            .int32 => |right_slice| fillIntBitArrayMixedTo(OutT, i32, out, op, left_bits, right_slice, true, unchecked_safe),
            .int64 => |right_slice| fillIntBitArrayMixedTo(OutT, i64, out, op, left_bits, right_slice, true, unchecked_safe),
        },
        .int8 => |left_slice| switch (right_items) {
            .bit => |right_bits| fillIntBitArrayMixedTo(OutT, i8, out, op, right_bits, left_slice, false, unchecked_safe),
            else => unreachable,
        },
        .int16 => |left_slice| switch (right_items) {
            .bit => |right_bits| fillIntBitArrayMixedTo(OutT, i16, out, op, right_bits, left_slice, false, unchecked_safe),
            else => unreachable,
        },
        .int32 => |left_slice| switch (right_items) {
            .bit => |right_bits| fillIntBitArrayMixedTo(OutT, i32, out, op, right_bits, left_slice, false, unchecked_safe),
            else => unreachable,
        },
        .int64 => |left_slice| switch (right_items) {
            .bit => |right_bits| fillIntBitArrayMixedTo(OutT, i64, out, op, right_bits, left_slice, false, unchecked_safe),
            else => unreachable,
        },
    };
}

fn fillIntNegArrayResult(out: *HostIntResult, items: HostIntArrayView, unchecked_safe: bool) KError!void {
    if (std.meta.activeTag(items) == .bit) {
        return switch (out.*) {
            .bit => unreachable,
            .int8 => |*dest| fillIntNegBitArrayTo(i8, dest.items, items.bit),
            .int16 => |*dest| fillIntNegBitArrayTo(i16, dest.items, items.bit),
            .int32 => |*dest| fillIntNegBitArrayTo(i32, dest.items, items.bit),
            .int64 => |*dest| fillIntNegBitArrayTo(i64, dest.items, items.bit),
        };
    }
    switch (out.*) {
        .bit => unreachable,
        .int8 => |*dest| switch (items) {
            .int8 => |slice| try fillIntNegArrayTo(i8, i8, dest.items, slice, unchecked_safe),
            .int16 => |slice| try fillIntNegArrayTo(i8, i16, dest.items, slice, unchecked_safe),
            .int32 => |slice| try fillIntNegArrayTo(i8, i32, dest.items, slice, unchecked_safe),
            .int64 => |slice| try fillIntNegArrayTo(i8, i64, dest.items, slice, unchecked_safe),
            .bit => unreachable,
        },
        .int16 => |*dest| switch (items) {
            .int8 => |slice| try fillIntNegArrayTo(i16, i8, dest.items, slice, unchecked_safe),
            .int16 => |slice| try fillIntNegArrayTo(i16, i16, dest.items, slice, unchecked_safe),
            .int32 => |slice| try fillIntNegArrayTo(i16, i32, dest.items, slice, unchecked_safe),
            .int64 => |slice| try fillIntNegArrayTo(i16, i64, dest.items, slice, unchecked_safe),
            .bit => unreachable,
        },
        .int32 => |*dest| switch (items) {
            .int8 => |slice| try fillIntNegArrayTo(i32, i8, dest.items, slice, unchecked_safe),
            .int16 => |slice| try fillIntNegArrayTo(i32, i16, dest.items, slice, unchecked_safe),
            .int32 => |slice| try fillIntNegArrayTo(i32, i32, dest.items, slice, unchecked_safe),
            .int64 => |slice| try fillIntNegArrayTo(i32, i64, dest.items, slice, unchecked_safe),
            .bit => unreachable,
        },
        .int64 => |*dest| switch (items) {
            .int8 => |slice| try fillIntNegArrayTo(i64, i8, dest.items, slice, unchecked_safe),
            .int16 => |slice| try fillIntNegArrayTo(i64, i16, dest.items, slice, unchecked_safe),
            .int32 => |slice| try fillIntNegArrayTo(i64, i32, dest.items, slice, unchecked_safe),
            .int64 => |slice| try fillIntNegArrayTo(i64, i64, dest.items, slice, unchecked_safe),
            .bit => unreachable,
        },
    }
}

fn fillIntNegDenseResult(out: *HostIntResult, items: HostIntDenseView, unchecked_safe: bool) KError!void {
    return switch (items) {
        .dense => |view| fillIntNegArrayResult(out, view, unchecked_safe),
        .range_iota, .flat_slice, .flat_stride, .flat_concat, .flat_segments, .first_axis_slice, .first_axis_index, .first_axis_concat, .transpose => {
            for (0..hostIntDenseViewLen(items)) |idx| {
                try out.set(idx, if (unchecked_safe)
                    applyIntOpUnchecked(.sub, 0, try hostIntDenseViewItem(items, idx))
                else
                    try checkedIntOp(.sub, 0, try hostIntDenseViewItem(items, idx)));
            }
        },
    };
}

fn fillFloatScalarArray(comptime T: type, out: []f64, op: BuiltinId, scalar: f64, items: []const T, scalar_left: bool) void {
    if (enable_dense_float_simd and comptime T == f64) {
        if (denseFloatSimdSupported(op)) {
            return switch (op) {
                .add => fillFloatDenseScalarArraySimd(.add, out, scalar, items, scalar_left),
                .sub => fillFloatDenseScalarArraySimd(.sub, out, scalar, items, scalar_left),
                .minimum => fillFloatDenseScalarArraySimd(.minimum, out, scalar, items, scalar_left),
                .maximum => fillFloatDenseScalarArraySimd(.maximum, out, scalar, items, scalar_left),
                .mul => fillFloatDenseScalarArraySimd(.mul, out, scalar, items, scalar_left),
                .div => fillFloatDenseScalarArraySimd(.div, out, scalar, items, scalar_left),
                else => unreachable,
            };
        }
    }
    for (items, 0..) |item, idx| {
        const lhs = if (scalar_left) scalar else toDenseFloat(item);
        const rhs = if (scalar_left) toDenseFloat(item) else scalar;
        out[idx] = applyFloatOp(op, lhs, rhs);
    }
}

fn fillFloatUnaryArray(comptime T: type, out: []f64, op: BuiltinId, items: []const T) void {
    for (items, 0..) |item, idx| {
        out[idx] = applyFloatMonadOp(op, toDenseFloat(item));
    }
}

fn fillFloatUnaryIntDenseView(out: []f64, op: BuiltinId, items: HostIntDenseView) void {
    for (0..hostIntDenseViewLen(items)) |idx| {
        out[idx] = applyFloatMonadOp(op, @floatFromInt(hostIntDenseViewItem(items, idx) catch unreachable));
    }
}

fn fillFloatReciprocalIntDenseView(out: []f64, items: HostIntDenseView) void {
    for (0..hostIntDenseViewLen(items)) |idx| {
        out[idx] = 1.0 / @as(f64, @floatFromInt(hostIntDenseViewItem(items, idx) catch unreachable));
    }
}

fn fillFloatArrayArray(comptime LT: type, comptime RT: type, out: []f64, op: BuiltinId, left_items: []const LT, right_items: []const RT) void {
    if (enable_dense_float_simd and comptime LT == f64 and RT == f64) {
        if (denseFloatSimdSupported(op)) {
            return switch (op) {
                .add => fillFloatDenseArrayArraySimd(.add, out, left_items, right_items),
                .sub => fillFloatDenseArrayArraySimd(.sub, out, left_items, right_items),
                .minimum => fillFloatDenseArrayArraySimd(.minimum, out, left_items, right_items),
                .maximum => fillFloatDenseArrayArraySimd(.maximum, out, left_items, right_items),
                .mul => fillFloatDenseArrayArraySimd(.mul, out, left_items, right_items),
                .div => fillFloatDenseArrayArraySimd(.div, out, left_items, right_items),
                else => unreachable,
            };
        }
    }
    for (left_items, 0..) |left_item, idx| {
        out[idx] = applyFloatOp(op, toDenseFloat(left_item), toDenseFloat(right_items[idx]));
    }
}

fn fillFloatNegDenseView(out: []f64, items: HostFloatDenseView) void {
    for (0..hostFloatDenseViewLen(items)) |idx| {
        out[idx] = -(hostFloatDenseViewItem(items, idx) catch unreachable);
    }
}

fn fillFloatReciprocalDenseView(out: []f64, items: HostFloatDenseView) void {
    for (0..hostFloatDenseViewLen(items)) |idx| {
        out[idx] = 1.0 / (hostFloatDenseViewItem(items, idx) catch unreachable);
    }
}

fn fillFloatUnaryDenseView(out: []f64, op: BuiltinId, items: HostFloatDenseView) void {
    for (0..hostFloatDenseViewLen(items)) |idx| {
        out[idx] = applyFloatMonadOp(op, hostFloatDenseViewItem(items, idx) catch unreachable);
    }
}

fn fillFloatScalarBitArray(out: []f64, op: BuiltinId, scalar: f64, items: HostBitSlice, scalar_left: bool) void {
    if (enable_mixed_bit_float_simd and denseFloatSimdSupported(op)) {
        return switch (op) {
            .add => fillFloatScalarBitArraySimd(.add, out, scalar, items, scalar_left),
            .sub => fillFloatScalarBitArraySimd(.sub, out, scalar, items, scalar_left),
            .minimum => fillFloatScalarBitArraySimd(.minimum, out, scalar, items, scalar_left),
            .maximum => fillFloatScalarBitArraySimd(.maximum, out, scalar, items, scalar_left),
            .mul => fillFloatScalarBitArraySimd(.mul, out, scalar, items, scalar_left),
            .div => fillFloatScalarBitArraySimd(.div, out, scalar, items, scalar_left),
            else => unreachable,
        };
    }
    if (items.len == 0) return;
    var out_idx: usize = 0;
    for (items.words, 0..) |_, word_idx| {
        var bits = bitWordMasked(items.words, items.len, word_idx);
        const active = bitWordActiveLen(items.len, word_idx, items.words.len);
        var bit_idx: usize = 0;
        while (bit_idx < active) : (bit_idx += 1) {
            const item = @as(f64, @floatFromInt(@as(u8, @intCast(bits & 1))));
            out[out_idx] = if (scalar_left) applyFloatOp(op, scalar, item) else applyFloatOp(op, item, scalar);
            bits >>= 1;
            out_idx += 1;
        }
    }
}

fn fillFloatUnaryBitArray(out: []f64, op: BuiltinId, items: HostBitSlice) void {
    if (items.len == 0) return;
    var out_idx: usize = 0;
    for (items.words, 0..) |_, word_idx| {
        var bits = bitWordMasked(items.words, items.len, word_idx);
        const active = bitWordActiveLen(items.len, word_idx, items.words.len);
        var bit_idx: usize = 0;
        while (bit_idx < active) : (bit_idx += 1) {
            out[out_idx] = applyFloatMonadOp(op, @as(f64, @floatFromInt(@as(u8, @intCast(bits & 1)))));
            bits >>= 1;
            out_idx += 1;
        }
    }
}

fn fillFloatBitViews(out: []f64, op: BuiltinId, left_items: HostBitSlice, right_items: HostBitSlice) void {
    if (enable_mixed_bit_float_simd and denseFloatSimdSupported(op)) {
        return switch (op) {
            .add => fillFloatBitViewsSimd(.add, out, left_items, right_items),
            .sub => fillFloatBitViewsSimd(.sub, out, left_items, right_items),
            .minimum => fillFloatBitViewsSimd(.minimum, out, left_items, right_items),
            .maximum => fillFloatBitViewsSimd(.maximum, out, left_items, right_items),
            .mul => fillFloatBitViewsSimd(.mul, out, left_items, right_items),
            .div => fillFloatBitViewsSimd(.div, out, left_items, right_items),
            else => unreachable,
        };
    }
    if (left_items.len == 0) return;
    var out_idx: usize = 0;
    for (left_items.words, 0..) |_, word_idx| {
        var left_bits = bitWordMasked(left_items.words, left_items.len, word_idx);
        var right_bits = bitWordMasked(right_items.words, right_items.len, word_idx);
        const active = bitWordActiveLen(left_items.len, word_idx, left_items.words.len);
        var bit_idx: usize = 0;
        while (bit_idx < active) : (bit_idx += 1) {
            out[out_idx] = applyFloatOp(
                op,
                @as(f64, @floatFromInt(@as(u8, @intCast(left_bits & 1)))),
                @as(f64, @floatFromInt(@as(u8, @intCast(right_bits & 1)))),
            );
            left_bits >>= 1;
            right_bits >>= 1;
            out_idx += 1;
        }
    }
}

fn fillFloatBitViewArray(comptime LeftBit: bool, out: []f64, op: BuiltinId, bit_items: HostBitSlice, other_items: []const f64) void {
    if (enable_mixed_bit_float_simd and denseFloatSimdSupported(op)) {
        return switch (op) {
            .add => fillFloatBitViewArraySimd(LeftBit, .add, out, bit_items, other_items),
            .sub => fillFloatBitViewArraySimd(LeftBit, .sub, out, bit_items, other_items),
            .minimum => fillFloatBitViewArraySimd(LeftBit, .minimum, out, bit_items, other_items),
            .maximum => fillFloatBitViewArraySimd(LeftBit, .maximum, out, bit_items, other_items),
            .mul => fillFloatBitViewArraySimd(LeftBit, .mul, out, bit_items, other_items),
            .div => fillFloatBitViewArraySimd(LeftBit, .div, out, bit_items, other_items),
            else => unreachable,
        };
    }
    if (bit_items.len == 0) return;
    var out_idx: usize = 0;
    for (bit_items.words, 0..) |_, word_idx| {
        var bits = bitWordMasked(bit_items.words, bit_items.len, word_idx);
        const active = bitWordActiveLen(bit_items.len, word_idx, bit_items.words.len);
        var bit_idx: usize = 0;
        while (bit_idx < active) : (bit_idx += 1) {
            const bit_value = @as(f64, @floatFromInt(@as(u8, @intCast(bits & 1))));
            out[out_idx] = if (LeftBit) applyFloatOp(op, bit_value, other_items[out_idx]) else applyFloatOp(op, other_items[out_idx], bit_value);
            bits >>= 1;
            out_idx += 1;
        }
    }
}

fn fillFloatScalarIntView(out: []f64, op: BuiltinId, scalar: f64, items: HostIntArrayView, scalar_left: bool) void {
    if (std.meta.activeTag(items) == .bit) return fillFloatScalarBitArray(out, op, scalar, items.bit, scalar_left);
    for (0..hostIntArrayViewLen(items)) |idx| {
        const item = @as(f64, @floatFromInt(hostIntViewItem(items, idx)));
        out[idx] = if (scalar_left) applyFloatOp(op, scalar, item) else applyFloatOp(op, item, scalar);
    }
}

fn fillFloatIntViews(out: []f64, op: BuiltinId, left_items: HostIntArrayView, right_items: HostIntArrayView) void {
    if (std.meta.activeTag(left_items) == .bit and std.meta.activeTag(right_items) == .bit) return fillFloatBitViews(out, op, left_items.bit, right_items.bit);
    for (0..hostIntArrayViewLen(left_items)) |idx| {
        out[idx] = applyFloatOp(
            op,
            @as(f64, @floatFromInt(hostIntViewItem(left_items, idx))),
            @as(f64, @floatFromInt(hostIntViewItem(right_items, idx))),
        );
    }
}

fn fillFloatIntViewArray(out: []f64, op: BuiltinId, left_items: HostIntArrayView, right_items: []const f64) void {
    if (std.meta.activeTag(left_items) == .bit) return fillFloatBitViewArray(true, out, op, left_items.bit, right_items);
    for (0..hostIntArrayViewLen(left_items)) |idx| {
        out[idx] = applyFloatOp(op, @as(f64, @floatFromInt(hostIntViewItem(left_items, idx))), right_items[idx]);
    }
}

fn fillFloatArrayIntView(out: []f64, op: BuiltinId, left_items: []const f64, right_items: HostIntArrayView) void {
    if (std.meta.activeTag(right_items) == .bit) return fillFloatBitViewArray(false, out, op, right_items.bit, left_items);
    for (0..hostIntArrayViewLen(right_items)) |idx| {
        out[idx] = applyFloatOp(op, left_items[idx], @as(f64, @floatFromInt(hostIntViewItem(right_items, idx))));
    }
}

fn fillFloatScalarIntDenseView(out: []f64, op: BuiltinId, scalar: f64, items: HostIntDenseView, scalar_left: bool) void {
    switch (items) {
        .dense => |view| fillFloatScalarIntView(out, op, scalar, view, scalar_left),
        .range_iota, .flat_slice, .flat_stride, .flat_concat, .flat_segments, .first_axis_slice, .first_axis_index, .first_axis_concat, .transpose => {
            for (0..hostIntDenseViewLen(items)) |idx| {
                const item = hostIntDenseViewItem(items, idx) catch unreachable;
                out[idx] = if (scalar_left)
                    applyFloatOp(op, scalar, @floatFromInt(item))
                else
                    applyFloatOp(op, @floatFromInt(item), scalar);
            }
        },
    }
}

fn fillFloatIntDenseViewArray(out: []f64, op: BuiltinId, left_items: HostIntDenseView, right_items: []const f64) void {
    switch (left_items) {
        .dense => |view| fillFloatIntViewArray(out, op, view, right_items),
        .range_iota, .flat_slice, .flat_stride, .flat_concat, .flat_segments, .first_axis_slice, .first_axis_index, .first_axis_concat, .transpose => {
            for (0..hostIntDenseViewLen(left_items)) |idx| {
                const item = hostIntDenseViewItem(left_items, idx) catch unreachable;
                out[idx] = applyFloatOp(op, @floatFromInt(item), right_items[idx]);
            }
        },
    }
}

fn fillFloatArrayIntDenseView(out: []f64, op: BuiltinId, left_items: []const f64, right_items: HostIntDenseView) void {
    switch (right_items) {
        .dense => |view| fillFloatArrayIntView(out, op, left_items, view),
        .range_iota, .flat_slice, .flat_stride, .flat_concat, .flat_segments, .first_axis_slice, .first_axis_index, .first_axis_concat, .transpose => {
            for (0..hostIntDenseViewLen(right_items)) |idx| {
                const item = hostIntDenseViewItem(right_items, idx) catch unreachable;
                out[idx] = applyFloatOp(op, left_items[idx], @floatFromInt(item));
            }
        },
    }
}

fn fillFloatIntDenseViewIntDenseView(out: []f64, op: BuiltinId, left_items: HostIntDenseView, right_items: HostIntDenseView) void {
    if (left_items == .dense and right_items == .dense) {
        fillFloatIntViews(out, op, left_items.dense, right_items.dense);
        return;
    }
    for (0..hostIntDenseViewLen(left_items)) |idx| {
        const left_value = hostIntDenseViewItem(left_items, idx) catch unreachable;
        const right_value = hostIntDenseViewItem(right_items, idx) catch unreachable;
        out[idx] = applyFloatOp(op, @floatFromInt(left_value), @floatFromInt(right_value));
    }
}

fn fillFloatScalarDenseView(out: []f64, op: BuiltinId, scalar: f64, items: HostFloatDenseView, scalar_left: bool) void {
    switch (items) {
        .dense => |view| fillFloatScalarArray(f64, out, op, scalar, view, scalar_left),
        .flat_slice, .flat_stride, .flat_concat, .flat_segments, .first_axis_slice, .first_axis_index, .first_axis_concat, .transpose => {
            for (0..hostFloatDenseViewLen(items)) |idx| {
                const item = hostFloatDenseViewItem(items, idx) catch unreachable;
                out[idx] = if (scalar_left) applyFloatOp(op, scalar, item) else applyFloatOp(op, item, scalar);
            }
        },
    }
}

fn fillFloatDenseViewIntDenseView(out: []f64, op: BuiltinId, left_items: HostFloatDenseView, right_items: HostIntDenseView) void {
    switch (left_items) {
        .dense => |view| fillFloatArrayIntDenseView(out, op, view, right_items),
        .flat_slice, .flat_stride, .flat_concat, .flat_segments, .first_axis_slice, .first_axis_index, .first_axis_concat, .transpose => {
            for (0..hostFloatDenseViewLen(left_items)) |idx| {
                const left_value = hostFloatDenseViewItem(left_items, idx) catch unreachable;
                const right_value = hostIntDenseViewItem(right_items, idx) catch unreachable;
                out[idx] = applyFloatOp(op, left_value, @floatFromInt(right_value));
            }
        },
    }
}

fn fillFloatIntDenseViewDenseView(out: []f64, op: BuiltinId, left_items: HostIntDenseView, right_items: HostFloatDenseView) void {
    switch (right_items) {
        .dense => |view| fillFloatIntDenseViewArray(out, op, left_items, view),
        .flat_slice, .flat_stride, .flat_concat, .flat_segments, .first_axis_slice, .first_axis_index, .first_axis_concat, .transpose => {
            for (0..hostIntDenseViewLen(left_items)) |idx| {
                const left_value = hostIntDenseViewItem(left_items, idx) catch unreachable;
                const right_value = hostFloatDenseViewItem(right_items, idx) catch unreachable;
                out[idx] = applyFloatOp(op, @floatFromInt(left_value), right_value);
            }
        },
    }
}

fn fillFloatFirstAxisIndexDenseViewDenseView(out: []f64, op: BuiltinId, left_items: HostFloatDenseView, right_items: HostFloatDenseView) bool {
    switch (left_items) {
        .first_axis_index => |left_index| switch (right_items) {
            .first_axis_index => |right_index| {
                if (left_index.row_width != right_index.row_width) return false;
                if (left_index.row_width == 0) return true;
                const rows = left_index.len / left_index.row_width;
                var out_idx: usize = 0;
                for (0..rows) |row_pos| {
                    const left_base = (hostFirstAxisIndexSourceRow(left_index, row_pos) catch unreachable) * left_index.row_width;
                    const right_base = (hostFirstAxisIndexSourceRow(right_index, row_pos) catch unreachable) * right_index.row_width;
                    for (0..left_index.row_width) |col_idx| {
                        out[out_idx] = applyFloatOp(
                            op,
                            hostFirstAxisIndexSourceFloatAt(left_index, left_base + col_idx) catch unreachable,
                            hostFirstAxisIndexSourceFloatAt(right_index, right_base + col_idx) catch unreachable,
                        );
                        out_idx += 1;
                    }
                }
                return true;
            },
            else => {
                if (left_index.row_width == 0) return true;
                const rows = left_index.len / left_index.row_width;
                var out_idx: usize = 0;
                for (0..rows) |row_pos| {
                    const left_base = (hostFirstAxisIndexSourceRow(left_index, row_pos) catch unreachable) * left_index.row_width;
                    for (0..left_index.row_width) |col_idx| {
                        out[out_idx] = applyFloatOp(
                            op,
                            hostFirstAxisIndexSourceFloatAt(left_index, left_base + col_idx) catch unreachable,
                            hostFloatDenseViewItem(right_items, out_idx) catch unreachable,
                        );
                        out_idx += 1;
                    }
                }
                return true;
            },
        },
        else => switch (right_items) {
            .first_axis_index => |right_index| {
                if (right_index.row_width == 0) return true;
                const rows = right_index.len / right_index.row_width;
                var out_idx: usize = 0;
                for (0..rows) |row_pos| {
                    const right_base = (hostFirstAxisIndexSourceRow(right_index, row_pos) catch unreachable) * right_index.row_width;
                    for (0..right_index.row_width) |col_idx| {
                        out[out_idx] = applyFloatOp(
                            op,
                            hostFloatDenseViewItem(left_items, out_idx) catch unreachable,
                            hostFirstAxisIndexSourceFloatAt(right_index, right_base + col_idx) catch unreachable,
                        );
                        out_idx += 1;
                    }
                }
                return true;
            },
            else => return false,
        },
    }
}

fn fillFloatDenseViewDenseView(out: []f64, op: BuiltinId, left_items: HostFloatDenseView, right_items: HostFloatDenseView) void {
    if (fillFloatFirstAxisIndexDenseViewDenseView(out, op, left_items, right_items)) return;
    switch (left_items) {
        .dense => |left_view| switch (right_items) {
            .dense => |right_view| fillFloatArrayArray(f64, f64, out, op, left_view, right_view),
            .flat_slice, .flat_stride, .flat_concat, .flat_segments, .first_axis_slice, .first_axis_index, .first_axis_concat, .transpose => {
                for (0..left_view.len) |idx| {
                    const right_value = hostFloatDenseViewItem(right_items, idx) catch unreachable;
                    out[idx] = applyFloatOp(op, left_view[idx], right_value);
                }
            },
        },
        .flat_slice, .flat_stride, .flat_concat, .flat_segments, .first_axis_slice, .first_axis_index, .first_axis_concat, .transpose => {
            for (0..hostFloatDenseViewLen(left_items)) |idx| {
                const left_value = hostFloatDenseViewItem(left_items, idx) catch unreachable;
                const right_value = hostFloatDenseViewItem(right_items, idx) catch unreachable;
                out[idx] = applyFloatOp(op, left_value, right_value);
            }
        },
    }
}

fn builtinChar(id: BuiltinId) u8 {
    return switch (id) {
        .add => '+',
        .sub => '-',
        .mul => '*',
        .div => '%',
        .pow => 'P',
        .exp => 'E',
        .log => 'L',
        .sin => 'I',
        .cos => 'O',
        .tanh => 'T',
        .sigmoid => 'S',
        .iota => '!',
        .minimum => '&',
        .maximum, .reverse => '|',
        .less, .grade_up => '<',
        .more, .grade_down => '>',
        .not => '~',
        .concat => ',',
        .count, .take => '#',
        .floor, .drop => '_',
        .null_fill_without, .sort, .reshape => '^',
        .equal => '=',
        .stringify, .cast => '$',
        .contains, .split, .join, .unique, .find => '?',
        .bytes => 'b',
        .utf8 => '8',
        .char => 'c',
        .tokenize => 'k',
        .detokenize => 'D',
        .eval_string => '.',
        .grad => 'g',
        .valuegrad => 'v',
        .prng => 'p',
        .load => 'l',
        .save => 'W',
        .sql => 'q',
        .register => 'Z',
        .rotcache => 'r',
        .rotcacheupdate => 'u',
        .rotcacheview => 'w',
        .rope => 'R',
        .ropeflat => 'J',
        .ropecisflat => 'F',
        .rmsnorm => 'n',
        .layernorm => 'H',
        .gelu => 'X',
        .geluapprox => 'G',
        .mlpdense => 'M',
        .conv2d => 'C',
        .convtranspose2d => 'K',
        .upsamplenearest2d => 'U',
        .groupnorm => 'Q',
        .softmax => 's',
        .sdpa => 'A',
        .sam3boxrpb => 'P',
        .sdpamask => 'Y',
        .sdpaflat => 'B',
    };
}

fn formatFloat(allocator: std.mem.Allocator, value: f64) KError![]u8 {
    const nearest = @round(value);
    const snapped = if (@abs(value - nearest) < 1e-6)
        nearest
    else
        @round(value * 1_000_000.0) / 1_000_000.0;
    var buf: [64]u8 = undefined;
    const raw = std.fmt.bufPrint(&buf, "{d:.6}", .{snapped}) catch unreachable;
    var end = raw.len;
    while (end > 0 and raw[end - 1] == '0') end -= 1;
    if (end > 0 and raw[end - 1] == '.') end -= 1;
    if (end == 0) return allocator.dupe(u8, "0");
    return allocator.dupe(u8, raw[0..end]);
}

fn scalarNumericValue(value: Value) KError!f64 {
    return switch (value.tag()) {
        .int => @floatFromInt(value.asInt()),
        .bool => @floatFromInt(@intFromBool(value.asBool())),
        .float => value.asFloat(),
        else => error.Type,
    };
}

fn denseAutodiffProgramSumsq() Session.DenseAutodiffProgram {
    var program = Session.DenseAutodiffProgram{};
    const input = program.push(.input, .vector);
    const squared = program.push(.{ .mul = .{ .left = input, .right = input } }, .vector);
    program.root = program.push(.{ .reduce_add = squared }, .scalar);
    return program;
}

fn denseAutodiffProgramScanSumsq() Session.DenseAutodiffProgram {
    var program = Session.DenseAutodiffProgram{};
    const input = program.push(.input, .vector);
    const prefix = program.push(.{ .scan_add = input }, .vector);
    const squared = program.push(.{ .mul = .{ .left = prefix, .right = prefix } }, .vector);
    program.root = program.push(.{ .reduce_add = squared }, .scalar);
    return program;
}

fn applyDenseAutodiffUnaryMap(op: BuiltinId, value: f64) f64 {
    return switch (op) {
        .exp, .log, .sin, .cos, .tanh, .sigmoid => applyFloatMonadOp(op, value),
        else => unreachable,
    };
}

fn applyDenseAutodiffUnaryMapDerivative(op: BuiltinId, input: f64, output: f64) f64 {
    return switch (op) {
        .exp => output,
        .log => 1.0 / input,
        .sin => std.math.cos(input),
        .cos => -std.math.sin(input),
        .tanh => 1.0 - (output * output),
        .sigmoid => output * (1.0 - output),
        else => unreachable,
    };
}

fn computeDenseAutodiffExecPlan(program: *const Session.DenseAutodiffProgram) Session.DenseAutodiffExecPlan {
    var plan = Session.DenseAutodiffExecPlan{};
    var last_consumer: [Session.dense_autodiff_max_nodes]u8 = [_]u8{0} ** Session.dense_autodiff_max_nodes;

    for (program.nodes[0..program.len], 0..) |node, idx| {
        const consumer: u8 = @intCast(idx);
        switch (node) {
            .input, .const_scalar => {},
            .scan_add => |src| last_consumer[src] = @max(last_consumer[src], consumer),
            .unary_map => |value| last_consumer[value.src] = @max(last_consumer[value.src], consumer),
            .neg => |src| last_consumer[src] = @max(last_consumer[src], consumer),
            .add => |value| {
                last_consumer[value.left] = @max(last_consumer[value.left], consumer);
                last_consumer[value.right] = @max(last_consumer[value.right], consumer);
            },
            .sub => |value| {
                last_consumer[value.left] = @max(last_consumer[value.left], consumer);
                last_consumer[value.right] = @max(last_consumer[value.right], consumer);
            },
            .mul => |value| {
                last_consumer[value.left] = @max(last_consumer[value.left], consumer);
                last_consumer[value.right] = @max(last_consumer[value.right], consumer);
            },
            .reduce_add => |src| last_consumer[src] = @max(last_consumer[src], consumer),
        }
    }

    for (program.kinds[0..program.len], 0..) |kind, idx| {
        if (kind != .vector or idx == 0) continue;
        plan.forward_slots[idx] = plan.forward_slot_count;
        plan.forward_slot_count += 1;
    }

    var active_end: [Session.dense_autodiff_max_nodes]u8 = [_]u8{0} ** Session.dense_autodiff_max_nodes;
    var active_used: [Session.dense_autodiff_max_nodes]bool = [_]bool{false} ** Session.dense_autodiff_max_nodes;
    for (program.kinds[0..program.len], 0..) |kind, idx| {
        if (kind != .vector or idx == 0) continue;
        const interval_start: u8 = @intCast(idx);
        const interval_end: u8 = @max(last_consumer[idx], interval_start);

        var slot: ?u8 = null;
        var slot_idx: usize = 0;
        while (slot_idx < plan.adjoint_slot_count) : (slot_idx += 1) {
            if (active_used[slot_idx] and active_end[slot_idx] >= interval_start) continue;
            slot = @intCast(slot_idx);
            break;
        }
        if (slot == null) {
            slot = plan.adjoint_slot_count;
            plan.adjoint_slot_count += 1;
        }

        const chosen = slot.?;
        active_used[chosen] = true;
        active_end[chosen] = interval_end;
        plan.adjoint_slots[idx] = chosen;
    }

    return plan;
}

fn executeDenseAutodiffProgram(allocator: std.mem.Allocator, program: *const Session.DenseAutodiffProgram, input: []const f64, grad: []f64) !f64 {
    std.debug.assert(program.len > 0);
    std.debug.assert(program.root < program.len);
    std.debug.assert(grad.len == input.len);
    if (input.len == 0) {
        @memset(grad, 0.0);
        return 0.0;
    }

    const plan = computeDenseAutodiffExecPlan(program);

    const forward_workspace = try allocator.alloc(f64, @as(usize, plan.forward_slot_count) * input.len);
    defer allocator.free(forward_workspace);
    const adjoint_workspace = try allocator.alloc(f64, @as(usize, plan.adjoint_slot_count) * input.len);
    defer allocator.free(adjoint_workspace);
    @memset(adjoint_workspace, 0.0);
    @memset(grad, 0.0);

    var forward_vectors: [Session.dense_autodiff_max_nodes]?[]f64 = [_]?[]f64{null} ** Session.dense_autodiff_max_nodes;
    var adjoint_vectors: [Session.dense_autodiff_max_nodes]?[]f64 = [_]?[]f64{null} ** Session.dense_autodiff_max_nodes;
    var scalar_values: [Session.dense_autodiff_max_nodes]f64 = [_]f64{0.0} ** Session.dense_autodiff_max_nodes;
    var scalar_adjoints: [Session.dense_autodiff_max_nodes]f64 = [_]f64{0.0} ** Session.dense_autodiff_max_nodes;

    if (program.kinds[0] == .scalar) scalar_values[0] = input[0];

    for (program.nodes[0..program.len], 0..) |node, idx| {
        if (program.kinds[idx] != .vector) continue;
        adjoint_vectors[idx] = if (idx == 0)
            grad
        else blk: {
            const slot = plan.adjoint_slots[idx];
            std.debug.assert(slot != Session.dense_autodiff_no_slot);
            break :blk adjoint_workspace[@as(usize, slot) * input.len .. (@as(usize, slot) + 1) * input.len];
        };
        forward_vectors[idx] = switch (node) {
            .input => @constCast(input),
            else => blk: {
                const slot = plan.forward_slots[idx];
                std.debug.assert(slot != Session.dense_autodiff_no_slot);
                break :blk forward_workspace[@as(usize, slot) * input.len .. (@as(usize, slot) + 1) * input.len];
            },
        };
    }

    for (program.nodes[0..program.len], 0..) |node, idx| {
        switch (node) {
            .input => {},
            .const_scalar => |value| scalar_values[idx] = value,
            .scan_add => |src| {
                const src_values = forward_vectors[src].?;
                const out = forward_vectors[idx].?;
                var prefix: f64 = 0.0;
                for (src_values, 0..) |value, item_idx| {
                    prefix += value;
                    out[item_idx] = prefix;
                }
            },
            .unary_map => |value| {
                if (program.kinds[idx] == .vector) {
                    const src_values = forward_vectors[value.src].?;
                    const out = forward_vectors[idx].?;
                    for (out, 0..) |*item, item_idx| item.* = applyDenseAutodiffUnaryMap(value.op, src_values[item_idx]);
                } else {
                    scalar_values[idx] = applyDenseAutodiffUnaryMap(value.op, scalar_values[value.src]);
                }
            },
            .neg => |src| {
                if (program.kinds[idx] == .vector) {
                    const src_values = forward_vectors[src].?;
                    const out = forward_vectors[idx].?;
                    for (out, 0..) |*item, item_idx| item.* = -src_values[item_idx];
                } else {
                    scalar_values[idx] = -scalar_values[src];
                }
            },
            .add => |value| {
                try executeDenseAutodiffBinaryForward(program, idx, value.left, value.right, forward_vectors[0..], &scalar_values);
            },
            .sub => |value| {
                try executeDenseAutodiffBinaryForwardSub(program, idx, value.left, value.right, forward_vectors[0..], &scalar_values);
            },
            .mul => |value| {
                try executeDenseAutodiffBinaryForwardMul(program, idx, value.left, value.right, forward_vectors[0..], &scalar_values);
            },
            .reduce_add => |src| {
                var total: f64 = 0.0;
                for (forward_vectors[src].?) |value| total += value;
                scalar_values[idx] = total;
            },
        }
    }

    switch (program.kinds[program.root]) {
        .scalar => scalar_adjoints[program.root] = 1.0,
        .vector => return error.Internal,
    }

    var rev: usize = program.len;
    while (rev > 0) {
        rev -= 1;
        const node = program.nodes[rev];
        switch (node) {
            .input, .const_scalar => {},
            .scan_add => |src| {
                const incoming = adjoint_vectors[rev].?;
                const dst = adjoint_vectors[src].?;
                var suffix: f64 = 0.0;
                var item_idx = incoming.len;
                while (item_idx > 0) {
                    item_idx -= 1;
                    suffix += incoming[item_idx];
                    dst[item_idx] += suffix;
                }
            },
            .unary_map => |value| {
                if (program.kinds[rev] == .vector) {
                    const incoming = adjoint_vectors[rev].?;
                    const src_values = forward_vectors[value.src].?;
                    const out_values = forward_vectors[rev].?;
                    if (program.kinds[value.src] == .vector) {
                        const dst = adjoint_vectors[value.src].?;
                        for (incoming, 0..) |item, item_idx| {
                            dst[item_idx] += item * applyDenseAutodiffUnaryMapDerivative(value.op, src_values[item_idx], out_values[item_idx]);
                        }
                    } else {
                        var total: f64 = 0.0;
                        for (incoming, 0..) |item, item_idx| {
                            total += item * applyDenseAutodiffUnaryMapDerivative(value.op, src_values[item_idx], out_values[item_idx]);
                        }
                        scalar_adjoints[value.src] += total;
                    }
                } else {
                    const incoming = scalar_adjoints[rev];
                    const src_value = scalar_values[value.src];
                    const out_value = scalar_values[rev];
                    scalar_adjoints[value.src] += incoming * applyDenseAutodiffUnaryMapDerivative(value.op, src_value, out_value);
                }
            },
            .neg => |src| {
                if (program.kinds[rev] == .vector) {
                    const incoming = adjoint_vectors[rev].?;
                    const dst = adjoint_vectors[src].?;
                    for (incoming, 0..) |item, item_idx| dst[item_idx] -= item;
                } else {
                    scalar_adjoints[src] -= scalar_adjoints[rev];
                }
            },
            .add => |value| {
                executeDenseAutodiffBinaryReverseAdd(program, rev, value.left, value.right, forward_vectors[0..], adjoint_vectors[0..], &scalar_values, &scalar_adjoints);
            },
            .sub => |value| {
                executeDenseAutodiffBinaryReverseSub(program, rev, value.left, value.right, forward_vectors[0..], adjoint_vectors[0..], &scalar_values, &scalar_adjoints);
            },
            .mul => |value| {
                executeDenseAutodiffBinaryReverseMul(program, rev, value.left, value.right, forward_vectors[0..], adjoint_vectors[0..], &scalar_values, &scalar_adjoints);
            },
            .reduce_add => |src| {
                const incoming = scalar_adjoints[rev];
                const dst = adjoint_vectors[src].?;
                for (dst) |*item| item.* += incoming;
            },
        }
    }

    switch (program.kinds[0]) {
        .vector => {
            const input_grad = adjoint_vectors[0] orelse return error.Internal;
            if (input_grad.ptr != grad.ptr) @memcpy(grad, input_grad);
        },
        .scalar => {
            if (grad.len != 1) return error.Internal;
            grad[0] = scalar_adjoints[0];
        },
    }
    return scalar_values[program.root];
}

fn executeDenseAutodiffBinaryForward(program: *const Session.DenseAutodiffProgram, idx: usize, left: Session.DenseAutodiffNodeIndex, right: Session.DenseAutodiffNodeIndex, forward_vectors: []?[]f64, scalar_values: *[Session.dense_autodiff_max_nodes]f64) !void {
    const left_kind = program.kinds[left];
    const right_kind = program.kinds[right];
    if (program.kinds[idx] == .scalar) {
        scalar_values[idx] = scalarValuesBinaryOp(.add, scalar_values[left], scalar_values[right]);
        return;
    }
    const out = forward_vectors[idx].?;
    switch (left_kind) {
        .vector => switch (right_kind) {
            .vector => {
                const left_values = forward_vectors[left].?;
                const right_values = forward_vectors[right].?;
                for (out, 0..) |*item, item_idx| item.* = left_values[item_idx] + right_values[item_idx];
            },
            .scalar => {
                const left_values = forward_vectors[left].?;
                const right_value = scalar_values[right];
                for (out, 0..) |*item, item_idx| item.* = left_values[item_idx] + right_value;
            },
        },
        .scalar => {
            const left_value = scalar_values[left];
            const right_values = forward_vectors[right].?;
            for (out, 0..) |*item, item_idx| item.* = left_value + right_values[item_idx];
        },
    }
}

fn executeDenseAutodiffBinaryForwardSub(program: *const Session.DenseAutodiffProgram, idx: usize, left: Session.DenseAutodiffNodeIndex, right: Session.DenseAutodiffNodeIndex, forward_vectors: []?[]f64, scalar_values: *[Session.dense_autodiff_max_nodes]f64) !void {
    const left_kind = program.kinds[left];
    const right_kind = program.kinds[right];
    if (program.kinds[idx] == .scalar) {
        scalar_values[idx] = scalarValuesBinaryOp(.sub, scalar_values[left], scalar_values[right]);
        return;
    }
    const out = forward_vectors[idx].?;
    switch (left_kind) {
        .vector => switch (right_kind) {
            .vector => {
                const left_values = forward_vectors[left].?;
                const right_values = forward_vectors[right].?;
                for (out, 0..) |*item, item_idx| item.* = left_values[item_idx] - right_values[item_idx];
            },
            .scalar => {
                const left_values = forward_vectors[left].?;
                const right_value = scalar_values[right];
                for (out, 0..) |*item, item_idx| item.* = left_values[item_idx] - right_value;
            },
        },
        .scalar => {
            const left_value = scalar_values[left];
            const right_values = forward_vectors[right].?;
            for (out, 0..) |*item, item_idx| item.* = left_value - right_values[item_idx];
        },
    }
}

fn executeDenseAutodiffBinaryForwardMul(program: *const Session.DenseAutodiffProgram, idx: usize, left: Session.DenseAutodiffNodeIndex, right: Session.DenseAutodiffNodeIndex, forward_vectors: []?[]f64, scalar_values: *[Session.dense_autodiff_max_nodes]f64) !void {
    const left_kind = program.kinds[left];
    const right_kind = program.kinds[right];
    if (program.kinds[idx] == .scalar) {
        scalar_values[idx] = scalarValuesBinaryOp(.mul, scalar_values[left], scalar_values[right]);
        return;
    }
    const out = forward_vectors[idx].?;
    switch (left_kind) {
        .vector => switch (right_kind) {
            .vector => {
                const left_values = forward_vectors[left].?;
                const right_values = forward_vectors[right].?;
                for (out, 0..) |*item, item_idx| item.* = left_values[item_idx] * right_values[item_idx];
            },
            .scalar => {
                const left_values = forward_vectors[left].?;
                const right_value = scalar_values[right];
                for (out, 0..) |*item, item_idx| item.* = left_values[item_idx] * right_value;
            },
        },
        .scalar => {
            const left_value = scalar_values[left];
            const right_values = forward_vectors[right].?;
            for (out, 0..) |*item, item_idx| item.* = left_value * right_values[item_idx];
        },
    }
}

const DenseAutodiffScalarBinaryOp = enum { add, sub, mul };

fn scalarValuesBinaryOp(op: DenseAutodiffScalarBinaryOp, left: f64, right: f64) f64 {
    return switch (op) {
        .add => left + right,
        .sub => left - right,
        .mul => left * right,
    };
}

fn executeDenseAutodiffBinaryReverseAdd(program: *const Session.DenseAutodiffProgram, idx: usize, left: Session.DenseAutodiffNodeIndex, right: Session.DenseAutodiffNodeIndex, forward_vectors: []?[]f64, adjoint_vectors: []?[]f64, scalar_values: *[Session.dense_autodiff_max_nodes]f64, scalar_adjoints: *[Session.dense_autodiff_max_nodes]f64) void {
    _ = forward_vectors;
    _ = scalar_values;
    if (program.kinds[idx] == .scalar) {
        const incoming = scalar_adjoints[idx];
        scalar_adjoints[left] += incoming;
        scalar_adjoints[right] += incoming;
        return;
    }
    const incoming = adjoint_vectors[idx].?;
    switch (program.kinds[left]) {
        .vector => {
            const left_adj = adjoint_vectors[left].?;
            for (incoming, 0..) |item, item_idx| left_adj[item_idx] += item;
        },
        .scalar => {
            var total: f64 = 0.0;
            for (incoming) |item| total += item;
            scalar_adjoints[left] += total;
        },
    }
    switch (program.kinds[right]) {
        .vector => {
            const right_adj = adjoint_vectors[right].?;
            for (incoming, 0..) |item, item_idx| right_adj[item_idx] += item;
        },
        .scalar => {
            var total: f64 = 0.0;
            for (incoming) |item| total += item;
            scalar_adjoints[right] += total;
        },
    }
}

fn executeDenseAutodiffBinaryReverseSub(program: *const Session.DenseAutodiffProgram, idx: usize, left: Session.DenseAutodiffNodeIndex, right: Session.DenseAutodiffNodeIndex, forward_vectors: []?[]f64, adjoint_vectors: []?[]f64, scalar_values: *[Session.dense_autodiff_max_nodes]f64, scalar_adjoints: *[Session.dense_autodiff_max_nodes]f64) void {
    _ = forward_vectors;
    _ = scalar_values;
    if (program.kinds[idx] == .scalar) {
        const incoming = scalar_adjoints[idx];
        scalar_adjoints[left] += incoming;
        scalar_adjoints[right] -= incoming;
        return;
    }
    const incoming = adjoint_vectors[idx].?;
    switch (program.kinds[left]) {
        .vector => {
            const left_adj = adjoint_vectors[left].?;
            for (incoming, 0..) |item, item_idx| left_adj[item_idx] += item;
        },
        .scalar => {
            var total: f64 = 0.0;
            for (incoming) |item| total += item;
            scalar_adjoints[left] += total;
        },
    }
    switch (program.kinds[right]) {
        .vector => {
            const right_adj = adjoint_vectors[right].?;
            for (incoming, 0..) |item, item_idx| right_adj[item_idx] -= item;
        },
        .scalar => {
            var total: f64 = 0.0;
            for (incoming) |item| total += item;
            scalar_adjoints[right] -= total;
        },
    }
}

fn executeDenseAutodiffBinaryReverseMul(program: *const Session.DenseAutodiffProgram, idx: usize, left: Session.DenseAutodiffNodeIndex, right: Session.DenseAutodiffNodeIndex, forward_vectors: []?[]f64, adjoint_vectors: []?[]f64, scalar_values: *[Session.dense_autodiff_max_nodes]f64, scalar_adjoints: *[Session.dense_autodiff_max_nodes]f64) void {
    if (program.kinds[idx] == .scalar) {
        const incoming = scalar_adjoints[idx];
        scalar_adjoints[left] += incoming * scalar_values[right];
        scalar_adjoints[right] += incoming * scalar_values[left];
        return;
    }
    const incoming = adjoint_vectors[idx].?;
    switch (program.kinds[left]) {
        .vector => {
            const left_adj = adjoint_vectors[left].?;
            switch (program.kinds[right]) {
                .vector => {
                    const right_values = forward_vectors[right].?;
                    for (incoming, 0..) |item, item_idx| left_adj[item_idx] += item * right_values[item_idx];
                },
                .scalar => {
                    const right_value = scalar_values[right];
                    for (incoming, 0..) |item, item_idx| left_adj[item_idx] += item * right_value;
                },
            }
        },
        .scalar => {
            const left_value = scalar_values[left];
            _ = left_value;
        },
    }
    switch (program.kinds[right]) {
        .vector => {
            const right_adj = adjoint_vectors[right].?;
            switch (program.kinds[left]) {
                .vector => {
                    const left_values = forward_vectors[left].?;
                    for (incoming, 0..) |item, item_idx| right_adj[item_idx] += item * left_values[item_idx];
                },
                .scalar => {
                    const left_value = scalar_values[left];
                    for (incoming, 0..) |item, item_idx| right_adj[item_idx] += item * left_value;
                },
            }
        },
        .scalar => {
            var total: f64 = 0.0;
            switch (program.kinds[left]) {
                .vector => {
                    const left_values = forward_vectors[left].?;
                    for (incoming, 0..) |item, item_idx| total += item * left_values[item_idx];
                },
                .scalar => total += scalar_adjoints[idx] * scalar_values[left],
            }
            scalar_adjoints[right] += total;
        },
    }
    if (program.kinds[left] == .scalar) {
        var total: f64 = 0.0;
        switch (program.kinds[right]) {
            .vector => {
                const right_values = forward_vectors[right].?;
                for (incoming, 0..) |item, item_idx| total += item * right_values[item_idx];
            },
            .scalar => {},
        }
        scalar_adjoints[left] += total;
    }
}

fn materializeAutogradTarget(allocator: std.mem.Allocator, value: Value) KError!Session.AutogradTarget {
    return switch (value.tag()) {
        .int => blk: {
            const items = try allocator.alloc(f64, 1);
            items[0] = @floatFromInt(value.asInt());
            break :blk .{
                .values = items,
                .shape = try allocator.alloc(i32, 0),
                .is_scalar = true,
                .backend = .host,
            };
        },
        .bool => blk: {
            const items = try allocator.alloc(f64, 1);
            items[0] = @floatFromInt(@intFromBool(value.asBool()));
            break :blk .{
                .values = items,
                .shape = try allocator.alloc(i32, 0),
                .is_scalar = true,
                .backend = .host,
            };
        },
        .float => blk: {
            const items = try allocator.alloc(f64, 1);
            items[0] = value.asFloat();
            break :blk .{
                .values = items,
                .shape = try allocator.alloc(i32, 0),
                .is_scalar = true,
                .backend = .host,
            };
        },
        .array => switch (value.activeArrayKind()) {
            .host_dense_array => blk: {
                const array = hostDenseIfPresent(value) orelse return error.Type;
                const shape = try allocator.alloc(i32, 1);
                shape[0] = @intCast(array.len());
                const view = hostIntArrayView(array);
                if (view) |int_view| {
                    const items = try allocator.alloc(f64, array.len());
                    for (0..array.len()) |idx| items[idx] = @floatFromInt(hostIntViewItem(int_view, idx));
                    break :blk .{
                        .values = items,
                        .shape = shape,
                        .is_scalar = false,
                        .backend = .host,
                    };
                }
                switch (array.storage) {
                    .float64 => |items| {
                        const owned = try allocator.dupe(f64, items);
                        break :blk .{
                            .values = owned,
                            .shape = shape,
                            .is_scalar = false,
                            .backend = .host,
                        };
                    },
                    else => return error.Type,
                }
            },
            .backend_array => blk: {
                var owned = value.asBackendArray().array.clone() catch |err| return mapMlxError(err);
                defer owned.deinit();
                owned.eval() catch |err| return mapMlxError(err);

                const shape = try allocator.alloc(i32, owned.ndim());
                for (owned.shape(), 0..) |dim, idx| shape[idx] = @intCast(dim);

                if (owned.ndim() == 0) {
                    const items = try allocator.alloc(f64, 1);
                    items[0] = switch (owned.dtype()) {
                        c.MLX_BOOL => @floatFromInt(@intFromBool(owned.boolItem() catch |err| return mapMlxError(err))),
                        c.MLX_INT32, c.MLX_INT64, c.MLX_UINT32 => @floatFromInt(owned.intItem() catch |err| return mapMlxError(err)),
                        c.MLX_FLOAT16, c.MLX_FLOAT32, c.MLX_FLOAT64, c.MLX_BFLOAT16 => owned.floatItem() catch |err| return mapMlxError(err),
                        else => return error.Type,
                    };
                    break :blk .{
                        .values = items,
                        .shape = shape,
                        .is_scalar = true,
                        .backend = .mlx,
                    };
                }

                break :blk switch (owned.dtype()) {
                    c.MLX_BOOL => blk_bool: {
                        const items = owned.readBools(allocator) catch |err| switch (err) {
                            error.OutOfMemory => return error.OutOfMemory,
                            else => return mapMlxError(err),
                        };
                        defer allocator.free(items);
                        const converted = try allocator.alloc(f64, items.len);
                        for (converted, 0..) |*item, idx| item.* = @floatFromInt(@intFromBool(items[idx]));
                        break :blk_bool .{
                            .values = converted,
                            .shape = shape,
                            .is_scalar = false,
                            .backend = .mlx,
                        };
                    },
                    c.MLX_INT32, c.MLX_INT64, c.MLX_UINT32 => blk_int: {
                        const items = owned.readInts(allocator) catch |err| switch (err) {
                            error.OutOfMemory => return error.OutOfMemory,
                            else => return mapMlxError(err),
                        };
                        defer allocator.free(items);
                        const converted = try allocator.alloc(f64, items.len);
                        for (converted, 0..) |*item, idx| item.* = @floatFromInt(items[idx]);
                        break :blk_int .{
                            .values = converted,
                            .shape = shape,
                            .is_scalar = false,
                            .backend = .mlx,
                        };
                    },
                    c.MLX_FLOAT16, c.MLX_FLOAT32, c.MLX_FLOAT64, c.MLX_BFLOAT16 => blk_float: {
                        const items = owned.readFloats(allocator) catch |err| switch (err) {
                            error.OutOfMemory => return error.OutOfMemory,
                            else => return mapMlxError(err),
                        };
                        defer allocator.free(items);
                        const converted = try allocator.alloc(f64, items.len);
                        for (converted, 0..) |*item, idx| item.* = items[idx];
                        break :blk_float .{
                            .values = converted,
                            .shape = shape,
                            .is_scalar = false,
                            .backend = .mlx,
                        };
                    },
                    else => return error.Type,
                };
            },
            else => error.Type,
        },
        else => error.Type,
    };
}

fn mapMlxError(err: anyerror) KError {
    return switch (err) {
        error.MlxFailure => error.Type,
        error.UnsupportedType => error.Type,
        error.InvalidDevice => error.Internal,
        else => error.Internal,
    };
}

fn mapSafetensorsError(err: anyerror) KError {
    return switch (err) {
        error.UnsupportedTarget,
        error.UnsupportedDtype,
        error.UnsupportedShape,
        => error.Unsupported,
        else => error.Type,
    };
}

fn safetensorMlxDtype(dtype: safetensors.Dtype) c.mlx_dtype {
    return switch (dtype) {
        .bool => c.MLX_BOOL,
        .u8, .f8_e4m3 => c.MLX_UINT8,
        .u16 => c.MLX_UINT16,
        .u32 => c.MLX_UINT32,
        .u64 => c.MLX_UINT64,
        .i8 => c.MLX_INT8,
        .i16 => c.MLX_INT16,
        .i32 => c.MLX_INT32,
        .i64 => c.MLX_INT64,
        .f16 => c.MLX_FLOAT16,
        .f32 => c.MLX_FLOAT32,
        .f64 => c.MLX_FLOAT64,
        .bf16 => c.MLX_BFLOAT16,
        .complex64 => c.MLX_COMPLEX64,
    };
}

fn mapDuckDbError(err: anyerror) KError {
    return switch (err) {
        error.OutOfMemory => error.OutOfMemory,
        error.DuckDbPrepareFailed,
        error.DuckDbQueryFailed,
        => error.Internal,
        error.DuckDbBindFailed => error.Type,
        error.DuckDbAppenderFailed => error.Unsupported,
        error.DuckDbParameterNameFailed => error.Unsupported,
        else => error.Unsupported,
    };
}

fn isIdentStart(ch: u8) bool {
    return std.ascii.isAlphabetic(ch) or ch == '_';
}

fn isIdentContinue(ch: u8) bool {
    return std.ascii.isAlphabetic(ch) or std.ascii.isDigit(ch) or ch == '_';
}

fn skipSpacesInSource(source: []const u8, start: usize) usize {
    var index = start;
    while (index < source.len and std.ascii.isWhitespace(source[index])) : (index += 1) {}
    return index;
}

const max_explicit_params = 16;
const max_body_instructions = 256;
const max_compact_k_stack_slots = 32;
const max_scope_depth = 32;
const max_body_bytes = max_body_instructions * 10;
const max_shaped_call_args = 8;
const max_shaped_global_local_args = 64;
const max_body_constants = 64;
const max_runtime_stack = 512;
const max_runtime_frames = 64;
const max_inline_frames = 256;
const max_pooled_objects = 128;

const ParamBindingKind = enum {
    frame_local,
    inline_local,
};

const IdentKey = struct {
    len: u16,
    prefix: u64,

    fn fromText(text: []const u8) IdentKey {
        if (text.len == 1) {
            return .{
                .len = 1,
                .prefix = text[0],
            };
        }

        var prefix: u64 = 0;
        const count: usize = @min(text.len, 8);
        var idx: usize = 0;
        while (idx < count) : (idx += 1) {
            prefix |= @as(u64, text[idx]) << @intCast(idx * 8);
        }
        return .{
            .len = @intCast(text.len),
            .prefix = prefix,
        };
    }
};

const IdentRef = struct {
    text: []const u8,
    key: IdentKey,
};

const ResolveResult = union(enum) {
    local: u16,
    inline_local: u16,
    global: void,
};

const ConsumeTrackedSlot = struct {
    slot: u16,
    last_load_start: ?usize = null,
};

const ShapedGlobalLocalArg = struct {
    slot: u8,
    load_start: usize,
    arg_kind_start: usize,
};

const ConsumeCandidates = struct {
    locals: [max_explicit_params]ConsumeTrackedSlot = undefined,
    local_count: u8 = 0,
    inline_locals: [max_explicit_params]ConsumeTrackedSlot = undefined,
    inline_local_count: u8 = 0,
    shaped_global_locals: [max_shaped_global_local_args]ShapedGlobalLocalArg = undefined,
    shaped_global_local_count: u16 = 0,

    fn addLocal(self: *ConsumeCandidates, slot: u16) KError!void {
        for (self.locals[0..self.local_count]) |candidate| {
            if (candidate.slot == slot) return;
        }
        if (self.local_count >= self.locals.len) return error.Unsupported;
        self.locals[self.local_count] = .{ .slot = slot };
        self.local_count += 1;
    }

    fn addInlineLocal(self: *ConsumeCandidates, slot: u16) KError!void {
        for (self.inline_locals[0..self.inline_local_count]) |candidate| {
            if (candidate.slot == slot) return;
        }
        if (self.inline_local_count >= self.inline_locals.len) return error.Unsupported;
        self.inline_locals[self.inline_local_count] = .{ .slot = slot };
        self.inline_local_count += 1;
    }

    fn addResolved(self: *ConsumeCandidates, resolved: ResolveResult) KError!void {
        switch (resolved) {
            .local => |slot| try self.addLocal(slot),
            .inline_local => |slot| try self.addInlineLocal(slot),
            .global => {},
        }
    }

    fn mergeFrom(self: *ConsumeCandidates, other: ConsumeCandidates) KError!void {
        for (other.locals[0..other.local_count]) |candidate| try self.addLocal(candidate.slot);
        for (other.inline_locals[0..other.inline_local_count]) |candidate| try self.addInlineLocal(candidate.slot);
        for (other.shaped_global_locals[0..other.shaped_global_local_count]) |site| {
            try self.noteShapedGlobalLocalArg(site.slot, site.load_start, site.arg_kind_start);
        }
    }

    fn withoutRecordedUses(self: ConsumeCandidates) ConsumeCandidates {
        var copy = self;
        for (copy.locals[0..copy.local_count]) |*candidate| candidate.last_load_start = null;
        for (copy.inline_locals[0..copy.inline_local_count]) |*candidate| candidate.last_load_start = null;
        copy.shaped_global_local_count = 0;
        return copy;
    }

    fn noteLoad(self: *ConsumeCandidates, resolved: ResolveResult, start: usize) void {
        switch (resolved) {
            .local => |slot| {
                for (self.locals[0..self.local_count]) |*candidate| {
                    if (candidate.slot == slot) candidate.last_load_start = start;
                }
            },
            .inline_local => |slot| {
                for (self.inline_locals[0..self.inline_local_count]) |*candidate| {
                    if (candidate.slot == slot) candidate.last_load_start = start;
                }
            },
            .global => {},
        }
    }

    fn noteShapedGlobalLocalArg(self: *ConsumeCandidates, slot: u8, load_start: usize, arg_kind_start: usize) KError!void {
        if (self.shaped_global_local_count >= self.shaped_global_locals.len) return;
        self.shaped_global_locals[self.shaped_global_local_count] = .{
            .slot = slot,
            .load_start = load_start,
            .arg_kind_start = arg_kind_start,
        };
        self.shaped_global_local_count += 1;
    }

    fn patchInto(self: ConsumeCandidates, out: *InstructionBuffer) void {
        for (self.locals[0..self.local_count]) |candidate| {
            const start = candidate.last_load_start orelse continue;
            if (start >= out.byte_len) continue;
            const current = std.meta.intToEnum(Op, out.bytes[start]) catch continue;
            if (current == .load_local) out.patchOpAt(start, .take_local);
        }
        for (self.inline_locals[0..self.inline_local_count]) |candidate| {
            const start = candidate.last_load_start orelse continue;
            if (start >= out.byte_len) continue;
            const current = std.meta.intToEnum(Op, out.bytes[start]) catch continue;
            if (current == .load_inline_local) out.patchOpAt(start, .take_inline_local);
        }
        for (self.shaped_global_locals[0..self.shaped_global_local_count]) |site| {
            if (!self.localLoadShouldConsume(site.slot, site.load_start)) continue;
            if (site.arg_kind_start >= out.byte_len) continue;
            out.bytes[site.arg_kind_start] |= global_call_arg_consume_bit;
        }
    }

    fn localLoadShouldConsume(self: ConsumeCandidates, slot: u8, start: usize) bool {
        for (self.locals[0..self.local_count]) |candidate| {
            if (candidate.slot == slot and candidate.last_load_start == start) return true;
        }
        return false;
    }
};

const ParsedLambda = struct {
    allow_implicit_params: bool = true,
    explicit_names: [max_explicit_params]IdentRef = undefined,
    explicit_count: u8 = 0,
    body_start: usize = 0,
    body_end: usize = 0,

    fn declareParam(self: *ParsedLambda, ident: IdentRef) KError!void {
        var idx: u8 = 0;
        while (idx < self.explicit_count) : (idx += 1) {
            if (identMatches(self.explicit_names[idx], ident)) return error.Parse;
        }
        if (self.explicit_count >= max_explicit_params) return error.Unsupported;
        self.explicit_names[self.explicit_count] = ident;
        self.explicit_count += 1;
    }
};

const PendingPrimary = union(enum) {
    none,
    global: u16,
    builtin: BuiltinId,
    const_value: Value,
    lambda_source: ParsedLambda,
};

const ExprForm = enum {
    nounish,
    verbial,
};

const ParsedPrimary = struct {
    pending: PendingPrimary,
    form: ExprForm,
};

const ProjectionSlotSummary = struct {
    slot_count: u8,
    hole_count: u8,
    hole_mask: u64,

    fn hasHoles(self: ProjectionSlotSummary) bool {
        return self.hole_count != 0;
    }

    fn isHole(self: ProjectionSlotSummary, slot_idx: usize) bool {
        return ((self.hole_mask >> @intCast(slot_idx)) & 1) != 0;
    }
};

const ProjectionInfo = struct {
    callee: Value,
    slot_count: usize,
    hole_mask: u64,
    slot_values: []const Value,
};

const BodyStatementSplit = struct {
    head: []const u8,
    tail: ?[]const u8,
};

const ConditionalSlices = struct {
    condition: []const u8,
    then_branch: []const u8,
    else_branch: []const u8,
};

const NameAssignmentMode = enum {
    bind,
    modified,
    explicit_global,
};

const LocalAssignment = struct {
    ident: IdentRef,
    rhs_source: []const u8,
    mode: NameAssignmentMode = .bind,
    builtin: BuiltinId = .add,
};

const IndexedAssignment = struct {
    ident: IdentRef,
    selector_source: []const u8,
    rhs_source: []const u8,
    mode: AmendMode,
    builtin: BuiltinId = .add,
};

const InnerProductInfo = struct {
    reduce: BuiltinId,
    map: BuiltinId,
};

const SimpleAtom = union(enum) {
    ident: IdentRef,
    int: i64,
    float: f64,
    bool: bool,
};

const NumericLiteral = union(enum) {
    int: i64,
    float: f64,
    bool: bool,
};

const ScannedIdent = struct {
    ident: IdentRef,
    next_index: usize,
};

const ProducedValue = union(enum) {
    const_int: struct {
        start: usize,
        end: usize,
        value: i64,
    },
    const_value: struct {
        start: usize,
        end: usize,
        value: Value,
    },
    load_local: struct {
        start: usize,
        end: usize,
        slot: u8,
    },
    load_inline_local: struct {
        start: usize,
        end: usize,
        slot: u8,
    },
    local_const_op: struct {
        start: usize,
        end: usize,
        slot: u8,
        op: BuiltinId,
        const_value: i64,
    },
    local_local_op: struct {
        start: usize,
        end: usize,
        left_slot: u8,
        right_slot: u8,
        op: BuiltinId,
    },
    local_local_const_op: struct {
        start: usize,
        end: usize,
        left_slot: u8,
        right_slot: u8,
        op: BuiltinId,
        const_op: BuiltinId,
        const_value: i64,
    },
    array_value: struct {
        start: usize,
        end: usize,
        elem_mode: ?HostDenseElem,
    },

    fn start(self: ProducedValue) usize {
        return switch (self) {
            .const_int => |inst| inst.start,
            .const_value => |inst| inst.start,
            .load_local => |inst| inst.start,
            .load_inline_local => |inst| inst.start,
            .local_const_op => |inst| inst.start,
            .local_local_op => |inst| inst.start,
            .local_local_const_op => |inst| inst.start,
            .array_value => |inst| inst.start,
        };
    }

    fn end(self: ProducedValue) usize {
        return switch (self) {
            .const_int => |inst| inst.end,
            .const_value => |inst| inst.end,
            .load_local => |inst| inst.end,
            .load_inline_local => |inst| inst.end,
            .local_const_op => |inst| inst.end,
            .local_local_op => |inst| inst.end,
            .local_local_const_op => |inst| inst.end,
            .array_value => |inst| inst.end,
        };
    }
};

const GlobalCallArgSource = union(enum) {
    local: struct {
        slot: u8,
        consume: bool,
    },
    const_int: i64,
    const_bool: bool,
    local_const_op: struct {
        slot: u8,
        consume: bool,
        op: BuiltinId,
        const_value: i64,
    },
    local_local_op: struct {
        left_slot: u8,
        right_slot: u8,
        op: BuiltinId,
    },
    local_local_const_op: struct {
        left_slot: u8,
        right_slot: u8,
        op: BuiltinId,
        const_op: BuiltinId,
        const_value: i64,
    },
};

const InstructionBuffer = struct {
    bytes: [max_body_bytes]u8 = undefined,
    byte_len: usize = 0,
    constants: [max_body_constants]Value = undefined,
    constant_len: usize = 0,
    references_globals: bool = false,
    previous_simple: ?ProducedValue = null,
    last_simple: ?ProducedValue = null,
    simple_history: [max_shaped_call_args]ProducedValue = undefined,
    simple_history_len: usize = 0,
    last_op_start: usize = 0,
    control_flow_op_count: usize = 0,

    const Mark = struct {
        byte_len: usize,
        constant_len: usize,
        references_globals: bool,
        previous_simple: ?ProducedValue,
        last_simple: ?ProducedValue,
        simple_history: [max_shaped_call_args]ProducedValue,
        simple_history_len: usize,
        last_op_start: usize,
        control_flow_op_count: usize,
    };

    fn byteSlice(self: *const InstructionBuffer) []const u8 {
        return self.bytes[0..self.byte_len];
    }

    fn mark(self: *const InstructionBuffer) Mark {
        return .{
            .byte_len = self.byte_len,
            .constant_len = self.constant_len,
            .references_globals = self.references_globals,
            .previous_simple = self.previous_simple,
            .last_simple = self.last_simple,
            .simple_history = self.simple_history,
            .simple_history_len = self.simple_history_len,
            .last_op_start = self.last_op_start,
            .control_flow_op_count = self.control_flow_op_count,
        };
    }

    fn restore(self: *InstructionBuffer, saved: Mark) void {
        self.byte_len = saved.byte_len;
        self.constant_len = saved.constant_len;
        self.references_globals = saved.references_globals;
        self.previous_simple = saved.previous_simple;
        self.last_simple = saved.last_simple;
        self.simple_history = saved.simple_history;
        self.simple_history_len = saved.simple_history_len;
        self.last_op_start = saved.last_op_start;
        self.control_flow_op_count = saved.control_flow_op_count;
    }

    fn constantSlice(self: *const InstructionBuffer) []const Value {
        return self.constants[0..self.constant_len];
    }

    inline fn appendOp(self: *InstructionBuffer, op: Op) KError!void {
        self.invalidateSimple();
        try self.appendRawOp(op);
    }

    inline fn appendRawOp(self: *InstructionBuffer, op: Op) KError!void {
        self.last_op_start = self.byte_len;
        try self.appendByte(@intFromEnum(op));
        switch (op) {
            .jump,
            .jump_if_false,
            .jump_if_false_equal_local_const,
            .jump_if_false_less_local_const,
            .jump_if_false_more_local_const,
            => self.control_flow_op_count += 1,
            else => {},
        }
    }

    fn appendShapedDyad(self: *InstructionBuffer, op: BuiltinId) KError!void {
        switch (op) {
            .add => {
                if (try self.tryFoldConstIntDyad(.add)) return;
                if (try self.tryShapeConstDyad(.add)) return;
                if (try self.tryShapeDyad(.add)) return;
                if (try self.tryShapeArrayDyad(.array_add)) return;
                try self.appendOp(.add);
            },
            .sub => {
                if (try self.tryFoldConstIntDyad(.sub)) return;
                if (try self.tryShapeConstDyad(.sub)) return;
                if (try self.tryShapeDyad(.sub)) return;
                if (try self.tryShapeArrayDyad(.array_sub)) return;
                try self.appendOp(.sub);
            },
            .mul => {
                if (try self.tryFoldConstIntDyad(.mul)) return;
                if (try self.tryShapeConstDyad(.mul)) return;
                if (try self.tryShapeDyad(.mul)) return;
                if (try self.tryShapeArrayDyad(.array_mul)) return;
                try self.appendOp(.mul);
            },
            .div => {
                if (try self.tryShapeArrayDyad(.array_div)) return;
                try self.appendOp(.div);
            },
            .minimum => {
                if (try self.tryShapeConstDyad(.minimum)) return;
                if (try self.tryShapeDyad(.minimum)) return;
                try self.appendOp(.minimum);
            },
            .maximum => {
                if (try self.tryShapeConstDyad(.maximum)) return;
                if (try self.tryShapeDyad(.maximum)) return;
                try self.appendOp(.maximum);
            },
            .less => {
                if (try self.tryShapeConstDyad(.less)) return;
                if (try self.tryShapeDyad(.less)) return;
                try self.appendOp(.less);
            },
            .more => {
                if (try self.tryShapeConstDyad(.more)) return;
                if (try self.tryShapeDyad(.more)) return;
                try self.appendOp(.more);
            },
            .equal => {
                if (try self.tryShapeConstDyad(.equal)) return;
                if (try self.tryShapeDyad(.equal)) return;
                try self.appendOp(.equal);
            },
            else => return error.Unsupported,
        }
    }

    fn appendDot(self: *InstructionBuffer) KError!void {
        self.invalidateSimple();
        try self.appendRawOp(.dot);
    }

    fn appendShapedMonad(self: *InstructionBuffer, op: Op) KError!void {
        switch (op) {
            .negate => {
                if (try self.tryFoldConstIntUnaryNegate()) return;
                if (try self.tryShapeUnary(.negate)) return;
                if (try self.tryShapeArrayMonad(.array_negate)) return;
                try self.appendOp(.negate);
            },
            .sqrt => {
                if (try self.tryShapeUnary(.sqrt)) return;
                if (try self.tryShapeArrayMonad(.array_sqrt)) return;
                try self.appendOp(.sqrt);
            },
            else => return error.Internal,
        }
    }

    fn appendShapedCall1(self: *InstructionBuffer) KError!void {
        if (try self.tryShapeCall1()) return;
        try self.appendOp(.call1);
        _ = try self.tryShapeArgmaxSuffix();
    }

    fn emitConstInt(self: *InstructionBuffer, value: i64) KError!void {
        const start = self.byte_len;
        try self.appendRawOp(.const_int);
        try self.appendU64(@bitCast(value));
        self.noteSimple(.{ .const_int = .{ .start = start, .end = self.byte_len, .value = value } });
    }

    fn emitLoadLocal(self: *InstructionBuffer, slot: u16) KError!void {
        const start = self.byte_len;
        try self.appendRawOp(.load_local);
        const pooled = std.math.cast(u8, slot) orelse return error.Unsupported;
        try self.appendByte(pooled);
        self.noteSimple(.{ .load_local = .{ .start = start, .end = self.byte_len, .slot = pooled } });
    }

    fn emitLoadInlineLocal(self: *InstructionBuffer, slot: u16) KError!void {
        const start = self.byte_len;
        try self.appendRawOp(.load_inline_local);
        const pooled = std.math.cast(u8, slot) orelse return error.Unsupported;
        try self.appendByte(pooled);
        self.noteSimple(.{ .load_inline_local = .{ .start = start, .end = self.byte_len, .slot = pooled } });
    }

    fn emitStoreLocal(self: *InstructionBuffer, slot: u16) KError!void {
        const pooled = std.math.cast(u8, slot) orelse return error.Unsupported;
        if (try self.tryShapeStoreLocalLocalConst(pooled)) return;
        if (try self.tryShapeStoreLocalGlobalCallSlots(pooled)) return;
        try self.appendOp(.store_local);
        try self.appendByte(pooled);
    }

    fn emitStoreGlobal(self: *InstructionBuffer, slot: u16, want_result: bool) KError!void {
        try self.appendOp(.store_global);
        try self.appendGlobalSlot(slot);
        if (!want_result) try self.appendOp(.discard);
    }

    fn tryShapeModifiedAssignConst(
        self: *InstructionBuffer,
        op: Op,
        slot: u16,
        builtin: BuiltinId,
        want_result: bool,
        rhs: ProducedValue,
    ) KError!bool {
        if (rhs.end() != self.byte_len) return false;
        const rhs_value = switch (rhs) {
            .const_int => |inst| inst.value,
            .const_value => |inst| switch (inst.value.tag()) {
                .bool => @as(i64, @intFromBool(inst.value.asBool())),
                else => return false,
            },
            else => return false,
        };

        self.byte_len = rhs.start();
        self.invalidateSimple();
        try self.appendOp(op);
        switch (op) {
            .modify_global_const => try self.appendGlobalSlot(slot),
            .modify_local_const => try self.appendPoolByte(slot),
            else => return error.Internal,
        }
        try self.appendByte(@intFromEnum(builtin));
        try self.appendByte(if (want_result) 1 else 0);
        try self.appendU64(@bitCast(rhs_value));
        return true;
    }

    fn emitModifiedAssignGlobal(self: *InstructionBuffer, slot: u16, builtin: BuiltinId, want_result: bool, rhs: ?ProducedValue) KError!void {
        if (rhs) |simple| {
            if (try self.tryShapeModifiedAssignConst(.modify_global_const, slot, builtin, want_result, simple)) return;
        }
        try self.appendOp(.modify_global);
        try self.appendGlobalSlot(slot);
        try self.appendByte(@intFromEnum(builtin));
        try self.appendByte(if (want_result) 1 else 0);
    }

    fn emitModifiedAssignLocal(self: *InstructionBuffer, slot: u16, builtin: BuiltinId, want_result: bool, rhs: ?ProducedValue) KError!void {
        const pooled = std.math.cast(u8, slot) orelse return error.Unsupported;
        if (rhs) |simple| {
            if (try self.tryShapeModifiedAssignConst(.modify_local_const, slot, builtin, want_result, simple)) return;
        }
        try self.appendOp(.modify_local);
        try self.appendByte(pooled);
        try self.appendByte(@intFromEnum(builtin));
        try self.appendByte(if (want_result) 1 else 0);
    }

    fn emitModifiedAssignInlineLocal(self: *InstructionBuffer, slot: u16, builtin: BuiltinId, want_result: bool) KError!void {
        const pooled = std.math.cast(u8, slot) orelse return error.Unsupported;
        try self.appendOp(.modify_inline_local);
        try self.appendByte(pooled);
        try self.appendByte(@intFromEnum(builtin));
        try self.appendByte(if (want_result) 1 else 0);
    }

    fn emitIndexedAssignGlobal(self: *InstructionBuffer, slot: u16, mode: AmendMode, builtin: BuiltinId, want_result: bool) KError!void {
        try self.appendOp(.assign_index_global);
        try self.appendGlobalSlot(slot);
        try self.appendByte(@intFromEnum(mode));
        try self.appendByte(@intFromEnum(builtin));
        try self.appendByte(if (want_result) 1 else 0);
    }

    fn tryShapeIndexedAssignGlobalSources(
        self: *InstructionBuffer,
        slot: u16,
        mode: AmendMode,
        builtin: BuiltinId,
        want_result: bool,
        selector: ProducedValue,
        rhs: ProducedValue,
    ) KError!bool {
        if (selector.end() != rhs.start() or rhs.end() != self.byte_len) return false;
        const selector_source = self.simpleGlobalCallArg(selector) orelse return false;
        const rhs_source = self.simpleGlobalCallArg(rhs) orelse return false;

        self.byte_len = selector.start();
        self.invalidateSimple();
        try self.appendOp(.assign_index_global_sources);
        try self.appendGlobalSlot(slot);
        try self.appendByte(@intFromEnum(mode));
        try self.appendByte(@intFromEnum(builtin));
        try self.appendByte(if (want_result) 1 else 0);
        try self.appendGlobalCallArgSource(selector_source);
        try self.appendGlobalCallArgSource(rhs_source);
        return true;
    }

    fn emitIndexedAssignLocal(self: *InstructionBuffer, slot: u16, mode: AmendMode, builtin: BuiltinId, want_result: bool) KError!void {
        const pooled = std.math.cast(u8, slot) orelse return error.Unsupported;
        try self.appendOp(.assign_index_local);
        try self.appendByte(pooled);
        try self.appendByte(@intFromEnum(mode));
        try self.appendByte(@intFromEnum(builtin));
        try self.appendByte(if (want_result) 1 else 0);
    }

    fn tryShapeIndexedAssignLocalSources(
        self: *InstructionBuffer,
        slot: u16,
        mode: AmendMode,
        builtin: BuiltinId,
        want_result: bool,
        selector: ProducedValue,
        rhs: ProducedValue,
    ) KError!bool {
        if (selector.end() != rhs.start() or rhs.end() != self.byte_len) return false;
        const selector_source = self.simpleGlobalCallArg(selector) orelse return false;
        const rhs_source = self.simpleGlobalCallArg(rhs) orelse return false;
        const pooled = std.math.cast(u8, slot) orelse return error.Unsupported;

        self.byte_len = selector.start();
        self.invalidateSimple();
        try self.appendOp(.assign_index_local_sources);
        try self.appendByte(pooled);
        try self.appendByte(@intFromEnum(mode));
        try self.appendByte(@intFromEnum(builtin));
        try self.appendByte(if (want_result) 1 else 0);
        try self.appendGlobalCallArgSource(selector_source);
        try self.appendGlobalCallArgSource(rhs_source);
        return true;
    }

    fn emitIndexedAssignInlineLocal(self: *InstructionBuffer, slot: u16, mode: AmendMode, builtin: BuiltinId, want_result: bool) KError!void {
        const pooled = std.math.cast(u8, slot) orelse return error.Unsupported;
        try self.appendOp(.assign_index_inline_local);
        try self.appendByte(pooled);
        try self.appendByte(@intFromEnum(mode));
        try self.appendByte(@intFromEnum(builtin));
        try self.appendByte(if (want_result) 1 else 0);
    }

    fn patchOpAt(self: *InstructionBuffer, start: usize, op: Op) void {
        std.debug.assert(start < self.byte_len);
        self.bytes[start] = @intFromEnum(op);
    }

    fn noteArrayValue(self: *InstructionBuffer, start: usize, end: usize, elem_mode: ?HostDenseElem) void {
        self.noteSimple(.{
            .array_value = .{
                .start = start,
                .end = end,
                .elem_mode = elem_mode,
            },
        });
    }

    fn rotateRangeLeft(self: *InstructionBuffer, start: usize, middle: usize, end: usize) void {
        std.debug.assert(start <= middle and middle <= end and end <= self.byte_len);
        if (start == middle or middle == end) return;
        const left_len = middle - start;
        const right_len = end - middle;
        var scratch: [max_body_bytes]u8 = undefined;
        @memcpy(scratch[0..left_len], self.bytes[start..middle]);
        std.mem.copyForwards(u8, self.bytes[start .. start + right_len], self.bytes[middle..end]);
        std.mem.copyForwards(u8, self.bytes[start + right_len .. end], scratch[0..left_len]);
    }

    inline fn appendByte(self: *InstructionBuffer, value: u8) KError!void {
        if (self.byte_len >= self.bytes.len) return error.Unsupported;
        self.bytes[self.byte_len] = value;
        self.byte_len += 1;
    }

    inline fn appendPoolByte(self: *InstructionBuffer, value: anytype) KError!void {
        const int_value = std.math.cast(u8, value) orelse return error.Unsupported;
        try self.appendByte(int_value);
    }

    inline fn appendU16(self: *InstructionBuffer, value: u16) KError!void {
        try self.appendByte(@intCast(value & 0xff));
        try self.appendByte(@intCast((value >> 8) & 0xff));
    }

    inline fn appendGlobalSlot(self: *InstructionBuffer, slot: u16) KError!void {
        self.references_globals = true;
        try self.appendU16(slot);
    }

    inline fn patchU16(self: *InstructionBuffer, start: usize, value: u16) KError!void {
        const end = start + 2;
        if (end > self.byte_len) return error.Internal;
        self.bytes[start] = @intCast(value & 0xff);
        self.bytes[start + 1] = @intCast((value >> 8) & 0xff);
    }

    fn emitJumpIfFalsePlaceholder(self: *InstructionBuffer) KError!usize {
        if (try self.tryShapeJumpIfFalseLocalConst()) |patch| return patch;
        try self.appendOp(.jump_if_false);
        const patch = self.byte_len;
        try self.appendU16(0);
        return patch;
    }

    fn tryShapeJumpIfFalseLocalConst(self: *InstructionBuffer) KError!?usize {
        if (self.byte_len == 0 or self.last_op_start >= self.byte_len) return null;
        const start = self.last_op_start;
        const op = std.meta.intToEnum(Op, self.bytes[start]) catch return null;
        const shaped: ?struct {
            op: Op,
            slot: u8,
            const_value: i64,
        } = switch (op) {
            .equal_local_const, .less_local_const, .more_local_const => blk: {
                if (start + 10 != self.byte_len) return null;
                const slot = self.bytes[start + 1];
                const const_value = Session.directReadI64(self.bytes[0..self.byte_len], start + 2) orelse return null;
                break :blk .{
                    .op = switch (op) {
                        .equal_local_const => .jump_if_false_equal_local_const,
                        .less_local_const => .jump_if_false_less_local_const,
                        .more_local_const => .jump_if_false_more_local_const,
                        else => unreachable,
                    },
                    .slot = slot,
                    .const_value = const_value,
                };
            },
            .equal_const_local, .less_const_local, .more_const_local => blk: {
                if (start + 10 != self.byte_len) return null;
                const const_value = Session.directReadI64(self.bytes[0..self.byte_len], start + 1) orelse return null;
                const slot = self.bytes[start + 9];
                break :blk .{
                    .op = switch (op) {
                        .equal_const_local => .jump_if_false_equal_local_const,
                        .less_const_local => .jump_if_false_more_local_const,
                        .more_const_local => .jump_if_false_less_local_const,
                        else => unreachable,
                    },
                    .slot = slot,
                    .const_value = const_value,
                };
            },
            else => null,
        };
        if (shaped == null) return null;

        self.byte_len = start;
        self.invalidateSimple();
        try self.appendOp(shaped.?.op);
        try self.appendByte(shaped.?.slot);
        try self.appendU64(@bitCast(shaped.?.const_value));
        const patch = self.byte_len;
        try self.appendU16(0);
        return patch;
    }

    fn simpleNumericInt(simple: ProducedValue) ?i64 {
        return switch (simple) {
            .const_int => |inst| inst.value,
            .const_value => |inst| switch (inst.value.tag()) {
                .int => inst.value.asInt(),
                .bool => @intFromBool(inst.value.asBool()),
                .float => {
                    const value = inst.value.asFloat();
                    const rounded = @round(value);
                    if (value == rounded and value >= @as(f64, @floatFromInt(std.math.minInt(i64))) and value <= @as(f64, @floatFromInt(std.math.maxInt(i64)))) {
                        return @intFromFloat(rounded);
                    }
                    return null;
                },
                else => null,
            },
            else => null,
        };
    }

    fn simpleNumericMode(simple: ProducedValue) ?HostDenseElem {
        return switch (simple) {
            .const_int => .int,
            .const_value => |inst| switch (inst.value.tag()) {
                .int, .bool => .int,
                .float => .float,
                else => null,
            },
            .array_value => |inst| inst.elem_mode,
            else => null,
        };
    }

    fn appendU64(self: *InstructionBuffer, value: u64) KError!void {
        var idx: usize = 0;
        while (idx < 8) : (idx += 1) {
            try self.appendByte(@intCast((value >> @intCast(idx * 8)) & 0xff));
        }
    }

    fn internConstant(self: *InstructionBuffer, value: Value) KError!u8 {
        var idx: usize = 0;
        while (idx < self.constant_len) : (idx += 1) {
            if (constantMatches(self.constants[idx], value)) return std.math.cast(u8, idx) orelse return error.Unsupported;
        }
        if (self.constant_len >= self.constants.len) return error.Unsupported;
        self.constants[self.constant_len] = value;
        self.constant_len += 1;
        return std.math.cast(u8, self.constant_len - 1) orelse return error.Unsupported;
    }

    fn tryFoldConstIntDyad(self: *InstructionBuffer, op: BuiltinId) KError!bool {
        const left = self.previous_simple orelse return false;
        const right = self.last_simple orelse return false;
        if (left.end() != right.start() or right.end() != self.byte_len) return false;
        const left_value = simpleNumericInt(left) orelse return false;
        const right_value = simpleNumericInt(right) orelse return false;

        const result = switch (op) {
            .add => @addWithOverflow(left_value, right_value),
            .sub => @subWithOverflow(left_value, right_value),
            .mul => @mulWithOverflow(left_value, right_value),
            .div => return false,
            else => return false,
        };
        if (result[1] != 0 or !Value.fitsInlineInt(result[0])) return false;

        self.byte_len = left.start();
        self.invalidateSimple();
        try self.emitConstInt(result[0]);
        return true;
    }

    fn tryFoldConstIntUnaryNegate(self: *InstructionBuffer) KError!bool {
        const value = self.last_simple orelse return false;
        if (value.end() != self.byte_len) return false;
        const int_value = simpleNumericInt(value) orelse return false;
        const result = @subWithOverflow(@as(i64, 0), int_value);
        if (result[1] != 0 or !Value.fitsInlineInt(result[0])) return false;

        self.byte_len = value.start();
        self.invalidateSimple();
        try self.emitConstInt(result[0]);
        return true;
    }

    fn tryShapeDyad(self: *InstructionBuffer, op: BuiltinId) KError!bool {
        const left = self.previous_simple orelse return false;
        const right = self.last_simple orelse return false;
        if (left.end() != right.start() or right.end() != self.byte_len) return false;

        const shaped: ?struct { op: Op, left_slot: u8, right_slot: u8 } = switch (left) {
            .load_local => |left_inst| switch (right) {
                .load_local => |right_inst| .{ .op = switch (op) {
                    .add => .add_local_local,
                    .sub => .sub_local_local,
                    .mul => .mul_local_local,
                    .minimum => .minimum_local_local,
                    .maximum => .maximum_local_local,
                    .less => .less_local_local,
                    .more => .more_local_local,
                    .equal => .equal_local_local,
                    .div => return false,
                    else => return false,
                }, .left_slot = left_inst.slot, .right_slot = right_inst.slot },
                else => null,
            },
            .load_inline_local => |left_inst| switch (right) {
                .load_inline_local => |right_inst| .{ .op = switch (op) {
                    .add => .add_inline_local_local,
                    .sub => .sub_inline_local_local,
                    .mul => .mul_inline_local_local,
                    .div => return false,
                    else => return false,
                }, .left_slot = left_inst.slot, .right_slot = right_inst.slot },
                else => null,
            },
            else => null,
        };
        if (shaped == null) return false;

        self.byte_len = left.start();
        const selector_shape: ?struct { left_slot: u8, right_slot: u8, op: BuiltinId } = switch (left) {
            .load_local => |left_inst| switch (right) {
                .load_local => |right_inst| switch (op) {
                    .add, .sub => .{ .left_slot = left_inst.slot, .right_slot = right_inst.slot, .op = op },
                    else => null,
                },
                else => null,
            },
            else => null,
        };
        if (selector_shape) |selector| {
            try self.appendRawOp(shaped.?.op);
            try self.appendByte(shaped.?.left_slot);
            try self.appendByte(shaped.?.right_slot);
            self.replaceSimpleTail(2, .{
                .local_local_op = .{
                    .start = left.start(),
                    .end = self.byte_len,
                    .left_slot = selector.left_slot,
                    .right_slot = selector.right_slot,
                    .op = selector.op,
                },
            });
            return true;
        }

        self.invalidateSimple();
        try self.appendOp(shaped.?.op);
        try self.appendByte(shaped.?.left_slot);
        try self.appendByte(shaped.?.right_slot);
        return true;
    }

    fn tryShapeConstDyad(self: *InstructionBuffer, op: BuiltinId) KError!bool {
        const left = self.previous_simple orelse return false;
        const right = self.last_simple orelse return false;
        if (left.end() != right.start() or right.end() != self.byte_len) return false;

        if (switch (left) {
            .local_local_op => true,
            else => false,
        } and switch (right) {
            .const_int => true,
            else => false,
        }) {
            const left_inst = switch (left) {
                .local_local_op => |inst| inst,
                else => unreachable,
            };
            const right_inst = switch (right) {
                .const_int => |inst| inst,
                else => unreachable,
            };
            switch (op) {
                .add, .sub => {},
                else => return false,
            }
            try self.appendRawOp(switch (op) {
                .add => .add,
                .sub => .sub,
                else => unreachable,
            });
            self.replaceSimpleTail(2, .{
                .local_local_const_op = .{
                    .start = left_inst.start,
                    .end = self.byte_len,
                    .left_slot = left_inst.left_slot,
                    .right_slot = left_inst.right_slot,
                    .op = left_inst.op,
                    .const_op = op,
                    .const_value = right_inst.value,
                },
            });
            return true;
        }

        const shaped: ?struct { op: Op, const_value: i64, slot: u8, const_first: bool } = switch (left) {
            .const_int => |left_inst| switch (right) {
                .load_local => |right_inst| .{
                    .op = switch (op) {
                        .add => .add_const_local,
                        .sub => .sub_const_local,
                        .mul => .mul_const_local,
                        .minimum => .minimum_const_local,
                        .maximum => .maximum_const_local,
                        .less => .less_const_local,
                        .more => .more_const_local,
                        .equal => .equal_const_local,
                        .div => return false,
                        else => return false,
                    },
                    .const_value = left_inst.value,
                    .slot = right_inst.slot,
                    .const_first = true,
                },
                .load_inline_local => |right_inst| .{
                    .op = switch (op) {
                        .add => .add_const_inline_local,
                        .sub => .sub_const_inline_local,
                        .mul => .mul_const_inline_local,
                        .div => return false,
                        else => return false,
                    },
                    .const_value = left_inst.value,
                    .slot = right_inst.slot,
                    .const_first = true,
                },
                else => null,
            },
            .load_local => |left_inst| switch (right) {
                .const_int => |right_inst| .{
                    .op = switch (op) {
                        .add => .add_local_const,
                        .sub => .sub_local_const,
                        .mul => .mul_local_const,
                        .minimum => .minimum_local_const,
                        .maximum => .maximum_local_const,
                        .less => .less_local_const,
                        .more => .more_local_const,
                        .equal => .equal_local_const,
                        .div => return false,
                        else => return false,
                    },
                    .const_value = right_inst.value,
                    .slot = left_inst.slot,
                    .const_first = false,
                },
                else => null,
            },
            .load_inline_local => |left_inst| switch (right) {
                .const_int => |right_inst| .{
                    .op = switch (op) {
                        .add => .add_inline_local_const,
                        .sub => .sub_inline_local_const,
                        .mul => .mul_inline_local_const,
                        .div => return false,
                        else => return false,
                    },
                    .const_value = right_inst.value,
                    .slot = left_inst.slot,
                    .const_first = false,
                },
                else => null,
            },
            else => null,
        };
        if (shaped == null) return false;

        self.byte_len = left.start();
        const local_const_shape: ?struct { slot: u8, op: BuiltinId, const_value: i64 } = if (!shaped.?.const_first) switch (left) {
            .load_local => |left_inst| .{
                .slot = left_inst.slot,
                .op = op,
                .const_value = shaped.?.const_value,
            },
            else => null,
        } else null;
        if (local_const_shape) |local_const| {
            try self.appendRawOp(shaped.?.op);
            try self.appendByte(shaped.?.slot);
            try self.appendU64(@bitCast(shaped.?.const_value));
            self.replaceSimpleTail(2, .{
                .local_const_op = .{
                    .start = left.start(),
                    .end = self.byte_len,
                    .slot = local_const.slot,
                    .op = local_const.op,
                    .const_value = local_const.const_value,
                },
            });
            return true;
        }

        self.invalidateSimple();
        try self.appendOp(shaped.?.op);
        if (shaped.?.const_first) {
            try self.appendU64(@bitCast(shaped.?.const_value));
            try self.appendByte(shaped.?.slot);
        } else {
            try self.appendByte(shaped.?.slot);
            try self.appendU64(@bitCast(shaped.?.const_value));
        }
        return true;
    }

    fn tryShapeStoreLocalLocalConst(self: *InstructionBuffer, dst_slot: u8) KError!bool {
        const value = self.last_simple orelse return false;
        if (value.end() != self.byte_len) return false;
        const inst = switch (value) {
            .local_const_op => |op_inst| op_inst,
            else => return false,
        };
        const op: Op = switch (inst.op) {
            .add => .store_local_add_local_const,
            .sub => .store_local_sub_local_const,
            .mul => .store_local_mul_local_const,
            else => return false,
        };

        self.byte_len = inst.start;
        self.invalidateSimple();
        try self.appendOp(op);
        try self.appendByte(dst_slot);
        try self.appendByte(inst.slot);
        try self.appendU64(@bitCast(inst.const_value));
        return true;
    }

    fn tryShapeStoreLocalGlobalCallSlots(self: *InstructionBuffer, dst_slot: u8) KError!bool {
        if (self.byte_len == 0 or self.last_op_start >= self.byte_len) return false;
        const op = std.meta.intToEnum(Op, self.bytes[self.last_op_start]) catch return false;
        switch (op) {
            .call_global_slots => self.patchOpAt(self.last_op_start, .call_global_slots_store_local),
            .index_global_source => self.patchOpAt(self.last_op_start, .index_global_source_store_local),
            else => return false,
        }
        self.invalidateSimple();
        try self.appendByte(dst_slot);
        return true;
    }

    fn tryShapeUnary(self: *InstructionBuffer, op: Op) KError!bool {
        const value = self.last_simple orelse return false;
        if (value.end() != self.byte_len) return false;

        const shaped: ?struct { op: Op, slot: u8 } = switch (value) {
            .load_local => |inst| .{ .op = switch (op) {
                .negate => .neg_local,
                .sqrt => .sqrt_local,
                else => return false,
            }, .slot = inst.slot },
            .load_inline_local => |inst| .{ .op = switch (op) {
                .negate => .neg_inline_local,
                .sqrt => .sqrt_inline_local,
                else => return false,
            }, .slot = inst.slot },
            else => null,
        };
        if (shaped == null) return false;

        self.byte_len = value.start();
        self.invalidateSimple();
        try self.appendOp(shaped.?.op);
        try self.appendByte(shaped.?.slot);
        return true;
    }

    fn tryShapeArrayDyad(self: *InstructionBuffer, op: Op) KError!bool {
        const left = self.previous_simple orelse return false;
        const right = self.last_simple orelse return false;
        if (left.end() != right.start() or right.end() != self.byte_len) return false;

        const left_array = switch (left) {
            .array_value => true,
            else => false,
        };
        const right_array = switch (right) {
            .array_value => true,
            else => false,
        };
        if (!left_array and !right_array) return false;

        const result_start = left.start();
        const left_mode = simpleNumericMode(left);
        const right_mode = simpleNumericMode(right);
        const shaped = switch (op) {
            .array_add => denseDyadOp(.add, left_mode, right_mode),
            .array_sub => denseDyadOp(.sub, left_mode, right_mode),
            .array_mul => denseDyadOp(.mul, left_mode, right_mode),
            .array_div => denseDyadOp(.div, left_mode, right_mode),
            else => null,
        };
        try self.appendOp(shaped orelse op);
        const result_mode = denseResultModeFromOperands(op, left_mode, right_mode);
        self.noteArrayValue(result_start, self.byte_len, result_mode);
        return true;
    }

    fn tryShapeArrayMonad(self: *InstructionBuffer, op: Op) KError!bool {
        const value = self.last_simple orelse return false;
        const array_value = switch (value) {
            .array_value => |inst| inst,
            else => return false,
        };
        if (array_value.end != self.byte_len) return false;

        const shaped = switch (op) {
            .array_negate => denseUnaryOp(.negate, array_value.elem_mode),
            .array_sqrt => denseUnaryOp(.sqrt, array_value.elem_mode),
            else => null,
        };
        try self.appendOp(shaped orelse op);
        const result_mode = denseResultModeFromUnary(op, array_value.elem_mode);
        self.noteArrayValue(array_value.start, self.byte_len, result_mode);
        return true;
    }

    fn tryShapeArgmaxSuffix(self: *InstructionBuffer) KError!bool {
        if (self.byte_len == 0) return false;
        const last_op = std.meta.intToEnum(Op, self.bytes[self.byte_len - 1]) catch return false;
        if (last_op != .find and last_op != .call1) return false;

        var start = self.byte_len;
        while (start > 0) {
            start -= 1;
            const slice = self.bytes[start..self.byte_len];
            const kind = Session.classifyArgmaxBytecode(slice, self.constantSlice()) orelse continue;
            const operand_len = Session.argmaxBytecodeOperandLen(slice, self.constantSlice(), kind);
            self.byte_len = start + operand_len;
            self.invalidateSimple();
            try self.appendOp(.argmax);
            return true;
        }
        return false;
    }

    fn tryShapeCall1(self: *InstructionBuffer) KError!bool {
        const callee = self.previous_simple orelse return false;
        const arg = self.last_simple orelse return false;
        if (callee.end() != arg.start() or arg.end() != self.byte_len) return false;

        switch (callee) {
            .load_local => |callee_inst| switch (arg) {
                .load_local => |arg_inst| {
                    self.byte_len = callee.start();
                    self.invalidateSimple();
                    try self.appendOp(.call1_local_local);
                    try self.appendByte(callee_inst.slot);
                    try self.appendByte(arg_inst.slot);
                    return true;
                },
                .local_local_op => |arg_inst| {
                    self.byte_len = callee.start();
                    self.invalidateSimple();
                    try self.appendOp(.call1_local_local_op);
                    try self.appendByte(callee_inst.slot);
                    try self.appendByte(@intFromEnum(arg_inst.op));
                    try self.appendByte(arg_inst.left_slot);
                    try self.appendByte(arg_inst.right_slot);
                    return true;
                },
                .local_local_const_op => |arg_inst| {
                    self.byte_len = callee.start();
                    self.invalidateSimple();
                    try self.appendOp(.call1_local_local_op_const);
                    try self.appendByte(callee_inst.slot);
                    try self.appendByte(@intFromEnum(arg_inst.op));
                    try self.appendByte(arg_inst.left_slot);
                    try self.appendByte(arg_inst.right_slot);
                    try self.appendByte(@intFromEnum(arg_inst.const_op));
                    try self.appendU64(@bitCast(arg_inst.const_value));
                    return true;
                },
                else => return false,
            },
            .load_inline_local => |callee_inst| switch (arg) {
                .load_inline_local => |arg_inst| {
                    self.byte_len = callee.start();
                    self.invalidateSimple();
                    try self.appendOp(.call1_inline_local_local);
                    try self.appendByte(callee_inst.slot);
                    try self.appendByte(arg_inst.slot);
                    return true;
                },
                else => return false,
            },
            else => return false,
        }
    }

    fn simpleTail(self: *const InstructionBuffer, count: usize) ?[]const ProducedValue {
        if (count == 0 or count > self.simple_history_len) return null;
        const start = self.simple_history_len - count;
        const tail = self.simple_history[start..self.simple_history_len];
        if (tail[tail.len - 1].end() != self.byte_len) return null;
        for (1..tail.len) |idx| {
            if (tail[idx - 1].end() != tail[idx].start()) return null;
        }
        return tail;
    }

    fn simpleGlobalCallArg(self: *const InstructionBuffer, simple: ProducedValue) ?GlobalCallArgSource {
        _ = self;
        return switch (simple) {
            .load_local => |inst| .{
                .local = .{
                    .slot = inst.slot,
                    .consume = false,
                },
            },
            .const_int => |inst| .{ .const_int = inst.value },
            .const_value => |inst| switch (inst.value.tag()) {
                .bool => .{ .const_bool = inst.value.asBool() },
                else => null,
            },
            .local_const_op => |inst| .{
                .local_const_op = .{
                    .slot = inst.slot,
                    .consume = false,
                    .op = inst.op,
                    .const_value = inst.const_value,
                },
            },
            .local_local_op => |inst| .{
                .local_local_op = .{
                    .left_slot = inst.left_slot,
                    .right_slot = inst.right_slot,
                    .op = inst.op,
                },
            },
            .local_local_const_op => |inst| .{
                .local_local_const_op = .{
                    .left_slot = inst.left_slot,
                    .right_slot = inst.right_slot,
                    .op = inst.op,
                    .const_op = inst.const_op,
                    .const_value = inst.const_value,
                },
            },
            else => null,
        };
    }

    fn appendGlobalCallArgSource(self: *InstructionBuffer, arg: GlobalCallArgSource) KError!void {
        switch (arg) {
            .local => |value| {
                try self.appendByte(global_call_arg_kind_byte(.local, value.consume));
                try self.appendByte(value.slot);
            },
            .const_int => |value| {
                try self.appendByte(global_call_arg_kind_byte(.const_int, false));
                try self.appendU64(@bitCast(value));
            },
            .const_bool => |value| {
                try self.appendByte(global_call_arg_kind_byte(if (value) .const_true else .const_false, false));
            },
            .local_const_op => |value| {
                const kind: GlobalCallArgKind = switch (value.op) {
                    .add => .local_add_const,
                    .sub => .local_sub_const,
                    .mul => .local_mul_const,
                    else => return error.Unsupported,
                };
                try self.appendByte(global_call_arg_kind_byte(kind, value.consume));
                try self.appendByte(value.slot);
                try self.appendU64(@bitCast(value.const_value));
            },
            .local_local_op => |value| {
                try self.appendByte(global_call_arg_kind_byte(.local_local_op, false));
                try self.appendByte(@intFromEnum(value.op));
                try self.appendByte(value.left_slot);
                try self.appendByte(value.right_slot);
            },
            .local_local_const_op => |value| {
                try self.appendByte(global_call_arg_kind_byte(.local_local_const_op, false));
                try self.appendByte(@intFromEnum(value.op));
                try self.appendByte(value.left_slot);
                try self.appendByte(value.right_slot);
                try self.appendByte(@intFromEnum(value.const_op));
                try self.appendU64(@bitCast(value.const_value));
            },
        }
    }

    fn tryShapeGlobalIndexSource(self: *InstructionBuffer, slot: u16, arg: ProducedValue, candidates: *ConsumeCandidates) KError!bool {
        if (arg.end() != self.byte_len) return false;
        const source = self.simpleGlobalCallArg(arg) orelse return false;
        self.byte_len = arg.start();
        self.invalidateSimple();
        try self.appendOp(.index_global_source);
        try self.appendGlobalSlot(slot);
        const arg_kind_start = self.byte_len;
        try self.appendGlobalCallArgSource(source);
        switch (arg) {
            .load_local => |inst| try candidates.noteShapedGlobalLocalArg(inst.slot, inst.start, arg_kind_start),
            .local_const_op => |inst| try candidates.noteShapedGlobalLocalArg(inst.slot, inst.start, arg_kind_start),
            else => {},
        }
        return true;
    }

    fn tryShapeGlobalCallSlots(self: *InstructionBuffer, slot: u16, argc: u8, candidates: *ConsumeCandidates) KError!bool {
        const args = self.simpleTail(argc) orelse return false;
        return try self.tryShapeGlobalCallSlotsFromSimples(slot, args, candidates);
    }

    fn tryShapeGlobalCallSlotsFromSimples(self: *InstructionBuffer, slot: u16, args: []const ProducedValue, candidates: *ConsumeCandidates) KError!bool {
        if (args.len == 0 or args.len > max_shaped_call_args) return false;
        if (args[args.len - 1].end() != self.byte_len) return false;
        const start = args[0].start();
        var sources: [max_shaped_call_args]GlobalCallArgSource = undefined;
        for (args, 0..) |arg, idx| {
            sources[idx] = self.simpleGlobalCallArg(arg) orelse return false;
        }

        self.byte_len = start;
        self.invalidateSimple();
        try self.appendOp(.call_global_slots);
        try self.appendGlobalSlot(slot);
        try self.appendByte(@intCast(args.len));
        for (args, 0..) |arg, idx| {
            const arg_kind_start = self.byte_len;
            try self.appendGlobalCallArgSource(sources[idx]);
            switch (arg) {
                .load_local => |inst| try candidates.noteShapedGlobalLocalArg(inst.slot, inst.start, arg_kind_start),
                .local_const_op => |inst| try candidates.noteShapedGlobalLocalArg(inst.slot, inst.start, arg_kind_start),
                else => {},
            }
        }
        return true;
    }

    fn tryRewriteTailCall(self: *InstructionBuffer) bool {
        if (self.byte_len == 0 or self.last_op_start >= self.byte_len) return false;
        const op = std.meta.intToEnum(Op, self.bytes[self.last_op_start]) catch return false;
        const shaped: ?Op = switch (op) {
            .call1 => .tail_call1,
            .call1_local_local => .tail_call1_local_local,
            .call1_local_local_op => .tail_call1_local_local_op,
            .call1_local_local_op_const => .tail_call1_local_local_op_const,
            .call2 => .tail_call2,
            .call_global1 => .tail_call_global1,
            .call_global2 => .tail_call_global2,
            .call_global3 => .tail_call_global3,
            .call_global4 => .tail_call_global4,
            .call_global_slots => .tail_call_global_slots,
            .index_global_source => .tail_index_global_source,
            else => null,
        };
        if (shaped == null) return false;
        self.bytes[self.last_op_start] = @intFromEnum(shaped.?);
        self.invalidateSimple();
        return true;
    }

    fn applyPostCompile(self: *InstructionBuffer, mode: PostCompileMode) void {
        switch (mode) {
            .top_level => {},
            .tail_position => _ = self.tryRewriteTailCall(),
        }
    }

    fn invalidateSimple(self: *InstructionBuffer) void {
        self.previous_simple = null;
        self.last_simple = null;
        self.simple_history_len = 0;
    }

    fn refreshSimplePointers(self: *InstructionBuffer) void {
        self.last_simple = if (self.simple_history_len >= 1) self.simple_history[self.simple_history_len - 1] else null;
        self.previous_simple = if (self.simple_history_len >= 2) self.simple_history[self.simple_history_len - 2] else null;
    }

    fn replaceSimpleTail(self: *InstructionBuffer, count: usize, simple: ProducedValue) void {
        if (count > self.simple_history_len) {
            self.invalidateSimple();
            self.noteSimple(simple);
            return;
        }
        self.simple_history_len -= count;
        if (self.simple_history_len == self.simple_history.len) {
            std.mem.copyForwards(ProducedValue, self.simple_history[0 .. self.simple_history.len - 1], self.simple_history[1..]);
            self.simple_history_len -= 1;
        }
        self.simple_history[self.simple_history_len] = simple;
        self.simple_history_len += 1;
        self.refreshSimplePointers();
    }

    fn noteSimple(self: *InstructionBuffer, simple: ProducedValue) void {
        if (self.simple_history_len == self.simple_history.len) {
            std.mem.copyForwards(ProducedValue, self.simple_history[0 .. self.simple_history.len - 1], self.simple_history[1..]);
            self.simple_history_len -= 1;
        }
        self.simple_history[self.simple_history_len] = simple;
        self.simple_history_len += 1;
        self.refreshSimplePointers();
    }
};

fn denseDyadOp(op: BuiltinId, left_mode: ?HostDenseElem, right_mode: ?HostDenseElem) ?Op {
    const left = left_mode orelse return null;
    const right = right_mode orelse return null;
    return switch (op) {
        .add => switch (left) {
            .int => switch (right) {
                .int => .array_add_ii,
                .float => .array_add_if,
            },
            .float => switch (right) {
                .int => .array_add_fi,
                .float => .array_add_ff,
            },
        },
        .sub => switch (left) {
            .int => switch (right) {
                .int => .array_sub_ii,
                .float => .array_sub_if,
            },
            .float => switch (right) {
                .int => .array_sub_fi,
                .float => .array_sub_ff,
            },
        },
        .mul => switch (left) {
            .int => switch (right) {
                .int => .array_mul_ii,
                .float => .array_mul_if,
            },
            .float => switch (right) {
                .int => .array_mul_fi,
                .float => .array_mul_ff,
            },
        },
        .div => switch (left) {
            .int => switch (right) {
                .int => .array_div_ii,
                .float => .array_div_if,
            },
            .float => switch (right) {
                .int => .array_div_fi,
                .float => .array_div_ff,
            },
        },
        else => null,
    };
}

fn denseUnaryOp(op: Op, elem_mode: ?HostDenseElem) ?Op {
    const mode = elem_mode orelse return null;
    return switch (op) {
        .array_negate => switch (mode) {
            .int => .array_negate_i,
            .float => .array_negate_f,
        },
        .array_sqrt => switch (mode) {
            .int => .array_sqrt_i,
            .float => .array_sqrt_f,
        },
        else => null,
    };
}

fn denseResultModeFromOperands(op: Op, left_mode: ?HostDenseElem, right_mode: ?HostDenseElem) ?HostDenseElem {
    const left = left_mode orelse return null;
    const right = right_mode orelse return null;
    return switch (op) {
        .array_div,
        .array_div_ii,
        .array_div_ff,
        .array_div_if,
        .array_div_fi,
        => .float,
        else => if (left == .float or right == .float) .float else .int,
    };
}

fn denseResultModeFromUnary(op: Op, elem_mode: ?HostDenseElem) ?HostDenseElem {
    const mode = elem_mode orelse return null;
    return switch (op) {
        .array_negate,
        .array_negate_i,
        .array_negate_f,
        => mode,
        .array_sqrt,
        .array_sqrt_i,
        .array_sqrt_f,
        => .float,
        else => null,
    };
}

fn identMatches(stored: IdentRef, query: IdentRef) bool {
    if (stored.key.len != query.key.len) return false;
    if (stored.key.prefix != query.key.prefix) return false;
    if (stored.key.len <= 8) return true;
    return std.mem.eql(u8, stored.text, query.text);
}

fn identRefFromText(text: []const u8) IdentRef {
    return .{
        .text = text,
        .key = IdentKey.fromText(text),
    };
}

fn sourceReferencesIdentCurrentLambda(source: []const u8, ident: IdentRef) bool {
    var index: usize = 0;
    var brace_depth: usize = 0;
    while (index < source.len) {
        const ch = source[index];
        if (ch == '"') {
            index += 1;
            while (index < source.len and source[index] != '"') : (index += 1) {}
            if (index < source.len) index += 1;
            continue;
        }
        if (ch == '`') {
            index += 1;
            while (index < source.len and isIdentContinue(source[index])) : (index += 1) {}
            continue;
        }
        if (ch == '{') {
            brace_depth += 1;
            index += 1;
            continue;
        }
        if (ch == '}') {
            if (brace_depth != 0) brace_depth -= 1;
            index += 1;
            continue;
        }
        if (brace_depth == 0 and isIdentStart(ch)) {
            const start = index;
            index += 1;
            while (index < source.len and isIdentContinue(source[index])) : (index += 1) {}
            if (identMatches(identRefFromText(source[start..index]), ident)) return true;
            continue;
        }
        index += 1;
    }
    return false;
}

fn constantMatches(stored: Value, query: Value) bool {
    if (stored.tag() != query.tag()) return false;
    return switch (stored.tag()) {
        .int => stored.asInt() == query.asInt(),
        .float => @as(u64, @bitCast(stored.asFloat())) == @as(u64, @bitCast(query.asFloat())),
        .bool => stored.asBool() == query.asBool(),
        .builtin => stored.asBuiltin() == query.asBuiltin(),
        .closure => stored.asClosure() == query.asClosure(),
        .array => stored.raw == query.raw,
    };
}

const Scope = struct {
    explicit_names: [max_explicit_params]IdentRef = undefined,
    explicit_count: u8 = 0,
    local_names: [max_explicit_params]IdentRef = undefined,
    local_slots: [max_explicit_params]u16 = undefined,
    local_count: u8 = 0,
    allow_implicit_params: bool = false,
    param_binding_kind: ParamBindingKind = .frame_local,
    arity: u8 = 0,
    frame_slot_count: u8 = 0,

    fn deinit(self: *Scope, allocator: std.mem.Allocator) void {
        _ = self;
        _ = allocator;
    }

    fn declareParam(self: *Scope, ident: IdentRef) !void {
        if (self.lookupExplicit(ident) != null) return error.Parse;
        if (self.explicit_count >= max_explicit_params) return error.Unsupported;
        const slot: u16 = self.arity;
        self.arity += 1;
        self.frame_slot_count = self.arity;
        self.explicit_names[self.explicit_count] = ident;
        self.explicit_count += 1;
        if (slot != self.explicit_count - 1) return error.Internal;
    }

    fn declareLocal(self: *Scope, ident: IdentRef) !u16 {
        if (self.lookupExplicit(ident)) |slot| return slot;
        var idx: u8 = 0;
        while (idx < self.local_count) : (idx += 1) {
            if (identMatches(self.local_names[idx], ident)) return self.local_slots[idx];
        }
        if (self.local_count >= max_explicit_params) return error.Unsupported;
        self.ensureLocalSlotFloor();
        const slot: u16 = self.frame_slot_count;
        self.local_names[self.local_count] = ident;
        self.local_slots[self.local_count] = slot;
        self.local_count += 1;
        self.frame_slot_count += 1;
        return slot;
    }

    fn declareShadowLocal(self: *Scope, ident: IdentRef) !u16 {
        if (self.local_count >= max_explicit_params) return error.Unsupported;
        self.ensureLocalSlotFloor();
        const slot: u16 = self.frame_slot_count;
        self.local_names[self.local_count] = ident;
        self.local_slots[self.local_count] = slot;
        self.local_count += 1;
        self.frame_slot_count += 1;
        return slot;
    }

    fn ensureLocalSlotFloor(self: *Scope) void {
        if (self.param_binding_kind == .frame_local and self.allow_implicit_params and self.explicit_count == 0 and self.frame_slot_count < 3) {
            self.frame_slot_count = 3;
        }
    }

    fn resolveLoad(self: *Scope, ident: IdentRef) !ResolveResult {
        if (self.lookupResolvedHere(ident)) |resolved| return resolved;
        return .global;
    }

    fn lookupLocal(self: *Scope, ident: IdentRef) ?u16 {
        var local_idx = self.local_count;
        while (local_idx > 0) {
            local_idx -= 1;
            if (identMatches(self.local_names[local_idx], ident)) return self.local_slots[local_idx];
        }
        if (self.lookupExplicit(ident)) |slot| return slot;
        if (!self.allow_implicit_params) return null;
        if (ident.text.len == 1) {
            switch (ident.text[0]) {
                'x' => {
                    if (self.arity < 1) self.arity = 1;
                    if (self.frame_slot_count < 1) self.frame_slot_count = 1;
                    return 0;
                },
                'y' => {
                    if (self.arity < 2) self.arity = 2;
                    if (self.frame_slot_count < 2) self.frame_slot_count = 2;
                    return 1;
                },
                'z' => {
                    if (self.arity < 3) self.arity = 3;
                    if (self.frame_slot_count < 3) self.frame_slot_count = 3;
                    return 2;
                },
                else => {},
            }
        }

        return null;
    }

    fn resolveLocal(self: *const Scope, slot: u16) ResolveResult {
        return switch (self.param_binding_kind) {
            .frame_local => .{ .local = slot },
            .inline_local => .{ .inline_local = slot },
        };
    }

    fn lookupResolvedHere(self: *Scope, ident: IdentRef) ?ResolveResult {
        if (self.lookupLocal(ident)) |slot| return self.resolveLocal(slot);
        return null;
    }

    fn lookupExplicit(self: *const Scope, ident: IdentRef) ?u16 {
        var idx: u8 = 0;
        while (idx < self.explicit_count) : (idx += 1) {
            if (identMatches(self.explicit_names[idx], ident)) return idx;
        }
        return null;
    }

    fn isPureGlobalScope(self: *const Scope) bool {
        return self.explicit_count == 0 and
            !self.allow_implicit_params;
    }
};

const Compiler = struct {
    session: *Session,
    source: []const u8,
    code_allocator: std.mem.Allocator,
    compile_mode: CompileMode,
    index: usize = 0,
    consume_candidates: ConsumeCandidates = .{},

    fn init(session: *Session, source: []const u8, code_allocator: std.mem.Allocator, compile_mode: CompileMode) KError!Compiler {
        return .{
            .session = session,
            .source = source,
            .code_allocator = code_allocator,
            .compile_mode = compile_mode,
            .index = skipSpacesInSource(source, 0),
        };
    }

    fn compileTopLevel(self: *Compiler) KError!*const Code {
        var scope = Scope{};
        defer scope.deinit(self.session.allocator);

        var instructions = InstructionBuffer{};
        try self.compileTopLevelInto(&instructions, &scope);
        return try self.finalizeCode(scope.arity, scope.frame_slot_count, &instructions, .top_level, self.source);
    }

    fn compileTopLevelScratch(self: *Compiler, scratch: *ScratchCode) KError!*const Code {
        var scope = Scope{};
        defer scope.deinit(self.session.allocator);

        try self.compileTopLevelInto(&scratch.instructions, &scope);
        const code = scratch.finalize(scope.arity, scope.frame_slot_count);
        self.assignCodeProfile(code, .top_level, self.source);
        return code;
    }

    fn compileTopLevelInto(self: *Compiler, instructions: *InstructionBuffer, scope: *Scope) KError!void {
        var statement_start: usize = 0;
        var compiled_any = false;

        while (nextTopLevelStatement(self.source, &statement_start)) |statement| {
            if (compiled_any) try instructions.appendOp(.discard);

            var statement_compiler = try Compiler.init(
                self.session,
                statement,
                self.code_allocator,
                self.compile_mode,
            );
            try statement_compiler.compileSingleTopLevelStatementInto(instructions, scope);
            compiled_any = true;
        }

        if (!compiled_any) return error.Parse;
        self.index = self.source.len;
        try finishCompiledInstructions(instructions, .top_level);
    }

    fn compileSingleTopLevelStatementInto(self: *Compiler, instructions: *InstructionBuffer, scope: *Scope) KError!void {
        if (try self.tryCompileSimpleTopLevelShape(instructions, scope)) return;

        if (try self.scanIndexedAssignmentStatement(self.source)) |assignment| {
            try self.compileIndexedAssignmentInto(instructions, scope, assignment, true);
            self.index = self.source.len;
        } else if (try self.scanLocalAssignmentStatement(self.source)) |assignment| {
            switch (assignment.mode) {
                .bind, .explicit_global => try self.compileExplicitGlobalAssignmentInto(instructions, scope, assignment, true),
                .modified => try self.compileModifiedAssignmentInto(instructions, scope, assignment, true),
            }
            self.index = self.source.len;
        } else {
            try self.compileExprSliceInto(instructions, scope, self.source);
            self.index = self.source.len;
        }

        if (!self.atEnd()) return error.Parse;
    }

    fn tryCompileSimpleTopLevelShape(self: *Compiler, instructions: *InstructionBuffer, scope: *Scope) KError!bool {
        if (try self.tryCompileSimpleExprSlice(instructions, scope, self.source)) {
            self.index = self.source.len;
            return true;
        }
        return false;
    }

    fn compileExprSliceInto(self: *Compiler, out: *InstructionBuffer, scope: *Scope, source_slice: []const u8) KError!void {
        const updated_candidates = try self.compileExprSliceIntoWithConsumeCandidates(out, scope, source_slice, self.consume_candidates);
        self.consume_candidates = updated_candidates;
    }

    fn compileExprSliceIntoWithConsumeCandidates(
        self: *Compiler,
        out: *InstructionBuffer,
        scope: *Scope,
        source_slice: []const u8,
        candidates: ConsumeCandidates,
    ) KError!ConsumeCandidates {
        if (try self.tryCompileWholeCondExprSlice(out, scope, source_slice, candidates)) |updated| return updated;

        var expr_compiler = try Compiler.init(
            self.session,
            source_slice,
            self.code_allocator,
            self.compile_mode,
        );
        expr_compiler.consume_candidates = candidates;
        if (try expr_compiler.tryCompileSimpleExprSlice(out, scope, source_slice)) {
            expr_compiler.index = expr_compiler.source.len;
        } else {
            _ = try expr_compiler.parseExpr(out, scope);
        }
        if (!expr_compiler.atEnd()) return error.Parse;
        return expr_compiler.consume_candidates;
    }

    fn tryCompileWholeCondExprSlice(
        self: *Compiler,
        out: *InstructionBuffer,
        scope: *Scope,
        source_slice: []const u8,
        candidates: ConsumeCandidates,
    ) KError!?ConsumeCandidates {
        const split = splitWholeCondSpecialForm(source_slice) orelse return null;

        _ = try self.compileExprSliceIntoWithConsumeCandidates(out, scope, split.condition, .{});
        const false_jump_patch = try out.emitJumpIfFalsePlaceholder();

        const branch_candidates = candidates.withoutRecordedUses();
        const then_candidates = try self.compileExprSliceIntoWithConsumeCandidates(out, scope, split.then_branch, branch_candidates);
        patchConsumeCandidates(out, then_candidates);

        try out.appendOp(.jump);
        const end_jump_patch = out.byte_len;
        try out.appendU16(0);

        try out.patchU16(false_jump_patch, std.math.cast(u16, out.byte_len) orelse return error.Unsupported);
        const else_candidates = try self.compileExprSliceIntoWithConsumeCandidates(out, scope, split.else_branch, branch_candidates);
        patchConsumeCandidates(out, else_candidates);
        try out.patchU16(end_jump_patch, std.math.cast(u16, out.byte_len) orelse return error.Unsupported);
        return .{};
    }

    fn compileLambdaBodyIntoWithConsumeCandidates(
        self: *Compiler,
        out: *InstructionBuffer,
        scope: *Scope,
        body_source: []const u8,
        candidates: ConsumeCandidates,
    ) KError!ConsumeCandidates {
        var body_compiler = try Compiler.init(
            self.session,
            body_source,
            self.code_allocator,
            self.compile_mode,
        );
        body_compiler.consume_candidates = candidates;
        try body_compiler.compileLambdaBodyInto(out, scope, body_source);
        return body_compiler.consume_candidates;
    }

    fn emitResolvedLoad(self: *Compiler, out: *InstructionBuffer, resolved: ResolveResult) KError!void {
        switch (resolved) {
            .local => |slot| try out.emitLoadLocal(slot),
            .inline_local => |slot| try out.emitLoadInlineLocal(slot),
            .global => return error.Internal,
        }
        self.consume_candidates.noteLoad(resolved, out.last_op_start);
    }

    fn patchConsumeCandidates(out: *InstructionBuffer, candidates: ConsumeCandidates) void {
        candidates.patchInto(out);
    }

    fn addScopeParamConsumeCandidates(candidates: *ConsumeCandidates, scope: *Scope) KError!void {
        var slot: u16 = 0;
        while (slot < scope.arity) : (slot += 1) {
            try candidates.addResolved(scope.resolveLocal(slot));
        }
    }

    fn addLocalBindingRhsConsumeCandidates(
        candidates: *ConsumeCandidates,
        scope: *Scope,
        rhs_source: []const u8,
        body_source: []const u8,
    ) KError!void {
        var explicit_idx: u8 = 0;
        while (explicit_idx < scope.explicit_count) : (explicit_idx += 1) {
            const ident = scope.explicit_names[explicit_idx];
            if (sourceReferencesIdentCurrentLambda(rhs_source, ident) and
                !sourceReferencesIdentCurrentLambda(body_source, ident))
            {
                try candidates.addResolved(scope.resolveLocal(explicit_idx));
            }
        }

        var local_idx: u8 = 0;
        while (local_idx < scope.local_count) : (local_idx += 1) {
            const ident = scope.local_names[local_idx];
            if (sourceReferencesIdentCurrentLambda(rhs_source, ident) and
                !sourceReferencesIdentCurrentLambda(body_source, ident))
            {
                try candidates.addResolved(scope.resolveLocal(scope.local_slots[local_idx]));
            }
        }

        if (scope.allow_implicit_params and scope.explicit_count == 0) {
            const implicit_names = [_][]const u8{ "x", "y", "z" };
            for (implicit_names, 0..) |name, slot| {
                const ident = identRefFromText(name);
                if (sourceReferencesIdentCurrentLambda(rhs_source, ident) and
                    !sourceReferencesIdentCurrentLambda(body_source, ident))
                {
                    if (scope.arity < slot + 1) scope.arity = @intCast(slot + 1);
                    if (scope.frame_slot_count < slot + 1) scope.frame_slot_count = @intCast(slot + 1);
                    try candidates.addResolved(scope.resolveLocal(@intCast(slot)));
                }
            }
        }
    }

    fn directAmendBaseConsumeCandidates(self: *Compiler, scope: *Scope, body_source: []const u8) KError!ConsumeCandidates {
        const trimmed = std.mem.trim(u8, body_source, " \t\r\n");
        if (!(std.mem.startsWith(u8, trimmed, "@[") or std.mem.startsWith(u8, trimmed, ".["))) return .{};

        const base_start = skipSpacesInSource(trimmed, 2);
        var source_compiler = try Compiler.init(
            self.session,
            trimmed,
            self.code_allocator,
            self.compile_mode,
        );
        const scanned = source_compiler.scanIdentifierAt(base_start) orelse return .{};
        const after_ident = skipSpacesInSource(trimmed, scanned.next_index);
        if (after_ident >= trimmed.len or trimmed[after_ident] != ';') return .{};

        var candidates = ConsumeCandidates{};
        try candidates.addResolved(try scope.resolveLoad(scanned.ident));
        return candidates;
    }

    fn compileLambdaBodyInto(self: *Compiler, out: *InstructionBuffer, scope: *Scope, body_source: []const u8) KError!void {
        const split = splitLambdaBodyHead(body_source) orelse return error.Parse;
        if (try self.scanIndexedAssignmentStatement(split.head)) |assignment| {
            try self.compileIndexedAssignmentInto(out, scope, assignment, split.tail == null);
            if (split.tail) |tail| try self.compileLambdaBodyInto(out, scope, tail);
            return;
        }
        if (try self.scanLocalAssignmentStatement(split.head)) |assignment| {
            switch (assignment.mode) {
                .bind => {
                    const tail_source = split.tail orelse assignment.ident.text;
                    try self.compileLocalBindingInto(out, scope, assignment.ident, assignment.rhs_source, tail_source);
                },
                .modified => {
                    try self.compileModifiedAssignmentInto(out, scope, assignment, split.tail == null);
                    if (split.tail) |tail| try self.compileLambdaBodyInto(out, scope, tail);
                },
                .explicit_global => {
                    try self.compileExplicitGlobalAssignmentInto(out, scope, assignment, split.tail == null);
                    if (split.tail) |tail| try self.compileLambdaBodyInto(out, scope, tail);
                },
            }
            return;
        }
        if (split.tail) |tail| {
            try self.compileExprSliceInto(out, scope, split.head);
            try out.appendOp(.discard);
            try self.compileLambdaBodyInto(out, scope, tail);
            return;
        }
        var final_candidates = self.consume_candidates;
        try final_candidates.mergeFrom(try self.directAmendBaseConsumeCandidates(scope, split.head));
        if (scope.param_binding_kind == .frame_local) try addScopeParamConsumeCandidates(&final_candidates, scope);
        const final_control_before = out.control_flow_op_count;
        const updated_final_candidates = try self.compileExprSliceIntoWithConsumeCandidates(out, scope, split.head, final_candidates);
        self.consume_candidates = updated_final_candidates;
        if (out.control_flow_op_count == final_control_before) patchConsumeCandidates(out, updated_final_candidates);
    }

    fn compileIndexedAssignmentInto(
        self: *Compiler,
        out: *InstructionBuffer,
        scope: *Scope,
        assignment: IndexedAssignment,
        want_result: bool,
    ) KError!void {
        const selector_start = out.byte_len;
        _ = try self.compileExprSliceIntoWithConsumeCandidates(out, scope, assignment.selector_source, .{});
        const selector_simple = if (out.last_simple) |simple|
            if (simple.start() >= selector_start and simple.end() == out.byte_len) simple else null
        else
            null;
        const rhs_start = out.byte_len;
        _ = try self.compileExprSliceIntoWithConsumeCandidates(out, scope, assignment.rhs_source, .{});
        const rhs_simple = if (out.last_simple) |simple|
            if (simple.start() >= rhs_start and simple.end() == out.byte_len) simple else null
        else
            null;

        switch (try scope.resolveLoad(assignment.ident)) {
            .local => |slot| {
                if (selector_simple) |selector| {
                    if (rhs_simple) |rhs| {
                        if (try out.tryShapeIndexedAssignLocalSources(slot, assignment.mode, assignment.builtin, want_result, selector, rhs)) return;
                    }
                }
                try out.emitIndexedAssignLocal(slot, assignment.mode, assignment.builtin, want_result);
            },
            .inline_local => |slot| try out.emitIndexedAssignInlineLocal(slot, assignment.mode, assignment.builtin, want_result),
            .global => {
                const slot = try self.globalSlot(assignment.ident.text);
                if (selector_simple) |selector| {
                    if (rhs_simple) |rhs| {
                        if (try out.tryShapeIndexedAssignGlobalSources(slot, assignment.mode, assignment.builtin, want_result, selector, rhs)) return;
                    }
                }
                try out.emitIndexedAssignGlobal(slot, assignment.mode, assignment.builtin, want_result);
            },
        }
    }

    fn compileExplicitGlobalAssignmentInto(
        self: *Compiler,
        out: *InstructionBuffer,
        scope: *Scope,
        assignment: LocalAssignment,
        want_result: bool,
    ) KError!void {
        _ = try self.compileExprSliceIntoWithConsumeCandidates(out, scope, assignment.rhs_source, .{});
        try out.emitStoreGlobal(try self.globalSlot(assignment.ident.text), want_result);
    }

    fn compileModifiedAssignmentInto(
        self: *Compiler,
        out: *InstructionBuffer,
        scope: *Scope,
        assignment: LocalAssignment,
        want_result: bool,
    ) KError!void {
        const rhs_start = out.byte_len;
        _ = try self.compileExprSliceIntoWithConsumeCandidates(out, scope, assignment.rhs_source, .{});
        const rhs_simple = if (out.last_simple) |simple|
            if (simple.start() >= rhs_start and simple.end() == out.byte_len) simple else null
        else
            null;

        switch (try scope.resolveLoad(assignment.ident)) {
            .local => |slot| try out.emitModifiedAssignLocal(slot, assignment.builtin, want_result, rhs_simple),
            .inline_local => |slot| try out.emitModifiedAssignInlineLocal(slot, assignment.builtin, want_result),
            .global => try out.emitModifiedAssignGlobal(try self.globalSlot(assignment.ident.text), assignment.builtin, want_result, rhs_simple),
        }
    }

    fn compileLocalBindingInto(
        self: *Compiler,
        out: *InstructionBuffer,
        parent: *Scope,
        ident: IdentRef,
        rhs_source: []const u8,
        body_source: []const u8,
    ) KError!void {
        if (parent.param_binding_kind == .frame_local) {
            var rhs_candidates = ConsumeCandidates{};
            try rhs_candidates.addResolved(try parent.resolveLoad(ident));
            try addLocalBindingRhsConsumeCandidates(&rhs_candidates, parent, rhs_source, body_source);
            const rhs_control_before = out.control_flow_op_count;
            const updated_rhs_candidates = try self.compileExprSliceIntoWithConsumeCandidates(out, parent, rhs_source, rhs_candidates);
            if (out.control_flow_op_count == rhs_control_before) patchConsumeCandidates(out, updated_rhs_candidates);
            const slot = try parent.declareLocal(ident);
            try out.emitStoreLocal(slot);
            try self.compileLambdaBodyInto(out, parent, body_source);
            return;
        }

        const rhs_control_before = out.control_flow_op_count;
        var rhs_candidates = ConsumeCandidates{};
        try rhs_candidates.addResolved(try parent.resolveLoad(ident));
        try addLocalBindingRhsConsumeCandidates(&rhs_candidates, parent, rhs_source, body_source);
        const updated_rhs_candidates = try self.compileExprSliceIntoWithConsumeCandidates(out, parent, rhs_source, rhs_candidates);
        if (out.control_flow_op_count == rhs_control_before) patchConsumeCandidates(out, updated_rhs_candidates);
        _ = try parent.declareShadowLocal(ident);
        try self.compileLambdaBodyInto(out, parent, body_source);
    }

    fn scanLocalAssignmentStatement(self: *Compiler, source_slice: []const u8) KError!?LocalAssignment {
        var statement_compiler = try Compiler.init(
            self.session,
            source_slice,
            self.code_allocator,
            self.compile_mode,
        );
        const scanned = statement_compiler.scanIdentifierAt(statement_compiler.index) orelse return null;
        var after = skipSpacesInSource(source_slice, scanned.next_index);
        if (after >= source_slice.len) return null;

        var mode: NameAssignmentMode = .bind;
        var builtin: BuiltinId = .add;
        if (source_slice[after] == ':') {
            if (after + 1 < source_slice.len and source_slice[after + 1] == ':') {
                mode = .explicit_global;
                after += 2;
            } else {
                after += 1;
            }
        } else if (indexedAssignmentBuiltin(source_slice[after])) |id| {
            mode = .modified;
            builtin = id;
            after = skipSpacesInSource(source_slice, after + 1);
            if (after >= source_slice.len or source_slice[after] != ':') return null;
            after += 1;
        } else {
            return null;
        }

        const rhs_start = skipSpacesInSource(source_slice, after);
        if (rhs_start >= source_slice.len) return error.Parse;
        const rhs_source = std.mem.trim(u8, source_slice[rhs_start..], " \t\r\n");
        if (rhs_source.len == 0) return error.Parse;
        return .{
            .ident = scanned.ident,
            .rhs_source = rhs_source,
            .mode = mode,
            .builtin = builtin,
        };
    }

    fn findIndexedAssignmentClose(source_slice: []const u8, open_index: usize) ?usize {
        if (open_index >= source_slice.len or source_slice[open_index] != '[') return null;
        var index = open_index + 1;
        var bracket_depth: usize = 1;
        var paren_depth: usize = 0;
        var brace_depth: usize = 0;
        while (index < source_slice.len) : (index += 1) {
            switch (source_slice[index]) {
                '"' => {
                    index += 1;
                    while (index < source_slice.len and source_slice[index] != '"') : (index += 1) {}
                    if (index >= source_slice.len) return null;
                },
                '[' => bracket_depth += 1,
                ']' => {
                    if (bracket_depth == 0) return null;
                    bracket_depth -= 1;
                    if (bracket_depth == 0 and paren_depth == 0 and brace_depth == 0) return index;
                },
                '(' => paren_depth += 1,
                ')' => {
                    if (paren_depth == 0) return null;
                    paren_depth -= 1;
                },
                '{' => brace_depth += 1,
                '}' => {
                    if (brace_depth == 0) return null;
                    brace_depth -= 1;
                },
                else => {},
            }
        }
        return null;
    }

    fn indexedAssignmentBuiltin(ch: u8) ?BuiltinId {
        return switch (ch) {
            '+', '-', '*', '%', '&', '|' => builtinFromChar(ch),
            else => null,
        };
    }

    fn scanIndexedAssignmentStatement(self: *Compiler, source_slice: []const u8) KError!?IndexedAssignment {
        var statement_compiler = try Compiler.init(
            self.session,
            source_slice,
            self.code_allocator,
            self.compile_mode,
        );
        const scanned = statement_compiler.scanIdentifierAt(statement_compiler.index) orelse return null;
        const open_index = skipSpacesInSource(source_slice, scanned.next_index);
        if (open_index >= source_slice.len or source_slice[open_index] != '[') return null;
        const close_index = findIndexedAssignmentClose(source_slice, open_index) orelse return error.Parse;
        const selector_source = std.mem.trim(u8, source_slice[open_index + 1 .. close_index], " \t\r\n");

        var after = skipSpacesInSource(source_slice, close_index + 1);
        if (after >= source_slice.len) return null;

        var mode: AmendMode = .assign;
        var builtin: BuiltinId = .add;
        if (source_slice[after] == ':') {
            after += 1;
        } else if (indexedAssignmentBuiltin(source_slice[after])) |id| {
            mode = .binary;
            builtin = id;
            after = skipSpacesInSource(source_slice, after + 1);
            if (after >= source_slice.len or source_slice[after] != ':') return null;
            after += 1;
        } else {
            return null;
        }

        if (selector_source.len == 0) return error.Parse;

        const rhs_start = skipSpacesInSource(source_slice, after);
        if (rhs_start >= source_slice.len) return error.Parse;
        const rhs_source = std.mem.trim(u8, source_slice[rhs_start..], " \t\r\n");
        if (rhs_source.len == 0) return error.Parse;
        return .{
            .ident = scanned.ident,
            .selector_source = selector_source,
            .rhs_source = rhs_source,
            .mode = mode,
            .builtin = builtin,
        };
    }

    fn lambdaBodyStartsWithLocalBinding(self: *Compiler, body_source: []const u8) KError!bool {
        const split = splitLambdaBodyHead(body_source) orelse return error.Parse;
        const assignment = (try self.scanLocalAssignmentStatement(split.head)) orelse return false;
        return assignment.mode == .bind;
    }

    fn emitGlobalLoadByName(self: *Compiler, out: *InstructionBuffer, name: []const u8) KError!void {
        try out.appendOp(.load_global);
        try out.appendGlobalSlot(try self.globalSlot(name));
    }

    fn emitSimpleAtom(self: *Compiler, out: *InstructionBuffer, scope: *Scope, atom: SimpleAtom) KError!void {
        switch (atom) {
            .int => |value| try out.emitConstInt(value),
            .float => |value| try self.emitConstFloat(out, value),
            .bool => |value| try self.emitConstBool(out, value),
            .ident => |ident| {
                const pending = try self.pendingResolvedIdent(out, scope, ident);
                try self.emitPendingPrimary(out, scope, pending);
            },
        }
    }

    fn scanNumericLiteral(text: []const u8, start: usize) ?struct { literal: NumericLiteral, next: usize } {
        var index = skipSpacesInSource(text, start);
        if (index >= text.len or !std.ascii.isDigit(text[index])) return null;

        const begin = index;
        while (index < text.len and std.ascii.isDigit(text[index])) : (index += 1) {}
        const int_end = index;

        if (index < text.len and text[index] == 'b') {
            if (int_end != begin + 1) return null;
            const ch = text[begin];
            if (ch != '0' and ch != '1') return null;
            return .{
                .literal = .{ .bool = ch == '1' },
                .next = skipSpacesInSource(text, index + 1),
            };
        }

        var is_float = false;
        if (index < text.len and text[index] == '.') {
            is_float = true;
            index += 1;
            if (index >= text.len or !std.ascii.isDigit(text[index])) return null;
            while (index < text.len and std.ascii.isDigit(text[index])) : (index += 1) {}
        }

        var parse_end = index;
        if (index < text.len and text[index] == 'f') {
            is_float = true;
            index += 1;
        }

        if (is_float) {
            parse_end = if (index > parse_end) index - 1 else parse_end;
            return .{
                .literal = .{
                    .float = std.fmt.parseFloat(f64, text[begin..parse_end]) catch return null,
                },
                .next = skipSpacesInSource(text, index),
            };
        }

        return .{
            .literal = .{
                .int = std.fmt.parseInt(i64, text[begin..index], 10) catch return null,
            },
            .next = skipSpacesInSource(text, index),
        };
    }

    fn scanSimpleAtom(text: []const u8, start: usize) ?struct { atom: SimpleAtom, next: usize } {
        var index = skipSpacesInSource(text, start);
        if (index >= text.len) return null;

        if (std.ascii.isDigit(text[index])) {
            const scanned = scanNumericLiteral(text, index) orelse return null;
            return .{
                .atom = switch (scanned.literal) {
                    .int => |value| .{ .int = value },
                    .float => |value| .{ .float = value },
                    .bool => |value| .{ .bool = value },
                },
                .next = scanned.next,
            };
        }

        if (isIdentStart(text[index])) {
            const begin = index;
            index += 1;
            while (index < text.len and isIdentContinue(text[index])) : (index += 1) {}
            const ident_text = text[begin..index];
            return .{
                .atom = .{
                    .ident = .{
                        .text = ident_text,
                        .key = IdentKey.fromText(ident_text),
                    },
                },
                .next = skipSpacesInSource(text, index),
            };
        }

        return null;
    }

    fn tryCompileSimpleExprSlice(self: *Compiler, out: *InstructionBuffer, scope: *Scope, source_slice: []const u8) KError!bool {
        const text = std.mem.trim(u8, source_slice, " \t\r\n");
        if (text.len == 0) return false;

        if (text[0] == '-' or text[0] == '%') {
            const atom = scanSimpleAtom(text, 1) orelse return false;
            if (atom.next != text.len) return false;
            try self.emitSimpleAtom(out, scope, atom.atom);
            try out.appendShapedMonad(if (text[0] == '-') .negate else .sqrt);
            return true;
        }

        const first = scanSimpleAtom(text, 0) orelse return false;
        if (first.next >= text.len) {
            try self.emitSimpleAtom(out, scope, first.atom);
            return true;
        }

        if (text[first.next] == '[') {
            const callee_ident = switch (first.atom) {
                .ident => |ident| ident,
                else => return false,
            };
            const arg0 = scanSimpleAtom(text, first.next + 1) orelse return false;
            if (arg0.next >= text.len or text[arg0.next] != ';') return false;
            const arg1 = scanSimpleAtom(text, arg0.next + 1) orelse return false;
            if (arg1.next >= text.len or text[arg1.next] != ']') return false;
            if (skipSpacesInSource(text, arg1.next + 1) != text.len) return false;
            if (builtinFromName(callee_ident.text)) |builtin| {
                if (builtinCallRequiresPreEmit(builtin)) {
                    try self.emitPendingPrimary(out, scope, .{ .builtin = builtin });
                    try self.emitSimpleAtom(out, scope, arg0.atom);
                    try self.emitSimpleAtom(out, scope, arg1.atom);
                    try out.appendOp(.call2);
                    return true;
                }
            }
            try self.emitSimpleAtom(out, scope, arg0.atom);
            const arg0_simple = out.last_simple orelse return false;
            try self.emitSimpleAtom(out, scope, arg1.atom);
            const arg1_simple = out.last_simple orelse return false;
            if (builtinFromName(callee_ident.text)) |builtin| {
                if (try self.tryEmitBuiltinCall(out, builtin, 2)) return true;
            }
            const slot = try self.globalSlot(callee_ident.text);
            const arg_simples = [_]ProducedValue{ arg0_simple, arg1_simple };
            if (!(try out.tryShapeGlobalCallSlotsFromSimples(slot, arg_simples[0..], &self.consume_candidates))) {
                try out.appendOp(.call_global2);
                try out.appendGlobalSlot(slot);
            }
            return true;
        }

        const op_index = first.next;
        if (op_index >= text.len) return false;
        const op = switch (text[op_index]) {
            '+' => BuiltinId.add,
            '-' => BuiltinId.sub,
            '*' => BuiltinId.mul,
            else => return false,
        };
        const second = scanSimpleAtom(text, op_index + 1) orelse return false;
        if (second.next != text.len) return false;
        try self.emitSimpleAtom(out, scope, first.atom);
        try self.emitSimpleAtom(out, scope, second.atom);
        try out.appendShapedDyad(op);
        return true;
    }

    fn parseExpr(self: *Compiler, out: *InstructionBuffer, scope: *Scope) KError!ExprForm {
        return try self.parseDyadExpr(out, scope);
    }

    fn parseDyadExpr(self: *Compiler, out: *InstructionBuffer, scope: *Scope) KError!ExprForm {
        const left_start = out.byte_len;
        const left_form = try self.parseApply(out, scope);
        const left_end = out.byte_len;
        const left_simple = out.last_simple;
        const op = self.peekDyadOp() orelse return left_form;
        _ = self.consumeByte();
        if (op != '.' and op != '@' and self.startsDerivedVerb()) {
            const primary = try self.parseBuiltinPrimaryFromConsumedChar(op);
            _ = try self.parsePostfixTail(out, scope, primary.pending, primary.form);
            out.rotateRangeLeft(left_start, left_end, out.byte_len);
            _ = try self.parseDyadExpr(out, scope);
            try out.appendOp(.call2);
            return .nounish;
        }
        const derived = if (op != '.') self.matchDerivedVerb() else null;
        _ = try self.parseDyadExpr(out, scope);
        if (left_simple) |left| {
            if (out.last_simple) |right| {
                if (left.end() == right.start()) {
                    out.previous_simple = left;
                }
            }
        }
        try self.emitParsedDyad(out, op, derived);
        return .nounish;
    }

    fn peekDyadOp(self: *Compiler) ?u8 {
        return switch (self.peekByte() orelse return null) {
            ',', '=', '<', '>', '+', '-', '!', '&', '|', '#', '_', '^', '?', '$', '*', '%', '~', '.', '@' => |op| op,
            else => null,
        };
    }

    fn emitParsedDyad(self: *Compiler, out: *InstructionBuffer, op: u8, derived: ?DerivedVerbKind) KError!void {
        if (derived) |kind| {
            try self.emitBuiltinDerivedDyad(out, switch (op) {
                ',' => .concat,
                '=' => .equal,
                '<' => .less,
                '>' => .more,
                '+' => .add,
                '-' => .sub,
                '!' => .iota,
                '&' => .minimum,
                '|' => .maximum,
                '#' => .take,
                '_' => .drop,
                '^' => .null_fill_without,
                '?' => .find,
                '$' => .cast,
                '*' => .mul,
                '%' => .div,
                '~' => .not,
                else => unreachable,
            }, kind);
            return;
        }
        switch (op) {
            ',' => try out.appendOp(.concat),
            '=' => try out.appendShapedDyad(.equal),
            '<' => try out.appendShapedDyad(.less),
            '>' => try out.appendShapedDyad(.more),
            '+' => try out.appendShapedDyad(.add),
            '-' => try out.appendShapedDyad(.sub),
            '!' => try out.appendOp(.mod),
            '&' => try out.appendShapedDyad(.minimum),
            '|' => try out.appendShapedDyad(.maximum),
            '#' => try out.appendOp(.take),
            '_' => try out.appendOp(.drop),
            '^' => try out.appendOp(.fill_without),
            '~' => try out.appendOp(.match),
            '?' => {
                try out.appendOp(.find);
                _ = try out.tryShapeArgmaxSuffix();
            },
            '$' => try out.appendOp(.cast),
            '*' => try out.appendShapedDyad(.mul),
            '%' => try out.appendShapedDyad(.div),
            '.' => try out.appendDot(),
            '@' => try out.appendShapedCall1(),
            else => unreachable,
        }
    }

    fn parseApply(self: *Compiler, out: *InstructionBuffer, scope: *Scope) KError!ExprForm {
        const left_start = out.byte_len;
        const left_form = try self.parseUnary(out, scope);
        if (try self.tryParseParenthesizedVerbialDyad(out, scope, left_start, left_form)) {
            return .nounish;
        }
        if (try self.tryParseUnparenthesizedVerbialDyad(out, scope, left_start, left_form)) {
            return .nounish;
        }
        if (self.startsJuxtapositionOperand(left_form)) {
            _ = try self.parseExpr(out, scope);
            try out.appendShapedCall1();
            return .nounish;
        }
        return left_form;
    }

    fn tryParseParenthesizedVerbialDyad(self: *Compiler, out: *InstructionBuffer, scope: *Scope, left_start: usize, left_form: ExprForm) KError!bool {
        if (left_form != .nounish) return false;
        if (self.peekByte() != '(') return false;

        const saved_index = self.index;
        const saved_out = out.mark();
        const left_end = out.byte_len;

        const callee_form = try self.parseUnary(out, scope);
        const callee_end = out.byte_len;

        if (callee_form != .verbial or !self.startsJuxtapositionOperand(callee_form)) {
            self.index = saved_index;
            out.restore(saved_out);
            return false;
        }

        _ = try self.parseExpr(out, scope);
        out.rotateRangeLeft(left_start, left_end, callee_end);
        try out.appendOp(.call2);
        return true;
    }

    fn tryParseUnparenthesizedVerbialDyad(self: *Compiler, out: *InstructionBuffer, scope: *Scope, left_start: usize, left_form: ExprForm) KError!bool {
        if (left_form != .nounish) return false;
        const ch = self.peekByte() orelse return false;
        if (ch != '{' and !(isIdentStart(ch) and builtinFromChar(ch) == null)) return false;

        const saved_index = self.index;
        const saved_out = out.mark();
        const left_end = out.byte_len;

        const callee_form = try self.parsePostfix(out, scope);
        const callee_end = out.byte_len;

        if (callee_form != .verbial or !self.startsJuxtapositionOperand(callee_form)) {
            self.index = saved_index;
            out.restore(saved_out);
            return false;
        }

        _ = try self.parseExpr(out, scope);
        out.rotateRangeLeft(left_start, left_end, callee_end);
        try out.appendOp(.call2);
        return true;
    }

    fn parseUnary(self: *Compiler, out: *InstructionBuffer, scope: *Scope) KError!ExprForm {
        if (self.peekStartsSignedNumericLiteral()) {
            try self.emitNumericLiteralOrVector(out);
            return .nounish;
        }
        if (self.peekPrimaryUnaryOp()) |op| {
            _ = self.consumeByte();
            if (op == '+' or op == '-' or op == '%' or op == '$' or op == '?' or op == '.') {
                _ = try self.parseDyadExpr(out, scope);
                switch (op) {
                    '+' => try out.appendOp(.transpose),
                    '-' => try out.appendShapedMonad(.negate),
                    '%' => try out.appendShapedMonad(.sqrt),
                    '$' => try out.appendOp(.stringify),
                    '?' => try out.appendOp(.unique),
                    '.' => try out.appendOp(.eval_string),
                    else => unreachable,
                }
                return .nounish;
            }
            if (op == '!' or op == '|' or op == '<' or op == '>' or op == '~' or op == '#' or op == '_' or op == '^') {
                _ = try self.parseDyadExpr(out, scope);
                switch (op) {
                    '!' => try out.appendOp(.iota),
                    '|' => try out.appendOp(.reverse),
                    '<' => try out.appendOp(.grade_up),
                    '>' => try out.appendOp(.grade_down),
                    '~' => try out.appendOp(.not),
                    '#' => try out.appendOp(.count),
                    '_' => try out.appendOp(.floor),
                    '^' => try out.appendOp(.null_test),
                    else => unreachable,
                }
                return .nounish;
            }
        }
        return try self.parsePostfix(out, scope);
    }

    fn parsePostfix(self: *Compiler, out: *InstructionBuffer, scope: *Scope) KError!ExprForm {
        const primary = try self.parsePrimary(out, scope);
        return try self.parsePostfixTail(out, scope, primary.pending, primary.form);
    }

    fn findParenthesizedInfixProjection(self: *const Compiler) ?struct { op_index: usize, close_index: usize, builtin: BuiltinId } {
        if (self.index >= self.source.len or self.source[self.index] != '(') return null;
        const body_start = skipSpacesInSource(self.source, self.index + 1);
        if (body_start >= self.source.len) return null;

        var index = body_start;
        var paren_depth: usize = 0;
        var bracket_depth: usize = 0;
        var brace_depth: usize = 0;
        while (index < self.source.len) : (index += 1) {
            const ch = self.source[index];
            switch (ch) {
                '"' => {
                    index += 1;
                    while (index < self.source.len and self.source[index] != '"') : (index += 1) {}
                    if (index >= self.source.len) return null;
                },
                '(' => paren_depth += 1,
                ')' => {
                    if (paren_depth != 0) {
                        paren_depth -= 1;
                        continue;
                    }
                    return null;
                },
                '[' => bracket_depth += 1,
                ']' => {
                    if (bracket_depth == 0) return null;
                    bracket_depth -= 1;
                },
                '{' => brace_depth += 1,
                '}' => {
                    if (brace_depth == 0) return null;
                    brace_depth -= 1;
                },
                ';' => {
                    if (paren_depth == 0 and bracket_depth == 0 and brace_depth == 0) return null;
                },
                else => {
                    if (paren_depth != 0 or bracket_depth != 0 or brace_depth != 0) continue;
                    const builtin = builtinFromChar(ch) orelse continue;
                    if (index == body_start) continue;
                    const after = skipSpacesInSource(self.source, index + 1);
                    if (after < self.source.len and self.source[after] == ')') {
                        return .{ .op_index = index, .close_index = after, .builtin = builtin };
                    }
                },
            }
        }
        return null;
    }

    fn tryParseParenthesizedInfixProjection(self: *Compiler, out: *InstructionBuffer, scope: *Scope) KError!bool {
        const projection = self.findParenthesizedInfixProjection() orelse return false;
        const left_source = std.mem.trim(u8, self.source[self.index + 1 .. projection.op_index], " \t\r\n");
        if (left_source.len == 0) return false;

        const saved_out = out.mark();
        const saved_candidates = self.consume_candidates;
        const left_start = out.byte_len;
        var left_compiler = try Compiler.init(
            self.session,
            left_source,
            self.code_allocator,
            self.compile_mode,
        );
        left_compiler.consume_candidates = self.consume_candidates;
        const left_form = if (try left_compiler.tryCompileSimpleExprSlice(out, scope, left_source)) blk: {
            left_compiler.index = left_compiler.source.len;
            break :blk ExprForm.nounish;
        } else try left_compiler.parseExpr(out, scope);
        if (!left_compiler.atEnd() or left_form != .nounish) {
            out.restore(saved_out);
            self.consume_candidates = saved_candidates;
            return false;
        }
        self.consume_candidates = left_compiler.consume_candidates;
        const left_end = out.byte_len;
        try self.emitPendingPrimary(out, scope, .{ .builtin = projection.builtin });
        out.rotateRangeLeft(left_start, left_end, out.byte_len);
        try out.appendOp(.make_projection);
        try out.appendByte(2);
        try out.appendU64(@as(u64, 1) << 1);
        self.index = skipSpacesInSource(self.source, projection.close_index + 1);
        return true;
    }

    fn scanProjectionSlots(self: *const Compiler, start_index: usize) KError!ProjectionSlotSummary {
        var index = skipSpacesInSource(self.source, start_index);
        if (index >= self.source.len) return error.Parse;
        if (self.source[index] == ']') {
            return .{ .slot_count = 0, .hole_count = 0, .hole_mask = 0 };
        }

        var summary = ProjectionSlotSummary{
            .slot_count = 0,
            .hole_count = 0,
            .hole_mask = 0,
        };
        var bracket_depth: usize = 0;
        var paren_depth: usize = 0;
        var brace_depth: usize = 0;
        var slot_has_content = false;

        while (index < self.source.len) : (index += 1) {
            const ch = self.source[index];
            switch (ch) {
                '"' => {
                    slot_has_content = true;
                    index += 1;
                    while (index < self.source.len and self.source[index] != '"') : (index += 1) {}
                    if (index >= self.source.len) return error.Parse;
                },
                '[' => {
                    bracket_depth += 1;
                    slot_has_content = true;
                },
                '(' => {
                    paren_depth += 1;
                    slot_has_content = true;
                },
                '{' => {
                    brace_depth += 1;
                    slot_has_content = true;
                },
                ']' => {
                    if (bracket_depth != 0) {
                        bracket_depth -= 1;
                        slot_has_content = true;
                        continue;
                    }
                    if (summary.slot_count >= 63) return error.Unsupported;
                    if (!slot_has_content) {
                        summary.hole_mask |= (@as(u64, 1) << @intCast(summary.slot_count));
                        summary.hole_count += 1;
                    }
                    summary.slot_count += 1;
                    return summary;
                },
                ')' => {
                    if (paren_depth == 0) return error.Parse;
                    paren_depth -= 1;
                    slot_has_content = true;
                },
                '}' => {
                    if (brace_depth == 0) return error.Parse;
                    brace_depth -= 1;
                    slot_has_content = true;
                },
                ';' => {
                    if (bracket_depth == 0 and paren_depth == 0 and brace_depth == 0) {
                        if (summary.slot_count >= 63) return error.Unsupported;
                        if (!slot_has_content) {
                            summary.hole_mask |= (@as(u64, 1) << @intCast(summary.slot_count));
                            summary.hole_count += 1;
                        }
                        summary.slot_count += 1;
                        slot_has_content = false;
                        index = skipSpacesInSource(self.source, index + 1);
                        if (index >= self.source.len) return error.Parse;
                        index -= 1;
                    } else {
                        slot_has_content = true;
                    }
                },
                ' ', '\n', '\t', '\r' => {},
                else => slot_has_content = true,
            }
        }

        return error.Parse;
    }

    fn parsePostfixTail(self: *Compiler, out: *InstructionBuffer, scope: *Scope, initial_pending: PendingPrimary, initial_form: ExprForm) KError!ExprForm {
        var pending = initial_pending;
        var form = initial_form;
        while (self.matchDerivedVerb()) |kind| {
            try self.emitPendingPrimary(out, scope, pending);
            pending = .none;
            try out.appendOp(.make_adverb);
            try out.appendByte(@intFromEnum(kind));
            form = .verbial;
        }
        while (self.matchChar('[')) {
            const global_slot = switch (pending) {
                .global => |slot| slot,
                else => null,
            };
            const builtin_id = switch (pending) {
                .builtin => |id| id,
                else => null,
            };
            const lambda_source = switch (pending) {
                .lambda_source => |value| value,
                else => null,
            };
            const slot_summary = try self.scanProjectionSlots(self.index);
            const needs_projection = slot_summary.hasHoles();
            if (needs_projection or (global_slot == null and builtin_id == null and lambda_source == null)) {
                try self.emitPendingPrimary(out, scope, pending);
                pending = .none;
            }

            var builtin_emitted_pre_args = false;
            if (!needs_projection) {
                if (builtin_id) |id| {
                    if (builtinCallRequiresPreEmit(id)) {
                        try self.emitPendingPrimary(out, scope, .{ .builtin = id });
                        pending = .none;
                        builtin_emitted_pre_args = true;
                    }
                }
            }

            var argc: u8 = 0;
            var arg_simples: [max_shaped_call_args]ProducedValue = undefined;
            var arg_simples_valid = true;
            if (needs_projection) {
                for (0..slot_summary.slot_count) |slot_idx| {
                    if (!slot_summary.isHole(slot_idx)) {
                        const arg_start = out.byte_len;
                        _ = try self.parseExpr(out, scope);
                        if (arg_simples_valid and argc < arg_simples.len) {
                            if (out.last_simple) |simple| {
                                if (simple.start() < arg_start or simple.end() != out.byte_len) {
                                    arg_simples_valid = false;
                                } else {
                                    arg_simples[argc] = simple;
                                }
                            } else {
                                arg_simples_valid = false;
                            }
                        } else if (arg_simples_valid) {
                            arg_simples_valid = false;
                        }
                        argc += 1;
                    }
                    if (slot_idx + 1 == slot_summary.slot_count) {
                        try self.expectChar(']');
                    } else {
                        try self.expectChar(';');
                    }
                }
            } else if (!self.matchChar(']')) {
                while (true) {
                    const arg_start = out.byte_len;
                    _ = try self.parseExpr(out, scope);
                    if (arg_simples_valid and argc < arg_simples.len) {
                        if (out.last_simple) |simple| {
                            if (simple.start() < arg_start or simple.end() != out.byte_len) {
                                arg_simples_valid = false;
                            } else {
                                arg_simples[argc] = simple;
                            }
                        } else {
                            arg_simples_valid = false;
                        }
                    } else if (arg_simples_valid) {
                        arg_simples_valid = false;
                    }
                    argc += 1;
                    if (self.matchChar(']')) break;
                    try self.expectChar(';');
                }
            }
            if (needs_projection) {
                try out.appendOp(.make_projection);
                try out.appendByte(slot_summary.slot_count);
                try out.appendU64(slot_summary.hole_mask);
                pending = .none;
                form = .nounish;
                continue;
            }
            if (builtin_id) |id| {
                if (!builtin_emitted_pre_args and try self.tryEmitBuiltinCall(out, id, argc)) {
                    pending = .none;
                    continue;
                }
                if (!builtin_emitted_pre_args) {
                    try self.emitPendingPrimary(out, scope, .{ .builtin = id });
                    pending = .none;
                }
                switch (argc) {
                    1 => {
                        try out.appendShapedCall1();
                    },
                    2 => try out.appendOp(.call2),
                    else => {
                        try out.appendOp(.call);
                        try out.appendByte(argc);
                    },
                }
            } else if (global_slot) |slot| {
                const simple_args = if (arg_simples_valid and argc <= arg_simples.len)
                    arg_simples[0..argc]
                else
                    &[_]ProducedValue{};
                if (arg_simples_valid and argc == 1 and try out.tryShapeGlobalIndexSource(slot, simple_args[0], &self.consume_candidates)) {
                    pending = .none;
                    form = .nounish;
                    continue;
                }
                if (!(arg_simples_valid and try out.tryShapeGlobalCallSlotsFromSimples(slot, simple_args, &self.consume_candidates))) {
                    switch (argc) {
                        1 => {
                            try out.appendOp(.call_global1);
                            try out.appendGlobalSlot(slot);
                        },
                        2 => {
                            try out.appendOp(.call_global2);
                            try out.appendGlobalSlot(slot);
                        },
                        3, 4 => {
                            try out.appendOp(if (argc == 3) .call_global3 else .call_global4);
                            try out.appendGlobalSlot(slot);
                        },
                        else => {
                            try out.appendOp(.call_global);
                            try out.appendGlobalSlot(slot);
                            try out.appendByte(argc);
                        },
                    }
                }
            } else if (lambda_source) |lambda| {
                try self.inlineLambdaCall(out, scope, lambda, argc);
            } else {
                switch (argc) {
                    1 => {
                        try out.appendShapedCall1();
                    },
                    2 => try out.appendOp(.call2),
                    else => {
                        try out.appendOp(.call);
                        try out.appendByte(argc);
                    },
                }
            }
            pending = .none;
            form = .nounish;
        }
        try self.emitPendingPrimary(out, scope, pending);
        return form;
    }

    fn startsDerivedVerb(self: *const Compiler) bool {
        if (self.index >= self.source.len) return false;
        return switch (self.source[self.index]) {
            '\'', '/', '\\' => true,
            else => false,
        };
    }

    fn matchDerivedVerb(self: *Compiler) ?DerivedVerbKind {
        if (self.index >= self.source.len) return null;
        return switch (self.source[self.index]) {
            '\'' => blk: {
                self.index += 1;
                self.skipSpaces();
                if (self.matchChar(':')) break :blk .each_prior;
                break :blk .each;
            },
            '/' => blk: {
                self.index += 1;
                self.skipSpaces();
                if (self.matchChar(':')) break :blk .each_right;
                break :blk .fold;
            },
            '\\' => blk: {
                self.index += 1;
                self.skipSpaces();
                if (self.matchChar(':')) break :blk .each_left;
                break :blk .scan;
            },
            else => null,
        };
    }

    fn emitBuiltinDerivedDyad(self: *Compiler, out: *InstructionBuffer, builtin: BuiltinId, kind: DerivedVerbKind) KError!void {
        _ = self;
        try out.appendOp(.call_builtin_derived2);
        try out.appendByte(@intFromEnum(builtin));
        try out.appendByte(@intFromEnum(kind));
    }

    fn tryEmitBuiltinCall(self: *Compiler, out: *InstructionBuffer, builtin: BuiltinId, argc: u8) KError!bool {
        _ = self;
        switch (argc) {
            1 => {
                switch (builtin) {
                    .add => try out.appendOp(.transpose),
                    .sub => try out.appendOp(.negate),
                    .div => try out.appendOp(.sqrt),
                    .pow => return false,
                    .mul => return false,
                    .exp, .log, .sin, .cos, .tanh, .sigmoid => return false,
                    .iota => try out.appendOp(.iota),
                    .minimum => return false,
                    .maximum => try out.appendOp(.reverse),
                    .reverse => try out.appendOp(.reverse),
                    .less => try out.appendOp(.grade_up),
                    .more => try out.appendOp(.grade_down),
                    .grade_up => try out.appendOp(.grade_up),
                    .grade_down => try out.appendOp(.grade_down),
                    .not => try out.appendOp(.not),
                    .count => try out.appendOp(.count),
                    .floor => try out.appendOp(.floor),
                    .null_fill_without => try out.appendOp(.null_test),
                    .sort => try out.appendOp(.sort),
                    .stringify => try out.appendOp(.stringify),
                    .unique => try out.appendOp(.unique),
                    .eval_string => try out.appendOp(.eval_string),
                    .concat, .take, .drop, .equal, .reshape, .cast, .contains, .split, .join, .bytes, .utf8, .char, .find, .tokenize, .detokenize, .grad, .valuegrad, .prng, .load, .save, .sql, .register, .rotcache, .rotcacheupdate, .rotcacheview, .rope, .ropeflat, .ropecisflat, .rmsnorm, .layernorm, .gelu, .geluapprox, .mlpdense, .conv2d, .convtranspose2d, .upsamplenearest2d, .groupnorm, .softmax, .sdpa, .sam3boxrpb, .sdpamask, .sdpaflat => return false,
                }
                return true;
            },
            2 => {
                switch (builtin) {
                    .add => try out.appendOp(.add),
                    .sub => try out.appendOp(.sub),
                    .mul => try out.appendOp(.mul),
                    .div => try out.appendOp(.div),
                    .pow => return false,
                    .iota => try out.appendOp(.mod),
                    .minimum => try out.appendOp(.minimum),
                    .maximum => try out.appendOp(.maximum),
                    .less => try out.appendOp(.less),
                    .more => try out.appendOp(.more),
                    .not => try out.appendOp(.match),
                    .exp, .log, .sin, .cos, .tanh, .sigmoid => return false,
                    .concat => try out.appendOp(.concat),
                    .count => try out.appendOp(.take),
                    .floor => try out.appendOp(.drop),
                    .null_fill_without => try out.appendOp(.fill_without),
                    .sort => try out.appendOp(.reshape),
                    .equal => try out.appendOp(.equal),
                    .cast => try out.appendOp(.cast),
                    .contains => try out.appendOp(.contains),
                    .split => try out.appendOp(.split),
                    .join => try out.appendOp(.join),
                    .find => try out.appendOp(.find),
                    .reverse, .grade_up, .grade_down, .take, .drop, .reshape, .stringify, .bytes, .utf8, .char, .unique, .tokenize, .detokenize, .eval_string, .grad, .valuegrad, .prng, .load, .save, .sql, .register, .rotcache, .rotcacheupdate, .rotcacheview, .rope, .ropeflat, .ropecisflat, .rmsnorm, .layernorm, .gelu, .geluapprox, .mlpdense, .conv2d, .convtranspose2d, .upsamplenearest2d, .groupnorm, .softmax, .sdpa, .sam3boxrpb, .sdpamask, .sdpaflat => return false,
                }
                return true;
            },
            else => return false,
        }
    }

    fn builtinCallRequiresPreEmit(builtin: BuiltinId) bool {
        return switch (builtin) {
            .pow, .exp, .log, .sin, .cos, .tanh, .sigmoid, .bytes, .utf8, .char, .tokenize, .detokenize, .grad, .valuegrad, .prng, .load, .save, .sql, .register, .rotcache, .rotcacheupdate, .rotcacheview, .rope, .ropeflat, .ropecisflat, .rmsnorm, .layernorm, .gelu, .geluapprox, .mlpdense, .conv2d, .convtranspose2d, .upsamplenearest2d, .groupnorm, .softmax, .sdpa, .sam3boxrpb, .sdpamask, .sdpaflat => true,
            else => false,
        };
    }

    fn tryParseBuiltinInnerProduct(self: *Compiler) KError!?PendingPrimary {
        const reduce_ch = self.peekByte() orelse return null;
        const reduce = builtinFromChar(reduce_ch) orelse return null;
        if (!builtinSupportsInnerProductVerb(reduce)) return null;
        var next = skipSpacesInSource(self.source, self.index + 1);
        if (next >= self.source.len or self.source[next] != '/') return null;
        next = skipSpacesInSource(self.source, next + 1);
        if (next >= self.source.len) return null;
        const map_ch = self.source[next];
        const map = builtinFromChar(map_ch) orelse return null;
        if (!builtinSupportsInnerProductVerb(map)) return null;
        if (self.peekPrimaryUnaryOpAt(next) != null) return null;
        self.index = skipSpacesInSource(self.source, next + 1);
        return .{ .const_value = Value.closure(try self.session.allocFrozenInnerProductClosure(reduce, map)) };
    }

    fn parseBuiltinPrimaryFromConsumedChar(self: *Compiler, ch: u8) KError!ParsedPrimary {
        const builtin = builtinFromChar(ch) orelse return error.Unsupported;
        if (self.compile_mode == .frozen) {
            if (self.matchDerivedVerb()) |kind| {
                const closure = try self.session.allocFrozenDerivedClosure(kind, Value.builtin(builtin));
                return .{ .pending = .{ .const_value = Value.closure(closure) }, .form = .verbial };
            }
        }
        return .{ .pending = .{ .builtin = builtin }, .form = .verbial };
    }

    fn parsePrimary(self: *Compiler, out: *InstructionBuffer, scope: *Scope) KError!ParsedPrimary {
        const ch = self.peekByte() orelse return error.Parse;
        if (ch == '@') {
            const next = skipSpacesInSource(self.source, self.index + 1);
            if (next < self.source.len and self.source[next] == '[') {
                self.index = skipSpacesInSource(self.source, next + 1);
                try self.parseAmendSpecialForm(out, scope, false);
                return .{ .pending = .none, .form = .nounish };
            }
        }
        if (ch == '.') {
            const next = skipSpacesInSource(self.source, self.index + 1);
            if (next < self.source.len and self.source[next] == '[') {
                self.index = skipSpacesInSource(self.source, next + 1);
                try self.parseAmendSpecialForm(out, scope, true);
                return .{ .pending = .none, .form = .nounish };
            }
        }
        if (std.ascii.isDigit(ch)) {
            try self.emitNumericLiteralOrVector(out);
            return .{ .pending = .none, .form = .nounish };
        }

        if (ch == '$') {
            const next = skipSpacesInSource(self.source, self.index + 1);
            if (next < self.source.len and self.source[next] == '[') {
                self.index = skipSpacesInSource(self.source, next + 1);
                try self.parseCondSpecialForm(out, scope);
                return .{ .pending = .none, .form = .nounish };
            }
        }

        switch (ch) {
            '(' => {
                if (try self.tryParseParenthesizedInfixProjection(out, scope)) {
                    return .{ .pending = .none, .form = .verbial };
                }
                _ = self.consumeByte();
                const form = try self.parseExpr(out, scope);
                var count: u8 = 1;
                if (self.matchChar(';')) {
                    while (true) {
                        _ = try self.parseExpr(out, scope);
                        count = std.math.add(u8, count, 1) catch return error.Unsupported;
                        if (self.matchChar(')')) break;
                        try self.expectChar(';');
                    }
                    try out.appendOp(.make_vector);
                    try out.appendByte(count);
                    return .{ .pending = .none, .form = .nounish };
                }
                try self.expectChar(')');
                return .{ .pending = .none, .form = form };
            },
            '[' => {
                const prior = out.previous_simple;
                const previous = out.last_simple;
                const literal_start = out.byte_len;
                var literal_mode: ?HostDenseElem = null;
                var literal_mode_known = true;
                _ = self.consumeByte();
                var count: u8 = 0;
                if (!self.matchChar(']')) {
                    while (true) {
                        _ = try self.parseExpr(out, scope);
                        const item_mode = if (out.last_simple) |simple| InstructionBuffer.simpleNumericMode(simple) else null;
                        if (!literal_mode_known or item_mode == null) {
                            literal_mode = null;
                            literal_mode_known = false;
                        } else if (literal_mode) |existing| {
                            literal_mode = switch (existing) {
                                .int => switch (item_mode.?) {
                                    .int => .int,
                                    .float => .float,
                                },
                                .float => .float,
                            };
                        } else {
                            literal_mode = item_mode;
                        }
                        count = std.math.add(u8, count, 1) catch return error.Unsupported;
                        if (self.matchChar(']')) break;
                        try self.expectChar(';');
                    }
                }
                try out.appendOp(.make_vector);
                try out.appendByte(count);
                out.previous_simple = previous;
                out.last_simple = .{
                    .array_value = .{
                        .start = literal_start,
                        .end = out.byte_len,
                        .elem_mode = literal_mode,
                    },
                };
                if (previous == null) out.previous_simple = prior;
                return .{ .pending = .none, .form = .nounish };
            },
            '{' => {
                _ = self.consumeByte();
                return .{ .pending = .{ .lambda_source = try self.parseLambdaSource() }, .form = .verbial };
            },
            '"' => return .{ .pending = .{ .const_value = try self.parseStringLiteralValue() }, .form = .nounish },
            '`' => {
                const first = try self.parseSymbolLiteralValue();
                if (self.peekByte() != '`') return .{ .pending = .{ .const_value = first }, .form = .nounish };

                const vector_start = out.byte_len;
                try self.emitPendingPrimary(out, scope, .{ .const_value = first });
                var count: u8 = 1;
                while (self.peekByte() == '`') {
                    const symbol = try self.parseSymbolLiteralValue();
                    try self.emitPendingPrimary(out, scope, .{ .const_value = symbol });
                    count = std.math.add(u8, count, 1) catch return error.Unsupported;
                }
                try out.appendOp(.make_vector);
                try out.appendByte(count);
                out.noteArrayValue(vector_start, out.byte_len, null);
                return .{ .pending = .none, .form = .nounish };
            },
            '+', '-', '*', '%', '!', '&', '|', '<', '>', '~', ',', '#', '_', '^', '=' => {
                if (try self.tryParseBuiltinInnerProduct()) |inner_product| {
                    return .{ .pending = inner_product, .form = .verbial };
                }
                _ = self.consumeByte();
                return try self.parseBuiltinPrimaryFromConsumedChar(ch);
            },
            else => {},
        }

        if (isIdentStart(ch)) {
            if (try self.appendFastSingleCharLocalLoad(out, scope, ch)) {
                return .{ .pending = .none, .form = .nounish };
            }
            const ident = self.scanIdentifier() orelse return error.Parse;
            return .{ .pending = try self.pendingResolvedIdent(out, scope, ident), .form = .nounish };
        }
        return error.Parse;
    }

    fn parseAmendSpecialForm(self: *Compiler, out: *InstructionBuffer, scope: *Scope, deep: bool) KError!void {
        _ = try self.parseExpr(out, scope);
        try self.expectChar(';');
        _ = try self.parseExpr(out, scope);
        try self.expectChar(';');

        var mode: AmendMode = .unary;
        if (self.peekByte() == ':') {
            _ = self.consumeByte();
            mode = .assign;
        } else {
            _ = try self.parseExpr(out, scope);
        }

        if (self.matchChar(']')) {
            if (mode != .unary) return error.Parse;
            try out.appendOp(if (deep) .deep_amend else .amend);
            try out.appendByte(@intFromEnum(mode));
            return;
        }

        try self.expectChar(';');
        _ = try self.parseExpr(out, scope);
        try self.expectChar(']');
        try out.appendOp(if (deep) .deep_amend else .amend);
        try out.appendByte(@intFromEnum(if (mode == .assign) AmendMode.assign else AmendMode.binary));
    }

    fn parseCondSpecialForm(self: *Compiler, out: *InstructionBuffer, scope: *Scope) KError!void {
        _ = try self.parseExpr(out, scope);
        try self.expectChar(';');

        const false_jump_patch = try out.emitJumpIfFalsePlaceholder();

        _ = try self.parseExpr(out, scope);
        try out.appendOp(.jump);
        const end_jump_patch = out.byte_len;
        try out.appendU16(0);

        try self.expectChar(';');
        try out.patchU16(false_jump_patch, std.math.cast(u16, out.byte_len) orelse return error.Unsupported);
        _ = try self.parseExpr(out, scope);
        try self.expectChar(']');
        try out.patchU16(end_jump_patch, std.math.cast(u16, out.byte_len) orelse return error.Unsupported);
    }

    fn parseStringLiteralValue(self: *Compiler) KError!Value {
        if (self.peekByte() != '"') return error.Parse;
        self.index += 1;
        const start = self.index;
        while (self.index < self.source.len and self.source[self.index] != '"') : (self.index += 1) {}
        if (self.index >= self.source.len) return error.Parse;
        const bytes = self.source[start..self.index];
        _ = self.consumeByte();
        return try self.session.frozenHostString(bytes);
    }

    fn parseSymbolLiteralValue(self: *Compiler) KError!Value {
        if (!self.matchChar('`')) return error.Parse;
        const ident = self.scanIdentifier() orelse return error.Parse;
        return try self.session.frozenHostSymbol(ident.text);
    }

    fn parseLambdaSource(self: *Compiler) KError!ParsedLambda {
        var lambda = ParsedLambda{};
        if (self.matchChar('[')) {
            lambda.allow_implicit_params = false;
            if (!self.matchChar(']')) {
                while (true) {
                    const ident = self.scanIdentifier() orelse return error.Parse;
                    try lambda.declareParam(ident);
                    if (self.matchChar(']')) break;
                    try self.expectChar(';');
                }
            }
        }
        lambda.body_start = self.index;
        lambda.body_end = try self.findLambdaBodyEnd(lambda.body_start);
        self.index = skipSpacesInSource(self.source, lambda.body_end + 1);
        return lambda;
    }

    fn inlineLambdaCall(self: *Compiler, out: *InstructionBuffer, parent: *Scope, lambda: ParsedLambda, argc: u8) KError!void {
        _ = parent;
        var scope = Scope{
            .allow_implicit_params = lambda.allow_implicit_params,
            .param_binding_kind = .inline_local,
        };
        defer scope.deinit(self.session.allocator);
        try self.declareParsedLambdaParams(&scope, lambda);
        if (scope.frame_slot_count < argc) scope.frame_slot_count = argc;

        const call_start = out.byte_len;
        try out.appendOp(.enter_inline);
        try out.appendByte(argc);
        const body_start = out.byte_len;
        const body_source = self.source[lambda.body_start..lambda.body_end];
        const local_count_before = scope.local_count;
        try self.compileLambdaBodyInto(out, &scope, body_source);
        if (argc != scope.arity) return error.Arity;
        if (scope.local_count == local_count_before and try self.tryShapeInlineCall(out, call_start, body_start, argc)) return;
        try out.appendOp(.leave_inline);
        try out.appendByte(argc);
    }

    fn tryShapeInlineCall(self: *Compiler, out: *InstructionBuffer, call_start: usize, body_start: usize, argc: u8) KError!bool {
        _ = self;
        const body = out.bytes[body_start..out.byte_len];

        if (argc == 2 and body.len == 3 and body[1] == 0 and body[2] == 1) {
            const op: ?Op = switch (body[0]) {
                @intFromEnum(Op.add_inline_local_local) => .inline_call_add2,
                @intFromEnum(Op.sub_inline_local_local) => .inline_call_sub2,
                @intFromEnum(Op.mul_inline_local_local) => .inline_call_mul2,
                else => null,
            };
            if (op) |shaped| {
                out.byte_len = call_start;
                out.invalidateSimple();
                try out.appendOp(shaped);
                return true;
            }
        }

        if (argc == 1) {
            if (Session.classifyArgmaxBytecode(body, out.constantSlice())) |kind| {
                const operand_len = Session.argmaxBytecodeOperandLen(body, out.constantSlice(), kind);
                if (operand_len == 2 and body[0] == @intFromEnum(Op.load_inline_local) and body[1] == 0) {
                    out.byte_len = call_start;
                    out.invalidateSimple();
                    try out.appendOp(.inline_call_argmax1);
                    return true;
                }
            }

            if (body.len == 2 and body[1] == 0) {
                const op: ?Op = switch (body[0]) {
                    @intFromEnum(Op.neg_inline_local) => .inline_call_negate1,
                    @intFromEnum(Op.sqrt_inline_local) => .inline_call_sqrt1,
                    else => null,
                };
                if (op) |shaped| {
                    out.byte_len = call_start;
                    out.invalidateSimple();
                    try out.appendOp(shaped);
                    return true;
                }
            }

            if (body.len == 4 and body[0] == @intFromEnum(Op.load_global) and body[3] == @intFromEnum(Op.negate)) {
                out.byte_len = call_start;
                out.invalidateSimple();
                try out.appendOp(.inline_call_negate_global);
                try out.appendGlobalSlot(Session.directReadU16(body, 1) orelse return false);
                return true;
            }
            if (body.len == 4 and body[0] == @intFromEnum(Op.load_global) and body[3] == @intFromEnum(Op.sqrt)) {
                out.byte_len = call_start;
                out.invalidateSimple();
                try out.appendOp(.inline_call_sqrt_global);
                try out.appendGlobalSlot(Session.directReadU16(body, 1) orelse return false);
                return true;
            }

            if (body.len == 6 and body[0] == @intFromEnum(Op.load_global) and body[3] == @intFromEnum(Op.load_inline_local) and body[4] == 0) {
                const op: ?Op = switch (body[5]) {
                    @intFromEnum(Op.add) => .inline_call_add_global,
                    @intFromEnum(Op.sub) => .inline_call_sub_global,
                    @intFromEnum(Op.mul) => .inline_call_mul_global,
                    else => null,
                };
                if (op) |shaped| {
                    out.byte_len = call_start;
                    out.invalidateSimple();
                    try out.appendOp(shaped);
                    try out.appendGlobalSlot(Session.directReadU16(body, 1) orelse return false);
                    return true;
                }
            }

            if (body.len == 6 and body[0] == @intFromEnum(Op.load_inline_local) and body[1] == 0 and body[2] == @intFromEnum(Op.load_global)) {
                const op: ?Op = switch (body[5]) {
                    @intFromEnum(Op.add) => .inline_call_add_arg_global,
                    @intFromEnum(Op.sub) => .inline_call_sub_arg_global,
                    @intFromEnum(Op.mul) => .inline_call_mul_arg_global,
                    else => null,
                };
                if (op) |shaped| {
                    out.byte_len = call_start;
                    out.invalidateSimple();
                    try out.appendOp(shaped);
                    try out.appendGlobalSlot(Session.directReadU16(body, 3) orelse return false);
                    return true;
                }
            }

            if (body.len == 3 and body[0] == @intFromEnum(Op.load_inline_local) and body[1] == 0 and body[2] == @intFromEnum(Op.argmax)) {
                out.byte_len = call_start;
                out.invalidateSimple();
                try out.appendOp(.inline_call_argmax1);
                return true;
            }
        }

        return false;
    }

    fn emitLambdaValueFromBodySource(
        self: *Compiler,
        out: *InstructionBuffer,
        parent: *Scope,
        allow_implicit_params: bool,
        explicit_names: []const IdentRef,
        body_source: []const u8,
    ) KError!void {
        _ = parent;
        var scope = Scope{
            .allow_implicit_params = allow_implicit_params,
        };
        defer scope.deinit(self.session.allocator);
        for (explicit_names) |ident| try scope.declareParam(ident);

        var body_storage = InstructionBuffer{};
        var lambda_scratch: ?*ScratchCode = null;
        const body: *InstructionBuffer = if (self.compile_mode == .scratch) blk: {
            const scratch = try self.code_allocator.create(ScratchCode);
            scratch.reset();
            lambda_scratch = scratch;
            break :blk &scratch.instructions;
        } else blk: {
            break :blk &body_storage;
        };

        var body_candidates = try self.directAmendBaseConsumeCandidates(&scope, body_source);
        if (!(try self.lambdaBodyStartsWithLocalBinding(body_source))) {
            try addScopeParamConsumeCandidates(&body_candidates, &scope);
        }
        const body_control_before = body.control_flow_op_count;
        const updated_body_candidates = try self.compileLambdaBodyIntoWithConsumeCandidates(body, &scope, body_source, body_candidates);
        if (body.control_flow_op_count == body_control_before) patchConsumeCandidates(body, updated_body_candidates);
        try finishCompiledInstructions(body, .tail_position);

        const code = if (self.compile_mode == .scratch) blk: {
            const scratch_code = lambda_scratch.?.finalize(scope.arity, scope.frame_slot_count);
            self.assignCodeProfile(scratch_code, .lambda, body_source);
            break :blk scratch_code;
        } else try self.finalizeCode(scope.arity, scope.frame_slot_count, body, .lambda, body_source);
        const closure = try self.code_allocator.create(Closure);
        closure.* = .{
            .header = HeapHeader.init(.closure, switch (self.compile_mode) {
                .frozen => .frozen,
                .scratch => .scratch,
            }),
            .kind = .plain,
            .code = code,
            .captures = &[_]Value{},
        };
        try out.appendOp(.const_value);
        try out.appendByte(try out.internConstant(Value.closure(closure)));
    }

    fn emitLambdaValue(self: *Compiler, out: *InstructionBuffer, parent: *Scope, lambda: ParsedLambda) KError!void {
        return try self.emitLambdaValueFromBodySource(
            out,
            parent,
            lambda.allow_implicit_params,
            lambda.explicit_names[0..lambda.explicit_count],
            self.source[lambda.body_start..lambda.body_end],
        );
    }

    fn declareParsedLambdaParams(self: *Compiler, scope: *Scope, lambda: ParsedLambda) KError!void {
        _ = self;
        var idx: u8 = 0;
        while (idx < lambda.explicit_count) : (idx += 1) {
            try scope.declareParam(lambda.explicit_names[idx]);
        }
    }

    fn findLambdaBodyEnd(self: *const Compiler, start: usize) KError!usize {
        var index = start;
        var nested: usize = 0;
        while (index < self.source.len) : (index += 1) {
            switch (self.source[index]) {
                '{' => nested += 1,
                '}' => {
                    if (nested == 0) return index;
                    nested -= 1;
                },
                else => {},
            }
        }
        return error.Parse;
    }

    fn finalizeCode(
        self: *Compiler,
        arity: u8,
        frame_slot_count: u8,
        instructions: *const InstructionBuffer,
        kind: SamplingProfileCodeKind,
        source: []const u8,
    ) !*const Code {
        const code = try duplicateCodeFromInstructions(self.code_allocator, arity, frame_slot_count, instructions);
        self.assignCodeProfile(code, kind, source);
        return code;
    }

    fn assignCodeProfile(self: *Compiler, code: *Code, kind: SamplingProfileCodeKind, source: []const u8) void {
        if (comptime !enable_sampling_profile) {
            code.profile_kind = .none;
            code.profile_source = "";
            code.profile_id = sampling_profile_no_code;
            assignCompactKProfile(code);
            return;
        }
        const trimmed = std.mem.trim(u8, source, " \t\r\n");
        code.profile_kind = kind;
        code.profile_source = trimmed;
        if (self.compile_mode != .frozen) {
            code.profile_id = sampling_profile_no_code;
            assignCompactKProfile(code);
            return;
        }
        if (code.profile_id != sampling_profile_no_code) {
            self.session.rememberSamplingProfileCodeInfo(code.profile_id, code.profile_kind, code.profile_source);
            return;
        }
        const id = self.session.nextSamplingProfileCodeId();
        code.profile_id = id;
        assignCompactKProfile(code);
        self.session.rememberSamplingProfileCodeInfo(id, code.profile_kind, code.profile_source);
    }

    fn skipSpaces(self: *Compiler) void {
        self.index = skipSpacesInSource(self.source, self.index);
    }

    fn peekByte(self: *const Compiler) ?u8 {
        if (self.index >= self.source.len) return null;
        return self.source[self.index];
    }

    fn consumeByte(self: *Compiler) ?u8 {
        if (self.index >= self.source.len) return null;
        const ch = self.source[self.index];
        self.index += 1;
        self.skipSpaces();
        return ch;
    }

    fn matchChar(self: *Compiler, expected: u8) bool {
        if (self.index >= self.source.len or self.source[self.index] != expected) return false;
        self.index += 1;
        self.skipSpaces();
        return true;
    }

    fn expectChar(self: *Compiler, expected: u8) KError!void {
        if (!self.matchChar(expected)) return error.Parse;
    }

    fn atEnd(self: *const Compiler) bool {
        return self.index >= self.source.len;
    }

    fn appendFastSingleCharLocalLoad(self: *Compiler, out: *InstructionBuffer, scope: *Scope, ch: u8) KError!bool {
        const start = self.index;
        const next = start + 1;
        if (next < self.source.len and isIdentContinue(self.source[next])) return false;

        if (scope.allow_implicit_params and scope.explicit_count == 0) {
            const maybe_slot: ?u16 = switch (ch) {
                'x' => blk: {
                    if (scope.arity < 1) scope.arity = 1;
                    break :blk 0;
                },
                'y' => blk: {
                    if (scope.arity < 2) scope.arity = 2;
                    break :blk 1;
                },
                'z' => blk: {
                    if (scope.arity < 3) scope.arity = 3;
                    break :blk 2;
                },
                else => null,
            };
            if (maybe_slot) |slot| {
                self.index = skipSpacesInSource(self.source, next);
                switch (scope.param_binding_kind) {
                    .frame_local => try self.emitResolvedLoad(out, .{ .local = slot }),
                    .inline_local => try self.emitResolvedLoad(out, .{ .inline_local = slot }),
                }
                return true;
            }
        }

        return false;
    }

    fn pendingResolvedIdent(self: *Compiler, out: *InstructionBuffer, scope: *Scope, ident: IdentRef) KError!PendingPrimary {
        if (builtinFromName(ident.text)) |builtin| return .{ .builtin = builtin };
        switch (try scope.resolveLoad(ident)) {
            .local => |slot| {
                try self.emitResolvedLoad(out, .{ .local = slot });
                return .none;
            },
            .inline_local => |slot| {
                try self.emitResolvedLoad(out, .{ .inline_local = slot });
                return .none;
            },
            .global => return .{ .global = try self.globalSlot(ident.text) },
        }
    }

    fn globalSlot(self: *Compiler, name: []const u8) KError!u16 {
        return try self.session.internGlobalSlot(name);
    }

    fn emitPendingPrimary(self: *Compiler, out: *InstructionBuffer, scope: *Scope, pending: PendingPrimary) KError!void {
        switch (pending) {
            .none => {},
            .global => |slot| {
                try out.appendOp(.load_global);
                try out.appendGlobalSlot(slot);
            },
            .builtin => |id| {
                try out.appendOp(.const_builtin);
                try out.appendByte(@intFromEnum(id));
            },
            .const_value => |value| {
                try out.appendOp(.const_value);
                try out.appendByte(try out.internConstant(value));
            },
            .lambda_source => |lambda| try self.emitLambdaValue(out, scope, lambda),
        }
    }

    fn peekPrimaryUnaryOp(self: *const Compiler) ?u8 {
        return self.peekPrimaryUnaryOpAt(self.index);
    }

    fn peekPrimaryUnaryOpAt(self: *const Compiler, index: usize) ?u8 {
        if (index >= self.source.len) return null;
        const ch = self.source[index];
        if (ch != '+' and ch != '-' and ch != '%' and ch != '!' and ch != '|' and ch != '<' and ch != '>' and ch != '~' and ch != '#' and ch != '_' and ch != '^' and ch != '$' and ch != '?' and ch != '.') return null;
        const next = skipSpacesInSource(self.source, index + 1);
        if (next >= self.source.len) return null;
        const follower = self.source[next];
        if (!isIdentStart(follower) and !std.ascii.isDigit(follower) and follower != '(' and follower != '{' and follower != '"' and follower != '`' and builtinFromChar(follower) == null) {
            return null;
        }
        return ch;
    }

    fn startsJuxtapositionOperand(self: *const Compiler, left_form: ExprForm) bool {
        if (self.index >= self.source.len) return false;
        if (self.source[self.index] == '$') {
            const next = skipSpacesInSource(self.source, self.index + 1);
            if (next < self.source.len and self.source[next] == '[') return true;
        }
        if (switch (self.source[self.index]) {
            '0'...'9', '(', '{', '[', '"', '`' => true,
            else => isIdentStart(self.source[self.index]) and builtinFromChar(self.source[self.index]) == null,
        }) return true;
        if (left_form != .verbial) return false;
        const op = self.peekPrimaryUnaryOp() orelse return false;
        return op != '.';
    }

    fn scanIdentifierAt(self: *const Compiler, start: usize) ?ScannedIdent {
        if (start >= self.source.len or !isIdentStart(self.source[start])) return null;
        const index = start;
        var end = index + 1;
        while (end < self.source.len and isIdentContinue(self.source[end])) : (end += 1) {}
        const text = self.source[index..end];
        return .{
            .ident = .{
                .text = text,
                .key = IdentKey.fromText(text),
            },
            .next_index = end,
        };
    }

    fn scanIdentifier(self: *Compiler) ?IdentRef {
        const scanned = self.scanIdentifierAt(self.index) orelse return null;
        self.index = skipSpacesInSource(self.source, scanned.next_index);
        return scanned.ident;
    }

    fn emitNumber(self: *Compiler, out: *InstructionBuffer) KError!void {
        const scanned = scanNumericLiteral(self.source, self.index) orelse return error.Parse;
        self.index = scanned.next;

        switch (scanned.literal) {
            .bool => |value| return try self.emitConstBool(out, value),
            .float => |value| return try self.emitConstFloat(out, value),
            .int => |final_value| {
                if (Value.fitsInlineInt(final_value)) {
                    return try out.emitConstInt(final_value);
                }
                try out.appendOp(.const_value);
                const value = try out.internConstant(try self.session.ownedConstantInt(
                    self.code_allocator,
                    switch (self.compile_mode) {
                        .frozen => .frozen,
                        .scratch => .scratch,
                    },
                    final_value,
                ));
                try out.appendByte(value);
                out.noteSimple(.{
                    .const_value = .{
                        .start = out.byte_len - 2,
                        .end = out.byte_len,
                        .value = out.constants[value],
                    },
                });
                return;
            },
        }
    }

    fn peekStartsSignedNumericLiteral(self: *const Compiler) bool {
        if (self.index >= self.source.len or self.source[self.index] != '-') return false;
        const next = skipSpacesInSource(self.source, self.index + 1);
        return next < self.source.len and std.ascii.isDigit(self.source[next]);
    }

    fn peekStartsVectorContinuationSignedNumericLiteral(self: *const Compiler, count: u8) bool {
        if (!self.peekStartsSignedNumericLiteral()) return false;
        if (count == 0) return true;
        if (self.index == 0) return false;
        return std.ascii.isWhitespace(self.source[self.index - 1]);
    }

    fn emitSignedNumber(self: *Compiler, out: *InstructionBuffer) KError!void {
        if (!self.peekStartsSignedNumericLiteral()) return error.Parse;
        const digit_start = skipSpacesInSource(self.source, self.index + 1);
        const scanned = scanNumericLiteral(self.source, digit_start) orelse return error.Parse;
        self.index = scanned.next;

        switch (scanned.literal) {
            .bool => return error.Parse,
            .float => |value| return try self.emitConstFloat(out, -value),
            .int => |value| {
                const negated = try checkedIntOp(.sub, 0, value);
                if (Value.fitsInlineInt(negated)) {
                    return try out.emitConstInt(negated);
                }
                try out.appendOp(.const_value);
                const pool_slot = try out.internConstant(try self.session.ownedConstantInt(
                    self.code_allocator,
                    switch (self.compile_mode) {
                        .frozen => .frozen,
                        .scratch => .scratch,
                    },
                    negated,
                ));
                try out.appendByte(pool_slot);
                out.noteSimple(.{
                    .const_value = .{
                        .start = out.byte_len - 2,
                        .end = out.byte_len,
                        .value = out.constants[pool_slot],
                    },
                });
                return;
            },
        }
    }

    fn emitConstFloat(self: *Compiler, out: *InstructionBuffer, value: f64) KError!void {
        try out.appendOp(.const_value);
        const pool_slot = try out.internConstant(try self.session.ownedConstantFloat(
            self.code_allocator,
            switch (self.compile_mode) {
                .frozen => .frozen,
                .scratch => .scratch,
            },
            value,
        ));
        try out.appendByte(pool_slot);
        out.noteSimple(.{
            .const_value = .{
                .start = out.byte_len - 2,
                .end = out.byte_len,
                .value = out.constants[pool_slot],
            },
        });
    }

    fn emitConstBool(self: *Compiler, out: *InstructionBuffer, value: bool) KError!void {
        _ = self;
        const start = out.byte_len;
        try out.appendRawOp(if (value) .const_true else .const_false);
        out.noteSimple(.{
            .const_value = .{
                .start = start,
                .end = out.byte_len,
                .value = Value.fromBool(value),
            },
        });
    }

    fn emitNumericLiteralOrVector(self: *Compiler, out: *InstructionBuffer) KError!void {
        const literal_start = out.byte_len;
        var count: u8 = 0;
        var literal_mode: ?HostDenseElem = null;

        while (true) {
            if (self.peekStartsVectorContinuationSignedNumericLiteral(count)) {
                try self.emitSignedNumber(out);
                count = std.math.add(u8, count, 1) catch return error.Unsupported;
                literal_mode = mergeLiteralMode(literal_mode, out.last_simple);
                if (!self.peekStartsNumericLiteral() and !self.peekStartsVectorContinuationSignedNumericLiteral(count)) break;
                continue;
            }

            if (try self.tryEmitBoolDigitVector(out, &count, &literal_mode)) {
                if (!self.peekStartsNumericLiteral() and !self.peekStartsVectorContinuationSignedNumericLiteral(count)) break;
                continue;
            }

            if (!self.peekStartsNumericLiteral()) break;
            try self.emitNumber(out);
            count = std.math.add(u8, count, 1) catch return error.Unsupported;
            literal_mode = mergeLiteralMode(literal_mode, out.last_simple);

            if (!self.peekStartsNumericLiteral() and !self.peekStartsVectorContinuationSignedNumericLiteral(count)) break;
        }

        if (count == 0) return error.Parse;
        if (count == 1) return;

        try out.appendOp(.make_vector);
        try out.appendByte(count);
        out.noteArrayValue(literal_start, out.byte_len, literal_mode);
    }

    fn tryEmitBoolDigitVector(self: *Compiler, out: *InstructionBuffer, count: *u8, literal_mode: *?HostDenseElem) KError!bool {
        const start = self.index;
        if (start >= self.source.len or !std.ascii.isDigit(self.source[start])) return false;

        var index = start;
        var digit_count: usize = 0;
        while (index < self.source.len and std.ascii.isDigit(self.source[index])) : (index += 1) {
            const ch = self.source[index];
            if (ch != '0' and ch != '1') return false;
            digit_count += 1;
        }
        if (digit_count <= 1 or index >= self.source.len or self.source[index] != 'b') return false;

        for (start..index) |digit_index| {
            try self.emitConstBool(out, self.source[digit_index] == '1');
        }
        count.* = std.math.add(u8, count.*, @intCast(digit_count)) catch return error.Unsupported;
        literal_mode.* = .int;
        self.index = skipSpacesInSource(self.source, index + 1);
        return true;
    }

    fn peekStartsNumericLiteral(self: *const Compiler) bool {
        return self.index < self.source.len and std.ascii.isDigit(self.source[self.index]);
    }
};

fn mergeLiteralMode(existing: ?HostDenseElem, simple: ?ProducedValue) ?HostDenseElem {
    const item_mode = if (simple) |value| InstructionBuffer.simpleNumericMode(value) else null;
    if (item_mode == null) return null;
    if (existing == null) return item_mode;
    return switch (existing.?) {
        .int => switch (item_mode.?) {
            .int => .int,
            .float => .float,
        },
        .float => .float,
    };
}

fn nextTopLevelStatement(source: []const u8, cursor: *usize) ?[]const u8 {
    var start = cursor.*;
    while (start < source.len and (source[start] == ' ' or source[start] == '\t' or source[start] == '\r' or source[start] == '\n')) : (start += 1) {}
    if (start >= source.len) {
        cursor.* = start;
        return null;
    }

    var index = start;
    var paren_depth: usize = 0;
    var bracket_depth: usize = 0;
    var brace_depth: usize = 0;
    while (index < source.len) : (index += 1) {
        switch (source[index]) {
            '(' => paren_depth += 1,
            ')' => {
                if (paren_depth != 0) paren_depth -= 1;
            },
            '[' => bracket_depth += 1,
            ']' => {
                if (bracket_depth != 0) bracket_depth -= 1;
            },
            '{' => brace_depth += 1,
            '}' => {
                if (brace_depth != 0) brace_depth -= 1;
            },
            '\n' => {
                if (paren_depth == 0 and bracket_depth == 0 and brace_depth == 0) {
                    const statement = std.mem.trim(u8, source[start..index], " \t\r\n");
                    cursor.* = index + 1;
                    if (statement.len == 0) return nextTopLevelStatement(source, cursor);
                    return statement;
                }
            },
            else => {},
        }
    }

    cursor.* = index;
    const statement = std.mem.trim(u8, source[start..index], " \t\r\n");
    if (statement.len == 0) return null;
    return statement;
}

fn splitLambdaBodyHead(source: []const u8) ?BodyStatementSplit {
    const start = skipSpacesInSource(source, 0);
    if (start >= source.len) return null;

    var index = start;
    var paren_depth: usize = 0;
    var bracket_depth: usize = 0;
    var brace_depth: usize = 0;
    while (index < source.len) : (index += 1) {
        switch (source[index]) {
            '"' => {
                index += 1;
                while (index < source.len and source[index] != '"') : (index += 1) {}
                if (index >= source.len) return null;
            },
            '(' => paren_depth += 1,
            ')' => {
                if (paren_depth == 0) return null;
                paren_depth -= 1;
            },
            '[' => bracket_depth += 1,
            ']' => {
                if (bracket_depth == 0) return null;
                bracket_depth -= 1;
            },
            '{' => brace_depth += 1,
            '}' => {
                if (brace_depth == 0) return null;
                brace_depth -= 1;
            },
            ';' => {
                if (paren_depth == 0 and bracket_depth == 0 and brace_depth == 0) {
                    const head = std.mem.trim(u8, source[start..index], " \t\r\n");
                    if (head.len == 0) return null;
                    const tail_start = skipSpacesInSource(source, index + 1);
                    if (tail_start >= source.len) return null;
                    const tail = std.mem.trim(u8, source[tail_start..], " \t\r\n");
                    if (tail.len == 0) return null;
                    return .{
                        .head = head,
                        .tail = tail,
                    };
                }
            },
            else => {},
        }
    }

    const head = std.mem.trim(u8, source[start..], " \t\r\n");
    if (head.len == 0) return null;
    return .{
        .head = head,
        .tail = null,
    };
}

fn splitWholeCondSpecialForm(source: []const u8) ?ConditionalSlices {
    const text = std.mem.trim(u8, source, " \t\r\n");
    if (text.len < 4 or text[0] != '$' or text[1] != '[') return null;

    var part_start = skipSpacesInSource(text, 2);
    var part_index: u8 = 0;
    var parts: [3][]const u8 = undefined;
    var index = part_start;
    var paren_depth: usize = 0;
    var bracket_depth: usize = 0;
    var brace_depth: usize = 0;

    while (index < text.len) : (index += 1) {
        switch (text[index]) {
            '"' => {
                index += 1;
                while (index < text.len and text[index] != '"') : (index += 1) {}
                if (index >= text.len) return null;
            },
            '(' => paren_depth += 1,
            ')' => {
                if (paren_depth == 0) return null;
                paren_depth -= 1;
            },
            '[' => bracket_depth += 1,
            ']' => {
                if (bracket_depth != 0) {
                    bracket_depth -= 1;
                    continue;
                }
                if (paren_depth != 0 or brace_depth != 0 or part_index != 2) return null;
                const part = std.mem.trim(u8, text[part_start..index], " \t\r\n");
                if (part.len == 0) return null;
                parts[part_index] = part;
                if (skipSpacesInSource(text, index + 1) != text.len) return null;
                return .{
                    .condition = parts[0],
                    .then_branch = parts[1],
                    .else_branch = parts[2],
                };
            },
            '{' => brace_depth += 1,
            '}' => {
                if (brace_depth == 0) return null;
                brace_depth -= 1;
            },
            ';' => {
                if (paren_depth == 0 and bracket_depth == 0 and brace_depth == 0) {
                    if (part_index >= 2) return null;
                    const part = std.mem.trim(u8, text[part_start..index], " \t\r\n");
                    if (part.len == 0) return null;
                    parts[part_index] = part;
                    part_index += 1;
                    part_start = skipSpacesInSource(text, index + 1);
                    index = part_start;
                    if (index >= text.len) return null;
                    index -= 1;
                }
            },
            else => {},
        }
    }

    return null;
}

fn builtinFromChar(ch: u8) ?BuiltinId {
    return switch (ch) {
        '+' => .add,
        '-' => .sub,
        '*' => .mul,
        '%' => .div,
        '!' => .iota,
        '&' => .minimum,
        '|' => .maximum,
        '<' => .less,
        '>' => .more,
        '~' => .not,
        ',' => .concat,
        '#' => .count,
        '_' => .floor,
        '^' => .null_fill_without,
        '=' => .equal,
        else => null,
    };
}

fn builtinSupportsInnerProductVerb(builtin: BuiltinId) bool {
    return switch (builtin) {
        .add, .sub, .mul, .div, .minimum, .maximum, .less, .more, .concat, .count, .floor, .sort, .equal => true,
        .iota, .not, .reverse, .grade_up, .grade_down, .stringify, .bytes, .utf8, .char, .unique, .tokenize, .detokenize, .eval_string, .cast, .contains, .split, .join, .find, .grad, .valuegrad, .prng, .load, .save, .sql, .register, .rotcache, .rotcacheupdate, .rotcacheview, .rope, .ropeflat, .ropecisflat, .rmsnorm, .layernorm, .gelu, .geluapprox, .mlpdense, .conv2d, .convtranspose2d, .upsamplenearest2d, .groupnorm, .softmax, .sdpa, .sam3boxrpb, .sdpamask, .sdpaflat, .exp, .log, .sin, .cos, .tanh, .sigmoid, .take, .drop, .reshape, .null_fill_without, .pow => false,
    };
}

fn builtinFromName(name: []const u8) ?BuiltinId {
    if (std.mem.eql(u8, name, "sqrt")) return .div;
    if (std.mem.eql(u8, name, "pow")) return .pow;
    if (std.mem.eql(u8, name, "exp")) return .exp;
    if (std.mem.eql(u8, name, "log")) return .log;
    if (std.mem.eql(u8, name, "sin")) return .sin;
    if (std.mem.eql(u8, name, "cos")) return .cos;
    if (std.mem.eql(u8, name, "tanh")) return .tanh;
    if (std.mem.eql(u8, name, "sigmoid")) return .sigmoid;
    if (std.mem.eql(u8, name, "contains")) return .contains;
    if (std.mem.eql(u8, name, "split")) return .split;
    if (std.mem.eql(u8, name, "join")) return .join;
    if (std.mem.eql(u8, name, "bytes")) return .bytes;
    if (std.mem.eql(u8, name, "utf8")) return .utf8;
    if (std.mem.eql(u8, name, "char")) return .char;
    if (std.mem.eql(u8, name, "tokenize")) return .tokenize;
    if (std.mem.eql(u8, name, "detokenize")) return .detokenize;
    if (std.mem.eql(u8, name, "null")) return .null_fill_without;
    if (std.mem.eql(u8, name, "fill")) return .null_fill_without;
    if (std.mem.eql(u8, name, "without")) return .null_fill_without;
    if (std.mem.eql(u8, name, "except")) return .null_fill_without;
    if (std.mem.eql(u8, name, "sort")) return .sort;
    if (std.mem.eql(u8, name, "grad")) return .grad;
    if (std.mem.eql(u8, name, "valuegrad")) return .valuegrad;
    if (std.mem.eql(u8, name, "prng")) return .prng;
    if (std.mem.eql(u8, name, "load")) return .load;
    if (std.mem.eql(u8, name, "save")) return .save;
    if (std.mem.eql(u8, name, "sql")) return .sql;
    if (std.mem.eql(u8, name, "register")) return .register;
    if (std.mem.eql(u8, name, "rotcache")) return .rotcache;
    if (std.mem.eql(u8, name, "rotcacheupdate")) return .rotcacheupdate;
    if (std.mem.eql(u8, name, "rotcacheview")) return .rotcacheview;
    if (std.mem.eql(u8, name, "rope")) return .rope;
    if (std.mem.eql(u8, name, "ropeflat")) return .ropeflat;
    if (std.mem.eql(u8, name, "ropecisflat")) return .ropecisflat;
    if (std.mem.eql(u8, name, "rmsnorm")) return .rmsnorm;
    if (std.mem.eql(u8, name, "layernorm")) return .layernorm;
    if (std.mem.eql(u8, name, "gelu")) return .gelu;
    if (std.mem.eql(u8, name, "geluapprox")) return .geluapprox;
    if (std.mem.eql(u8, name, "mlpdense")) return .mlpdense;
    if (std.mem.eql(u8, name, "conv2d")) return .conv2d;
    if (std.mem.eql(u8, name, "convtranspose2d")) return .convtranspose2d;
    if (std.mem.eql(u8, name, "upsamplenearest2d")) return .upsamplenearest2d;
    if (std.mem.eql(u8, name, "groupnorm")) return .groupnorm;
    if (std.mem.eql(u8, name, "softmax")) return .softmax;
    if (std.mem.eql(u8, name, "sdpa")) return .sdpa;
    if (std.mem.eql(u8, name, "sam3boxrpb")) return .sam3boxrpb;
    if (std.mem.eql(u8, name, "sdpamask")) return .sdpamask;
    if (std.mem.eql(u8, name, "sdpaflat")) return .sdpaflat;
    return null;
}
